/* ssm-data.js — Food Manager practice (ServSafe-style, FDA Food Code 2022). 5 categories, all 6 languages.
   window.SSM = { cats:[{id,name,blurb}], q:[{cat,a,q,o,e}] }
   140 questions: pathogens(28), flow(28), haccp(28), staff(28), facilities(28) */
window.SSM = {"cats":[{"id":"pathogens","name":{"en":"Pathogens & Contamination","es":"Patógenos y contaminación","ru":"Патогены и загрязнение","tr":"Patojenler ve Bulaşma","hi":"रोगजनक और संदूषण","ar":"مسببات الأمراض والتلوث"},"blurb":{"en":"The Big 6, hazard classes, allergens, TCS foods and FAT TOM.","es":"Los 6 grandes, tipos de peligros, alérgenos, alimentos TCS y FAT TOM.","ru":"«Большая шестёрка», классы опасностей, аллергены, продукты TCS и FAT TOM.","tr":"Big 6, tehlike sınıfları, alerjenler, TCS gıdalar ve FAT TOM.","hi":"बिग 6, खतरे की श्रेणियाँ, एलर्जेन, TCS खाद्य पदार्थ और FAT TOM।","ar":"الستة الكبرى وأصناف المخاطر ومسببات الحساسية وأطعمة TCS وFAT TOM."}},{"id":"flow","name":{"en":"Flow of Food","es":"Flujo de los alimentos","ru":"Путь продукта","tr":"Gıdanın Akışı","hi":"भोजन का प्रवाह","ar":"مسار الغذاء"},"blurb":{"en":"Receiving, storage, cooking, cooling, reheating, holding and time control.","es":"Recepción, almacenamiento, cocción, enfriamiento, recalentamiento, mantenimiento y control por tiempo.","ru":"Приёмка, хранение, приготовление, охлаждение, разогрев, хранение и контроль по времени.","tr":"Teslim alma, depolama, pişirme, soğutma, yeniden ısıtma, bekletme ve zaman kontrolü.","hi":"प्राप्ति, भंडारण, पकाना, ठंडा करना, दोबारा गर्म करना, रखना और समय नियंत्रण।","ar":"الاستلام والتخزين والطهي والتبريد وإعادة التسخين والحفظ والتحكم بالوقت."}},{"id":"haccp","name":{"en":"Management Systems & HACCP","es":"Sistemas de gestión y HACCP","ru":"Системы управления и HACCP","tr":"Yönetim Sistemleri ve HACCP","hi":"प्रबंधन प्रणालियाँ और HACCP","ar":"أنظمة الإدارة وHACCP"},"blurb":{"en":"Active managerial control, the 7 HACCP principles, variances and crisis response.","es":"Control gerencial activo, los 7 principios HACCP, variaciones y respuesta a crisis.","ru":"Активный управленческий контроль, 7 принципов HACCP, отклонения и реагирование на кризисы.","tr":"Aktif yönetimsel kontrol, 7 HACCP ilkesi, varyanslar ve kriz yönetimi.","hi":"सक्रिय प्रबंधकीय नियंत्रण, 7 HACCP सिद्धांत, विचरण और संकट प्रतिक्रिया।","ar":"التحكم الإداري الفعّال ومبادئ HACCP السبعة والإعفاءات وإدارة الأزمات."}},{"id":"staff","name":{"en":"Staff, Hygiene & Training","es":"Personal, higiene y capacitación","ru":"Персонал, гигиена и обучение","tr":"Personel, Hijyen ve Eğitim","hi":"स्टाफ, स्वच्छता और प्रशिक्षण","ar":"الموظفون والنظافة والتدريب"},"blurb":{"en":"Manager duties, exclusion vs restriction, handwashing, training and food safety culture.","es":"Deberes del gerente, exclusión vs restricción, lavado de manos, capacitación y cultura de seguridad alimentaria.","ru":"Обязанности менеджера, отстранение и ограничение, мытьё рук, обучение и культура пищевой безопасности.","tr":"Yönetici görevleri, dışlama ve kısıtlama, el yıkama, eğitim ve gıda güvenliği kültürü.","hi":"प्रबंधक कर्तव्य, बहिष्करण बनाम प्रतिबंध, हाथ धोना, प्रशिक्षण और खाद्य सुरक्षा संस्कृति।","ar":"مهام المدير والاستبعاد مقابل التقييد وغسل اليدين والتدريب وثقافة سلامة الغذاء."}},{"id":"facilities","name":{"en":"Facilities, Cleaning & Pests","es":"Instalaciones, limpieza y plagas","ru":"Помещения, уборка и вредители","tr":"Tesisler, Temizlik ve Haşereler","hi":"सुविधाएँ, सफाई और कीट","ar":"المرافق والتنظيف والآفات"},"blurb":{"en":"Equipment standards, warewashing, sanitizers, plumbing, lighting and pest management.","es":"Normas de equipo, lavado de vajilla, desinfectantes, plomería, iluminación y control de plagas.","ru":"Стандарты оборудования, мойка посуды, дезинфектанты, сантехника, освещение и борьба с вредителями.","tr":"Ekipman standartları, bulaşık yıkama, dezenfektanlar, tesisat, aydınlatma ve haşere yönetimi.","hi":"उपकरण मानक, बर्तन धुलाई, सैनिटाइज़र, नलसाजी, प्रकाश और कीट प्रबंधन।","ar":"معايير المعدات وغسل الأواني والمطهرات والسباكة والإضاءة ومكافحة الآفات."}}],"q":[{"cat":"pathogens","a":2,"q":{"en":"A banquet guest becomes violently ill with vomiting only 2 hours after eating a ham salad left at room temperature. Which type of foodborne illness does this rapid onset most strongly suggest?","es":"Un invitado a un banquete se enferma gravemente con vómitos solo 2 horas después de comer una ensalada de jamón dejada a temperatura ambiente. ¿Qué tipo de enfermedad transmitida por alimentos sugiere con más fuerza este inicio tan rápido?","ru":"Гость банкета тяжело заболевает — только рвота — всего через 2 часа после употребления салата с ветчиной, оставленного при комнатной температуре. На какой тип пищевого заболевания сильнее всего указывает такое быстрое начало?","tr":"Bir ziyafet konuğu, oda sıcaklığında bırakılmış jambonlu salata yedikten sadece 2 saat sonra şiddetli kusma ile hastalanır. Bu hızlı başlangıç en güçlü şekilde hangi gıda kaynaklı hastalık türüne işaret eder?","hi":"एक भोज अतिथि कमरे के तापमान पर छोड़े गए हैम सलाद को खाने के केवल 2 घंटे बाद उल्टी के साथ गंभीर रूप से बीमार हो जाता है। यह तेज़ शुरुआत सबसे मजबूती से किस प्रकार की खाद्य जनित बीमारी का संकेत देती है?","ar":"يُصاب أحد ضيوف المأدبة بمرض شديد مع القيء بعد ساعتين فقط من تناول سلطة لحم الخنزير التي تُركت في درجة حرارة الغرفة. أي نوع من الأمراض المنقولة بالغذاء تشير إليه هذه البداية السريعة بقوة؟"},"o":[{"en":"A viral infection such as Hepatitis A","es":"Una infección viral como la Hepatitis A","ru":"Вирусная инфекция, например гепатит A","tr":"Hepatit A gibi viral bir enfeksiyon","hi":"हेपेटाइटिस A जैसा वायरल संक्रमण","ar":"عدوى فيروسية مثل التهاب الكبد A"},{"en":"A parasitic infection from Anisakis","es":"Una infección parasitaria por Anisakis","ru":"Паразитарная инфекция, вызванная Anisakis","tr":"Anisakis kaynaklı paraziter bir enfeksiyon","hi":"Anisakis से परजीवी संक्रमण","ar":"عدوى طفيلية من الأنيساكيس"},{"en":"An intoxication from a preformed toxin (e.g., Staphylococcus aureus)","es":"Una intoxicación por una toxina preformada (p. ej., Staphylococcus aureus)","ru":"Интоксикация уже образовавшимся токсином (например, Staphylococcus aureus)","tr":"Önceden oluşmuş bir toksinden kaynaklanan zehirlenme (örn. Staphylococcus aureus)","hi":"पूर्व-निर्मित विष से विषाक्तता (जैसे, Staphylococcus aureus)","ar":"تسمم من سُم مُتكوّن مسبقًا (مثل المكورات العنقودية الذهبية)"},{"en":"A toxin-mediated infection from Shiga toxin-producing E. coli","es":"Una infección mediada por toxina de E. coli productora de toxina Shiga","ru":"Токсин-опосредованная инфекция, вызванная E. coli, продуцирующей шига-токсин","tr":"Shiga toksini üreten E. coli'den kaynaklanan toksin aracılı enfeksiyon","hi":"शिगा-विष उत्पादक E. coli से विष-मध्यस्थ संक्रमण","ar":"عدوى بوساطة السموم من الإشريكية القولونية المنتجة لسم شيغا"}],"e":{"en":"Very rapid onset (1–6 hours) with sudden vomiting points to an intoxication, where a preformed toxin (classically Staphylococcus aureus) is already in the food; cooking does not destroy this heat-stable toxin.","es":"Un inicio muy rápido (1–6 horas) con vómitos repentinos apunta a una intoxicación, donde una toxina preformada (clásicamente Staphylococcus aureus) ya está en el alimento; cocinar no destruye esta toxina termoestable.","ru":"Очень быстрое начало (1–6 часов) с внезапной рвотой указывает на интоксикацию, когда уже образовавшийся токсин (классически Staphylococcus aureus) уже находится в пище; при варке этот термостойкий токсин не разрушается.","tr":"Çok hızlı başlangıç (1–6 saat) ve ani kusma, önceden oluşmuş bir toksinin (klasik olarak Staphylococcus aureus) gıdada zaten bulunduğu bir zehirlenmeye işaret eder; pişirme bu ısıya dayanıklı toksini yok etmez.","hi":"बहुत तेज़ शुरुआत (1–6 घंटे) और अचानक उल्टी विषाक्तता की ओर इशारा करती है, जहाँ पूर्व-निर्मित विष (आमतौर पर Staphylococcus aureus) पहले से भोजन में होता है; पकाने से यह ऊष्मा-स्थिर विष नष्ट नहीं होता।","ar":"البداية السريعة جدًا (1–6 ساعات) مع القيء المفاجئ تشير إلى تسمم، حيث يكون السُم المُتكوّن مسبقًا (وعادةً المكورات العنقودية الذهبية) موجودًا بالفعل في الطعام؛ والطهي لا يدمر هذا السُم المقاوم للحرارة."}},{"cat":"pathogens","a":0,"q":{"en":"Of the three hazard classes recognized in the Food Code, which is responsible for the large majority of reported foodborne-illness outbreaks?","es":"De las tres clases de peligros reconocidas en el Código de Alimentos, ¿cuál es responsable de la gran mayoría de los brotes de enfermedades transmitidas por alimentos notificados?","ru":"Из трёх классов опасностей, признанных в Кодексе пищевых продуктов, какой отвечает за подавляющее большинство зарегистрированных вспышек пищевых заболеваний?","tr":"Gıda Kodu'nda tanınan üç tehlike sınıfından hangisi bildirilen gıda kaynaklı hastalık salgınlarının büyük çoğunluğundan sorumludur?","hi":"फूड कोड में मान्यता प्राप्त तीन खतरा वर्गों में से, रिपोर्ट किए गए अधिकांश खाद्य जनित बीमारी के प्रकोपों के लिए कौन जिम्मेदार है?","ar":"من بين فئات المخاطر الثلاث المعترف بها في مدونة الغذاء، أيها مسؤول عن الغالبية العظمى من فاشيات الأمراض المنقولة بالغذاء المُبلّغ عنها؟"},"o":[{"en":"Biological hazards (bacteria, viruses, parasites, fungi)","es":"Peligros biológicos (bacterias, virus, parásitos, hongos)","ru":"Биологические опасности (бактерии, вирусы, паразиты, грибки)","tr":"Biyolojik tehlikeler (bakteriler, virüsler, parazitler, mantarlar)","hi":"जैविक खतरे (बैक्टीरिया, वायरस, परजीवी, कवक)","ar":"المخاطر البيولوجية (البكتيريا والفيروسات والطفيليات والفطريات)"},{"en":"Chemical hazards (cleaners, pesticides, toxic metals)","es":"Peligros químicos (limpiadores, pesticidas, metales tóxicos)","ru":"Химические опасности (чистящие средства, пестициды, токсичные металлы)","tr":"Kimyasal tehlikeler (temizleyiciler, pestisitler, toksik metaller)","hi":"रासायनिक खतरे (क्लीनर, कीटनाशक, विषैली धातुएँ)","ar":"المخاطر الكيميائية (المنظفات والمبيدات والمعادن السامة)"},{"en":"Physical hazards (glass, metal, bone fragments)","es":"Peligros físicos (vidrio, metal, fragmentos de hueso)","ru":"Физические опасности (стекло, металл, осколки костей)","tr":"Fiziksel tehlikeler (cam, metal, kemik parçaları)","hi":"भौतिक खतरे (काँच, धातु, हड्डी के टुकड़े)","ar":"المخاطر الفيزيائية (الزجاج والمعدن وشظايا العظام)"},{"en":"Radiological hazards (radioactive isotopes)","es":"Peligros radiológicos (isótopos radiactivos)","ru":"Радиологические опасности (радиоактивные изотопы)","tr":"Radyolojik tehlikeler (radyoaktif izotoplar)","hi":"रेडियोलॉजिकल खतरे (रेडियोधर्मी समस्थानिक)","ar":"المخاطر الإشعاعية (النظائر المشعة)"}],"e":{"en":"Biological hazards — especially bacteria and viruses — cause the large majority of foodborne illnesses, which is why time/temperature control and personal hygiene are the manager's central defenses.","es":"Los peligros biológicos, especialmente bacterias y virus, causan la gran mayoría de las enfermedades transmitidas por alimentos, por lo que el control de tiempo/temperatura y la higiene personal son las defensas centrales del gerente.","ru":"Биологические опасности — особенно бактерии и вирусы — вызывают подавляющее большинство пищевых заболеваний, поэтому контроль времени/температуры и личная гигиена являются главной защитой менеджера.","tr":"Biyolojik tehlikeler — özellikle bakteriler ve virüsler — gıda kaynaklı hastalıkların büyük çoğunluğuna neden olur; bu nedenle zaman/sıcaklık kontrolü ve kişisel hijyen yöneticinin temel savunmalarıdır.","hi":"जैविक खतरे — विशेषकर बैक्टीरिया और वायरस — अधिकांश खाद्य जनित बीमारियों का कारण बनते हैं, इसीलिए समय/तापमान नियंत्रण और व्यक्तिगत स्वच्छता प्रबंधक की मुख्य रक्षा हैं।","ar":"المخاطر البيولوجية — وخاصة البكتيريا والفيروسات — تسبب الغالبية العظمى من الأمراض المنقولة بالغذاء، ولهذا فإن التحكم في الوقت/الحرارة والنظافة الشخصية هما الدفاع الرئيسي للمدير."}},{"cat":"pathogens","a":1,"q":{"en":"A manager reviews an outbreak traced to undercooked poultry and raw shell eggs used in a house-made dressing. Which Big 6 pathogen is the most likely cause?","es":"Un gerente revisa un brote atribuido a aves de corral poco cocidas y huevos crudos con cáscara usados en un aderezo hecho en casa. ¿Cuál patógeno de los 'Big 6' es la causa más probable?","ru":"Менеджер разбирает вспышку, связанную с недостаточно прожаренной птицей и сырыми яйцами в скорлупе, использованными в домашней заправке. Какой патоген из «Большой шестёрки» является наиболее вероятной причиной?","tr":"Bir yönetici, az pişmiş kümes hayvanları ve ev yapımı sosta kullanılan çiğ kabuklu yumurtalara dayandırılan bir salgını inceliyor. 'Büyük 6' patojeninden hangisi en olası nedendir?","hi":"एक प्रबंधक कम पके पोल्ट्री और घर में बनी ड्रेसिंग में इस्तेमाल किए गए कच्चे खोल वाले अंडों से जुड़े प्रकोप की समीक्षा करता है। 'बिग 6' रोगजनकों में से कौन सबसे संभावित कारण है?","ar":"يراجع مدير فاشية عُزيت إلى دواجن غير مطهية جيدًا وبيض نيء بقشره استُخدم في صلصة محلية الصنع. أي من مسببات 'الستة الكبار' هو السبب الأرجح؟"},"o":[{"en":"Hepatitis A","es":"Hepatitis A","ru":"Гепатит A","tr":"Hepatit A","hi":"हेपेटाइटिस A","ar":"التهاب الكبد A"},{"en":"Nontyphoidal Salmonella spp.","es":"Salmonella spp. no tifoidea","ru":"Нетифоидные Salmonella spp.","tr":"Tifo dışı Salmonella spp.","hi":"गैर-टाइफाइडल Salmonella spp.","ar":"السالمونيلا غير التيفية"},{"en":"Norovirus","es":"Norovirus","ru":"Норовирус","tr":"Norovirüs","hi":"नोरोवायरस","ar":"نوروفيروس"},{"en":"Shigella spp.","es":"Shigella spp.","ru":"Shigella spp.","tr":"Shigella spp.","hi":"Shigella spp.","ar":"الشيغيلا"}],"e":{"en":"Nontyphoidal Salmonella is classically associated with poultry, eggs, and dairy; it causes an infection, so thorough cooking (poultry to 165°F) and proper egg handling are the key controls.","es":"La Salmonella no tifoidea se asocia clásicamente con aves, huevos y lácteos; causa una infección, por lo que la cocción completa (aves a 165°F) y el manejo adecuado de los huevos son los controles clave.","ru":"Нетифоидная Salmonella классически связана с птицей, яйцами и молочными продуктами; она вызывает инфекцию, поэтому тщательная тепловая обработка (птица до 165°F) и правильное обращение с яйцами являются ключевыми мерами контроля.","tr":"Tifo dışı Salmonella klasik olarak kümes hayvanları, yumurta ve süt ürünleriyle ilişkilidir; enfeksiyona neden olur, bu nedenle iyice pişirme (kümes hayvanları 165°F) ve doğru yumurta kullanımı temel kontrollerdir.","hi":"गैर-टाइफाइडल Salmonella आमतौर पर पोल्ट्री, अंडे और डेयरी से जुड़ा होता है; यह संक्रमण पैदा करता है, इसलिए अच्छी तरह पकाना (पोल्ट्री 165°F तक) और अंडों का उचित प्रबंधन मुख्य नियंत्रण हैं।","ar":"ترتبط السالمونيلا غير التيفية عادةً بالدواجن والبيض ومنتجات الألبان؛ وتسبب عدوى، لذا فإن الطهي الجيد (الدواجن إلى 165°F) والتعامل السليم مع البيض هما الضابطان الرئيسيان."}},{"cat":"pathogens","a":3,"q":{"en":"Why does the Food Code single out Salmonella Typhi for stricter employee-exclusion and reporting than most other pathogens?","es":"¿Por qué el Código de Alimentos distingue a Salmonella Typhi con una exclusión y notificación de empleados más estrictas que la mayoría de los demás patógenos?","ru":"Почему Кодекс пищевых продуктов выделяет Salmonella Typhi для более строгого отстранения сотрудников и отчётности, чем большинство других патогенов?","tr":"Gıda Kodu neden Salmonella Typhi'yi çoğu diğer patojene göre daha katı çalışan dışlama ve bildirim için ayırıyor?","hi":"फूड कोड अधिकांश अन्य रोगजनकों की तुलना में Salmonella Typhi को कर्मचारी बहिष्करण और रिपोर्टिंग के लिए अधिक सख्ती से अलग क्यों करता है?","ar":"لماذا تُفرد مدونة الغذاء السالمونيلا التيفية باستبعاد وإبلاغ أكثر صرامة للموظفين مقارنة بمعظم مسببات الأمراض الأخرى؟"},"o":[{"en":"It only survives in acidic foods below pH 4.6","es":"Solo sobrevive en alimentos ácidos por debajo de pH 4.6","ru":"Она выживает только в кислых продуктах ниже pH 4.6","tr":"Yalnızca pH 4.6'nın altındaki asidik gıdalarda hayatta kalır","hi":"यह केवल pH 4.6 से नीचे अम्लीय भोजन में जीवित रहता है","ar":"لا تبقى إلا في الأطعمة الحمضية أقل من درجة حموضة 4.6"},{"en":"It grows only at freezing temperatures","es":"Solo crece a temperaturas de congelación","ru":"Она растёт только при температуре замерзания","tr":"Yalnızca donma sıcaklıklarında ürer","hi":"यह केवल जमाव तापमान पर बढ़ता है","ar":"لا تنمو إلا في درجات حرارة التجمد"},{"en":"It is a physical hazard, not a biological one","es":"Es un peligro físico, no biológico","ru":"Это физическая опасность, а не биологическая","tr":"Biyolojik değil, fiziksel bir tehlikedir","hi":"यह जैविक नहीं, बल्कि भौतिक खतरा है","ar":"إنها خطر فيزيائي وليس بيولوجيًا"},{"en":"It causes typhoid fever, a severe systemic illness, and humans are its reservoir, so an infected worker readily spreads it","es":"Causa fiebre tifoidea, una enfermedad sistémica grave, y los humanos son su reservorio, por lo que un trabajador infectado la propaga fácilmente","ru":"Она вызывает брюшной тиф — тяжёлое системное заболевание, и человек является её резервуаром, поэтому инфицированный работник легко её распространяет","tr":"Şiddetli sistemik bir hastalık olan tifoya neden olur ve insanlar onun rezervuarıdır, bu yüzden enfekte bir çalışan onu kolayca yayar","hi":"यह टाइफाइड बुखार, एक गंभीर प्रणालीगत बीमारी पैदा करता है, और मनुष्य इसका भंडार हैं, इसलिए संक्रमित कर्मचारी इसे आसानी से फैलाता है","ar":"تسبب حمى التيفوئيد، وهي مرض جهازي شديد، والإنسان هو مستودعها، لذا فإن العامل المصاب ينشرها بسهولة"}],"e":{"en":"Salmonella Typhi lives in humans and causes typhoid fever; because an infected food worker can shed it and transmit a severe illness, the Code requires exclusion and notification of the regulatory authority.","es":"Salmonella Typhi vive en los humanos y causa fiebre tifoidea; como un trabajador infectado puede excretarla y transmitir una enfermedad grave, el Código exige la exclusión y la notificación a la autoridad reguladora.","ru":"Salmonella Typhi живёт в организме человека и вызывает брюшной тиф; поскольку инфицированный работник может выделять её и передавать тяжёлое заболевание, Кодекс требует отстранения и уведомления контролирующего органа.","tr":"Salmonella Typhi insanlarda yaşar ve tifoya neden olur; enfekte bir gıda çalışanı onu saçabileceği ve şiddetli bir hastalığı bulaştırabileceği için, Kod dışlamayı ve düzenleyici otoritenin bilgilendirilmesini gerektirir.","hi":"Salmonella Typhi मनुष्यों में रहता है और टाइफाइड बुखार पैदा करता है; चूँकि संक्रमित खाद्य कर्मचारी इसे फैला सकता है और गंभीर बीमारी संचारित कर सकता है, कोड बहिष्करण और नियामक प्राधिकरण को सूचित करने की माँग करता है।","ar":"تعيش السالمونيلا التيفية في البشر وتسبب حمى التيفوئيد؛ ولأن العامل المصاب يمكن أن يطرحها وينقل مرضًا شديدًا، تشترط المدونة الاستبعاد وإبلاغ السلطة التنظيمية."}},{"cat":"pathogens","a":1,"q":{"en":"Within FAT TOM, most foodborne bacteria grow best in foods whose pH falls in which range?","es":"Dentro de FAT TOM, la mayoría de las bacterias transmitidas por alimentos crecen mejor en alimentos cuyo pH se encuentra en qué rango?","ru":"В рамках FAT TOM большинство пищевых бактерий лучше всего растут в продуктах, pH которых находится в каком диапазоне?","tr":"FAT TOM içinde, çoğu gıda kaynaklı bakteri, pH'ı hangi aralıkta olan gıdalarda en iyi ürer?","hi":"FAT TOM के भीतर, अधिकांश खाद्य जनित बैक्टीरिया उन खाद्य पदार्थों में सबसे अच्छे से बढ़ते हैं जिनका pH किस सीमा में होता है?","ar":"ضمن FAT TOM، تنمو معظم البكتيريا المنقولة بالغذاء بشكل أفضل في الأطعمة التي تقع درجة حموضتها في أي نطاق؟"},"o":[{"en":"0.0 to 3.0 (strongly acidic)","es":"0.0 a 3.0 (fuertemente ácido)","ru":"от 0.0 до 3.0 (сильнокислая)","tr":"0.0 ile 3.0 (güçlü asidik)","hi":"0.0 से 3.0 (अत्यधिक अम्लीय)","ar":"0.0 إلى 3.0 (حمضي قوي)"},{"en":"4.6 to 7.5 (slightly acidic to neutral)","es":"4.6 a 7.5 (ligeramente ácido a neutro)","ru":"от 4.6 до 7.5 (слабокислая до нейтральной)","tr":"4.6 ile 7.5 (hafif asidik ile nötr)","hi":"4.6 से 7.5 (हल्का अम्लीय से उदासीन)","ar":"4.6 إلى 7.5 (حمضي خفيف إلى متعادل)"},{"en":"8.0 to 10.0 (alkaline)","es":"8.0 a 10.0 (alcalino)","ru":"от 8.0 до 10.0 (щелочная)","tr":"8.0 ile 10.0 (alkali)","hi":"8.0 से 10.0 (क्षारीय)","ar":"8.0 إلى 10.0 (قلوي)"},{"en":"11.0 to 14.0 (strongly alkaline)","es":"11.0 a 14.0 (fuertemente alcalino)","ru":"от 11.0 до 14.0 (сильнощелочная)","tr":"11.0 ile 14.0 (güçlü alkali)","hi":"11.0 से 14.0 (अत्यधिक क्षारीय)","ar":"11.0 إلى 14.0 (قلوي قوي)"}],"e":{"en":"Bacteria grow best at a pH of 4.6 to 7.5. Foods with pH at or below 4.6 (like properly acidified pickles) resist growth, which is why acidification is a recognized control.","es":"Las bacterias crecen mejor a un pH de 4.6 a 7.5. Los alimentos con pH igual o inferior a 4.6 (como los encurtidos correctamente acidificados) resisten el crecimiento, por lo que la acidificación es un control reconocido.","ru":"Бактерии лучше всего растут при pH от 4.6 до 7.5. Продукты с pH 4.6 или ниже (например, правильно подкисленные соленья) препятствуют росту, поэтому подкисление является признанной мерой контроля.","tr":"Bakteriler en iyi 4.6 ile 7.5 pH aralığında ürer. pH'ı 4.6 veya altında olan gıdalar (uygun şekilde asitlendirilmiş turşular gibi) üremeye direnir, bu nedenle asitlendirme tanınan bir kontroldür.","hi":"बैक्टीरिया 4.6 से 7.5 के pH पर सबसे अच्छे से बढ़ते हैं। 4.6 या उससे कम pH वाले खाद्य पदार्थ (जैसे उचित रूप से अम्लीकृत अचार) वृद्धि का प्रतिरोध करते हैं, इसीलिए अम्लीकरण एक मान्यता प्राप्त नियंत्रण है।","ar":"تنمو البكتيريا بشكل أفضل عند درجة حموضة من 4.6 إلى 7.5. الأطعمة ذات درجة الحموضة 4.6 أو أقل (مثل المخللات المُحمّضة بشكل صحيح) تقاوم النمو، ولهذا يُعد التحميض ضابطًا معترفًا به."}},{"cat":"pathogens","a":2,"q":{"en":"A manager is deciding whether a new house-made product needs time/temperature control. Above which water activity (aw) value can most pathogenic bacteria multiply?","es":"Un gerente está decidiendo si un nuevo producto hecho en casa necesita control de tiempo/temperatura. ¿Por encima de qué valor de actividad de agua (aw) pueden multiplicarse la mayoría de las bacterias patógenas?","ru":"Менеджер решает, нужен ли новому домашнему продукту контроль времени/температуры. Выше какого значения активности воды (aw) могут размножаться большинство патогенных бактерий?","tr":"Bir yönetici, yeni bir ev yapımı ürünün zaman/sıcaklık kontrolü gerektirip gerektirmediğine karar veriyor. Çoğu patojen bakteri hangi su aktivitesi (aw) değerinin üzerinde çoğalabilir?","hi":"एक प्रबंधक तय कर रहा है कि क्या एक नए घर-निर्मित उत्पाद को समय/तापमान नियंत्रण की आवश्यकता है। किस जल सक्रियता (aw) मान से ऊपर अधिकांश रोगजनक बैक्टीरिया गुणा कर सकते हैं?","ar":"يقرر مدير ما إذا كان منتج جديد محلي الصنع يحتاج إلى التحكم في الوقت/الحرارة. فوق أي قيمة نشاط مائي (aw) يمكن أن تتكاثر معظم البكتيريا المُمرضة؟"},"o":[{"en":"0.60","es":"0.60","ru":"0.60","tr":"0.60","hi":"0.60","ar":"0.60"},{"en":"0.75","es":"0.75","ru":"0.75","tr":"0.75","hi":"0.75","ar":"0.75"},{"en":"0.85","es":"0.85","ru":"0.85","tr":"0.85","hi":"0.85","ar":"0.85"},{"en":"0.95","es":"0.95","ru":"0.95","tr":"0.95","hi":"0.95","ar":"0.95"}],"e":{"en":"Water activity above 0.85 supports growth of most disease-causing bacteria; a product with aw of 0.85 or below (combined with the right pH) may be classified non-TCS.","es":"Una actividad de agua superior a 0.85 favorece el crecimiento de la mayoría de las bacterias causantes de enfermedades; un producto con aw de 0.85 o menos (combinado con el pH correcto) puede clasificarse como no TCS.","ru":"Активность воды выше 0.85 поддерживает рост большинства болезнетворных бактерий; продукт с aw 0.85 или ниже (в сочетании с нужным pH) может быть классифицирован как не-TCS.","tr":"0.85'in üzerindeki su aktivitesi çoğu hastalık yapan bakterinin üremesini destekler; aw'si 0.85 veya altında olan bir ürün (doğru pH ile birleştiğinde) TCS olmayan olarak sınıflandırılabilir.","hi":"0.85 से ऊपर जल सक्रियता अधिकांश रोग-कारक बैक्टीरिया की वृद्धि का समर्थन करती है; 0.85 या उससे कम aw वाला उत्पाद (सही pH के साथ मिलकर) गैर-TCS वर्गीकृत किया जा सकता है।","ar":"النشاط المائي فوق 0.85 يدعم نمو معظم البكتيريا المسببة للأمراض؛ والمنتج ذو النشاط المائي 0.85 أو أقل (مع درجة الحموضة الصحيحة) قد يُصنّف على أنه غير خاضع للتحكم في الوقت والحرارة."}},{"cat":"pathogens","a":0,"q":{"en":"Which of the following, once prepared, is a TCS food that many operators overlook because it seems 'dry' or 'plain'?","es":"¿Cuál de los siguientes, una vez preparado, es un alimento TCS que muchos operadores pasan por alto porque parece 'seco' o 'simple'?","ru":"Какой из следующих продуктов после приготовления является TCS-продуктом, который многие операторы упускают из виду, потому что он кажется «сухим» или «простым»?","tr":"Aşağıdakilerden hangisi, hazırlandıktan sonra, 'kuru' veya 'sade' göründüğü için birçok işletmecinin gözden kaçırdığı bir TCS gıdasıdır?","hi":"निम्नलिखित में से कौन, एक बार तैयार होने पर, एक TCS भोजन है जिसे कई ऑपरेटर अनदेखा करते हैं क्योंकि यह 'सूखा' या 'सादा' लगता है?","ar":"أي مما يلي، بعد تحضيره، يُعد طعامًا خاضعًا للتحكم في الوقت والحرارة يغفل عنه كثير من المشغلين لأنه يبدو 'جافًا' أو 'عاديًا'؟"},"o":[{"en":"A baked potato","es":"Una papa al horno","ru":"Печёный картофель","tr":"Fırında patates","hi":"एक बेक किया हुआ आलू","ar":"بطاطا مشوية"},{"en":"A whole raw lemon","es":"Un limón crudo entero","ru":"Целый сырой лимон","tr":"Bütün çiğ limon","hi":"एक पूरा कच्चा नींबू","ar":"ليمونة نيئة كاملة"},{"en":"Dry white sugar","es":"Azúcar blanca seca","ru":"Сухой белый сахар","tr":"Kuru beyaz şeker","hi":"सूखी सफेद चीनी","ar":"سكر أبيض جاف"},{"en":"Uncooked dry rice in a sealed bag","es":"Arroz seco crudo en una bolsa sellada","ru":"Сырой сухой рис в запечатанном пакете","tr":"Kapalı torbada çiğ kuru pirinç","hi":"सीलबंद बैग में कच्चा सूखा चावल","ar":"أرز جاف نيء في كيس محكم الغلق"}],"e":{"en":"A baked potato is TCS once cooked because its moisture and near-neutral pH support pathogen growth (including C. botulinum if wrapped in foil and held warm too long); dry sugar, whole lemons, and uncooked rice are not TCS.","es":"Una papa al horno es TCS una vez cocida porque su humedad y pH casi neutro favorecen el crecimiento de patógenos (incluido C. botulinum si se envuelve en papel aluminio y se mantiene caliente demasiado tiempo); el azúcar seca, los limones enteros y el arroz crudo no son TCS.","ru":"Печёный картофель является TCS после приготовления, потому что его влажность и почти нейтральный pH поддерживают рост патогенов (включая C. botulinum, если он завёрнут в фольгу и слишком долго держится тёплым); сухой сахар, целые лимоны и сырой рис не являются TCS.","tr":"Fırında patates pişirildikten sonra TCS'dir çünkü nemi ve neredeyse nötr pH'ı patojen üremesini destekler (folyoya sarılıp çok uzun süre sıcak tutulursa C. botulinum dahil); kuru şeker, bütün limon ve çiğ pirinç TCS değildir.","hi":"बेक किया हुआ आलू पकने के बाद TCS होता है क्योंकि इसकी नमी और लगभग-उदासीन pH रोगजनक वृद्धि का समर्थन करते हैं (यदि पन्नी में लपेटकर बहुत देर तक गर्म रखा जाए तो C. botulinum सहित); सूखी चीनी, पूरे नींबू और कच्चे चावल TCS नहीं हैं।","ar":"البطاطا المشوية تصبح خاضعة للتحكم في الوقت والحرارة بعد الطهي لأن رطوبتها ودرجة حموضتها القريبة من التعادل تدعم نمو الممرضات (بما في ذلك المطثية الوشيقية إذا لُفّت بالرقائق وحُفظت دافئة لفترة طويلة)؛ أما السكر الجاف والليمون الكامل والأرز النيء فليست كذلك."}},{"cat":"pathogens","a":3,"q":{"en":"A cook wants to store house-made garlic-in-oil at room temperature. Which pathogen makes this dangerous, and which FAT TOM condition does it exploit?","es":"Un cocinero quiere almacenar ajo en aceite hecho en casa a temperatura ambiente. ¿Qué patógeno hace esto peligroso y qué condición de FAT TOM aprovecha?","ru":"Повар хочет хранить домашний чеснок в масле при комнатной температуре. Какой патоген делает это опасным и какое условие FAT TOM он использует?","tr":"Bir aşçı, ev yapımı sarımsaklı yağı oda sıcaklığında saklamak istiyor. Hangi patojen bunu tehlikeli yapar ve hangi FAT TOM koşulundan yararlanır?","hi":"एक रसोइया घर में बने लहसुन-तेल को कमरे के तापमान पर रखना चाहता है। कौन सा रोगजनक इसे खतरनाक बनाता है, और यह किस FAT TOM स्थिति का लाभ उठाता है?","ar":"يريد طاهٍ تخزين الثوم بالزيت المصنوع منزليًا في درجة حرارة الغرفة. أي مُمرض يجعل هذا خطيرًا، وأي شرط من شروط FAT TOM يستغله؟"},"o":[{"en":"Norovirus, which needs high oxygen","es":"Norovirus, que necesita mucho oxígeno","ru":"Норовирус, которому нужно много кислорода","tr":"Yüksek oksijene ihtiyaç duyan norovirüs","hi":"नोरोवायरस, जिसे उच्च ऑक्सीजन चाहिए","ar":"نوروفيروس الذي يحتاج إلى أكسجين مرتفع"},{"en":"Hepatitis A, which needs high acidity","es":"Hepatitis A, que necesita alta acidez","ru":"Гепатит A, которому нужна высокая кислотность","tr":"Yüksek asitliğe ihtiyaç duyan Hepatit A","hi":"हेपेटाइटिस A, जिसे उच्च अम्लता चाहिए","ar":"التهاب الكبد A الذي يحتاج إلى حموضة عالية"},{"en":"Salmonella, which requires a frozen environment","es":"Salmonella, que requiere un entorno congelado","ru":"Salmonella, которой требуется замороженная среда","tr":"Donmuş bir ortam gerektiren Salmonella","hi":"Salmonella, जिसे जमे हुए वातावरण की आवश्यकता होती है","ar":"السالمونيلا التي تتطلب بيئة مجمدة"},{"en":"Clostridium botulinum, which is anaerobic and thrives in the oxygen-free oil","es":"Clostridium botulinum, que es anaerobio y prospera en el aceite sin oxígeno","ru":"Clostridium botulinum, который является анаэробом и процветает в бескислородном масле","tr":"Anaerobik olan ve oksijensiz yağda gelişen Clostridium botulinum","hi":"Clostridium botulinum, जो अवायवीय है और ऑक्सीजन-रहित तेल में पनपता है","ar":"المطثية الوشيقية اللاهوائية التي تزدهر في الزيت الخالي من الأكسجين"}],"e":{"en":"Garlic-in-oil is a classic TCS product because Clostridium botulinum, an anaerobe, can grow in the oxygen-free oil and produce deadly toxin; it must be kept cold or acidified. This illustrates the Oxygen factor in FAT TOM.","es":"El ajo en aceite es un producto TCS clásico porque Clostridium botulinum, un anaerobio, puede crecer en el aceite sin oxígeno y producir una toxina mortal; debe mantenerse frío o acidificado. Esto ilustra el factor Oxígeno en FAT TOM.","ru":"Чеснок в масле — классический TCS-продукт, потому что Clostridium botulinum, анаэроб, может расти в бескислородном масле и вырабатывать смертельный токсин; его нужно хранить холодным или подкисленным. Это иллюстрирует фактор кислорода в FAT TOM.","tr":"Sarımsaklı yağ klasik bir TCS ürünüdür çünkü anaerobik olan Clostridium botulinum oksijensiz yağda üreyip ölümcül toksin üretebilir; soğuk tutulmalı veya asitlendirilmelidir. Bu, FAT TOM'daki Oksijen faktörünü gösterir.","hi":"लहसुन-तेल एक क्लासिक TCS उत्पाद है क्योंकि Clostridium botulinum, एक अवायवीय जीव, ऑक्सीजन-रहित तेल में बढ़ सकता है और घातक विष बना सकता है; इसे ठंडा या अम्लीकृत रखना चाहिए। यह FAT TOM में ऑक्सीजन कारक को दर्शाता है।","ar":"الثوم بالزيت منتج خاضع للتحكم بالوقت والحرارة كلاسيكيًا لأن المطثية الوشيقية اللاهوائية يمكن أن تنمو في الزيت الخالي من الأكسجين وتنتج سمًا قاتلًا؛ لذا يجب حفظه باردًا أو محمَّضًا. وهذا يوضح عامل الأكسجين في FAT TOM."}},{"cat":"pathogens","a":1,"q":{"en":"Several diners report flushing, headache, and a peppery mouth feeling within minutes of eating seared tuna. This reaction to a heat-stable toxin from time-temperature abuse is characteristic of which hazard?","es":"Varios comensales informan enrojecimiento, dolor de cabeza y una sensación de picor en la boca a los pocos minutos de comer atún sellado. Esta reacción a una toxina termoestable por abuso de tiempo-temperatura es característica de ¿cuál peligro?","ru":"Несколько посетителей сообщают о покраснении, головной боли и остром жжении во рту через несколько минут после употребления обжаренного тунца. Такая реакция на термостойкий токсин из-за нарушения температурно-временного режима характерна для какой опасности?","tr":"Birkaç müşteri, mühürlenmiş ton balığı yedikten dakikalar sonra kızarma, baş ağrısı ve ağızda biberimsi bir his bildiriyor. Zaman-sıcaklık ihlalinden kaynaklanan ısıya dayanıklı bir toksine karşı bu tepki hangi tehlikenin özelliğidir?","hi":"कई भोजन करने वाले सीयर्ड टूना खाने के कुछ ही मिनटों में चेहरे की लाली, सिरदर्द और मुँह में तीखेपन की सूचना देते हैं। समय-तापमान दुरुपयोग से ऊष्मा-स्थिर विष के प्रति यह प्रतिक्रिया किस खतरे की विशेषता है?","ar":"يُبلّغ عدة زبائن عن احمرار وصداع وشعور لاذع في الفم خلال دقائق من تناول التونة المشوية. هذا التفاعل مع سُم مقاوم للحرارة ناتج عن سوء التحكم في الوقت والحرارة يُميّز أي خطر؟"},"o":[{"en":"Ciguatera toxin from a large reef fish","es":"Toxina de ciguatera de un pez de arrecife grande","ru":"Токсин сигуатеры от крупной рифовой рыбы","tr":"Büyük bir resif balığından siguatera toksini","hi":"बड़ी रीफ मछली से सिगुएटेरा विष","ar":"سُم السيغاتيرا من سمكة شعاب مرجانية كبيرة"},{"en":"Scombrotoxin (histamine) poisoning","es":"Intoxicación por escombrotoxina (histamina)","ru":"Отравление скомбротоксином (гистамином)","tr":"Skombrotoksin (histamin) zehirlenmesi","hi":"स्कोम्ब्रोटॉक्सिन (हिस्टामिन) विषाक्तता","ar":"تسمم الإسكومبروتوكسين (الهستامين)"},{"en":"A physical hazard (bone fragments)","es":"Un peligro físico (fragmentos de hueso)","ru":"Физическая опасность (осколки костей)","tr":"Fiziksel bir tehlike (kemik parçaları)","hi":"एक भौतिक खतरा (हड्डी के टुकड़े)","ar":"خطر فيزيائي (شظايا العظام)"},{"en":"Norovirus infection","es":"Infección por norovirus","ru":"Норовирусная инфекция","tr":"Norovirüs enfeksiyonu","hi":"नोरोवायरस संक्रमण","ar":"عدوى نوروفيروس"}],"e":{"en":"Scombrotoxin (histamine) forms when tuna, mahi-mahi, and similar fish are temperature-abused; the toxin is heat-stable, so the only control is strict temperature management from receiving onward.","es":"La escombrotoxina (histamina) se forma cuando el atún, el mahi-mahi y peces similares sufren abuso de temperatura; la toxina es termoestable, por lo que el único control es una gestión estricta de la temperatura desde la recepción.","ru":"Скомбротоксин (гистамин) образуется, когда тунец, махи-махи и подобные рыбы подвергаются температурному нарушению; токсин термостойкий, поэтому единственная мера контроля — строгое управление температурой начиная с приёмки.","tr":"Skombrotoksin (histamin), ton balığı, mahi-mahi ve benzeri balıklar sıcaklık ihlaline uğradığında oluşur; toksin ısıya dayanıklıdır, bu yüzden tek kontrol teslim alımından itibaren sıkı sıcaklık yönetimidir.","hi":"स्कोम्ब्रोटॉक्सिन (हिस्टामिन) तब बनता है जब टूना, माही-माही और समान मछलियों के साथ तापमान दुरुपयोग होता है; विष ऊष्मा-स्थिर है, इसलिए एकमात्र नियंत्रण प्राप्ति से आगे सख्त तापमान प्रबंधन है।","ar":"يتكوّن الإسكومبروتوكسين (الهستامين) عندما تتعرض التونة والماهي ماهي والأسماك المشابهة لسوء التحكم في الحرارة؛ والسُم مقاوم للحرارة، لذا فإن الضابط الوحيد هو إدارة الحرارة بصرامة منذ الاستلام."}},{"cat":"pathogens","a":2,"q":{"en":"A guest who ate barracuda reports tingling lips, reversal of hot/cold sensation, and joint aches hours later. Which naturally occurring toxin is the likely cause?","es":"Un invitado que comió barracuda informa hormigueo en los labios, inversión de la sensación de calor/frío y dolores articulares horas después. ¿Cuál toxina natural es la causa probable?","ru":"Гость, съевший барракуду, сообщает о покалывании губ, инверсии ощущения горячего/холодного и болях в суставах спустя часы. Какой природный токсин является вероятной причиной?","tr":"Barrakuda yiyen bir konuk, saatler sonra dudaklarda karıncalanma, sıcak/soğuk hissinin ters dönmesi ve eklem ağrıları bildiriyor. Hangi doğal toksin olası nedendir?","hi":"बाराकुडा खाने वाला एक अतिथि घंटों बाद होंठों में झुनझुनी, गर्म/ठंडे संवेदना का उलटाव और जोड़ों में दर्द की सूचना देता है। कौन सा प्राकृतिक रूप से पाया जाने वाला विष संभावित कारण है?","ar":"يُبلّغ ضيف تناول سمك الباراكودا عن وخز في الشفتين وانعكاس الإحساس بالحار/البارد وآلام في المفاصل بعد ساعات. أي سُم طبيعي هو السبب المُرجّح؟"},"o":[{"en":"Scombrotoxin (histamine)","es":"Escombrotoxina (histamina)","ru":"Скомбротоксин (гистамин)","tr":"Skombrotoksin (histamin)","hi":"स्कोम्ब्रोटॉक्सिन (हिस्टामिन)","ar":"الإسكومبروتوكسين (الهستامين)"},{"en":"Botulinum toxin","es":"Toxina botulínica","ru":"Ботулинический токсин","tr":"Botulinum toksini","hi":"बोटुलिनम विष","ar":"سُم البوتولينوم"},{"en":"Ciguatera toxin","es":"Toxina de ciguatera","ru":"Токсин сигуатеры","tr":"Siguatera toksini","hi":"सिगुएटेरा विष","ar":"سُم السيغاتيرا"},{"en":"Shellfish (saxitoxin) poisoning","es":"Intoxicación por mariscos (saxitoxina)","ru":"Отравление моллюсками (сакситоксин)","tr":"Kabuklu deniz ürünü (saksitoksin) zehirlenmesi","hi":"शेलफिश (सैक्सीटॉक्सिन) विषाक्तता","ar":"تسمم المحار (ساكسيتوكسين)"}],"e":{"en":"Ciguatera toxin accumulates in large predatory reef fish (barracuda, grouper, amberjack) and causes the classic hot/cold reversal; it is heat-stable and cannot be cooked out, so purchasing from approved sources is the control.","es":"La toxina de ciguatera se acumula en grandes peces depredadores de arrecife (barracuda, mero, medregal) y causa la clásica inversión de calor/frío; es termoestable y no se elimina cocinando, por lo que comprar a proveedores aprobados es el control.","ru":"Токсин сигуатеры накапливается в крупных хищных рифовых рыбах (барракуда, групер, желтохвост) и вызывает классическую инверсию горячего/холодного; он термостойкий и не разрушается при варке, поэтому мерой контроля является закупка у одобренных поставщиков.","tr":"Siguatera toksini büyük yırtıcı resif balıklarında (barrakuda, orfoz, sarıkuyruk) birikir ve klasik sıcak/soğuk tersine dönmesine neden olur; ısıya dayanıklıdır ve pişirmeyle giderilemez, bu yüzden onaylı kaynaklardan satın almak kontroldür.","hi":"सिगुएटेरा विष बड़ी शिकारी रीफ मछलियों (बाराकुडा, ग्रुपर, एम्बरजैक) में जमा होता है और क्लासिक गर्म/ठंडे उलटाव का कारण बनता है; यह ऊष्मा-स्थिर है और पकाने से नहीं हटता, इसलिए अनुमोदित स्रोतों से खरीदना ही नियंत्रण है।","ar":"يتراكم سُم السيغاتيرا في أسماك الشعاب المرجانية المفترسة الكبيرة (الباراكودا والهامور والأمبرجاك) ويسبب الانعكاس الكلاسيكي للحار/البارد؛ وهو مقاوم للحرارة ولا يُزال بالطهي، لذا فإن الشراء من مصادر معتمدة هو الضابط."}},{"cat":"pathogens","a":0,"q":{"en":"During a staff training, a manager needs to clarify the difference between allergen cross-contact and cross-contamination. Which statement is correct?","es":"Durante una capacitación del personal, un gerente necesita aclarar la diferencia entre el contacto cruzado de alérgenos y la contaminación cruzada. ¿Cuál afirmación es correcta?","ru":"Во время обучения персонала менеджеру нужно разъяснить разницу между аллергенным перекрёстным контактом и перекрёстным загрязнением. Какое утверждение верно?","tr":"Bir personel eğitimi sırasında, bir yöneticinin alerjen çapraz teması ile çapraz bulaşma arasındaki farkı netleştirmesi gerekiyor. Hangi ifade doğrudur?","hi":"स्टाफ प्रशिक्षण के दौरान, एक प्रबंधक को एलर्जेन क्रॉस-कॉन्टैक्ट और क्रॉस-कंटैमिनेशन के बीच अंतर स्पष्ट करने की आवश्यकता है। कौन सा कथन सही है?","ar":"أثناء تدريب الموظفين، يحتاج المدير إلى توضيح الفرق بين التلامس المتبادل للمواد المُسبِّبة للحساسية والتلوث المتبادل. أي عبارة صحيحة؟"},"o":[{"en":"Cross-contact is the unintended transfer of an allergen to a food that should not contain it; cross-contamination is the transfer of pathogens or other contaminants to food","es":"El contacto cruzado es la transferencia no intencionada de un alérgeno a un alimento que no debería contenerlo; la contaminación cruzada es la transferencia de patógenos u otros contaminantes a los alimentos","ru":"Перекрёстный контакт — это непреднамеренный перенос аллергена в пищу, которая не должна его содержать; перекрёстное загрязнение — это перенос патогенов или других загрязнителей в пищу","tr":"Çapraz temas, bir alerjenin onu içermemesi gereken bir gıdaya istenmeden aktarılmasıdır; çapraz bulaşma ise patojenlerin veya diğer kirleticilerin gıdaya aktarılmasıdır","hi":"क्रॉस-कॉन्टैक्ट एक एलर्जेन का अनजाने में उस भोजन में स्थानांतरण है जिसमें वह नहीं होना चाहिए; क्रॉस-कंटैमिनेशन रोगजनकों या अन्य दूषकों का भोजन में स्थानांतरण है","ar":"التلامس المتبادل هو انتقال غير مقصود لمادة مُسبِّبة للحساسية إلى طعام لا ينبغي أن يحتوي عليها؛ أما التلوث المتبادل فهو انتقال الممرضات أو الملوثات الأخرى إلى الطعام"},{"en":"They are two names for the exact same event","es":"Son dos nombres para el mismo evento exacto","ru":"Это два названия для одного и того же события","tr":"İkisi de tamamen aynı olayın iki adıdır","hi":"वे बिल्कुल एक ही घटना के दो नाम हैं","ar":"هما اسمان لنفس الحدث تمامًا"},{"en":"Cross-contact only involves pathogens; cross-contamination only involves allergens","es":"El contacto cruzado solo involucra patógenos; la contaminación cruzada solo involucra alérgenos","ru":"Перекрёстный контакт касается только патогенов; перекрёстное загрязнение — только аллергенов","tr":"Çapraz temas yalnızca patojenleri içerir; çapraz bulaşma yalnızca alerjenleri içerir","hi":"क्रॉस-कॉन्टैक्ट में केवल रोगजनक शामिल होते हैं; क्रॉस-कंटैमिनेशन में केवल एलर्जेन","ar":"التلامس المتبادل يشمل الممرضات فقط؛ والتلوث المتبادل يشمل المواد المُسبِّبة للحساسية فقط"},{"en":"Both are eliminated simply by cooking the food thoroughly","es":"Ambos se eliminan simplemente cocinando bien el alimento","ru":"Оба устраняются просто тщательной тепловой обработкой пищи","tr":"İkisi de gıdayı iyice pişirerek ortadan kaldırılır","hi":"दोनों को केवल भोजन को अच्छी तरह पकाकर समाप्त किया जाता है","ar":"يُزال كلاهما ببساطة عن طريق طهي الطعام جيدًا"}],"e":{"en":"Cross-contact transfers an allergen protein; cross-contamination transfers pathogens or filth. Cooking may kill many pathogens but does NOT remove allergen proteins, so cross-contact requires separate controls.","es":"El contacto cruzado transfiere una proteína alergénica; la contaminación cruzada transfiere patógenos o suciedad. Cocinar puede matar muchos patógenos pero NO elimina las proteínas alergénicas, por lo que el contacto cruzado requiere controles separados.","ru":"Перекрёстный контакт переносит белок-аллерген; перекрёстное загрязнение переносит патогены или грязь. Тепловая обработка может убить многие патогены, но НЕ удаляет белки-аллергены, поэтому для перекрёстного контакта нужны отдельные меры контроля.","tr":"Çapraz temas bir alerjen proteinini aktarır; çapraz bulaşma patojenleri veya kiri aktarır. Pişirme birçok patojeni öldürebilir ama alerjen proteinlerini gidermez, bu yüzden çapraz temas ayrı kontroller gerektirir.","hi":"क्रॉस-कॉन्टैक्ट एक एलर्जेन प्रोटीन स्थानांतरित करता है; क्रॉस-कंटैमिनेशन रोगजनक या गंदगी स्थानांतरित करता है। पकाना कई रोगजनकों को मार सकता है लेकिन एलर्जेन प्रोटीन को नहीं हटाता, इसलिए क्रॉस-कॉन्टैक्ट के लिए अलग नियंत्रण चाहिए।","ar":"ينقل التلامس المتبادل بروتين المادة المُسبِّبة للحساسية؛ بينما ينقل التلوث المتبادل الممرضات أو الأوساخ. قد يقتل الطهي كثيرًا من الممرضات لكنه لا يزيل بروتينات الحساسية، لذا يتطلب التلامس المتبادل ضوابط منفصلة."}},{"cat":"pathogens","a":3,"q":{"en":"Effective January 1, 2023, which allergen was added to make the U.S. list the 'Big 9' major food allergens?","es":"A partir del 1 de enero de 2023, ¿qué alérgeno se agregó para que la lista de EE. UU. se convirtiera en los 'Big 9' principales alérgenos alimentarios?","ru":"С 1 января 2023 года какой аллерген был добавлен, чтобы список США стал «Большой девяткой» основных пищевых аллергенов?","tr":"1 Ocak 2023'ten itibaren, ABD listesini 'Büyük 9' başlıca gıda alerjeni yapmak için hangi alerjen eklendi?","hi":"1 जनवरी 2023 से प्रभावी, अमेरिकी सूची को 'बिग 9' प्रमुख खाद्य एलर्जेन बनाने के लिए कौन सा एलर्जेन जोड़ा गया?","ar":"اعتبارًا من 1 يناير 2023، أي مادة مُسبِّبة للحساسية أُضيفت لتصبح قائمة الولايات المتحدة 'الكبار التسعة' من مسببات الحساسية الغذائية الرئيسية؟"},"o":[{"en":"Mustard","es":"Mostaza","ru":"Горчица","tr":"Hardal","hi":"सरसों","ar":"الخردل"},{"en":"Celery","es":"Apio","ru":"Сельдерей","tr":"Kereviz","hi":"अजवाइन","ar":"الكرفس"},{"en":"Sulfites","es":"Sulfitos","ru":"Сульфиты","tr":"Sülfitler","hi":"सल्फाइट्स","ar":"الكبريتات"},{"en":"Sesame","es":"Sésamo","ru":"Кунжут","tr":"Susam","hi":"तिल","ar":"السمسم"}],"e":{"en":"Sesame became the ninth major U.S. food allergen on January 1, 2023 (FASTER Act), joining milk, eggs, fish, crustacean shellfish, tree nuts, peanuts, wheat, and soybeans.","es":"El sésamo se convirtió en el noveno principal alérgeno alimentario de EE. UU. el 1 de enero de 2023 (Ley FASTER), uniéndose a leche, huevos, pescado, mariscos crustáceos, frutos secos de árbol, cacahuetes, trigo y soja.","ru":"Кунжут стал девятым основным пищевым аллергеном США 1 января 2023 года (Закон FASTER), присоединившись к молоку, яйцам, рыбе, ракообразным, лесным орехам, арахису, пшенице и сое.","tr":"Susam, 1 Ocak 2023'te (FASTER Yasası) ABD'nin dokuzuncu başlıca gıda alerjeni oldu; süt, yumurta, balık, kabuklu deniz ürünleri, ağaç kuruyemişleri, yer fıstığı, buğday ve soyaya katıldı.","hi":"तिल 1 जनवरी 2023 को अमेरिका का नौवां प्रमुख खाद्य एलर्जेन बन गया (FASTER अधिनियम), जो दूध, अंडे, मछली, क्रस्टेशियन शेलफिश, ट्री नट्स, मूंगफली, गेहूं और सोयाबीन में शामिल हो गया।","ar":"أصبح السمسم تاسع مُسبِّب رئيسي للحساسية الغذائية في الولايات المتحدة في 1 يناير 2023 (قانون FASTER)، منضمًا إلى الحليب والبيض والسمك والقشريات والمكسرات الشجرية والفول السوداني والقمح وفول الصويا."}},{"cat":"pathogens","a":1,"q":{"en":"An outbreak of sudden vomiting and diarrhea among many guests over one weekend is traced to ready-to-eat foods handled by staff. Which Big 6 pathogen is most consistent with a very low infectious dose and transmission by ill food handlers?","es":"Un brote de vómitos y diarrea repentinos entre muchos invitados durante un fin de semana se atribuye a alimentos listos para comer manipulados por el personal. ¿Cuál patógeno de los 'Big 6' es más consistente con una dosis infecciosa muy baja y transmisión por manipuladores enfermos?","ru":"Вспышка внезапной рвоты и диареи среди многих гостей за один выходной прослеживается до готовых к употреблению продуктов, обработанных персоналом. Какой патоген из «Большой шестёрки» наиболее соответствует очень низкой инфекционной дозе и передаче больными работниками?","tr":"Bir hafta sonu boyunca birçok konukta ani kusma ve ishal salgını, personel tarafından ele alınan yemeye hazır gıdalara dayandırılıyor. Çok düşük bir enfeksiyon dozu ve hasta gıda çalışanları tarafından bulaşma ile en tutarlı 'Büyük 6' patojeni hangisidir?","hi":"एक सप्ताहांत में कई मेहमानों में अचानक उल्टी और दस्त का प्रकोप स्टाफ द्वारा संभाले गए रेडी-टू-ईट खाद्य पदार्थों से जुड़ा है। बहुत कम संक्रामक खुराक और बीमार खाद्य हैंडलर द्वारा संचरण के साथ कौन सा 'बिग 6' रोगजनक सबसे संगत है?","ar":"فاشية قيء وإسهال مفاجئين بين كثير من الضيوف خلال عطلة أسبوعية عُزيت إلى أطعمة جاهزة للأكل تعامل معها الموظفون. أي من مسببات 'الستة الكبار' أكثر اتساقًا مع جرعة عدوى منخفضة جدًا وانتقال عبر عاملين مرضى؟"},"o":[{"en":"Clostridium perfringens","es":"Clostridium perfringens","ru":"Clostridium perfringens","tr":"Clostridium perfringens","hi":"Clostridium perfringens","ar":"المطثية الحاطمة"},{"en":"Norovirus","es":"Norovirus","ru":"Норовирус","tr":"Norovirüs","hi":"नोरोवायरस","ar":"نوروفيروس"},{"en":"Bacillus cereus","es":"Bacillus cereus","ru":"Bacillus cereus","tr":"Bacillus cereus","hi":"Bacillus cereus","ar":"العصوية الشمعية"},{"en":"Listeria monocytogenes","es":"Listeria monocytogenes","ru":"Listeria monocytogenes","tr":"Listeria monocytogenes","hi":"Listeria monocytogenes","ar":"الليستيريا المستوحدة"}],"e":{"en":"Norovirus is highly contagious with a very low infectious dose and is commonly spread by infected food handlers touching ready-to-eat foods; excluding ill staff and no bare-hand contact with RTE food are key controls.","es":"El norovirus es altamente contagioso con una dosis infecciosa muy baja y comúnmente se propaga por manipuladores infectados que tocan alimentos listos para comer; excluir al personal enfermo y no tener contacto de manos desnudas con alimentos LPC son controles clave.","ru":"Норовирус очень заразен, имеет очень низкую инфекционную дозу и обычно распространяется инфицированными работниками, прикасающимися к готовым продуктам; отстранение больного персонала и запрет контакта голыми руками с готовой пищей — ключевые меры.","tr":"Norovirüs çok bulaşıcıdır, çok düşük enfeksiyon dozuna sahiptir ve genellikle yemeye hazır gıdalara dokunan enfekte gıda çalışanları tarafından yayılır; hasta personeli dışlamak ve yemeye hazır gıdayla çıplak el temasını önlemek temel kontrollerdir.","hi":"नोरोवायरस अत्यधिक संक्रामक है, इसकी संक्रामक खुराक बहुत कम है और यह आमतौर पर रेडी-टू-ईट खाद्य पदार्थों को छूने वाले संक्रमित खाद्य हैंडलर द्वारा फैलता है; बीमार स्टाफ को बाहर रखना और RTE भोजन के साथ नंगे हाथ संपर्क न करना मुख्य नियंत्रण हैं।","ar":"نوروفيروس شديد العدوى بجرعة عدوى منخفضة جدًا وينتشر عادةً عبر عاملين مصابين يلمسون الأطعمة الجاهزة للأكل؛ واستبعاد الموظفين المرضى ومنع ملامسة الطعام الجاهز باليد المجردة هما ضابطان رئيسيان."}},{"cat":"pathogens","a":2,"q":{"en":"In a 'toxin-mediated infection,' the illness is caused by which mechanism?","es":"En una 'infección mediada por toxina', la enfermedad es causada por ¿cuál mecanismo?","ru":"При «токсин-опосредованной инфекции» заболевание вызывается каким механизмом?","tr":"'Toksin aracılı enfeksiyonda' hastalık hangi mekanizmayla oluşur?","hi":"'विष-मध्यस्थ संक्रमण' में, बीमारी किस तंत्र से होती है?","ar":"في 'العدوى بوساطة السموم'، بأي آلية يحدث المرض؟"},"o":[{"en":"A toxin already fully formed in the food before it is eaten","es":"Una toxina ya completamente formada en el alimento antes de comerlo","ru":"Токсином, уже полностью образовавшимся в пище до её употребления","tr":"Yenmeden önce gıdada tamamen oluşmuş bir toksin","hi":"भोजन खाने से पहले उसमें पूरी तरह बना विष","ar":"سُم مُتكوّن بالكامل في الطعام قبل أكله"},{"en":"The living pathogen simply invading body tissue with no toxin involved","es":"El patógeno vivo simplemente invadiendo el tejido corporal sin toxina involucrada","ru":"Живым патогеном, просто вторгающимся в ткани тела без участия токсина","tr":"Canlı patojenin herhangi bir toksin olmadan vücut dokusunu istila etmesi","hi":"जीवित रोगजनक बिना किसी विष के शरीर के ऊतक पर आक्रमण करता है","ar":"مُمرض حي يغزو نسيج الجسم دون أي سُم"},{"en":"A living pathogen that is eaten and then produces a toxin inside the intestines","es":"Un patógeno vivo que se ingiere y luego produce una toxina dentro de los intestinos","ru":"Живым патогеном, который проглатывается и затем вырабатывает токсин в кишечнике","tr":"Yenilen ve ardından bağırsaklarda toksin üreten canlı bir patojen","hi":"एक जीवित रोगजनक जिसे खाया जाता है और फिर आंतों के अंदर विष पैदा करता है","ar":"مُمرض حي يُؤكل ثم يُنتج سُمًا داخل الأمعاء"},{"en":"A chemical residue from a cleaning agent","es":"Un residuo químico de un agente de limpieza","ru":"Химическим остатком чистящего средства","tr":"Bir temizlik maddesinden kalan kimyasal kalıntı","hi":"एक सफाई एजेंट से रासायनिक अवशेष","ar":"بقايا كيميائية من مادة تنظيف"}],"e":{"en":"In a toxin-mediated infection, a live organism is ingested and then produces toxin in the gut — as with Shiga toxin-producing E. coli and Clostridium perfringens — distinct from a straight infection (Salmonella) or an intoxication (preformed toxin).","es":"En una infección mediada por toxina, se ingiere un organismo vivo que luego produce toxina en el intestino, como con E. coli productora de toxina Shiga y Clostridium perfringens, distinto de una infección directa (Salmonella) o una intoxicación (toxina preformada).","ru":"При токсин-опосредованной инфекции живой организм проглатывается и затем вырабатывает токсин в кишечнике — как в случае E. coli, продуцирующей шига-токсин, и Clostridium perfringens — в отличие от прямой инфекции (Salmonella) или интоксикации (уже образовавшийся токсин).","tr":"Toksin aracılı enfeksiyonda canlı bir organizma yutulur ve ardından bağırsakta toksin üretir — Shiga toksini üreten E. coli ve Clostridium perfringens'te olduğu gibi — doğrudan enfeksiyondan (Salmonella) veya zehirlenmeden (önceden oluşmuş toksin) farklıdır.","hi":"विष-मध्यस्थ संक्रमण में, एक जीवित जीव निगला जाता है और फिर आंत में विष पैदा करता है — जैसे शिगा-विष उत्पादक E. coli और Clostridium perfringens के साथ — जो सीधे संक्रमण (Salmonella) या विषाक्तता (पूर्व-निर्मित विष) से अलग है।","ar":"في العدوى بوساطة السموم، يُبتلع كائن حي ثم يُنتج سُمًا في الأمعاء — كما في الإشريكية القولونية المنتجة لسم شيغا والمطثية الحاطمة — على عكس العدوى المباشرة (السالمونيلا) أو التسمم (سُم مُتكوّن مسبقًا)."}},{"cat":"pathogens","a":0,"q":{"en":"Shiga toxin-producing E. coli (STEC) is of special concern to a manager because, in addition to bloody diarrhea, it can cause which severe complication, especially in children?","es":"La E. coli productora de toxina Shiga (STEC) es de especial preocupación para un gerente porque, además de diarrea con sangre, puede causar ¿cuál complicación grave, especialmente en niños?","ru":"E. coli, продуцирующая шига-токсин (STEC), вызывает особую озабоченность у менеджера, потому что, помимо кровавой диареи, она может вызвать какое тяжёлое осложнение, особенно у детей?","tr":"Shiga toksini üreten E. coli (STEC), kanlı ishale ek olarak, özellikle çocuklarda hangi şiddetli komplikasyona neden olabileceği için bir yönetici açısından özellikle endişe vericidir?","hi":"शिगा-विष उत्पादक E. coli (STEC) एक प्रबंधक के लिए विशेष चिंता का विषय है क्योंकि, खूनी दस्त के अलावा, यह किस गंभीर जटिलता का कारण बन सकता है, विशेषकर बच्चों में?","ar":"تُعد الإشريكية القولونية المنتجة لسم شيغا (STEC) مصدر قلق خاص للمدير لأنها، بالإضافة إلى الإسهال الدموي، قد تسبب أي مضاعفة شديدة، خاصةً لدى الأطفال؟"},"o":[{"en":"Hemolytic uremic syndrome (kidney failure)","es":"Síndrome urémico hemolítico (insuficiencia renal)","ru":"Гемолитико-уремический синдром (почечная недостаточность)","tr":"Hemolitik üremik sendrom (böbrek yetmezliği)","hi":"हेमोलिटिक यूरीमिक सिंड्रोम (गुर्दे की विफलता)","ar":"متلازمة انحلال الدم اليوريمية (الفشل الكلوي)"},{"en":"Permanent loss of hearing","es":"Pérdida permanente de la audición","ru":"Необратимая потеря слуха","tr":"Kalıcı işitme kaybı","hi":"श्रवण की स्थायी हानि","ar":"فقدان دائم للسمع"},{"en":"Chronic high blood pressure only","es":"Solo presión arterial alta crónica","ru":"Только хроническое высокое кровяное давление","tr":"Yalnızca kronik yüksek tansiyon","hi":"केवल दीर्घकालिक उच्च रक्तचाप","ar":"ارتفاع ضغط الدم المزمن فقط"},{"en":"A skin rash that lasts one hour","es":"Una erupción cutánea que dura una hora","ru":"Кожная сыпь, длящаяся один час","tr":"Bir saat süren cilt döküntüsü","hi":"एक घंटे तक चलने वाला त्वचा पर दाने","ar":"طفح جلدي يستمر ساعة واحدة"}],"e":{"en":"STEC (e.g., E. coli O157:H7) is linked to undercooked ground beef and contaminated produce and can progress to hemolytic uremic syndrome and kidney failure; it is a reportable Big 6 pathogen.","es":"La STEC (p. ej., E. coli O157:H7) está vinculada a carne molida poco cocida y productos contaminados y puede progresar a síndrome urémico hemolítico e insuficiencia renal; es un patógeno de los Big 6 de declaración obligatoria.","ru":"STEC (например, E. coli O157:H7) связана с недостаточно прожаренным говяжьим фаршем и загрязнёнными продуктами и может прогрессировать до гемолитико-уремического синдрома и почечной недостаточности; это подлежащий регистрации патоген «Большой шестёрки».","tr":"STEC (örn. E. coli O157:H7) az pişmiş kıyma ve kirlenmiş ürünlerle ilişkilidir ve hemolitik üremik sendrom ile böbrek yetmezliğine ilerleyebilir; bildirimi zorunlu bir 'Büyük 6' patojenidir.","hi":"STEC (जैसे, E. coli O157:H7) कम पके पिसे हुए मांस और दूषित उपज से जुड़ा है और हेमोलिटिक यूरीमिक सिंड्रोम और गुर्दे की विफलता तक बढ़ सकता है; यह एक रिपोर्ट करने योग्य 'बिग 6' रोगजनक है।","ar":"ترتبط STEC (مثل E. coli O157:H7) باللحم المفروم غير المطهي جيدًا والمنتجات الملوثة، وقد تتطور إلى متلازمة انحلال الدم اليوريمية والفشل الكلوي؛ وهي من مسببات 'الستة الكبار' واجبة الإبلاغ."}},{"cat":"pathogens","a":1,"q":{"en":"Shigella spp., one of the Big 6, is most often introduced into food through which route, making handwashing and fly control critical?","es":"Shigella spp., uno de los 'Big 6', se introduce con mayor frecuencia en los alimentos a través de ¿cuál vía, lo que hace crítico el lavado de manos y el control de moscas?","ru":"Shigella spp., один из «Большой шестёрки», чаще всего попадает в пищу каким путём, что делает мытьё рук и борьбу с мухами критически важными?","tr":"'Büyük 6'dan biri olan Shigella spp., gıdaya en sık hangi yolla girer, bu da el yıkamayı ve sinek kontrolünü kritik hale getirir?","hi":"Shigella spp., 'बिग 6' में से एक, अक्सर किस मार्ग से भोजन में प्रवेश करता है, जिससे हाथ धोना और मक्खी नियंत्रण महत्वपूर्ण हो जाता है?","ar":"الشيغيلا، إحدى 'الستة الكبار'، تدخل الطعام غالبًا عبر أي مسار، مما يجعل غسل اليدين ومكافحة الذباب أمرًا حاسمًا؟"},"o":[{"en":"Growth in sealed cans due to lack of oxygen","es":"Crecimiento en latas selladas por falta de oxígeno","ru":"Рост в запечатанных банках из-за отсутствия кислорода","tr":"Oksijen eksikliği nedeniyle kapalı konservelerde üreme","hi":"ऑक्सीजन की कमी के कारण सीलबंद डिब्बों में वृद्धि","ar":"النمو في العلب المحكمة بسبب نقص الأكسجين"},{"en":"The fecal-oral route from infected people and flies contacting food","es":"La vía fecal-oral desde personas infectadas y moscas que contactan los alimentos","ru":"Фекально-оральным путём от инфицированных людей и мух, контактирующих с пищей","tr":"Enfekte kişilerden ve gıdaya temas eden sineklerden fekal-oral yol","hi":"संक्रमित लोगों और भोजन के संपर्क में आने वाली मक्खियों से फ़ेकल-ओरल मार्ग","ar":"المسار البرازي الفموي من الأشخاص المصابين والذباب الذي يلامس الطعام"},{"en":"Formation of a heat-stable toxin during cooking","es":"Formación de una toxina termoestable durante la cocción","ru":"Образованием термостойкого токсина во время варки","tr":"Pişirme sırasında ısıya dayanıklı bir toksin oluşumu","hi":"पकाने के दौरान ऊष्मा-स्थिर विष का निर्माण","ar":"تكوّن سُم مقاوم للحرارة أثناء الطهي"},{"en":"Naturally living in reef fish tissue","es":"Vivir naturalmente en el tejido de peces de arrecife","ru":"Естественным обитанием в тканях рифовых рыб","tr":"Resif balığı dokusunda doğal olarak yaşama","hi":"रीफ मछली के ऊतक में स्वाभाविक रूप से रहना","ar":"العيش الطبيعي في نسيج أسماك الشعاب المرجانية"}],"e":{"en":"Shigella lives in the human intestine and spreads via the fecal-oral route, often through infected food workers and flies; strict handwashing, excluding ill workers, and fly control are the key defenses.","es":"Shigella vive en el intestino humano y se propaga por la vía fecal-oral, a menudo a través de trabajadores infectados y moscas; el lavado de manos estricto, excluir a los trabajadores enfermos y el control de moscas son las defensas clave.","ru":"Shigella живёт в кишечнике человека и распространяется фекально-оральным путём, часто через инфицированных работников и мух; строгое мытьё рук, отстранение больных работников и борьба с мухами — ключевые меры защиты.","tr":"Shigella insan bağırsağında yaşar ve fekal-oral yolla yayılır, genellikle enfekte gıda çalışanları ve sinekler aracılığıyla; sıkı el yıkama, hasta çalışanları dışlamak ve sinek kontrolü temel savunmalardır.","hi":"Shigella मानव आंत में रहता है और फ़ेकल-ओरल मार्ग से फैलता है, अक्सर संक्रमित खाद्य कर्मचारियों और मक्खियों के माध्यम से; सख्त हाथ धोना, बीमार कर्मचारियों को बाहर रखना और मक्खी नियंत्रण मुख्य रक्षा हैं।","ar":"تعيش الشيغيلا في أمعاء الإنسان وتنتشر عبر المسار البرازي الفموي، غالبًا عبر العاملين المصابين والذباب؛ وغسل اليدين الصارم واستبعاد العاملين المرضى ومكافحة الذباب هي الدفاعات الرئيسية."}},{"cat":"pathogens","a":3,"q":{"en":"Which statement about Hepatitis A is most accurate for a food protection manager?","es":"¿Cuál afirmación sobre la Hepatitis A es más precisa para un gerente de protección de alimentos?","ru":"Какое утверждение о гепатите A наиболее точно для менеджера по защите пищевых продуктов?","tr":"Bir gıda güvenliği yöneticisi için Hepatit A hakkındaki hangi ifade en doğrudur?","hi":"एक खाद्य सुरक्षा प्रबंधक के लिए हेपेटाइटिस A के बारे में कौन सा कथन सबसे सटीक है?","ar":"أي عبارة عن التهاب الكبد A هي الأدق لمدير حماية الغذاء؟"},"o":[{"en":"It is a bacterium that grows rapidly in TCS foods","es":"Es una bacteria que crece rápidamente en alimentos TCS","ru":"Это бактерия, которая быстро растёт в TCS-продуктах","tr":"TCS gıdalarında hızla üreyen bir bakteridir","hi":"यह एक बैक्टीरिया है जो TCS खाद्य पदार्थों में तेजी से बढ़ता है","ar":"إنها بكتيريا تنمو بسرعة في الأطعمة الخاضعة للتحكم بالوقت والحرارة"},{"en":"Symptoms always appear within 30 minutes of exposure","es":"Los síntomas siempre aparecen dentro de los 30 minutos de la exposición","ru":"Симптомы всегда появляются в течение 30 минут после контакта","tr":"Belirtiler her zaman maruziyetten sonraki 30 dakika içinde ortaya çıkar","hi":"लक्षण हमेशा संपर्क के 30 मिनट के भीतर दिखाई देते हैं","ar":"تظهر الأعراض دائمًا خلال 30 دقيقة من التعرض"},{"en":"It cannot be spread by food handlers","es":"No puede ser propagada por manipuladores de alimentos","ru":"Она не может распространяться работниками пищевой отрасли","tr":"Gıda çalışanları tarafından yayılamaz","hi":"इसे खाद्य हैंडलर द्वारा नहीं फैलाया जा सकता","ar":"لا يمكن أن ينتشر عبر متداولي الطعام"},{"en":"It is a virus spread by the fecal-oral route; an infected worker can shed it before symptoms appear, so handwashing and reporting jaundice are vital","es":"Es un virus que se propaga por la vía fecal-oral; un trabajador infectado puede excretarlo antes de que aparezcan los síntomas, por lo que el lavado de manos y reportar la ictericia son vitales","ru":"Это вирус, распространяющийся фекально-оральным путём; инфицированный работник может выделять его до появления симптомов, поэтому мытьё рук и сообщение о желтухе жизненно важны","tr":"Fekal-oral yolla yayılan bir virüstür; enfekte bir çalışan belirtiler ortaya çıkmadan önce onu saçabilir, bu yüzden el yıkama ve sarılığı bildirmek hayati önem taşır","hi":"यह एक वायरस है जो फ़ेकल-ओरल मार्ग से फैलता है; एक संक्रमित कर्मचारी लक्षण दिखने से पहले इसे फैला सकता है, इसलिए हाथ धोना और पीलिया की रिपोर्ट करना महत्वपूर्ण है","ar":"إنه فيروس ينتشر عبر المسار البرازي الفموي؛ ويمكن للعامل المصاب أن يطرحه قبل ظهور الأعراض، لذا فإن غسل اليدين والإبلاغ عن اليرقان أمران حيويان"}],"e":{"en":"Hepatitis A is a virus shed in feces; an infected person is contagious before jaundice appears, so proper handwashing, no bare-hand contact with RTE food, and reporting jaundice/diagnosis are essential controls.","es":"La Hepatitis A es un virus que se excreta en las heces; una persona infectada es contagiosa antes de que aparezca la ictericia, por lo que el lavado de manos adecuado, no tener contacto de manos desnudas con alimentos LPC y reportar la ictericia/diagnóstico son controles esenciales.","ru":"Гепатит A — это вирус, выделяющийся с калом; инфицированный человек заразен до появления желтухи, поэтому правильное мытьё рук, отсутствие контакта голыми руками с готовой пищей и сообщение о желтухе/диагнозе — важнейшие меры контроля.","tr":"Hepatit A dışkıyla atılan bir virüstür; enfekte kişi sarılık ortaya çıkmadan önce bulaşıcıdır, bu yüzden doğru el yıkama, yemeye hazır gıdayla çıplak el teması olmaması ve sarılık/tanının bildirilmesi temel kontrollerdir.","hi":"हेपेटाइटिस A एक वायरस है जो मल में उत्सर्जित होता है; एक संक्रमित व्यक्ति पीलिया दिखने से पहले संक्रामक होता है, इसलिए उचित हाथ धोना, RTE भोजन के साथ नंगे हाथ संपर्क न करना और पीलिया/निदान की रिपोर्ट करना आवश्यक नियंत्रण हैं।","ar":"التهاب الكبد A فيروس يُطرح في البراز؛ ويكون الشخص المصاب معديًا قبل ظهور اليرقان، لذا فإن غسل اليدين السليم وعدم ملامسة الطعام الجاهز باليد المجردة والإبلاغ عن اليرقان/التشخيص ضوابط أساسية."}},{"cat":"pathogens","a":0,"q":{"en":"A guest bites into a dessert and finds a shard of glass from a broken light bulb over the prep line. This is best classified as which type of hazard?","es":"Un invitado muerde un postre y encuentra un fragmento de vidrio de una bombilla rota sobre la línea de preparación. Esto se clasifica mejor como ¿cuál tipo de peligro?","ru":"Гость откусывает десерт и находит осколок стекла от разбитой лампочки над линией приготовления. Это лучше всего классифицировать как какой тип опасности?","tr":"Bir konuk tatlıyı ısırır ve hazırlık hattının üzerindeki kırık bir ampulden bir cam parçası bulur. Bu en iyi hangi tehlike türü olarak sınıflandırılır?","hi":"एक अतिथि मिठाई में काटता है और प्रेप लाइन के ऊपर एक टूटे हुए बल्ब से काँच का टुकड़ा पाता है। इसे किस प्रकार के खतरे के रूप में सबसे अच्छी तरह वर्गीकृत किया गया है?","ar":"يعض ضيف حلوى فيجد شظية زجاج من مصباح مكسور فوق خط التحضير. كيف يُصنّف هذا بشكل أفضل؟"},"o":[{"en":"A physical hazard","es":"Un peligro físico","ru":"Физическая опасность","tr":"Fiziksel bir tehlike","hi":"एक भौतिक खतरा","ar":"خطر فيزيائي"},{"en":"A biological hazard","es":"Un peligro biológico","ru":"Биологическая опасность","tr":"Biyolojik bir tehlike","hi":"एक जैविक खतरा","ar":"خطر بيولوجي"},{"en":"A chemical hazard","es":"Un peligro químico","ru":"Химическая опасность","tr":"Kimyasal bir tehlike","hi":"एक रासायनिक खतरा","ar":"خطر كيميائي"},{"en":"An allergen hazard only","es":"Solo un peligro de alérgeno","ru":"Только аллергенная опасность","tr":"Yalnızca alerjen tehlikesi","hi":"केवल एक एलर्जेन खतरा","ar":"خطر مُسبِّب للحساسية فقط"}],"e":{"en":"Glass, metal shavings, bone, jewelry, and bandages are physical hazards — foreign objects in food. Shielded lighting over prep areas is the standard control to prevent glass contamination.","es":"El vidrio, las virutas de metal, los huesos, las joyas y las vendas son peligros físicos: objetos extraños en los alimentos. La iluminación protegida sobre las áreas de preparación es el control estándar para prevenir la contaminación por vidrio.","ru":"Стекло, металлическая стружка, кости, украшения и бинты — это физические опасности, посторонние предметы в пище. Защищённое освещение над зонами приготовления — стандартная мера предотвращения загрязнения стеклом.","tr":"Cam, metal talaşı, kemik, takı ve bandajlar fiziksel tehlikelerdir — gıdadaki yabancı cisimler. Hazırlık alanlarının üzerinde korumalı aydınlatma, cam bulaşmasını önlemek için standart kontroldür.","hi":"काँच, धातु की छीलन, हड्डी, आभूषण और पट्टियाँ भौतिक खतरे हैं — भोजन में बाहरी वस्तुएँ। प्रेप क्षेत्रों के ऊपर सुरक्षित प्रकाश व्यवस्था काँच संदूषण को रोकने का मानक नियंत्रण है।","ar":"الزجاج وبرادة المعدن والعظام والمجوهرات والضمادات مخاطر فيزيائية — أجسام غريبة في الطعام. والإضاءة المحمية فوق مناطق التحضير هي الضابط القياسي لمنع التلوث بالزجاج."}},{"cat":"pathogens","a":2,"q":{"en":"A guest who was told a dish was peanut-free develops hives, swelling of the lips and throat, and difficulty breathing. What is the correct immediate response?","es":"Un invitado a quien se le dijo que un plato no tenía cacahuetes desarrolla urticaria, hinchazón de labios y garganta, y dificultad para respirar. ¿Cuál es la respuesta inmediata correcta?","ru":"У гостя, которому сказали, что блюдо не содержит арахиса, развиваются крапивница, отёк губ и горла и затруднённое дыхание. Каков правильный немедленный ответ?","tr":"Bir yemeğin fıstıksız olduğu söylenen bir konukta kurdeşen, dudak ve boğazda şişme ve nefes darlığı gelişir. Doğru acil yanıt nedir?","hi":"एक अतिथि जिसे बताया गया था कि एक व्यंजन मूंगफली-मुक्त है, में पित्ती, होंठ और गले की सूजन और साँस लेने में कठिनाई विकसित होती है। सही तत्काल प्रतिक्रिया क्या है?","ar":"يُصاب ضيف قيل له إن طبقًا خالٍ من الفول السوداني بشرى وتورم في الشفتين والحلق وصعوبة في التنفس. ما الاستجابة الفورية الصحيحة؟"},"o":[{"en":"Offer the guest a glass of water and wait to see if it passes","es":"Ofrecer al invitado un vaso de agua y esperar a ver si pasa","ru":"Предложить гостю стакан воды и подождать, пройдёт ли это","tr":"Konuğa bir bardak su verip geçip geçmediğini beklemek","hi":"अतिथि को एक गिलास पानी देना और यह देखने के लिए इंतजार करना कि क्या यह ठीक हो जाता है","ar":"تقديم كوب ماء للضيف والانتظار لمعرفة إن كان سيزول"},{"en":"Bring the guest a replacement dish and continue service","es":"Traer al invitado un plato de reemplazo y continuar el servicio","ru":"Принести гостю замену блюда и продолжить обслуживание","tr":"Konuğa yeni bir yemek getirip servise devam etmek","hi":"अतिथि को एक प्रतिस्थापन व्यंजन लाना और सेवा जारी रखना","ar":"إحضار طبق بديل للضيف ومتابعة الخدمة"},{"en":"Treat it as a possible anaphylactic reaction: call for emergency medical help immediately","es":"Tratarlo como una posible reacción anafiláctica: llamar de inmediato a los servicios médicos de emergencia","ru":"Расценивать это как возможную анафилактическую реакцию: немедленно вызвать неотложную медицинскую помощь","tr":"Bunu olası bir anafilaktik reaksiyon olarak değerlendirmek: derhal acil tıbbi yardım çağırmak","hi":"इसे एक संभावित एनाफिलेक्टिक प्रतिक्रिया के रूप में मानना: तुरंत आपातकालीन चिकित्सा सहायता के लिए कॉल करना","ar":"التعامل معه على أنه تفاعل تأقي محتمل: طلب المساعدة الطبية الطارئة فورًا"},{"en":"Ask the guest to sign a waiver and note it for later","es":"Pedir al invitado que firme una exención y anotarlo para más tarde","ru":"Попросить гостя подписать отказ и записать это на потом","tr":"Konuktan bir feragatname imzalamasını istemek ve daha sonrası için not almak","hi":"अतिथि से एक छूट पर हस्ताक्षर करने के लिए कहना और इसे बाद के लिए नोट करना","ar":"مطالبة الضيف بتوقيع إعفاء وتدوينه لاحقًا"}],"e":{"en":"Swelling of the lips/throat and trouble breathing signal anaphylaxis, a life-threatening emergency; staff must call emergency services immediately (and assist with the guest's epinephrine if available). Never wait it out.","es":"La hinchazón de labios/garganta y la dificultad para respirar señalan anafilaxia, una emergencia potencialmente mortal; el personal debe llamar de inmediato a los servicios de emergencia (y ayudar con la epinefrina del invitado si está disponible). Nunca esperar a que pase.","ru":"Отёк губ/горла и затруднённое дыхание сигнализируют об анафилаксии — угрожающем жизни состоянии; персонал должен немедленно вызвать неотложную помощь (и помочь с адреналином гостя, если он есть). Никогда не ждите, пока это пройдёт.","tr":"Dudak/boğaz şişmesi ve nefes darlığı, hayatı tehdit eden bir acil durum olan anafilaksiye işaret eder; personel derhal acil servisi aramalı (ve varsa konuğun epinefrinine yardımcı olmalı). Asla geçmesini beklemeyin.","hi":"होंठ/गले की सूजन और साँस लेने में कठिनाई एनाफिलेक्सिस का संकेत देती है, जो जानलेवा आपातकाल है; स्टाफ को तुरंत आपातकालीन सेवाओं को कॉल करना चाहिए (और उपलब्ध होने पर अतिथि के एपिनेफ्रीन में सहायता करनी चाहिए)। कभी इंतजार न करें।","ar":"تورم الشفتين/الحلق وصعوبة التنفس تشير إلى التأق، وهو حالة طارئة تهدد الحياة؛ يجب على الموظفين الاتصال بخدمات الطوارئ فورًا (والمساعدة في إعطاء الإبينفرين الخاص بالضيف إن وُجد). لا تنتظر أبدًا زواله."}},{"cat":"pathogens","a":1,"q":{"en":"A guest with a severe tree-nut allergy places an order. Which practice most reliably prevents allergen cross-contact in the kitchen?","es":"Un invitado con una alergia grave a los frutos secos de árbol hace un pedido. ¿Cuál práctica previene de manera más confiable el contacto cruzado de alérgenos en la cocina?","ru":"Гость с тяжёлой аллергией на лесные орехи делает заказ. Какая практика наиболее надёжно предотвращает аллергенный перекрёстный контакт на кухне?","tr":"Ağır ağaç kuruyemişi alerjisi olan bir konuk sipariş verir. Hangi uygulama mutfakta alerjen çapraz temasını en güvenilir şekilde önler?","hi":"गंभीर ट्री-नट एलर्जी वाला एक अतिथि ऑर्डर देता है। कौन सी प्रथा रसोई में एलर्जेन क्रॉस-कॉन्टैक्ट को सबसे विश्वसनीय रूप से रोकती है?","ar":"يطلب ضيف يعاني من حساسية شديدة تجاه المكسرات الشجرية. أي ممارسة تمنع بشكل أكثر موثوقية التلامس المتبادل للمواد المُسبِّبة للحساسية في المطبخ؟"},"o":[{"en":"Rinsing the nut-containing utensils under warm water before reuse","es":"Enjuagar los utensilios con frutos secos bajo agua tibia antes de reutilizarlos","ru":"Ополаскивание содержащей орехи посуды тёплой водой перед повторным использованием","tr":"Kuruyemiş içeren aletleri yeniden kullanmadan önce ılık suyla durulamak","hi":"नट युक्त बर्तनों को पुन: उपयोग से पहले गर्म पानी के नीचे धोना","ar":"شطف الأدوات المحتوية على المكسرات بالماء الدافئ قبل إعادة استخدامها"},{"en":"Preparing the order in a cleaned and sanitized area using clean equipment, utensils, and washed hands/fresh gloves","es":"Preparar el pedido en un área limpia y desinfectada usando equipo, utensilios limpios y manos lavadas/guantes nuevos","ru":"Приготовление заказа в очищенной и продезинфицированной зоне с использованием чистого оборудования, посуды и вымытых рук/свежих перчаток","tr":"Siparişi temizlenmiş ve dezenfekte edilmiş bir alanda temiz ekipman, aletler ve yıkanmış eller/temiz eldivenler kullanarak hazırlamak","hi":"ऑर्डर को साफ और सैनिटाइज़ किए गए क्षेत्र में स्वच्छ उपकरण, बर्तन और धुले हाथों/नए दस्ताने का उपयोग करके तैयार करना","ar":"تحضير الطلب في منطقة نظيفة ومُطهّرة باستخدام معدات وأدوات نظيفة وأيدٍ مغسولة/قفازات جديدة"},{"en":"Simply cooking the dish to a higher temperature to destroy the nut protein","es":"Simplemente cocinar el plato a una temperatura más alta para destruir la proteína del fruto seco","ru":"Просто приготовление блюда при более высокой температуре, чтобы разрушить белок ореха","tr":"Kuruyemiş proteinini yok etmek için yemeği daha yüksek sıcaklıkta pişirmek","hi":"नट प्रोटीन को नष्ट करने के लिए बस व्यंजन को उच्च तापमान पर पकाना","ar":"مجرد طهي الطبق في درجة حرارة أعلى لتدمير بروتين المكسرات"},{"en":"Placing the finished plate under a heat lamp for 10 minutes","es":"Colocar el plato terminado bajo una lámpara de calor durante 10 minutos","ru":"Размещение готового блюда под тепловой лампой на 10 минут","tr":"Bitmiş tabağı 10 dakika ısı lambasının altına koymak","hi":"तैयार प्लेट को 10 मिनट के लिए हीट लैंप के नीचे रखना","ar":"وضع الطبق الجاهز تحت مصباح حراري لمدة 10 دقائق"}],"e":{"en":"Because cooking does not destroy allergen proteins, cross-contact is prevented only by physical separation: clean/sanitized surfaces, dedicated or freshly cleaned equipment and utensils, and washed hands with fresh gloves.","es":"Como la cocción no destruye las proteínas alergénicas, el contacto cruzado se previene solo mediante la separación física: superficies limpias/desinfectadas, equipo y utensilios dedicados o recién limpiados, y manos lavadas con guantes nuevos.","ru":"Поскольку тепловая обработка не разрушает белки-аллергены, перекрёстный контакт предотвращается только физическим разделением: чистые/продезинфицированные поверхности, выделенное или свежевымытое оборудование и посуда, вымытые руки со свежими перчатками.","tr":"Pişirme alerjen proteinlerini yok etmediği için, çapraz temas yalnızca fiziksel ayırma ile önlenir: temiz/dezenfekte yüzeyler, ayrılmış veya yeni temizlenmiş ekipman ve aletler, yıkanmış eller ve temiz eldivenler.","hi":"चूँकि पकाने से एलर्जेन प्रोटीन नष्ट नहीं होते, क्रॉस-कॉन्टैक्ट केवल भौतिक पृथक्करण से रोका जाता है: स्वच्छ/सैनिटाइज़ सतहें, समर्पित या ताज़ा-साफ किए गए उपकरण और बर्तन, और नए दस्ताने के साथ धुले हाथ।","ar":"لأن الطهي لا يدمر بروتينات الحساسية، لا يُمنع التلامس المتبادل إلا بالفصل المادي: أسطح نظيفة/مُطهّرة، ومعدات وأدوات مخصصة أو منظفة حديثًا، وأيدٍ مغسولة مع قفازات جديدة."}},{"cat":"pathogens","a":0,"q":{"en":"An employee refills a sugar container from an unlabeled bin that actually held a powdered cleaning compound, and it ends up in a beverage. This foodborne-illness risk is which class of hazard?","es":"Un empleado rellena un recipiente de azúcar desde un contenedor sin etiqueta que en realidad contenía un compuesto de limpieza en polvo, y termina en una bebida. ¿Este riesgo de enfermedad transmitida por alimentos es qué clase de peligro?","ru":"Сотрудник наполняет ёмкость для сахара из немаркированного контейнера, в котором на самом деле находилось порошковое чистящее средство, и оно попадает в напиток. Этот риск пищевого заболевания относится к какому классу опасности?","tr":"Bir çalışan, aslında toz halinde bir temizlik bileşiği içeren etiketsiz bir kaptan şeker kabını doldurur ve bu bir içeceğe karışır. Bu gıda kaynaklı hastalık riski hangi tehlike sınıfındandır?","hi":"एक कर्मचारी एक बिना लेबल वाले डिब्बे से चीनी का कंटेनर भरता है जिसमें वास्तव में पाउडर सफाई यौगिक था, और यह एक पेय में समाप्त हो जाता है। यह खाद्य जनित बीमारी जोखिम किस वर्ग का खतरा है?","ar":"يعيد موظف ملء وعاء سكر من صندوق غير مُعنون كان يحتوي فعليًا على مركب تنظيف مسحوق، فينتهي به الأمر في مشروب. هذا الخطر من الأمراض المنقولة بالغذاء من أي فئة؟"},"o":[{"en":"A chemical hazard","es":"Un peligro químico","ru":"Химическая опасность","tr":"Kimyasal bir tehlike","hi":"एक रासायनिक खतरा","ar":"خطر كيميائي"},{"en":"A physical hazard","es":"Un peligro físico","ru":"Физическая опасность","tr":"Fiziksel bir tehlike","hi":"एक भौतिक खतरा","ar":"خطر فيزيائي"},{"en":"A biological hazard","es":"Un peligro biológico","ru":"Биологическая опасность","tr":"Biyolojik bir tehlike","hi":"एक जैविक खतरा","ar":"خطر بيولوجي"},{"en":"Not a hazard at all if it is food-grade sugar","es":"No es un peligro en absoluto si es azúcar de grado alimenticio","ru":"Вовсе не опасность, если это пищевой сахар","tr":"Gıda sınıfı şekerse hiç tehlike değildir","hi":"यदि यह खाद्य-ग्रेड चीनी है तो यह बिल्कुल भी खतरा नहीं है","ar":"ليس خطرًا على الإطلاق إن كان سكرًا صالحًا للأكل"}],"e":{"en":"Cleaning compounds, sanitizers, pesticides, and toxic-metal leaching are chemical hazards. Labeling all working containers and storing chemicals away from and below food prevents this classic contamination.","es":"Los compuestos de limpieza, desinfectantes, pesticidas y la lixiviación de metales tóxicos son peligros químicos. Etiquetar todos los recipientes de trabajo y almacenar los químicos lejos y debajo de los alimentos previene esta contaminación clásica.","ru":"Чистящие средства, дезинфектанты, пестициды и выщелачивание токсичных металлов — это химические опасности. Маркировка всех рабочих контейнеров и хранение химикатов вдали от пищи и ниже неё предотвращает это классическое загрязнение.","tr":"Temizlik bileşikleri, dezenfektanlar, pestisitler ve toksik metal sızması kimyasal tehlikelerdir. Tüm çalışma kaplarını etiketlemek ve kimyasalları gıdadan uzakta ve altında saklamak bu klasik bulaşmayı önler.","hi":"सफाई यौगिक, सैनिटाइज़र, कीटनाशक और विषैली धातु का रिसाव रासायनिक खतरे हैं। सभी कार्यशील कंटेनरों को लेबल करना और रसायनों को भोजन से दूर और नीचे रखना इस क्लासिक संदूषण को रोकता है।","ar":"مركبات التنظيف والمُطهّرات والمبيدات وترشح المعادن السامة مخاطر كيميائية. ووسم جميع أوعية العمل وتخزين الكيماويات بعيدًا عن الطعام وأسفله يمنع هذا التلوث الكلاسيكي."}},{"cat":"pathogens","a":2,"q":{"en":"A manager consults the Food Code's pH/water-activity interaction table to decide if a house product is TCS. Which combination would classify a food as NOT requiring time/temperature control?","es":"Un gerente consulta la tabla de interacción pH/actividad de agua del Código de Alimentos para decidir si un producto de la casa es TCS. ¿Cuál combinación clasificaría un alimento como que NO requiere control de tiempo/temperatura?","ru":"Менеджер сверяется с таблицей взаимодействия pH/активности воды из Кодекса пищевых продуктов, чтобы решить, является ли домашний продукт TCS. Какая комбинация классифицировала бы продукт как НЕ требующий контроля времени/температуры?","tr":"Bir yönetici, bir ev ürününün TCS olup olmadığına karar vermek için Gıda Kodu'nun pH/su aktivitesi etkileşim tablosuna başvurur. Hangi kombinasyon bir gıdayı zaman/sıcaklık kontrolü GEREKTİRMEYEN olarak sınıflandırır?","hi":"एक प्रबंधक यह तय करने के लिए फूड कोड की pH/जल-सक्रियता इंटरैक्शन तालिका से परामर्श करता है कि क्या एक घरेलू उत्पाद TCS है। कौन सा संयोजन एक भोजन को समय/तापमान नियंत्रण की आवश्यकता नहीं के रूप में वर्गीकृत करेगा?","ar":"يستعين مدير بجدول تفاعل درجة الحموضة/النشاط المائي في مدونة الغذاء ليقرر ما إذا كان منتج محلي خاضعًا للتحكم بالوقت والحرارة. أي تركيبة تصنّف طعامًا على أنه لا يحتاج إلى التحكم بالوقت والحرارة؟"},"o":[{"en":"pH of 6.5 and water activity of 0.98","es":"pH de 6.5 y actividad de agua de 0.98","ru":"pH 6.5 и активность воды 0.98","tr":"pH 6.5 ve su aktivitesi 0.98","hi":"6.5 का pH और 0.98 की जल सक्रियता","ar":"درجة حموضة 6.5 ونشاط مائي 0.98"},{"en":"pH of 7.0 and water activity of 0.90","es":"pH de 7.0 y actividad de agua de 0.90","ru":"pH 7.0 и активность воды 0.90","tr":"pH 7.0 ve su aktivitesi 0.90","hi":"7.0 का pH और 0.90 की जल सक्रियता","ar":"درجة حموضة 7.0 ونشاط مائي 0.90"},{"en":"pH of 4.2 and water activity of 0.82","es":"pH de 4.2 y actividad de agua de 0.82","ru":"pH 4.2 и активность воды 0.82","tr":"pH 4.2 ve su aktivitesi 0.82","hi":"4.2 का pH और 0.82 की जल सक्रियता","ar":"درجة حموضة 4.2 ونشاط مائي 0.82"},{"en":"pH of 5.5 and water activity of 0.95","es":"pH de 5.5 y actividad de agua de 0.95","ru":"pH 5.5 и активность воды 0.95","tr":"pH 5.5 ve su aktivitesi 0.95","hi":"5.5 का pH और 0.95 की जल सक्रियता","ar":"درجة حموضة 5.5 ونشاط مائي 0.95"}],"e":{"en":"A food that is both acidic enough (pH 4.2) and dry enough (aw 0.82) does not support pathogen growth, so it is not TCS; each of the other options keeps pH and aw within the ranges that support growth.","es":"Un alimento que es suficientemente ácido (pH 4.2) y suficientemente seco (aw 0.82) no favorece el crecimiento de patógenos, por lo que no es TCS; cada una de las otras opciones mantiene el pH y la aw dentro de los rangos que favorecen el crecimiento.","ru":"Продукт, который одновременно достаточно кислый (pH 4.2) и достаточно сухой (aw 0.82), не поддерживает рост патогенов, поэтому не является TCS; каждый из других вариантов удерживает pH и aw в диапазонах, поддерживающих рост.","tr":"Hem yeterince asidik (pH 4.2) hem de yeterince kuru (aw 0.82) olan bir gıda patojen üremesini desteklemez, bu yüzden TCS değildir; diğer seçeneklerin her biri pH ve aw'yi üremeyi destekleyen aralıklarda tutar.","hi":"एक भोजन जो पर्याप्त अम्लीय (pH 4.2) और पर्याप्त सूखा (aw 0.82) दोनों है, रोगजनक वृद्धि का समर्थन नहीं करता, इसलिए यह TCS नहीं है; अन्य प्रत्येक विकल्प pH और aw को वृद्धि का समर्थन करने वाली सीमाओं में रखता है।","ar":"الطعام الحمضي بدرجة كافية (درجة حموضة 4.2) والجاف بدرجة كافية (نشاط مائي 0.82) لا يدعم نمو الممرضات، لذا فهو غير خاضع للتحكم بالوقت والحرارة؛ أما الخيارات الأخرى فتُبقي درجة الحموضة والنشاط المائي ضمن نطاقات تدعم النمو."}},{"cat":"pathogens","a":3,"q":{"en":"A can of vegetables received with a swollen, bulging end could harbor Clostridium botulinum toxin. Which category of illness would eating it most likely cause?","es":"Una lata de verduras recibida con un extremo hinchado y abultado podría albergar la toxina de Clostridium botulinum. ¿Qué categoría de enfermedad causaría con mayor probabilidad comerla?","ru":"Банка овощей, полученная с вздутым, выпуклым краем, может содержать токсин Clostridium botulinum. Какую категорию заболевания вероятнее всего вызовет её употребление?","tr":"Şişmiş, kabarık bir ucu olan bir konserve sebze kutusu Clostridium botulinum toksini barındırabilir. Onu yemek büyük olasılıkla hangi hastalık kategorisine neden olur?","hi":"एक फूला हुआ, उभरा हुआ सिरा वाला सब्जियों का डिब्बा Clostridium botulinum विष को आश्रय दे सकता है। इसे खाने से सबसे अधिक संभावना किस श्रेणी की बीमारी होगी?","ar":"علبة خضار وردت بطرف منتفخ ومتورم قد تحتوي على سُم المطثية الوشيقية. أي فئة من الأمراض من الأرجح أن يسببها تناولها؟"},"o":[{"en":"A simple infection with no toxin involved","es":"Una simple infección sin toxina involucrada","ru":"Простую инфекцию без участия токсина","tr":"Toksin içermeyen basit bir enfeksiyon","hi":"बिना किसी विष के एक साधारण संक्रमण","ar":"عدوى بسيطة دون أي سُم"},{"en":"A physical hazard injury","es":"Una lesión por peligro físico","ru":"Травму от физической опасности","tr":"Fiziksel tehlike yaralanması","hi":"एक भौतिक खतरा चोट","ar":"إصابة من خطر فيزيائي"},{"en":"An allergic reaction","es":"Una reacción alérgica","ru":"Аллергическую реакцию","tr":"Alerjik bir reaksiyon","hi":"एक एलर्जी प्रतिक्रिया","ar":"تفاعل تحسسي"},{"en":"An intoxication from a preformed toxin","es":"Una intoxicación por una toxina preformada","ru":"Интоксикацию уже образовавшимся токсином","tr":"Önceden oluşmuş bir toksinden zehirlenme","hi":"पूर्व-निर्मित विष से एक विषाक्तता","ar":"تسمم من سُم مُتكوّن مسبقًا"}],"e":{"en":"Botulism is an intoxication: C. botulinum grows anaerobically in the sealed can and produces a potent neurotoxin before the food is eaten. Swollen or leaking cans must be rejected or discarded, never tasted.","es":"El botulismo es una intoxicación: C. botulinum crece de forma anaerobia en la lata sellada y produce una potente neurotoxina antes de comer el alimento. Las latas hinchadas o con fugas deben rechazarse o desecharse, nunca probarse.","ru":"Ботулизм — это интоксикация: C. botulinum растёт анаэробно в запечатанной банке и вырабатывает мощный нейротоксин до употребления пищи. Вздутые или протекающие банки нужно отклонять или выбрасывать, никогда не пробовать.","tr":"Botulizm bir zehirlenmedir: C. botulinum kapalı konservede anaerobik olarak ürer ve gıda yenmeden önce güçlü bir nörotoksin üretir. Şişmiş veya sızdıran konserveler reddedilmeli veya atılmalı, asla tadılmamalıdır.","hi":"बोटुलिज़्म एक विषाक्तता है: C. botulinum सीलबंद डिब्बे में अवायवीय रूप से बढ़ता है और भोजन खाने से पहले एक शक्तिशाली न्यूरोटॉक्सिन पैदा करता है। फूले हुए या रिसते डिब्बों को अस्वीकार या त्याग देना चाहिए, कभी नहीं चखना चाहिए।","ar":"التسمم الوشيقي هو تسمم: تنمو المطثية الوشيقية لاهوائيًا في العلبة المحكمة وتنتج سُمًا عصبيًا قويًا قبل أكل الطعام. يجب رفض العلب المنتفخة أو المتسربة أو التخلص منها، وعدم تذوقها أبدًا."}},{"cat":"pathogens","a":1,"q":{"en":"Cooked rice held at room temperature for hours, then flash-fried, is classically linked to which organism whose emetic form acts as an intoxication?","es":"El arroz cocido mantenido a temperatura ambiente durante horas y luego salteado rápidamente está clásicamente vinculado a ¿cuál organismo cuya forma emética actúa como una intoxicación?","ru":"Варёный рис, оставленный при комнатной температуре на несколько часов, а затем быстро обжаренный, классически связан с каким организмом, эметическая форма которого действует как интоксикация?","tr":"Saatlerce oda sıcaklığında bekletilip sonra çabucak kavrulan pişmiş pirinç, kusturucu formu zehirlenme gibi davranan hangi organizmayla klasik olarak ilişkilidir?","hi":"घंटों तक कमरे के तापमान पर रखा गया, फिर तुरंत तला गया पका हुआ चावल, आमतौर पर किस जीव से जुड़ा है जिसका उल्टी-कारक रूप एक विषाक्तता के रूप में कार्य करता है?","ar":"الأرز المطبوخ الذي يُترك في درجة حرارة الغرفة لساعات ثم يُقلى سريعًا يرتبط عادةً بأي كائن يعمل شكله المُقيّئ كتسمم؟"},"o":[{"en":"Listeria monocytogenes","es":"Listeria monocytogenes","ru":"Listeria monocytogenes","tr":"Listeria monocytogenes","hi":"Listeria monocytogenes","ar":"الليستيريا المستوحدة"},{"en":"Bacillus cereus","es":"Bacillus cereus","ru":"Bacillus cereus","tr":"Bacillus cereus","hi":"Bacillus cereus","ar":"العصوية الشمعية"},{"en":"Hepatitis A","es":"Hepatitis A","ru":"Гепатит A","tr":"Hepatit A","hi":"हेपेटाइटिस A","ar":"التهاب الكبد A"},{"en":"Vibrio vulnificus","es":"Vibrio vulnificus","ru":"Vibrio vulnificus","tr":"Vibrio vulnificus","hi":"Vibrio vulnificus","ar":"ضمة الجُرح"}],"e":{"en":"Bacillus cereus forms spores that survive cooking; held warm, it can produce a heat-stable emetic toxin (an intoxication) commonly tied to cooked rice, so rapid cooling and proper hot holding are essential.","es":"Bacillus cereus forma esporas que sobreviven a la cocción; mantenido caliente, puede producir una toxina emética termoestable (una intoxicación) comúnmente ligada al arroz cocido, por lo que el enfriamiento rápido y el mantenimiento en caliente adecuado son esenciales.","ru":"Bacillus cereus образует споры, которые выживают при варке; при хранении в тепле он может вырабатывать термостойкий эметический токсин (интоксикацию), обычно связанный с варёным рисом, поэтому быстрое охлаждение и правильное горячее хранение необходимы.","tr":"Bacillus cereus, pişmeye dayanan sporlar oluşturur; sıcak tutulduğunda, genellikle pişmiş pirinçle ilişkili ısıya dayanıklı bir kusturucu toksin (zehirlenme) üretebilir, bu yüzden hızlı soğutma ve doğru sıcak muhafaza gereklidir.","hi":"Bacillus cereus बीजाणु बनाता है जो पकाने से बच जाते हैं; गर्म रखने पर, यह एक ऊष्मा-स्थिर उल्टी-कारक विष (विषाक्तता) पैदा कर सकता है जो आमतौर पर पके चावल से जुड़ा होता है, इसलिए तेज़ ठंडा करना और उचित गर्म-होल्डिंग आवश्यक है।","ar":"تُكوّن العصوية الشمعية أبواغًا تنجو من الطهي؛ وعند حفظها دافئة يمكن أن تنتج سُمًا مُقيّئًا مقاومًا للحرارة (تسمم) يرتبط عادةً بالأرز المطبوخ، لذا فإن التبريد السريع والحفظ الساخن السليم ضروريان."}},{"cat":"pathogens","a":2,"q":{"en":"A manager is labeling which prepped items need date marking as TCS. Which of the following is NOT a TCS food?","es":"Un gerente está etiquetando qué artículos preparados necesitan marcado de fecha como TCS. ¿Cuál de los siguientes NO es un alimento TCS?","ru":"Менеджер отмечает, какие подготовленные продукты нуждаются в маркировке даты как TCS. Какой из следующих продуктов НЕ является TCS?","tr":"Bir yönetici, hangi hazırlanmış ürünlerin TCS olarak tarih işaretlemesi gerektiğini etiketliyor. Aşağıdakilerden hangisi TCS gıdası DEĞİLDİR?","hi":"एक प्रबंधक लेबल कर रहा है कि किन तैयार वस्तुओं को TCS के रूप में तिथि अंकन की आवश्यकता है। निम्नलिखित में से कौन TCS भोजन नहीं है?","ar":"يقوم مدير بوسم أي أصناف مُحضّرة تحتاج إلى وسم التاريخ كأطعمة خاضعة للتحكم بالوقت والحرارة. أي مما يلي ليس طعامًا خاضعًا لذلك؟"},"o":[{"en":"Cut leafy greens","es":"Verduras de hoja cortadas","ru":"Нарезанная листовая зелень","tr":"Doğranmış yapraklı yeşillikler","hi":"कटी हुई पत्तेदार सब्जियाँ","ar":"الخضراوات الورقية المقطعة"},{"en":"Cut tomatoes","es":"Tomates cortados","ru":"Нарезанные помидоры","tr":"Doğranmış domatesler","hi":"कटे हुए टमाटर","ar":"الطماطم المقطعة"},{"en":"A whole, uncut raw carrot","es":"Una zanahoria cruda entera, sin cortar","ru":"Целая, неразрезанная сырая морковь","tr":"Bütün, kesilmemiş çiğ havuç","hi":"एक पूरा, बिना कटा कच्चा गाजर","ar":"جزرة نيئة كاملة غير مقطعة"},{"en":"Cut melon","es":"Melón cortado","ru":"Нарезанная дыня","tr":"Doğranmış kavun","hi":"कटा हुआ खरबूजा","ar":"شمام مقطع"}],"e":{"en":"Cut leafy greens, cut tomatoes, and cut melons are specifically listed as TCS. A whole raw carrot has an intact protective surface and low risk, so it is not TCS until it is cut and its moisture is exposed.","es":"Las verduras de hoja cortadas, los tomates cortados y los melones cortados están específicamente listados como TCS. Una zanahoria cruda entera tiene una superficie protectora intacta y bajo riesgo, por lo que no es TCS hasta que se corta y se expone su humedad.","ru":"Нарезанная листовая зелень, нарезанные помидоры и нарезанные дыни специально указаны как TCS. Целая сырая морковь имеет неповреждённую защитную поверхность и низкий риск, поэтому она не является TCS, пока не нарезана и её влага не открыта.","tr":"Doğranmış yapraklı yeşillikler, doğranmış domatesler ve doğranmış kavunlar özellikle TCS olarak listelenir. Bütün çiğ havuç, sağlam bir koruyucu yüzeye ve düşük riske sahiptir, bu yüzden kesilip nemi açığa çıkana kadar TCS değildir.","hi":"कटी हुई पत्तेदार सब्जियाँ, कटे हुए टमाटर और कटे हुए खरबूजे विशेष रूप से TCS के रूप में सूचीबद्ध हैं। एक पूरे कच्चे गाजर की सतह अक्षुण्ण सुरक्षात्मक होती है और जोखिम कम होता है, इसलिए यह तब तक TCS नहीं है जब तक इसे काटा नहीं जाता और इसकी नमी उजागर नहीं होती।","ar":"الخضراوات الورقية المقطعة والطماطم المقطعة والشمام المقطع مُدرجة تحديدًا كأطعمة خاضعة للتحكم بالوقت والحرارة. أما الجزرة النيئة الكاملة فلها سطح واقٍ سليم وخطر منخفض، لذا فهي ليست كذلك حتى تُقطع وتنكشف رطوبتها."}},{"cat":"pathogens","a":0,"q":{"en":"For a menu that includes raw fish served in sushi, which control specifically addresses the parasite hazard (such as Anisakis)?","es":"Para un menú que incluye pescado crudo servido en sushi, ¿cuál control aborda específicamente el peligro de parásitos (como Anisakis)?","ru":"Для меню, включающего сырую рыбу, подаваемую в суши, какая мера контроля конкретно устраняет паразитарную опасность (например, Anisakis)?","tr":"Suşide servis edilen çiğ balık içeren bir menü için, hangi kontrol özellikle parazit tehlikesini (Anisakis gibi) ele alır?","hi":"सुशी में परोसी जाने वाली कच्ची मछली शामिल करने वाले मेनू के लिए, कौन सा नियंत्रण विशेष रूप से परजीवी खतरे (जैसे Anisakis) को संबोधित करता है?","ar":"لقائمة تشمل السمك النيء المُقدّم في السوشي، أي ضابط يعالج تحديدًا خطر الطفيليات (مثل الأنيساكيس)؟"},"o":[{"en":"Freezing the fish according to the Food Code's time-temperature parameters before service","es":"Congelar el pescado según los parámetros de tiempo-temperatura del Código de Alimentos antes del servicio","ru":"Замораживание рыбы в соответствии с параметрами времени-температуры Кодекса пищевых продуктов перед подачей","tr":"Servis öncesi balığı Gıda Kodu'nun zaman-sıcaklık parametrelerine göre dondurmak","hi":"सेवा से पहले फूड कोड के समय-तापमान मापदंडों के अनुसार मछली को जमाना","ar":"تجميد السمك وفقًا لمعايير الوقت والحرارة في مدونة الغذاء قبل التقديم"},{"en":"Holding the fish at 41°F for 24 hours","es":"Mantener el pescado a 41°F durante 24 horas","ru":"Хранение рыбы при 41°F в течение 24 часов","tr":"Balığı 41°F'de 24 saat tutmak","hi":"मछली को 41°F पर 24 घंटे रखना","ar":"حفظ السمك عند 41°F لمدة 24 ساعة"},{"en":"Adding an acidic marinade for 30 minutes","es":"Agregar una marinada ácida durante 30 minutos","ru":"Добавление кислого маринада на 30 минут","tr":"30 dakika asidik bir marine eklemek","hi":"30 मिनट के लिए एक अम्लीय मैरिनेड जोड़ना","ar":"إضافة نقيع حمضي لمدة 30 دقيقة"},{"en":"Rinsing the fish under cold running water","es":"Enjuagar el pescado bajo agua fría corriente","ru":"Ополаскивание рыбы под холодной проточной водой","tr":"Balığı soğuk akan su altında durulamak","hi":"मछली को ठंडे बहते पानी के नीचे धोना","ar":"شطف السمك تحت ماء بارد جارٍ"}],"e":{"en":"Parasites do not multiply in food but are killed by proper freezing; fish intended to be served raw must be frozen per the Food Code (e.g., -4°F for 7 days or -31°F for about 15 hours). Refrigeration, acid, and rinsing do not reliably kill parasites.","es":"Los parásitos no se multiplican en los alimentos pero mueren con la congelación adecuada; el pescado destinado a servirse crudo debe congelarse según el Código de Alimentos (p. ej., -4°F por 7 días o -31°F por unas 15 horas). La refrigeración, el ácido y el enjuague no matan los parásitos de manera confiable.","ru":"Паразиты не размножаются в пище, но погибают при правильном замораживании; рыбу, предназначенную для подачи в сыром виде, нужно заморозить согласно Кодексу (например, -4°F в течение 7 дней или -31°F около 15 часов). Охлаждение, кислота и ополаскивание не убивают паразитов надёжно.","tr":"Parazitler gıdada çoğalmaz ama doğru dondurma ile ölür; çiğ servis edilecek balık Gıda Kodu'na göre dondurulmalıdır (örn. -4°F'de 7 gün veya -31°F'de yaklaşık 15 saat). Soğutma, asit ve durulama parazitleri güvenilir şekilde öldürmez.","hi":"परजीवी भोजन में गुणा नहीं करते लेकिन उचित ठंडक से मर जाते हैं; कच्चा परोसे जाने वाली मछली को फूड कोड के अनुसार जमाना चाहिए (जैसे, -4°F पर 7 दिन या -31°F पर लगभग 15 घंटे)। प्रशीतन, अम्ल और धुलाई परजीवियों को विश्वसनीय रूप से नहीं मारते।","ar":"لا تتكاثر الطفيليات في الطعام لكنها تُقتل بالتجميد السليم؛ فالسمك المُعد للتقديم نيئًا يجب تجميده وفقًا لمدونة الغذاء (مثل -4°F لمدة 7 أيام أو -31°F لنحو 15 ساعة). أما التبريد والحمض والشطف فلا تقتل الطفيليات بشكل موثوق."}},{"cat":"pathogens","a":3,"q":{"en":"A manager finds visible mold on a bag of grain and on some soft cheese. What is the correct food-safety reasoning about the mold toxins (mycotoxins) that may be present?","es":"Un gerente encuentra moho visible en una bolsa de grano y en algo de queso blando. ¿Cuál es el razonamiento correcto de seguridad alimentaria sobre las toxinas del moho (micotoxinas) que pueden estar presentes?","ru":"Менеджер обнаруживает видимую плесень на мешке с зерном и на мягком сыре. Каково правильное рассуждение о безопасности пищевых продуктов относительно плесневых токсинов (микотоксинов), которые могут присутствовать?","tr":"Bir yönetici bir tahıl torbasında ve bir miktar yumuşak peynirde görünür küf bulur. Mevcut olabilecek küf toksinleri (mikotoksinler) hakkında doğru gıda güvenliği mantığı nedir?","hi":"एक प्रबंधक अनाज के एक बैग और कुछ नरम पनीर पर दिखाई देने वाला फफूंद पाता है। मौजूद हो सकने वाले फफूंद विषों (मायकोटॉक्सिन) के बारे में सही खाद्य-सुरक्षा तर्क क्या है?","ar":"يجد مدير عفنًا مرئيًا على كيس حبوب وعلى بعض الجبن الطري. ما التفكير الصحيح لسلامة الغذاء بشأن سموم العفن (السموم الفطرية) التي قد تكون موجودة؟"},"o":[{"en":"Cutting away the visible mold always makes the whole item safe","es":"Cortar el moho visible siempre hace que todo el artículo sea seguro","ru":"Срезание видимой плесени всегда делает весь продукт безопасным","tr":"Görünür küfü kesip atmak her zaman tüm ürünü güvenli hale getirir","hi":"दिखाई देने वाले फफूंद को काट देना हमेशा पूरी वस्तु को सुरक्षित बना देता है","ar":"إزالة العفن المرئي تجعل الصنف كله آمنًا دائمًا"},{"en":"Mycotoxins are destroyed by normal refrigeration","es":"Las micotoxinas se destruyen con la refrigeración normal","ru":"Микотоксины разрушаются при обычном охлаждении","tr":"Mikotoksinler normal soğutma ile yok edilir","hi":"मायकोटॉक्सिन सामान्य प्रशीतन से नष्ट हो जाते हैं","ar":"تُدمَّر السموم الفطرية بالتبريد العادي"},{"en":"Moldy food is always safe once it is cooked to 165°F","es":"Los alimentos con moho siempre son seguros una vez cocinados a 165°F","ru":"Заплесневелая пища всегда безопасна после приготовления до 165°F","tr":"Küflü gıda 165°F'ye pişirildiğinde her zaman güvenlidir","hi":"फफूंद लगा भोजन 165°F तक पकाए जाने के बाद हमेशा सुरक्षित होता है","ar":"الطعام المتعفن آمن دائمًا بمجرد طهيه إلى 165°F"},{"en":"Mycotoxins can penetrate beyond the visible mold and are heat-stable, so moldy items (except a few hard cheeses/salamis handled per policy) should generally be discarded","es":"Las micotoxinas pueden penetrar más allá del moho visible y son termoestables, por lo que los artículos con moho (excepto algunos quesos/salamis duros manejados según la política) generalmente deben desecharse","ru":"Микотоксины могут проникать за пределы видимой плесени и термостойки, поэтому заплесневелые продукты (кроме нескольких твёрдых сыров/салями, обрабатываемых по регламенту) обычно следует выбрасывать","tr":"Mikotoksinler görünür küfün ötesine geçebilir ve ısıya dayanıklıdır, bu yüzden küflü ürünler (politikaya göre işlenen birkaç sert peynir/salam hariç) genellikle atılmalıdır","hi":"मायकोटॉक्सिन दिखाई देने वाले फफूंद से परे प्रवेश कर सकते हैं और ऊष्मा-स्थिर होते हैं, इसलिए फफूंद लगी वस्तुओं (नीति के अनुसार संभाले गए कुछ कठोर पनीर/सलामी को छोड़कर) को आमतौर पर त्याग देना चाहिए","ar":"يمكن أن تتغلغل السموم الفطرية إلى ما وراء العفن المرئي وهي مقاومة للحرارة، لذا يجب عمومًا التخلص من الأصناف المتعفنة (باستثناء بعض الأجبان الصلبة/السلامي المُعالجة وفق السياسة)"}],"e":{"en":"Mycotoxins can extend into food beyond visible mold and resist normal cooking and refrigeration; soft/high-moisture moldy foods should be discarded, and only certain hard cheeses or dry cured meats may be trimmed per policy.","es":"Las micotoxinas pueden extenderse en los alimentos más allá del moho visible y resisten la cocción y refrigeración normales; los alimentos con moho blandos o de alta humedad deben desecharse, y solo ciertos quesos duros o carnes curadas secas pueden recortarse según la política.","ru":"Микотоксины могут распространяться в пище за пределы видимой плесени и устойчивы к обычной варке и охлаждению; мягкие или влажные заплесневелые продукты следует выбрасывать, и только некоторые твёрдые сыры или сухие вяленые мясные изделия можно обрезать по регламенту.","tr":"Mikotoksinler gıdada görünür küfün ötesine uzanabilir ve normal pişirme ile soğutmaya direnir; yumuşak veya yüksek nemli küflü gıdalar atılmalı, yalnızca belirli sert peynirler veya kuru salamura etler politikaya göre kesilebilir.","hi":"मायकोटॉक्सिन दिखाई देने वाले फफूंद से परे भोजन में फैल सकते हैं और सामान्य पकाने और प्रशीतन का प्रतिरोध करते हैं; नरम या उच्च-नमी वाले फफूंद लगे खाद्य पदार्थों को त्याग देना चाहिए, और केवल कुछ कठोर पनीर या सूखे क्योर किए गए मांस को नीति के अनुसार काटा जा सकता है।","ar":"يمكن أن تمتد السموم الفطرية في الطعام إلى ما وراء العفن المرئي وتقاوم الطهي والتبريد العاديين؛ لذا يجب التخلص من الأطعمة المتعفنة الطرية أو عالية الرطوبة، ولا يجوز تشذيب إلا بعض الأجبان الصلبة أو اللحوم المُقددة الجافة وفق السياسة."}},{"cat":"pathogens","a":2,"q":{"en":"A guest states an allergy to 'shellfish.' Why does the manager treat crustacean shellfish (shrimp, crab, lobster) as its own major allergen distinct from finned fish?","es":"Un invitado declara alergia a los 'mariscos'. ¿Por qué el gerente trata los mariscos crustáceos (camarón, cangrejo, langosta) como su propio alérgeno principal, distinto del pescado con aletas?","ru":"Гость заявляет об аллергии на «морепродукты». Почему менеджер рассматривает ракообразных (креветки, крабы, омары) как отдельный основной аллерген, отличный от рыбы с плавниками?","tr":"Bir konuk 'kabuklu deniz ürünlerine' alerjisi olduğunu belirtir. Yönetici neden kabuklu deniz ürünlerini (karides, yengeç, ıstakoz) yüzgeçli balıktan ayrı, kendi başına başlıca bir alerjen olarak ele alır?","hi":"एक अतिथि 'शेलफिश' से एलर्जी बताता है। प्रबंधक क्रस्टेशियन शेलफिश (झींगा, केकड़ा, लॉबस्टर) को पंख वाली मछली से अलग अपने स्वयं के प्रमुख एलर्जेन के रूप में क्यों मानता है?","ar":"يذكر ضيف أنه يعاني من حساسية تجاه 'المحار'. لماذا يتعامل المدير مع القشريات (الجمبري وسرطان البحر والكركند) كمُسبِّب رئيسي مستقل للحساسية يختلف عن الأسماك ذات الزعانف؟"},"o":[{"en":"Because crustaceans are never served in restaurants","es":"Porque los crustáceos nunca se sirven en restaurantes","ru":"Потому что ракообразных никогда не подают в ресторанах","tr":"Çünkü kabuklular restoranlarda asla servis edilmez","hi":"क्योंकि क्रस्टेशियन कभी रेस्तरां में नहीं परोसे जाते","ar":"لأن القشريات لا تُقدّم أبدًا في المطاعم"},{"en":"Because cooking crustaceans removes all allergen proteins","es":"Porque cocinar crustáceos elimina todas las proteínas alergénicas","ru":"Потому что приготовление ракообразных удаляет все белки-аллергены","tr":"Çünkü kabukluları pişirmek tüm alerjen proteinlerini giderir","hi":"क्योंकि क्रस्टेशियन पकाने से सभी एलर्जेन प्रोटीन हट जाते हैं","ar":"لأن طهي القشريات يزيل جميع بروتينات الحساسية"},{"en":"Because finned fish and crustacean shellfish are separate major allergens; a guest may react to one and not the other, so staff must clarify exactly which foods to avoid","es":"Porque el pescado con aletas y los mariscos crustáceos son alérgenos principales separados; un invitado puede reaccionar a uno y no al otro, por lo que el personal debe aclarar exactamente qué alimentos evitar","ru":"Потому что рыба с плавниками и ракообразные — это отдельные основные аллергены; гость может реагировать на один и не реагировать на другой, поэтому персонал должен уточнить, какие именно продукты избегать","tr":"Çünkü yüzgeçli balık ve kabuklu deniz ürünleri ayrı başlıca alerjenlerdir; bir konuk birine tepki verip diğerine vermeyebilir, bu yüzden personel tam olarak hangi gıdalardan kaçınılacağını netleştirmelidir","hi":"क्योंकि पंख वाली मछली और क्रस्टेशियन शेलफिश अलग प्रमुख एलर्जेन हैं; एक अतिथि एक पर प्रतिक्रिया कर सकता है और दूसरे पर नहीं, इसलिए स्टाफ को ठीक-ठीक स्पष्ट करना चाहिए कि किन खाद्य पदार्थों से बचना है","ar":"لأن الأسماك ذات الزعانف والقشريات مُسبِّبان رئيسيان منفصلان للحساسية؛ فقد يتفاعل الضيف مع أحدهما دون الآخر، لذا يجب على الموظفين توضيح الأطعمة التي يجب تجنبها بالضبط"},{"en":"Because shellfish allergies always disappear by adulthood","es":"Porque las alergias a los mariscos siempre desaparecen en la edad adulta","ru":"Потому что аллергия на моллюсков всегда исчезает к взрослому возрасту","tr":"Çünkü kabuklu deniz ürünü alerjileri yetişkinlikte her zaman kaybolur","hi":"क्योंकि शेलफिश एलर्जी वयस्कता तक हमेशा गायब हो जाती है","ar":"لأن حساسية المحار تختفي دائمًا في سن البلوغ"}],"e":{"en":"Finned fish and crustacean shellfish are two distinct major allergens; a guest may be allergic to one but tolerate the other, so staff must confirm the specific foods and prevent cross-contact accordingly.","es":"El pescado con aletas y los mariscos crustáceos son dos alérgenos principales distintos; un invitado puede ser alérgico a uno pero tolerar el otro, por lo que el personal debe confirmar los alimentos específicos y prevenir el contacto cruzado en consecuencia.","ru":"Рыба с плавниками и ракообразные — два разных основных аллергена; гость может иметь аллергию на один, но переносить другой, поэтому персонал должен уточнить конкретные продукты и соответственно предотвращать перекрёстный контакт.","tr":"Yüzgeçli balık ve kabuklu deniz ürünleri iki farklı başlıca alerjendir; bir konuk birine alerjik olup diğerini tolere edebilir, bu yüzden personel belirli gıdaları teyit etmeli ve buna göre çapraz teması önlemelidir.","hi":"पंख वाली मछली और क्रस्टेशियन शेलफिश दो अलग प्रमुख एलर्जेन हैं; एक अतिथि को एक से एलर्जी हो सकती है लेकिन दूसरे को सहन कर सकता है, इसलिए स्टाफ को विशिष्ट खाद्य पदार्थों की पुष्टि करनी चाहिए और तदनुसार क्रॉस-कॉन्टैक्ट को रोकना चाहिए।","ar":"الأسماك ذات الزعانف والقشريات مُسبِّبان رئيسيان مختلفان للحساسية؛ فقد يكون الضيف مصابًا بالحساسية تجاه أحدهما ويتحمل الآخر، لذا يجب على الموظفين تأكيد الأطعمة المحددة ومنع التلامس المتبادل وفقًا لذلك."}},{"cat":"flow","a":2,"q":{"en":"A refrigerated truck delivers cut cantaloupe measured at 47°F. What is the correct manager decision?","es":"Un camión refrigerado entrega melón cortado medido a 47°F. ¿Cuál es la decisión correcta del gerente?","ru":"Рефрижератор доставляет нарезанную дыню с температурой 47°F. Какое решение менеджера правильное?","tr":"Soğutmalı bir kamyon 47°F ölçülen dilimlenmiş kavun getiriyor. Doğru yönetici kararı nedir?","hi":"एक रेफ्रिजरेटेड ट्रक 47°F पर मापा गया कटा हुआ खरबूजा पहुंचाता है। सही प्रबंधक निर्णय क्या है?","ar":"تُوصّل شاحنة مبردة شمامًا مقطّعًا بدرجة حرارة 47°F. ما القرار الإداري الصحيح؟"},"o":[{"en":"Accept it because cut melon is a produce item","es":"Aceptarlo porque el melón cortado es un producto agrícola","ru":"Принять, потому что нарезанная дыня — это овощ/фрукт","tr":"Kabul etmek, çünkü dilimlenmiş kavun bir sebze-meyve ürünüdür","hi":"इसे स्वीकार करें क्योंकि कटा खरबूजा एक उपज वस्तु है","ar":"قبولها لأن الشمام المقطّع من منتجات الخضار والفاكهة"},{"en":"Accept it and cool it to 41°F within 4 hours","es":"Aceptarlo y enfriarlo a 41°F en 4 horas","ru":"Принять и охладить до 41°F в течение 4 часов","tr":"Kabul edip 4 saat içinde 41°F'ye soğutmak","hi":"इसे स्वीकार करें और 4 घंटे में 41°F तक ठंडा करें","ar":"قبولها وتبريدها إلى 41°F خلال 4 ساعات"},{"en":"Reject it because cold TCS food must be received at 41°F or below","es":"Rechazarlo porque los alimentos TCS fríos deben recibirse a 41°F o menos","ru":"Отклонить, потому что холодные продукты TCS должны приниматься при 41°F или ниже","tr":"Reddetmek, çünkü soğuk TCS gıdalar 41°F veya altında teslim alınmalıdır","hi":"इसे अस्वीकार करें क्योंकि ठंडा TCS भोजन 41°F या उससे कम पर प्राप्त होना चाहिए","ar":"رفضها لأن أطعمة TCS الباردة يجب استلامها عند 41°F أو أقل"},{"en":"Accept it only if it is used within 2 hours","es":"Aceptarlo solo si se usa en 2 horas","ru":"Принять только если использовать в течение 2 часов","tr":"Yalnızca 2 saat içinde kullanılacaksa kabul etmek","hi":"केवल तभी स्वीकार करें जब 2 घंटे में उपयोग हो","ar":"قبولها فقط إذا استُخدمت خلال ساعتين"}],"e":{"en":"Cut melon is a TCS food and must be received at 41°F or below; at 47°F the delivery must be rejected.","es":"El melón cortado es un alimento TCS y debe recibirse a 41°F o menos; a 47°F la entrega debe rechazarse.","ru":"Нарезанная дыня — это продукт TCS и должна приниматься при 41°F или ниже; при 47°F поставку следует отклонить.","tr":"Dilimlenmiş kavun bir TCS gıdadır ve 41°F veya altında teslim alınmalıdır; 47°F'de teslimat reddedilmelidir.","hi":"कटा खरबूजा एक TCS भोजन है और 41°F या उससे कम पर प्राप्त होना चाहिए; 47°F पर डिलीवरी अस्वीकार करनी चाहिए।","ar":"الشمام المقطّع طعام TCS ويجب استلامه عند 41°F أو أقل؛ عند 47°F يجب رفض الشحنة."}},{"cat":"flow","a":1,"q":{"en":"How long must an operation keep shellstock identification tags after the last shellfish from that container is used?","es":"¿Cuánto tiempo debe conservar un establecimiento las etiquetas de identificación de mariscos después de usar el último molusco de ese envase?","ru":"Как долго заведение должно хранить идентификационные бирки моллюсков после использования последнего моллюска из контейнера?","tr":"Bir işletme, o kaptan son kabuklu deniz ürünü kullanıldıktan sonra kabuklu tanımlama etiketlerini ne kadar saklamalıdır?","hi":"उस कंटेनर से आखिरी शेलफिश उपयोग होने के बाद प्रतिष्ठान को शेलस्टॉक पहचान टैग कितने समय तक रखने चाहिए?","ar":"كم يجب أن تحتفظ المنشأة ببطاقات تعريف المحار بعد استخدام آخر محارة من تلك العبوة؟"},"o":[{"en":"30 days","es":"30 días","ru":"30 дней","tr":"30 gün","hi":"30 दिन","ar":"30 يومًا"},{"en":"90 days","es":"90 días","ru":"90 дней","tr":"90 gün","hi":"90 दिन","ar":"90 يومًا"},{"en":"7 days","es":"7 días","ru":"7 дней","tr":"7 gün","hi":"7 दिन","ar":"7 أيام"},{"en":"1 year","es":"1 año","ru":"1 год","tr":"1 yıl","hi":"1 वर्ष","ar":"سنة واحدة"}],"e":{"en":"Shellstock tags must be kept on file for 90 days from the date the last item was used, to allow traceback during an illness investigation.","es":"Las etiquetas de mariscos deben conservarse en archivo durante 90 días desde que se usó el último producto, para permitir el rastreo en una investigación de enfermedad.","ru":"Бирки моллюсков нужно хранить 90 дней с даты использования последней единицы, чтобы обеспечить прослеживаемость при расследовании заболевания.","tr":"Kabuklu etiketleri, hastalık soruşturmasında geriye izlemeye olanak tanımak için son ürünün kullanıldığı tarihten itibaren 90 gün dosyada tutulmalıdır.","hi":"बीमारी की जांच के दौरान ट्रेसबैक की अनुमति देने के लिए शेलस्टॉक टैग आखिरी वस्तु के उपयोग की तारीख से 90 दिनों तक फ़ाइल में रखने चाहिए।","ar":"يجب الاحتفاظ ببطاقات المحار في السجلات لمدة 90 يومًا من تاريخ استخدام آخر صنف، للسماح بالتتبّع أثناء التحقيق في مرض."}},{"cat":"flow","a":3,"q":{"en":"At what temperature must raw shell eggs be received according to the Food Code?","es":"¿A qué temperatura deben recibirse los huevos crudos con cáscara según el Código de Alimentos?","ru":"При какой температуре должны приниматься сырые яйца в скорлупе согласно Пищевому кодексу?","tr":"Gıda Kanunu'na göre çiğ kabuklu yumurtalar hangi sıcaklıkta teslim alınmalıdır?","hi":"फूड कोड के अनुसार कच्चे शेल अंडे किस तापमान पर प्राप्त होने चाहिए?","ar":"عند أي درجة حرارة يجب استلام بيض القشرة النيء وفقًا لقانون الغذاء؟"},"o":[{"en":"An internal temperature of 41°F or below","es":"Una temperatura interna de 41°F o menos","ru":"Внутренняя температура 41°F или ниже","tr":"41°F veya altında iç sıcaklık","hi":"41°F या उससे कम आंतरिक तापमान","ar":"درجة حرارة داخلية 41°F أو أقل"},{"en":"Any temperature, since eggs are shelf stable","es":"Cualquier temperatura, ya que los huevos son estables en estante","ru":"Любая температура, так как яйца стабильны при хранении","tr":"Herhangi bir sıcaklık, çünkü yumurtalar raf ömürlüdür","hi":"कोई भी तापमान, क्योंकि अंडे शेल्फ स्थिर हैं","ar":"أي درجة حرارة، لأن البيض ثابت على الرف"},{"en":"An ambient air temperature of 41°F or below","es":"Una temperatura ambiente del aire de 41°F o menos","ru":"Температура окружающего воздуха 41°F или ниже","tr":"41°F veya altında ortam hava sıcaklığı","hi":"41°F या उससे कम परिवेशी वायु तापमान","ar":"درجة حرارة هواء محيطة 41°F أو أقل"},{"en":"An ambient air temperature of 45°F or below","es":"Una temperatura ambiente del aire de 45°F o menos","ru":"Температура окружающего воздуха 45°F или ниже","tr":"45°F veya altında ortam hava sıcaklığı","hi":"45°F या उससे कम परिवेशी वायु तापमान","ar":"درجة حرارة هواء محيطة 45°F أو أقل"}],"e":{"en":"Raw shell eggs must be received at an ambient (air) temperature of 45°F or below to slow the growth of Salmonella.","es":"Los huevos crudos con cáscara deben recibirse a una temperatura ambiente (del aire) de 45°F o menos para retrasar el crecimiento de Salmonella.","ru":"Сырые яйца в скорлупе должны приниматься при температуре окружающего воздуха 45°F или ниже, чтобы замедлить рост Salmonella.","tr":"Çiğ kabuklu yumurtalar, Salmonella üremesini yavaşlatmak için 45°F veya altında ortam (hava) sıcaklığında teslim alınmalıdır.","hi":"साल्मोनेला की वृद्धि को धीमा करने के लिए कच्चे शेल अंडे 45°F या उससे कम परिवेशी (वायु) तापमान पर प्राप्त होने चाहिए।","ar":"يجب استلام بيض القشرة النيء عند درجة حرارة هواء محيطة 45°F أو أقل لإبطاء نمو السالمونيلا."}},{"cat":"flow","a":0,"q":{"en":"Fluid milk may be received at 45°F or below. What must the operation then do?","es":"La leche líquida puede recibirse a 45°F o menos. ¿Qué debe hacer entonces el establecimiento?","ru":"Жидкое молоко можно принимать при 45°F или ниже. Что затем должно сделать заведение?","tr":"Sıvı süt 45°F veya altında teslim alınabilir. İşletme bundan sonra ne yapmalıdır?","hi":"तरल दूध 45°F या उससे कम पर प्राप्त किया जा सकता है। फिर प्रतिष्ठान को क्या करना चाहिए?","ar":"يمكن استلام الحليب السائل عند 45°F أو أقل. ماذا يجب أن تفعل المنشأة بعد ذلك؟"},"o":[{"en":"Cool it to 41°F or below within 4 hours","es":"Enfriarla a 41°F o menos en 4 horas","ru":"Охладить до 41°F или ниже в течение 4 часов","tr":"4 saat içinde 41°F veya altına soğutmak","hi":"इसे 4 घंटे में 41°F या उससे कम तक ठंडा करें","ar":"تبريده إلى 41°F أو أقل خلال 4 ساعات"},{"en":"Keep it at 45°F for the rest of its shelf life","es":"Mantenerla a 45°F por el resto de su vida útil","ru":"Хранить при 45°F до конца срока годности","tr":"Raf ömrünün geri kalanında 45°F'de tutmak","hi":"इसे शेल्फ जीवन के बाकी समय 45°F पर रखें","ar":"إبقاؤه عند 45°F لبقية مدة صلاحيته"},{"en":"Freeze it immediately","es":"Congelarla de inmediato","ru":"Немедленно заморозить","tr":"Hemen dondurmak","hi":"इसे तुरंत फ्रीज करें","ar":"تجميده فورًا"},{"en":"Cool it to 41°F within 6 hours","es":"Enfriarla a 41°F en 6 horas","ru":"Охладить до 41°F в течение 6 часов","tr":"6 saat içinde 41°F'ye soğutmak","hi":"इसे 6 घंटे में 41°F तक ठंडा करें","ar":"تبريده إلى 41°F خلال 6 ساعات"}],"e":{"en":"Milk received at 45°F or below must be cooled to 41°F or below within 4 hours of receipt.","es":"La leche recibida a 45°F o menos debe enfriarse a 41°F o menos dentro de las 4 horas posteriores a la recepción.","ru":"Молоко, принятое при 45°F или ниже, необходимо охладить до 41°F или ниже в течение 4 часов после получения.","tr":"45°F veya altında teslim alınan süt, teslim alındıktan sonraki 4 saat içinde 41°F veya altına soğutulmalıdır.","hi":"45°F या उससे कम पर प्राप्त दूध को प्राप्ति के 4 घंटे के भीतर 41°F या उससे कम तक ठंडा करना चाहिए।","ar":"يجب تبريد الحليب المستلم عند 45°F أو أقل إلى 41°F أو أقل خلال 4 ساعات من الاستلام."}},{"cat":"flow","a":2,"q":{"en":"A case of frozen shrimp arrives with large ice crystals and fluid stains on the box. What does this most likely indicate?","es":"Llega una caja de camarones congelados con grandes cristales de hielo y manchas de líquido en la caja. ¿Qué indica esto con mayor probabilidad?","ru":"Коробка замороженных креветок прибывает с крупными кристаллами льда и следами жидкости на упаковке. Что это скорее всего указывает?","tr":"Bir kutu dondurulmuş karides, kutuda büyük buz kristalleri ve sıvı lekeleriyle geliyor. Bu büyük olasılıkla neyi gösterir?","hi":"जमे हुए झींगे का एक डिब्बा बड़े बर्फ के क्रिस्टल और बॉक्स पर तरल दाग के साथ आता है। यह सबसे अधिक संभावना क्या दर्शाता है?","ar":"يصل صندوق من الجمبري المجمّد مع بلورات ثلج كبيرة وبقع سائلة على الصندوق. ما الذي يشير إليه هذا على الأرجح؟"},"o":[{"en":"The product is fresher than normal","es":"El producto está más fresco de lo normal","ru":"Продукт свежее обычного","tr":"Ürün normalden daha tazedir","hi":"उत्पाद सामान्य से अधिक ताजा है","ar":"المنتج أطزج من المعتاد"},{"en":"The shrimp were flash frozen correctly","es":"Los camarones se congelaron rápidamente de forma correcta","ru":"Креветки были правильно заморожены шоковым способом","tr":"Karidesler doğru şekilde şok dondurulmuş","hi":"झींगे को सही तरीके से फ्लैश फ्रोजन किया गया","ar":"تم تجميد الجمبري بالصدمة بشكل صحيح"},{"en":"The product was thawed and refrozen and should be rejected","es":"El producto se descongeló y se volvió a congelar y debe rechazarse","ru":"Продукт был разморожен и повторно заморожен и должен быть отклонён","tr":"Ürün çözülüp yeniden dondurulmuş ve reddedilmelidir","hi":"उत्पाद को पिघलाकर फिर से जमाया गया और अस्वीकार किया जाना चाहिए","ar":"تم إذابة المنتج وإعادة تجميده ويجب رفضه"},{"en":"The packaging simply needs to be wiped down","es":"El empaque simplemente necesita limpiarse","ru":"Упаковку просто нужно протереть","tr":"Ambalajın sadece silinmesi gerekir","hi":"पैकेजिंग को बस पोंछने की जरूरत है","ar":"العبوة تحتاج فقط إلى المسح"}],"e":{"en":"Large ice crystals and fluid stains are signs the product was thawed and refrozen; such deliveries must be rejected.","es":"Los grandes cristales de hielo y las manchas de líquido son señales de que el producto se descongeló y se volvió a congelar; tales entregas deben rechazarse.","ru":"Крупные кристаллы льда и следы жидкости — признаки того, что продукт размораживали и повторно замораживали; такие поставки нужно отклонять.","tr":"Büyük buz kristalleri ve sıvı lekeleri, ürünün çözülüp yeniden dondurulduğunun işaretidir; bu tür teslimatlar reddedilmelidir.","hi":"बड़े बर्फ के क्रिस्टल और तरल दाग संकेत हैं कि उत्पाद को पिघलाकर फिर से जमाया गया; ऐसी डिलीवरी अस्वीकार करनी चाहिए।","ar":"بلورات الثلج الكبيرة والبقع السائلة علامات على أن المنتج أُذيب وأُعيد تجميده؛ يجب رفض هذه الشحنات."}},{"cat":"flow","a":1,"q":{"en":"A supplier delivers hot soup as a hot TCS food. At what minimum temperature must it be received?","es":"Un proveedor entrega sopa caliente como alimento TCS caliente. ¿A qué temperatura mínima debe recibirse?","ru":"Поставщик доставляет горячий суп как горячий продукт TCS. При какой минимальной температуре его нужно принять?","tr":"Bir tedarikçi sıcak çorbayı sıcak TCS gıda olarak teslim ediyor. Minimum hangi sıcaklıkta teslim alınmalıdır?","hi":"एक आपूर्तिकर्ता गर्म सूप को गर्म TCS भोजन के रूप में पहुंचाता है। इसे किस न्यूनतम तापमान पर प्राप्त करना चाहिए?","ar":"يقوم مورّد بتوصيل حساء ساخن كطعام TCS ساخن. عند أي درجة حرارة دنيا يجب استلامه؟"},"o":[{"en":"125°F or above","es":"125°F o más","ru":"125°F или выше","tr":"125°F veya üzeri","hi":"125°F या अधिक","ar":"125°F أو أعلى"},{"en":"135°F or above","es":"135°F o más","ru":"135°F или выше","tr":"135°F veya üzeri","hi":"135°F या अधिक","ar":"135°F أو أعلى"},{"en":"115°F or above","es":"115°F o más","ru":"115°F или выше","tr":"115°F veya üzeri","hi":"115°F या अधिक","ar":"115°F أو أعلى"},{"en":"165°F or above","es":"165°F o más","ru":"165°F или выше","tr":"165°F veya üzeri","hi":"165°F या अधिक","ar":"165°F أو أعلى"}],"e":{"en":"Hot TCS food must be received at 135°F or above; below that it is in the danger zone and should be rejected.","es":"Los alimentos TCS calientes deben recibirse a 135°F o más; por debajo de eso están en la zona de peligro y deben rechazarse.","ru":"Горячие продукты TCS должны приниматься при 135°F или выше; ниже этого они находятся в опасной зоне и подлежат отклонению.","tr":"Sıcak TCS gıdalar 135°F veya üzerinde teslim alınmalıdır; bunun altında tehlike bölgesindedir ve reddedilmelidir.","hi":"गर्म TCS भोजन 135°F या अधिक पर प्राप्त होना चाहिए; उससे कम पर यह खतरे के क्षेत्र में है और अस्वीकार किया जाना चाहिए।","ar":"يجب استلام أطعمة TCS الساخنة عند 135°F أو أعلى؛ دون ذلك تكون في منطقة الخطر ويجب رفضها."}},{"cat":"flow","a":0,"q":{"en":"When rotating stock using FIFO, which product should be placed at the front to be used first?","es":"Al rotar el inventario usando FIFO, ¿qué producto debe colocarse al frente para usarse primero?","ru":"При ротации запасов по методу FIFO, какой продукт следует ставить впереди для использования первым?","tr":"FIFO ile stok döndürürken, ilk kullanılmak üzere hangi ürün öne yerleştirilmelidir?","hi":"FIFO का उपयोग करके स्टॉक घुमाते समय, पहले उपयोग करने के लिए कौन सा उत्पाद सामने रखा जाना चाहिए?","ar":"عند تدوير المخزون باستخدام FIFO، أي منتج يجب وضعه في المقدمة لاستخدامه أولًا؟"},"o":[{"en":"The product with the earliest use-by or expiration date","es":"El producto con la fecha de caducidad o consumo preferente más temprana","ru":"Продукт с самой ранней датой годности или срока использования","tr":"En erken son kullanma veya tüketim tarihine sahip ürün","hi":"सबसे पहले की उपयोग-तिथि या समाप्ति तिथि वाला उत्पाद","ar":"المنتج ذو أقرب تاريخ استخدام أو انتهاء صلاحية"},{"en":"The product that was received most recently","es":"El producto recibido más recientemente","ru":"Продукт, полученный последним","tr":"En son teslim alınan ürün","hi":"सबसे हाल ही में प्राप्त उत्पाद","ar":"المنتج المستلم مؤخرًا"},{"en":"The largest package regardless of date","es":"El paquete más grande sin importar la fecha","ru":"Самая большая упаковка независимо от даты","tr":"Tarihe bakılmaksızın en büyük paket","hi":"तारीख की परवाह किए बिना सबसे बड़ा पैकेज","ar":"أكبر عبوة بغض النظر عن التاريخ"},{"en":"Whichever product is easiest to reach","es":"El producto que sea más fácil de alcanzar","ru":"Тот продукт, до которого легче дотянуться","tr":"En kolay ulaşılan ürün","hi":"जो भी उत्पाद पहुंचने में आसान हो","ar":"أي منتج يسهل الوصول إليه"}],"e":{"en":"FIFO means the item with the earliest use-by date is placed in front and used first, reducing spoilage and waste.","es":"FIFO significa que el artículo con la fecha de consumo más temprana se coloca al frente y se usa primero, reduciendo el deterioro y el desperdicio.","ru":"FIFO означает, что продукт с самой ранней датой годности ставится вперёд и используется первым, снижая порчу и отходы.","tr":"FIFO, en erken son kullanma tarihli ürünün öne yerleştirilip ilk kullanılması demektir; bozulmayı ve israfı azaltır.","hi":"FIFO का मतलब है कि सबसे पहले की उपयोग-तिथि वाली वस्तु को सामने रखा जाता है और पहले उपयोग किया जाता है, जिससे खराबी और बर्बादी कम होती है।","ar":"يعني FIFO وضع الصنف ذي أقرب تاريخ استخدام في المقدمة واستخدامه أولًا، مما يقلل التلف والهدر."}},{"cat":"flow","a":3,"q":{"en":"Why is raw poultry stored on the bottom shelf below all other raw meats in a cooler?","es":"¿Por qué se almacena la carne de ave cruda en el estante inferior, debajo de todas las demás carnes crudas en un refrigerador?","ru":"Почему сырая птица хранится на нижней полке, ниже всех остальных сырых видов мяса в холодильнике?","tr":"Çiğ kümes hayvanları neden buzdolabında diğer tüm çiğ etlerin altında en alt rafta saklanır?","hi":"एक कूलर में कच्चे मुर्गे को अन्य सभी कच्चे मांस के नीचे सबसे निचली शेल्फ पर क्यों रखा जाता है?","ar":"لماذا يُخزّن الدواجن النيئة على الرف السفلي أسفل جميع اللحوم النيئة الأخرى في المبرد؟"},"o":[{"en":"Because poultry is the heaviest product","es":"Porque la carne de ave es el producto más pesado","ru":"Потому что птица — самый тяжёлый продукт","tr":"Çünkü kümes eti en ağır üründür","hi":"क्योंकि मुर्गा सबसे भारी उत्पाद है","ar":"لأن الدواجن هي المنتج الأثقل"},{"en":"Because it spoils faster than other meats","es":"Porque se echa a perder más rápido que otras carnes","ru":"Потому что она портится быстрее других видов мяса","tr":"Çünkü diğer etlerden daha hızlı bozulur","hi":"क्योंकि यह अन्य मांस की तुलना में तेजी से खराब होता है","ar":"لأنها تفسد أسرع من اللحوم الأخرى"},{"en":"Because it must be kept warmer than other items","es":"Porque debe mantenerse más caliente que otros artículos","ru":"Потому что её нужно держать теплее других продуктов","tr":"Çünkü diğer ürünlerden daha sıcak tutulmalıdır","hi":"क्योंकि इसे अन्य वस्तुओं से गर्म रखना चाहिए","ar":"لأنه يجب حفظها أدفأ من الأصناف الأخرى"},{"en":"Because it has the highest required cooking temperature (165°F), so drips will not contaminate foods cooked at lower temperatures","es":"Porque tiene la temperatura de cocción requerida más alta (165°F), por lo que las gotas no contaminarán alimentos cocinados a temperaturas más bajas","ru":"Потому что у неё самая высокая требуемая температура приготовления (165°F), поэтому стекающая жидкость не загрязнит продукты, готовящиеся при более низких температурах","tr":"Çünkü en yüksek pişirme sıcaklığına (165°F) sahiptir, böylece damlalar daha düşük sıcaklıkta pişen gıdaları kirletmez","hi":"क्योंकि इसका सबसे अधिक आवश्यक खाना पकाने का तापमान (165°F) है, इसलिए टपकने वाला रस कम तापमान पर पकाए गए भोजन को दूषित नहीं करेगा","ar":"لأن لديها أعلى درجة حرارة طهي مطلوبة (165°F)، لذا لن تلوّث القطرات الأطعمة المطهوة عند درجات حرارة أقل"}],"e":{"en":"Storage order follows minimum cooking temperature; raw poultry (165°F) goes on the bottom so its drippings cannot contaminate foods cooked to lower temperatures.","es":"El orden de almacenamiento sigue la temperatura mínima de cocción; la carne de ave cruda (165°F) va abajo para que sus jugos no contaminen alimentos cocinados a temperaturas más bajas.","ru":"Порядок хранения соответствует минимальной температуре приготовления; сырая птица (165°F) размещается внизу, чтобы её сок не загрязнял продукты, готовящиеся при более низких температурах.","tr":"Depolama sırası minimum pişirme sıcaklığını izler; çiğ kümes eti (165°F) en alta konur, böylece damlaları daha düşük sıcaklıkta pişen gıdaları kirletmez.","hi":"भंडारण क्रम न्यूनतम खाना पकाने के तापमान का पालन करता है; कच्चा मुर्गा (165°F) नीचे रखा जाता है ताकि उसका रस कम तापमान पर पकाए भोजन को दूषित न करे।","ar":"يتبع ترتيب التخزين درجة حرارة الطهي الدنيا؛ توضع الدواجن النيئة (165°F) في الأسفل حتى لا تلوّث قطراتها الأطعمة المطهوة عند درجات أقل."}},{"cat":"flow","a":2,"q":{"en":"A cooler holds ready-to-eat pie, raw salmon, raw ground beef, and raw chicken. What is the correct top-to-bottom order?","es":"Un refrigerador tiene pastel listo para comer, salmón crudo, carne molida cruda de res y pollo crudo. ¿Cuál es el orden correcto de arriba a abajo?","ru":"В холодильнике находятся готовый к употреблению пирог, сырой лосось, сырой говяжий фарш и сырая курица. Каков правильный порядок сверху вниз?","tr":"Bir buzdolabında yemeye hazır turta, çiğ somon, çiğ kıyma dana eti ve çiğ tavuk var. Doğru yukarıdan aşağıya sıralama nedir?","hi":"एक कूलर में खाने के लिए तैयार पाई, कच्चा सैल्मन, कच्चा ग्राउंड बीफ और कच्चा चिकन है। ऊपर से नीचे का सही क्रम क्या है?","ar":"يحتوي المبرد على فطيرة جاهزة للأكل، وسلمون نيء، ولحم بقري مفروم نيء، ودجاج نيء. ما الترتيب الصحيح من الأعلى إلى الأسفل؟"},"o":[{"en":"Raw chicken, raw ground beef, raw salmon, ready-to-eat pie","es":"Pollo crudo, carne molida cruda, salmón crudo, pastel listo para comer","ru":"Сырая курица, сырой фарш, сырой лосось, готовый пирог","tr":"Çiğ tavuk, çiğ kıyma, çiğ somon, yemeye hazır turta","hi":"कच्चा चिकन, कच्चा ग्राउंड बीफ, कच्चा सैल्मन, तैयार पाई","ar":"دجاج نيء، لحم مفروم نيء، سلمون نيء، فطيرة جاهزة"},{"en":"Raw salmon, ready-to-eat pie, raw ground beef, raw chicken","es":"Salmón crudo, pastel listo para comer, carne molida cruda, pollo crudo","ru":"Сырой лосось, готовый пирог, сырой фарш, сырая курица","tr":"Çiğ somon, yemeye hazır turta, çiğ kıyma, çiğ tavuk","hi":"कच्चा सैल्मन, तैयार पाई, कच्चा ग्राउंड बीफ, कच्चा चिकन","ar":"سلمون نيء، فطيرة جاهزة، لحم مفروم نيء، دجاج نيء"},{"en":"Ready-to-eat pie, raw salmon, raw ground beef, raw chicken","es":"Pastel listo para comer, salmón crudo, carne molida cruda, pollo crudo","ru":"Готовый пирог, сырой лосось, сырой фарш, сырая курица","tr":"Yemeye hazır turta, çiğ somon, çiğ kıyma, çiğ tavuk","hi":"तैयार पाई, कच्चा सैल्मन, कच्चा ग्राउंड बीफ, कच्चा चिकन","ar":"فطيرة جاهزة، سلمون نيء، لحم مفروم نيء، دجاج نيء"},{"en":"Ready-to-eat pie, raw chicken, raw ground beef, raw salmon","es":"Pastel listo para comer, pollo crudo, carne molida cruda, salmón crudo","ru":"Готовый пирог, сырая курица, сырой фарш, сырой лосось","tr":"Yemeye hazır turta, çiğ tavuk, çiğ kıyma, çiğ somon","hi":"तैयार पाई, कच्चा चिकन, कच्चा ग्राउंड बीफ, कच्चा सैल्मन","ar":"فطيرة جاهزة، دجاج نيء، لحم مفروم نيء، سلمون نيء"}],"e":{"en":"Order by minimum cooking temperature: ready-to-eat on top, then salmon (145°F), ground beef (155°F), and raw chicken (165°F) on the bottom.","es":"Ordene por temperatura mínima de cocción: listo para comer arriba, luego salmón (145°F), carne molida (155°F) y pollo crudo (165°F) abajo.","ru":"Порядок по минимальной температуре приготовления: готовое сверху, затем лосось (145°F), фарш (155°F) и сырая курица (165°F) внизу.","tr":"Minimum pişirme sıcaklığına göre sıralayın: yemeye hazır en üstte, sonra somon (145°F), kıyma (155°F) ve en altta çiğ tavuk (165°F).","hi":"न्यूनतम खाना पकाने के तापमान के अनुसार क्रम: ऊपर तैयार भोजन, फिर सैल्मन (145°F), ग्राउंड बीफ (155°F), और नीचे कच्चा चिकन (165°F)।","ar":"الترتيب حسب درجة حرارة الطهي الدنيا: الجاهز للأكل في الأعلى، ثم السلمون (145°F)، اللحم المفروم (155°F)، والدجاج النيء (165°F) في الأسفل."}},{"cat":"flow","a":1,"q":{"en":"A receiving clerk is putting away a delivery of canned goods in dry storage. Placing the cases directly on the storeroom floor would violate which requirement?","es":"Un empleado de recepción está guardando una entrega de productos enlatados en el almacenamiento en seco. Colocar las cajas directamente en el piso del almacén violaría ¿cuál requisito?","ru":"Приёмщик раскладывает поставку консервов на сухом складе. Размещение коробок прямо на полу склада нарушит какое требование?","tr":"Bir teslim alma görevlisi kuru depoya bir konserve teslimatını yerleştiriyor. Kutuları doğrudan depo zeminine koymak hangi gereksinimi ihlal eder?","hi":"एक प्राप्ति क्लर्क सूखे भंडारण में डिब्बाबंद सामान की डिलीवरी रख रहा है। बक्सों को सीधे स्टोररूम के फर्श पर रखना किस आवश्यकता का उल्लंघन करेगा?","ar":"موظف استلام يقوم بتخزين شحنة معلبات في التخزين الجاف. وضع الصناديق مباشرة على أرضية المخزن يخالف أي متطلب؟"},"o":[{"en":"Food may be stored on the floor if it is canned","es":"Los alimentos pueden almacenarse en el piso si están enlatados","ru":"Продукты можно хранить на полу, если они консервированные","tr":"Konserve ise gıda yerde saklanabilir","hi":"यदि भोजन डिब्बाबंद है तो इसे फर्श पर रखा जा सकता है","ar":"يمكن تخزين الطعام على الأرض إذا كان معلبًا"},{"en":"Food must be stored at least 6 inches off the floor","es":"Los alimentos deben almacenarse al menos a 6 pulgadas del piso","ru":"Продукты нужно хранить не менее чем в 6 дюймах от пола","tr":"Gıdalar yerden en az 6 inç yükseğe depolanmalıdır","hi":"भोजन को फर्श से कम से कम 6 इंच ऊपर रखा जाना चाहिए","ar":"يجب تخزين الطعام على ارتفاع 6 بوصات على الأقل عن الأرض"},{"en":"Food must be stored at least 12 inches off the floor","es":"Los alimentos deben almacenarse al menos a 12 pulgadas del piso","ru":"Продукты нужно хранить не менее чем в 12 дюймах от пола","tr":"Gıdalar yerden en az 12 inç yükseğe depolanmalıdır","hi":"भोजन को फर्श से कम से कम 12 इंच ऊपर रखा जाना चाहिए","ar":"يجب تخزين الطعام على ارتفاع 12 بوصة على الأقل عن الأرض"},{"en":"Food must be stored at least 2 inches off the floor","es":"Los alimentos deben almacenarse al menos a 2 pulgadas del piso","ru":"Продукты нужно хранить не менее чем в 2 дюймах от пола","tr":"Gıdalar yerden en az 2 inç yükseğe depolanmalıdır","hi":"भोजन को फर्श से कम से कम 2 इंच ऊपर रखा जाना चाहिए","ar":"يجب تخزين الطعام على ارتفاع 2 بوصة على الأقل عن الأرض"}],"e":{"en":"All food, including canned goods, must be stored at least 6 inches off the floor to protect it from contamination and splash and to allow cleaning.","es":"Todos los alimentos, incluidos los enlatados, deben almacenarse al menos a 6 pulgadas del piso para protegerlos de la contaminación y salpicaduras y permitir la limpieza.","ru":"Все продукты, включая консервы, нужно хранить не менее чем в 6 дюймах от пола, чтобы защитить от загрязнения и брызг и обеспечить уборку.","tr":"Konserveler dahil tüm gıdalar, kirlenme ve sıçramadan korumak ve temizliğe olanak sağlamak için yerden en az 6 inç yükseğe depolanmalıdır.","hi":"डिब्बाबंद सामान सहित सभी भोजन को दूषण और छींटों से बचाने और सफाई की अनुमति देने के लिए फर्श से कम से कम 6 इंच ऊपर रखा जाना चाहिए।","ar":"يجب تخزين جميع الأطعمة، بما فيها المعلبات، على ارتفاع 6 بوصات على الأقل عن الأرض لحمايتها من التلوث والرذاذ والسماح بالتنظيف."}},{"cat":"flow","a":3,"q":{"en":"House-made tuna salad is prepared and refrigerated at 41°F on January 1. What is the last date it may be served, and on which day should it be labeled to discard?","es":"Se prepara ensalada de atún casera y se refrigera a 41°F el 1 de enero. ¿Cuál es la última fecha en que puede servirse y para qué día debe etiquetarse para desechar?","ru":"Домашний салат из тунца приготовлен и охлаждён при 41°F 1 января. Какая последняя дата, когда его можно подавать, и на какой день его следует промаркировать для утилизации?","tr":"Ev yapımı ton balığı salatası 1 Ocak'ta hazırlanıp 41°F'de soğutulur. Servis edilebileceği son tarih nedir ve hangi gün için atılmak üzere etiketlenmelidir?","hi":"घर में बना टूना सलाद 1 जनवरी को तैयार किया जाता है और 41°F पर प्रशीतित किया जाता है। इसे परोसने की अंतिम तिथि क्या है, और इसे किस दिन फेंकने के लिए लेबल किया जाना चाहिए?","ar":"يُحضّر سلطة تونة منزلية وتُبرّد عند 41°F في 1 يناير. ما آخر تاريخ يمكن تقديمها فيه، وأي يوم يجب أن تُوسم للتخلص منها؟"},"o":[{"en":"January 3, because prepared salads last only 3 days","es":"3 de enero, porque las ensaladas preparadas duran solo 3 días","ru":"3 января, потому что готовые салаты хранятся только 3 дня","tr":"3 Ocak, çünkü hazırlanmış salatalar yalnızca 3 gün dayanır","hi":"3 जनवरी, क्योंकि तैयार सलाद केवल 3 दिन चलते हैं","ar":"3 يناير، لأن السلطات المُحضّرة تدوم 3 أيام فقط"},{"en":"January 15, counting two weeks from preparation","es":"15 de enero, contando dos semanas desde la preparación","ru":"15 января, отсчитывая две недели от приготовления","tr":"15 Ocak, hazırlıktan iki hafta sayarak","hi":"15 जनवरी, तैयारी से दो सप्ताह गिनते हुए","ar":"15 يناير، باحتساب أسبوعين من التحضير"},{"en":"January 5, counting the prep day as day zero","es":"5 de enero, contando el día de preparación como día cero","ru":"5 января, считая день приготовления нулевым днём","tr":"5 Ocak, hazırlık gününü sıfırıncı gün sayarak","hi":"5 जनवरी, तैयारी के दिन को शून्य दिन गिनते हुए","ar":"5 يناير، باحتساب يوم التحضير كيوم صفر"},{"en":"January 7, because the 7-day limit counts the prep day as day 1","es":"7 de enero, porque el límite de 7 días cuenta el día de preparación como día 1","ru":"7 января, потому что 7-дневный лимит считает день приготовления днём 1","tr":"7 Ocak, çünkü 7 günlük sınır hazırlık gününü 1. gün sayar","hi":"7 जनवरी, क्योंकि 7-दिन की सीमा तैयारी के दिन को दिन 1 गिनती है","ar":"7 يناير، لأن حد الـ 7 أيام يحتسب يوم التحضير كيوم 1"}],"e":{"en":"Ready-to-eat TCS food held at 41°F or below gets a 7-day shelf life with the preparation day counted as day 1, so food made January 1 must be discarded after January 7.","es":"Los alimentos TCS listos para comer mantenidos a 41°F o menos tienen una vida útil de 7 días contando el día de preparación como día 1, por lo que el alimento hecho el 1 de enero debe desecharse después del 7 de enero.","ru":"Готовые продукты TCS, хранящиеся при 41°F или ниже, имеют срок годности 7 дней, при этом день приготовления считается днём 1, поэтому продукт, сделанный 1 января, нужно выбросить после 7 января.","tr":"41°F veya altında tutulan yemeye hazır TCS gıdalar, hazırlık günü 1. gün sayılarak 7 günlük raf ömrüne sahiptir; bu nedenle 1 Ocak'ta yapılan gıda 7 Ocak'tan sonra atılmalıdır.","hi":"41°F या उससे कम पर रखा गया खाने के लिए तैयार TCS भोजन का शेल्फ जीवन 7 दिन का होता है जिसमें तैयारी का दिन दिन 1 गिना जाता है, इसलिए 1 जनवरी को बना भोजन 7 जनवरी के बाद फेंक देना चाहिए।","ar":"طعام TCS الجاهز للأكل المحفوظ عند 41°F أو أقل له مدة صلاحية 7 أيام مع احتساب يوم التحضير كيوم 1، لذا يجب التخلص من الطعام المُعدّ في 1 يناير بعد 7 يناير."}},{"cat":"flow","a":0,"q":{"en":"A cook needs to thaw frozen chicken breasts quickly at the sink. Which practice keeps the operation compliant with the Food Code?","es":"Un cocinero necesita descongelar rápidamente pechugas de pollo congeladas en el fregadero. ¿Qué práctica mantiene al establecimiento en cumplimiento con el Código de Alimentos?","ru":"Повару нужно быстро разморозить замороженные куриные грудки в раковине. Какая практика сохраняет соответствие Пищевому кодексу?","tr":"Bir aşçının dondurulmuş tavuk göğüslerini evyede hızlıca çözmesi gerekiyor. Hangi uygulama işletmeyi Gıda Kanunu'na uygun tutar?","hi":"एक रसोइये को सिंक में जमे हुए चिकन ब्रेस्ट को जल्दी पिघलाना है। कौन सी प्रथा प्रतिष्ठान को फूड कोड के अनुरूप रखती है?","ar":"يحتاج طاهٍ إلى إذابة صدور الدجاج المجمّدة بسرعة عند الحوض. أي ممارسة تُبقي المنشأة ملتزمة بقانون الغذاء؟"},"o":[{"en":"Run potable water at 70°F or below over the chicken while it is submerged","es":"Dejar correr agua potable a 70°F o menos sobre el pollo mientras está sumergido","ru":"Пропускать питьевую воду при 70°F или ниже над погружённой курицей","tr":"Tavuk daldırılmışken üzerinden 70°F veya altında içme suyu akıtmak","hi":"चिकन के डूबे रहने पर उस पर 70°F या उससे कम पीने योग्य पानी बहाएं","ar":"تمرير ماء صالح للشرب بدرجة 70°F أو أقل فوق الدجاج وهو مغمور"},{"en":"Fill the sink with hot water at 120°F to speed thawing","es":"Llenar el fregadero con agua caliente a 120°F para acelerar la descongelación","ru":"Наполнить раковину горячей водой при 120°F для ускорения размораживания","tr":"Çözmeyi hızlandırmak için evyeyi 120°F sıcak suyla doldurmak","hi":"पिघलने में तेजी लाने के लिए सिंक को 120°F गर्म पानी से भरें","ar":"ملء الحوض بماء ساخن بدرجة 120°F لتسريع الإذابة"},{"en":"Let the chicken sit in standing lukewarm water for several hours","es":"Dejar el pollo en agua tibia estancada durante varias horas","ru":"Оставить курицу в стоячей тёплой воде на несколько часов","tr":"Tavuğu birkaç saat durgun ılık suda bekletmek","hi":"चिकन को कई घंटों तक स्थिर गुनगुने पानी में छोड़ दें","ar":"ترك الدجاج في ماء فاتر راكد لعدة ساعات"},{"en":"Thaw it at room temperature next to the sink","es":"Descongelarlo a temperatura ambiente junto al fregadero","ru":"Разморозить при комнатной температуре рядом с раковиной","tr":"Evyenin yanında oda sıcaklığında çözmek","hi":"इसे सिंक के पास कमरे के तापमान पर पिघलाएं","ar":"إذابته بدرجة حرارة الغرفة بجانب الحوض"}],"e":{"en":"Thawing under running potable water at 70°F or below is an approved method; warm or standing water and room-temperature thawing let the surface enter the danger zone.","es":"Descongelar bajo agua potable corriente a 70°F o menos es un método aprobado; el agua tibia o estancada y la descongelación a temperatura ambiente permiten que la superficie entre en la zona de peligro.","ru":"Размораживание под проточной питьевой водой при 70°F или ниже — одобренный метод; тёплая или стоячая вода и размораживание при комнатной температуре позволяют поверхности войти в опасную зону.","tr":"70°F veya altında akan içme suyu altında çözme onaylı bir yöntemdir; ılık veya durgun su ve oda sıcaklığında çözme yüzeyin tehlike bölgesine girmesine izin verir.","hi":"70°F या उससे कम पर बहते पीने योग्य पानी के नीचे पिघलाना एक अनुमोदित तरीका है; गर्म या स्थिर पानी और कमरे के तापमान पर पिघलाना सतह को खतरे के क्षेत्र में जाने देता है।","ar":"الإذابة تحت ماء صالح للشرب جارٍ بدرجة 70°F أو أقل طريقة معتمدة؛ أما الماء الدافئ أو الراكد والإذابة بدرجة حرارة الغرفة فتسمح للسطح بدخول منطقة الخطر."}},{"cat":"flow","a":2,"q":{"en":"A pot of beef stew has cooled from 135°F to only 90°F after 2 hours. What must the manager do?","es":"Una olla de estofado de res se ha enfriado de 135°F a solo 90°F después de 2 horas. ¿Qué debe hacer el gerente?","ru":"Кастрюля с говяжьим рагу за 2 часа остыла со 135°F только до 90°F. Что должен сделать менеджер?","tr":"Bir tencere dana yahnisi 2 saat sonra 135°F'den yalnızca 90°F'ye soğudu. Yönetici ne yapmalıdır?","hi":"गोमांस स्टू का एक बर्तन 2 घंटे बाद 135°F से केवल 90°F तक ठंडा हुआ है। प्रबंधक को क्या करना चाहिए?","ar":"قِدر من يخنة اللحم البقري بردت من 135°F إلى 90°F فقط بعد ساعتين. ماذا يجب أن يفعل المدير؟"},"o":[{"en":"Continue cooling because it still has 4 more hours","es":"Continuar enfriando porque todavía tiene 4 horas más","ru":"Продолжить охлаждение, потому что есть ещё 4 часа","tr":"Soğutmaya devam etmek çünkü hâlâ 4 saati var","hi":"ठंडा करना जारी रखें क्योंकि अभी 4 घंटे और हैं","ar":"الاستمرار في التبريد لأنه لا يزال أمامه 4 ساعات"},{"en":"Move it to hot holding at 135°F","es":"Moverlo a mantenimiento en caliente a 135°F","ru":"Переместить в горячее хранение при 135°F","tr":"135°F'de sıcak muhafazaya taşımak","hi":"इसे 135°F पर हॉट होल्डिंग में ले जाएं","ar":"نقلها إلى الحفظ الساخن عند 135°F"},{"en":"Discard the stew because it did not reach 70°F within the first 2 hours","es":"Desechar el estofado porque no alcanzó 70°F dentro de las primeras 2 horas","ru":"Выбросить рагу, потому что оно не достигло 70°F в первые 2 часа","tr":"Yahniyi atmak çünkü ilk 2 saatte 70°F'ye ulaşmadı","hi":"स्टू को फेंक दें क्योंकि यह पहले 2 घंटों में 70°F तक नहीं पहुंचा","ar":"التخلص من اليخنة لأنها لم تصل إلى 70°F خلال أول ساعتين"},{"en":"Add hot water to reset the cooling clock","es":"Agregar agua caliente para reiniciar el reloj de enfriamiento","ru":"Добавить горячей воды, чтобы сбросить отсчёт охлаждения","tr":"Soğutma sayacını sıfırlamak için sıcak su eklemek","hi":"ठंडा करने का समय रीसेट करने के लिए गर्म पानी डालें","ar":"إضافة ماء ساخن لإعادة ضبط عداد التبريد"}],"e":{"en":"The first cooling stage requires reaching 70°F within 2 hours; food that fails this step must be discarded because it cannot be safely completed.","es":"La primera etapa de enfriamiento requiere alcanzar 70°F en 2 horas; los alimentos que fallan este paso deben desecharse porque no pueden completarse de forma segura.","ru":"Первый этап охлаждения требует достижения 70°F в течение 2 часов; продукт, не прошедший этот этап, нужно выбросить, так как безопасно завершить охлаждение нельзя.","tr":"İlk soğutma aşaması 2 saat içinde 70°F'ye ulaşmayı gerektirir; bu adımda başarısız olan gıda güvenli şekilde tamamlanamayacağı için atılmalıdır.","hi":"पहले ठंडा करने के चरण में 2 घंटे में 70°F तक पहुंचना आवश्यक है; जो भोजन इस चरण में विफल होता है उसे फेंक देना चाहिए क्योंकि इसे सुरक्षित रूप से पूरा नहीं किया जा सकता।","ar":"تتطلب مرحلة التبريد الأولى الوصول إلى 70°F خلال ساعتين؛ الطعام الذي يفشل في هذه الخطوة يجب التخلص منه لأنه لا يمكن إكماله بأمان."}},{"cat":"flow","a":1,"q":{"en":"A large batch of gravy finishes cooking at 2:00 PM and cooling begins immediately. By what time must it reach 41°F if cooling proceeds correctly?","es":"Un gran lote de salsa termina de cocinarse a las 2:00 PM y el enfriamiento comienza de inmediato. ¿A qué hora debe alcanzar 41°F si el enfriamiento se realiza correctamente?","ru":"Большая партия соуса заканчивает готовиться в 14:00, и охлаждение начинается сразу. К какому времени она должна достичь 41°F при правильном охлаждении?","tr":"Büyük bir sos partisi 14:00'te pişmeyi bitirir ve soğutma hemen başlar. Soğutma doğru yapılırsa 41°F'ye en geç saat kaçta ulaşmalıdır?","hi":"ग्रेवी का एक बड़ा बैच दोपहर 2:00 बजे पकना समाप्त करता है और ठंडा करना तुरंत शुरू होता है। यदि ठंडा करना सही ढंग से होता है तो इसे किस समय तक 41°F तक पहुंचना चाहिए?","ar":"دفعة كبيرة من المرق تنتهي من الطهي عند الساعة 2:00 ظهرًا ويبدأ التبريد فورًا. في أي وقت يجب أن تصل إلى 41°F إذا تم التبريد بشكل صحيح؟"},"o":[{"en":"By 4:00 PM (2 hours total)","es":"A las 4:00 PM (2 horas en total)","ru":"К 16:00 (всего 2 часа)","tr":"En geç 16:00 (toplam 2 saat)","hi":"शाम 4:00 बजे तक (कुल 2 घंटे)","ar":"بحلول 4:00 عصرًا (ساعتان إجمالًا)"},{"en":"By 8:00 PM (6 hours total)","es":"A las 8:00 PM (6 horas en total)","ru":"К 20:00 (всего 6 часов)","tr":"En geç 20:00 (toplam 6 saat)","hi":"रात 8:00 बजे तक (कुल 6 घंटे)","ar":"بحلول 8:00 مساءً (6 ساعات إجمالًا)"},{"en":"By 10:00 PM (8 hours total)","es":"A las 10:00 PM (8 horas en total)","ru":"К 22:00 (всего 8 часов)","tr":"En geç 22:00 (toplam 8 saat)","hi":"रात 10:00 बजे तक (कुल 8 घंटे)","ar":"بحلول 10:00 مساءً (8 ساعات إجمالًا)"},{"en":"By 6:00 PM (4 hours total)","es":"A las 6:00 PM (4 horas en total)","ru":"К 18:00 (всего 4 часа)","tr":"En geç 18:00 (toplam 4 saat)","hi":"शाम 6:00 बजे तक (कुल 4 घंटे)","ar":"بحلول 6:00 مساءً (4 ساعات إجمالًا)"}],"e":{"en":"Cooling allows a total of 6 hours (135°F to 70°F within 2 hours, then 70°F to 41°F within 4 more), so gravy starting at 2:00 PM must reach 41°F by 8:00 PM.","es":"El enfriamiento permite un total de 6 horas (de 135°F a 70°F en 2 horas, luego de 70°F a 41°F en 4 más), por lo que la salsa que comienza a las 2:00 PM debe alcanzar 41°F para las 8:00 PM.","ru":"Охлаждение допускает в общей сложности 6 часов (со 135°F до 70°F за 2 часа, затем с 70°F до 41°F ещё за 4), поэтому соус, начатый в 14:00, должен достичь 41°F к 20:00.","tr":"Soğutma toplam 6 saate izin verir (2 saatte 135°F'den 70°F'ye, sonra 4 saatte 70°F'den 41°F'ye), bu nedenle 14:00'te başlayan sos en geç 20:00'de 41°F'ye ulaşmalıdır.","hi":"ठंडा करने में कुल 6 घंटे की अनुमति है (2 घंटे में 135°F से 70°F, फिर 4 घंटे में 70°F से 41°F), इसलिए दोपहर 2:00 बजे शुरू होने वाली ग्रेवी को रात 8:00 बजे तक 41°F तक पहुंचना चाहिए।","ar":"يسمح التبريد بإجمالي 6 ساعات (من 135°F إلى 70°F خلال ساعتين، ثم من 70°F إلى 41°F خلال 4 ساعات)، لذا يجب أن يصل المرق الذي يبدأ عند 2:00 ظهرًا إلى 41°F بحلول 8:00 مساءً."}},{"cat":"flow","a":3,"q":{"en":"Leftover cooked chili made in-house will be reheated for hot holding. To what temperature and within what time must it be reheated?","es":"Chili cocido sobrante hecho en casa se recalentará para mantenimiento en caliente. ¿A qué temperatura y en qué tiempo debe recalentarse?","ru":"Оставшийся приготовленный чили, сделанный на месте, будет разогрет для горячего хранения. До какой температуры и за какое время его нужно разогреть?","tr":"Evde yapılan artan pişmiş chili, sıcak muhafaza için yeniden ısıtılacak. Hangi sıcaklığa ve hangi süre içinde yeniden ısıtılmalıdır?","hi":"घर में बना बचा हुआ पका हुआ चिली हॉट होल्डिंग के लिए फिर से गर्म किया जाएगा। इसे किस तापमान और किस समय के भीतर फिर से गर्म किया जाना चाहिए?","ar":"سيُعاد تسخين الفلفل الحار المطبوخ المتبقي المُعدّ داخليًا للحفظ الساخن. إلى أي درجة حرارة وخلال أي وقت يجب إعادة تسخينه؟"},"o":[{"en":"135°F within 4 hours","es":"135°F en 4 horas","ru":"135°F в течение 4 часов","tr":"4 saat içinde 135°F","hi":"4 घंटे में 135°F","ar":"135°F خلال 4 ساعات"},{"en":"145°F within 2 hours","es":"145°F en 2 horas","ru":"145°F в течение 2 часов","tr":"2 saat içinde 145°F","hi":"2 घंटे में 145°F","ar":"145°F خلال ساعتين"},{"en":"155°F within 1 hour","es":"155°F en 1 hora","ru":"155°F в течение 1 часа","tr":"1 saat içinde 155°F","hi":"1 घंटे में 155°F","ar":"155°F خلال ساعة واحدة"},{"en":"165°F for 15 seconds within 2 hours","es":"165°F durante 15 segundos en 2 horas","ru":"165°F в течение 15 секунд за 2 часа","tr":"2 saat içinde 15 saniye boyunca 165°F","hi":"2 घंटे में 15 सेकंड के लिए 165°F","ar":"165°F لمدة 15 ثانية خلال ساعتين"}],"e":{"en":"TCS food reheated for hot holding must reach 165°F for 15 seconds within 2 hours to limit time in the danger zone.","es":"Los alimentos TCS recalentados para mantenimiento en caliente deben alcanzar 165°F durante 15 segundos en 2 horas para limitar el tiempo en la zona de peligro.","ru":"Продукт TCS, разогреваемый для горячего хранения, должен достичь 165°F в течение 15 секунд за 2 часа, чтобы ограничить время в опасной зоне.","tr":"Sıcak muhafaza için yeniden ısıtılan TCS gıda, tehlike bölgesindeki süreyi sınırlamak için 2 saat içinde 15 saniye boyunca 165°F'ye ulaşmalıdır.","hi":"हॉट होल्डिंग के लिए फिर से गर्म किया गया TCS भोजन खतरे के क्षेत्र में समय सीमित करने के लिए 2 घंटे में 15 सेकंड के लिए 165°F तक पहुंचना चाहिए।","ar":"يجب أن يصل طعام TCS المُعاد تسخينه للحفظ الساخن إلى 165°F لمدة 15 ثانية خلال ساعتين للحد من الوقت في منطقة الخطر."}},{"cat":"flow","a":0,"q":{"en":"A manager is deciding reheat targets. A sealed, commercially processed nacho cheese pouch will be opened and heated only for hot holding. What minimum temperature applies to it?","es":"Un gerente está decidiendo las temperaturas de recalentamiento. Una bolsa de queso nacho sellada, procesada comercialmente, se abrirá y calentará solo para mantenimiento en caliente. ¿Qué temperatura mínima aplica?","ru":"Менеджер определяет целевые температуры разогрева. Запечатанный пакет сырного соуса начос промышленного производства откроют и нагреют только для горячего хранения. Какая минимальная температура к нему применяется?","tr":"Bir yönetici yeniden ısıtma hedeflerini belirliyor. Mühürlü, ticari olarak işlenmiş bir nacho peyniri poşeti açılıp yalnızca sıcak muhafaza için ısıtılacak. Ona hangi minimum sıcaklık uygulanır?","hi":"एक प्रबंधक पुनः गर्म करने के लक्ष्य तय कर रहा है। एक सीलबंद, व्यावसायिक रूप से संसाधित नाचो पनीर पाउच खोला जाएगा और केवल हॉट होल्डिंग के लिए गर्म किया जाएगा। इस पर कौन सा न्यूनतम तापमान लागू होता है?","ar":"يقرر مدير أهداف إعادة التسخين. سيتم فتح كيس جبن ناتشو مُصنّع تجاريًا ومُحكم الإغلاق وتسخينه فقط للحفظ الساخن. ما درجة الحرارة الدنيا المطبّقة عليه؟"},"o":[{"en":"135°F","es":"135°F","ru":"135°F","tr":"135°F","hi":"135°F","ar":"135°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"}],"e":{"en":"Because it was already fully cooked and hermetically sealed by the manufacturer, a commercially processed RTE food only needs to reach 135°F when reheated for hot holding.","es":"Como ya fue completamente cocido y sellado herméticamente por el fabricante, un alimento RTE procesado comercialmente solo necesita alcanzar 135°F al recalentarse para mantenimiento en caliente.","ru":"Поскольку он уже полностью приготовлен и герметично упакован производителем, готовый к употреблению продукт промышленного производства при разогреве для горячего хранения должен достичь только 135°F.","tr":"Üretici tarafından zaten tam olarak pişirilip hava geçirmez şekilde mühürlendiği için, ticari olarak işlenmiş yemeye hazır bir gıda sıcak muhafaza için yeniden ısıtıldığında yalnızca 135°F'ye ulaşması gerekir.","hi":"चूंकि इसे निर्माता द्वारा पहले ही पूरी तरह पकाया और वायुरोधी सील किया गया था, व्यावसायिक रूप से संसाधित RTE भोजन को हॉट होल्डिंग के लिए फिर से गर्म करते समय केवल 135°F तक पहुंचने की आवश्यकता है।","ar":"لأنه طُهي بالكامل وأُحكم إغلاقه من قبل الشركة المصنّعة، فإن طعام RTE المُصنّع تجاريًا يحتاج فقط إلى الوصول إلى 135°F عند إعادة تسخينه للحفظ الساخن."}},{"cat":"flow","a":2,"q":{"en":"At a 4-hour check, cold-held potato salad on a buffet reads 44°F but records show it started at 40°F. What is the best corrective action?","es":"En una verificación de 4 horas, la ensalada de papa mantenida en frío en un buffet marca 44°F pero los registros muestran que comenzó a 40°F. ¿Cuál es la mejor acción correctiva?","ru":"При проверке через 4 часа охлаждённый картофельный салат на шведском столе показывает 44°F, но записи показывают, что он начался при 40°F. Каково лучшее корректирующее действие?","tr":"4 saatlik kontrolde, açık büfedeki soğuk tutulan patates salatası 44°F gösteriyor ama kayıtlar 40°F'de başladığını gösteriyor. En iyi düzeltici işlem nedir?","hi":"4 घंटे की जांच में, बुफे पर ठंडा रखा आलू सलाद 44°F पढ़ता है लेकिन रिकॉर्ड दिखाते हैं कि यह 40°F पर शुरू हुआ था। सबसे अच्छी सुधारात्मक कार्रवाई क्या है?","ar":"عند فحص بعد 4 ساعات، سلطة البطاطس المحفوظة باردة على البوفيه تُظهر 44°F لكن السجلات تُظهر أنها بدأت عند 40°F. ما أفضل إجراء تصحيحي؟"},"o":[{"en":"Immediately discard the entire batch","es":"Desechar inmediatamente todo el lote","ru":"Немедленно выбросить всю партию","tr":"Tüm partiyi hemen atmak","hi":"तुरंत पूरे बैच को फेंक दें","ar":"التخلص فورًا من الدفعة بأكملها"},{"en":"Leave it out and re-check in another 4 hours","es":"Dejarla afuera y volver a verificar en otras 4 horas","ru":"Оставить и перепроверить ещё через 4 часа","tr":"Dışarıda bırakıp 4 saat sonra tekrar kontrol etmek","hi":"इसे बाहर छोड़ दें और अन्य 4 घंटों में फिर से जांचें","ar":"تركها وإعادة الفحص بعد 4 ساعات أخرى"},{"en":"Cool it back to 41°F or below since it is only slightly out of range at an intermediate check","es":"Enfriarla nuevamente a 41°F o menos ya que solo está ligeramente fuera de rango en una verificación intermedia","ru":"Охладить обратно до 41°F или ниже, так как при промежуточной проверке она лишь незначительно вне диапазона","tr":"Ara kontrolde yalnızca hafifçe aralık dışında olduğu için 41°F veya altına geri soğutmak","hi":"इसे वापस 41°F या उससे कम पर ठंडा करें क्योंकि यह मध्यवर्ती जांच में केवल थोड़ा सीमा से बाहर है","ar":"إعادة تبريدها إلى 41°F أو أقل لأنها خارج النطاق قليلًا فقط في فحص وسيط"},{"en":"Move it to hot holding at 135°F","es":"Moverla a mantenimiento en caliente a 135°F","ru":"Переместить в горячее хранение при 135°F","tr":"135°F'de sıcak muhafazaya taşımak","hi":"इसे 135°F पर हॉट होल्डिंग में ले जाएं","ar":"نقلها إلى الحفظ الساخن عند 135°F"}],"e":{"en":"At an intermediate check, food slightly above 41°F can be cooled back to 41°F or below; discarding is only required when the limit is exceeded at the end of the holding period or by a large margin.","es":"En una verificación intermedia, los alimentos ligeramente por encima de 41°F pueden enfriarse de nuevo a 41°F o menos; solo se requiere desechar cuando se excede el límite al final del período de mantenimiento o por un margen grande.","ru":"При промежуточной проверке продукт немного выше 41°F можно охладить обратно до 41°F или ниже; выбрасывать нужно только если предел превышен в конце периода хранения или на большую величину.","tr":"Ara kontrolde 41°F'nin biraz üzerindeki gıda 41°F veya altına geri soğutulabilir; atma yalnızca muhafaza süresi sonunda veya büyük bir farkla sınır aşıldığında gerekir.","hi":"मध्यवर्ती जांच में, 41°F से थोड़ा ऊपर भोजन को वापस 41°F या उससे कम पर ठंडा किया जा सकता है; फेंकना केवल तब आवश्यक है जब होल्डिंग अवधि के अंत में या बड़े अंतर से सीमा पार हो जाए।","ar":"في الفحص الوسيط، يمكن إعادة تبريد الطعام الأعلى قليلًا من 41°F إلى 41°F أو أقل؛ التخلص مطلوب فقط عند تجاوز الحد في نهاية فترة الحفظ أو بفارق كبير."}},{"cat":"flow","a":1,"q":{"en":"To catch a hot-holding failure before food must be thrown out, at what maximum interval should staff record hot-held TCS food temperatures?","es":"Para detectar una falla de mantenimiento en caliente antes de tener que desechar los alimentos, ¿en qué intervalo máximo debe el personal registrar las temperaturas de los alimentos TCS mantenidos en caliente?","ru":"Чтобы обнаружить сбой горячего хранения до того, как продукт придётся выбросить, с каким максимальным интервалом персонал должен фиксировать температуру продуктов TCS горячего хранения?","tr":"Gıda atılmadan önce bir sıcak muhafaza arızasını yakalamak için, personel sıcak tutulan TCS gıda sıcaklıklarını en fazla hangi aralıkta kaydetmelidir?","hi":"भोजन को फेंकने से पहले हॉट-होल्डिंग विफलता को पकड़ने के लिए, कर्मचारियों को गर्म रखे गए TCS भोजन के तापमान को किस अधिकतम अंतराल पर दर्ज करना चाहिए?","ar":"لاكتشاف فشل الحفظ الساخن قبل أن يتعيّن التخلص من الطعام، ما أقصى فترة يجب أن يسجّل فيها الموظفون درجات حرارة طعام TCS المحفوظ ساخنًا؟"},"o":[{"en":"Once per shift is sufficient","es":"Una vez por turno es suficiente","ru":"Достаточно одного раза за смену","tr":"Vardiya başına bir kez yeterlidir","hi":"प्रति शिफ्ट एक बार पर्याप्त है","ar":"مرة واحدة لكل مناوبة كافية"},{"en":"At least every 4 hours","es":"Al menos cada 4 horas","ru":"Не реже чем каждые 4 часа","tr":"En az her 4 saatte bir","hi":"कम से कम हर 4 घंटे में","ar":"على الأقل كل 4 ساعات"},{"en":"Every 12 hours","es":"Cada 12 horas","ru":"Каждые 12 часов","tr":"Her 12 saatte bir","hi":"हर 12 घंटे में","ar":"كل 12 ساعة"},{"en":"Only at closing","es":"Solo al cerrar","ru":"Только при закрытии","tr":"Yalnızca kapanışta","hi":"केवल बंद करते समय","ar":"فقط عند الإغلاق"}],"e":{"en":"Recording temperatures at least every 4 hours lets a manager take corrective action (reheat or discard) before the food has been unsafe for too long.","es":"Registrar las temperaturas al menos cada 4 horas permite al gerente tomar medidas correctivas (recalentar o desechar) antes de que el alimento haya sido inseguro por demasiado tiempo.","ru":"Фиксация температуры не реже чем каждые 4 часа позволяет менеджеру принять корректирующие меры (разогреть или выбросить) до того, как продукт слишком долго был небезопасным.","tr":"Sıcaklıkları en az her 4 saatte bir kaydetmek, yöneticinin gıda çok uzun süre güvensiz kalmadan önce düzeltici işlem (yeniden ısıtma veya atma) yapmasına olanak tanır.","hi":"कम से कम हर 4 घंटे में तापमान दर्ज करने से प्रबंधक भोजन के बहुत लंबे समय तक असुरक्षित रहने से पहले सुधारात्मक कार्रवाई (फिर से गर्म करना या फेंकना) कर सकता है।","ar":"تسجيل درجات الحرارة على الأقل كل 4 ساعات يتيح للمدير اتخاذ إجراء تصحيحي (إعادة تسخين أو تخلص) قبل أن يبقى الطعام غير آمن لفترة طويلة."}},{"cat":"flow","a":3,"q":{"en":"Mozzarella sticks are removed from refrigeration at 41°F and held on the line using time as a public health control with no temperature monitoring. When must they be discarded?","es":"Los palitos de mozzarella se sacan de refrigeración a 41°F y se mantienen en la línea usando el tiempo como control de salud pública sin monitoreo de temperatura. ¿Cuándo deben desecharse?","ru":"Палочки моцареллы вынимают из холодильника при 41°F и держат на линии, используя время как метод общественного здравоохранения без контроля температуры. Когда их нужно выбросить?","tr":"Mozzarella çubukları 41°F'de buzdolabından çıkarılıp sıcaklık takibi olmadan zamanı halk sağlığı kontrolü olarak kullanarak hatta tutuluyor. Ne zaman atılmalıdır?","hi":"मोज़ेरेला स्टिक्स को 41°F पर रेफ्रिजरेशन से निकाला जाता है और तापमान निगरानी के बिना समय को सार्वजनिक स्वास्थ्य नियंत्रण के रूप में उपयोग करके लाइन पर रखा जाता है। इन्हें कब फेंकना चाहिए?","ar":"تُخرج أصابع الموزاريلا من التبريد عند 41°F وتُحفظ على الخط باستخدام الوقت كضابط للصحة العامة دون مراقبة الحرارة. متى يجب التخلص منها؟"},"o":[{"en":"After 8 hours","es":"Después de 8 horas","ru":"Через 8 часов","tr":"8 saat sonra","hi":"8 घंटे बाद","ar":"بعد 8 ساعات"},{"en":"After 6 hours","es":"Después de 6 horas","ru":"Через 6 часов","tr":"6 saat sonra","hi":"6 घंटे बाद","ar":"بعد 6 ساعات"},{"en":"At the end of the shift","es":"Al final del turno","ru":"В конце смены","tr":"Vardiya sonunda","hi":"शिफ्ट के अंत में","ar":"في نهاية المناوبة"},{"en":"After 4 hours","es":"Después de 4 horas","ru":"Через 4 часа","tr":"4 saat sonra","hi":"4 घंटे बाद","ar":"بعد 4 ساعات"}],"e":{"en":"Under the 4-hour time control rule, TCS food removed from temperature control must be sold, served, or discarded within 4 hours; it cannot be returned to storage.","es":"Bajo la regla de control de tiempo de 4 horas, los alimentos TCS retirados del control de temperatura deben venderse, servirse o desecharse dentro de 4 horas; no pueden devolverse al almacenamiento.","ru":"По правилу 4-часового контроля времени продукт TCS, снятый с температурного контроля, должен быть продан, подан или выброшен в течение 4 часов; его нельзя вернуть на хранение.","tr":"4 saatlik zaman kontrolü kuralına göre, sıcaklık kontrolünden çıkarılan TCS gıda 4 saat içinde satılmalı, servis edilmeli veya atılmalıdır; depoya geri konamaz.","hi":"4-घंटे समय नियंत्रण नियम के तहत, तापमान नियंत्रण से हटाए गए TCS भोजन को 4 घंटे के भीतर बेचा, परोसा या फेंका जाना चाहिए; इसे भंडारण में वापस नहीं किया जा सकता।","ar":"بموجب قاعدة ضبط الوقت 4 ساعات، يجب بيع أو تقديم أو التخلص من طعام TCS المُخرج من ضبط الحرارة خلال 4 ساعات؛ ولا يمكن إعادته إلى التخزين."}},{"cat":"flow","a":0,"q":{"en":"Cut leafy greens start at 41°F and are held using time as a public health control under the 6-hour rule. What condition must be met for the full 6 hours to apply?","es":"Las verduras de hoja cortadas comienzan a 41°F y se mantienen usando el tiempo como control de salud pública bajo la regla de 6 horas. ¿Qué condición debe cumplirse para que apliquen las 6 horas completas?","ru":"Нарезанная листовая зелень начинается при 41°F и держится с использованием времени как метода общественного здравоохранения по правилу 6 часов. Какое условие должно выполняться, чтобы применялись все 6 часов?","tr":"Doğranmış yeşil yapraklılar 41°F'de başlar ve 6 saat kuralı kapsamında zamanı halk sağlığı kontrolü olarak kullanarak tutulur. Tam 6 saatin geçerli olması için hangi koşul sağlanmalıdır?","hi":"कटी पत्तेदार सब्जियां 41°F पर शुरू होती हैं और 6-घंटे नियम के तहत समय को सार्वजनिक स्वास्थ्य नियंत्रण के रूप में उपयोग करके रखी जाती हैं। पूरे 6 घंटे लागू होने के लिए कौन सी शर्त पूरी होनी चाहिए?","ar":"تبدأ الخضروات الورقية المقطّعة عند 41°F وتُحفظ باستخدام الوقت كضابط للصحة العامة بموجب قاعدة الـ 6 ساعات. ما الشرط الذي يجب توفّره لتطبيق الـ 6 ساعات كاملة؟"},"o":[{"en":"The food must stay at or below 70°F throughout the 6 hours","es":"El alimento debe permanecer a 70°F o menos durante las 6 horas","ru":"Продукт должен оставаться при 70°F или ниже в течение всех 6 часов","tr":"Gıda 6 saat boyunca 70°F veya altında kalmalıdır","hi":"भोजन को 6 घंटे तक 70°F या उससे कम पर रहना चाहिए","ar":"يجب أن يبقى الطعام عند 70°F أو أقل طوال الـ 6 ساعات"},{"en":"The food must be reheated to 165°F halfway through","es":"El alimento debe recalentarse a 165°F a la mitad","ru":"Продукт нужно разогреть до 165°F в середине","tr":"Gıda yarısında 165°F'ye yeniden ısıtılmalıdır","hi":"भोजन को बीच में 165°F तक फिर से गर्म करना चाहिए","ar":"يجب إعادة تسخين الطعام إلى 165°F في المنتصف"},{"en":"The food must be kept above 135°F","es":"El alimento debe mantenerse por encima de 135°F","ru":"Продукт нужно держать выше 135°F","tr":"Gıda 135°F'nin üzerinde tutulmalıdır","hi":"भोजन को 135°F से ऊपर रखा जाना चाहिए","ar":"يجب حفظ الطعام فوق 135°F"},{"en":"The food must be monitored with a thermometer every hour","es":"El alimento debe monitorearse con un termómetro cada hora","ru":"Продукт нужно контролировать термометром каждый час","tr":"Gıda her saat termometreyle izlenmelidir","hi":"भोजन को हर घंटे थर्मामीटर से निगरानी करनी चाहिए","ar":"يجب مراقبة الطعام بميزان حرارة كل ساعة"}],"e":{"en":"The 6-hour cold TPHC option requires the food to begin at 41°F and remain at or below 70°F throughout; if it exceeds 70°F it must be discarded.","es":"La opción de TPHC en frío de 6 horas requiere que el alimento comience a 41°F y permanezca a 70°F o menos durante todo el tiempo; si supera 70°F debe desecharse.","ru":"Вариант холодного TPHC на 6 часов требует, чтобы продукт начинался при 41°F и оставался при 70°F или ниже всё время; если он превысит 70°F, его нужно выбросить.","tr":"6 saatlik soğuk TPHC seçeneği, gıdanın 41°F'de başlamasını ve boyunca 70°F veya altında kalmasını gerektirir; 70°F'yi aşarsa atılmalıdır.","hi":"6-घंटे ठंडा TPHC विकल्प के लिए आवश्यक है कि भोजन 41°F पर शुरू हो और पूरे समय 70°F या उससे कम पर रहे; यदि यह 70°F से अधिक हो जाता है तो इसे फेंकना चाहिए।","ar":"يتطلب خيار TPHC البارد لمدة 6 ساعات أن يبدأ الطعام عند 41°F ويبقى عند 70°F أو أقل طوال الوقت؛ إذا تجاوز 70°F يجب التخلص منه."}},{"cat":"flow","a":2,"q":{"en":"During service, how should a food handler assemble a ready-to-eat sandwich to comply with the Food Code?","es":"Durante el servicio, ¿cómo debe un manipulador de alimentos armar un sándwich listo para comer para cumplir con el Código de Alimentos?","ru":"Во время обслуживания, как работник должен собирать готовый к употреблению сэндвич, чтобы соблюдать Пищевой кодекс?","tr":"Servis sırasında, bir gıda çalışanı Gıda Kanunu'na uymak için yemeye hazır bir sandviçi nasıl hazırlamalıdır?","hi":"सेवा के दौरान, फूड कोड का पालन करने के लिए एक फूड हैंडलर को खाने के लिए तैयार सैंडविच कैसे बनाना चाहिए?","ar":"أثناء الخدمة، كيف يجب أن يُعدّ عامل الطعام شطيرة جاهزة للأكل للالتزام بقانون الغذاء؟"},"o":[{"en":"With clean bare hands since they were just washed","es":"Con las manos limpias y desnudas ya que se acaban de lavar","ru":"Чистыми голыми руками, так как их только что помыли","tr":"Yeni yıkandıkları için temiz çıplak ellerle","hi":"साफ नंगे हाथों से क्योंकि उन्हें अभी धोया गया था","ar":"بأيدٍ عارية نظيفة لأنها غُسلت للتو"},{"en":"By breathing on utensils to warm them first","es":"Soplando en los utensilios para calentarlos primero","ru":"Подышав на посуду, чтобы сначала её согреть","tr":"Önce ısıtmak için mutfak aletlerine üfleyerek","hi":"पहले उन्हें गर्म करने के लिए बर्तनों पर सांस लेकर","ar":"بالنفخ على الأدوات لتدفئتها أولًا"},{"en":"Using gloves, tongs, deli tissue, or other utensils to avoid bare-hand contact","es":"Usando guantes, pinzas, papel de deli u otros utensilios para evitar el contacto con las manos","ru":"Используя перчатки, щипцы, деликатесную бумагу или другую посуду, чтобы избежать контакта голыми руками","tr":"Çıplak el temasından kaçınmak için eldiven, maşa, jambon kağıdı veya başka aletler kullanarak","hi":"नंगे हाथ के संपर्क से बचने के लिए दस्ताने, चिमटे, डेली टिशू या अन्य बर्तनों का उपयोग करके","ar":"باستخدام قفازات أو ملقط أو ورق تقديم أو أدوات أخرى لتجنّب ملامسة اليد العارية"},{"en":"With bare hands as long as gloves are worn afterward","es":"Con las manos desnudas siempre que se usen guantes después","ru":"Голыми руками, если перчатки надеваются потом","tr":"Sonrasında eldiven giyilmesi şartıyla çıplak ellerle","hi":"नंगे हाथों से जब तक बाद में दस्ताने पहने जाएं","ar":"بأيدٍ عارية طالما تُرتدى القفازات بعد ذلك"}],"e":{"en":"The Food Code prohibits bare-hand contact with ready-to-eat food; handlers must use gloves, tongs, deli tissue, or other utensils.","es":"El Código de Alimentos prohíbe el contacto con las manos desnudas con alimentos listos para comer; los manipuladores deben usar guantes, pinzas, papel de deli u otros utensilios.","ru":"Пищевой кодекс запрещает контакт голыми руками с готовыми к употреблению продуктами; работники должны использовать перчатки, щипцы, деликатесную бумагу или другую посуду.","tr":"Gıda Kanunu, yemeye hazır gıdaya çıplak elle teması yasaklar; çalışanlar eldiven, maşa, jambon kağıdı veya başka aletler kullanmalıdır.","hi":"फूड कोड खाने के लिए तैयार भोजन के साथ नंगे हाथ के संपर्क को प्रतिबंधित करता है; हैंडलर्स को दस्ताने, चिमटे, डेली टिशू या अन्य बर्तनों का उपयोग करना चाहिए।","ar":"يحظر قانون الغذاء ملامسة اليد العارية للطعام الجاهز للأكل؛ يجب على العاملين استخدام قفازات أو ملقط أو ورق تقديم أو أدوات أخرى."}},{"cat":"flow","a":1,"q":{"en":"On a self-service salad bar, how should serving utensils be positioned?","es":"En una barra de ensaladas de autoservicio, ¿cómo deben colocarse los utensilios de servicio?","ru":"На салат-баре самообслуживания, как следует размещать сервировочную посуду?","tr":"Self servis salata barında servis aletleri nasıl konumlandırılmalıdır?","hi":"स्वयं-सेवा सलाद बार पर, परोसने वाले बर्तनों को कैसे रखा जाना चाहिए?","ar":"في بار السلطة ذاتي الخدمة، كيف يجب وضع أدوات التقديم؟"},"o":[{"en":"Buried inside the food so they stay cold","es":"Enterrados dentro de la comida para que se mantengan fríos","ru":"Погружёнными внутрь еды, чтобы оставались холодными","tr":"Soğuk kalmaları için yiyeceğin içine gömülü","hi":"भोजन के अंदर दबे हुए ताकि वे ठंडे रहें","ar":"مدفونة داخل الطعام لتبقى باردة"},{"en":"With handles extending up and out of the food so hands do not touch the food","es":"Con los mangos hacia arriba y fuera de la comida para que las manos no toquen los alimentos","ru":"С ручками, торчащими вверх и наружу из еды, чтобы руки не касались продукта","tr":"Ellerin yiyeceğe değmemesi için sapları yukarı ve yiyeceğin dışına doğru","hi":"हैंडल भोजन से ऊपर और बाहर की ओर ताकि हाथ भोजन को न छुएं","ar":"بمقابض ممتدة لأعلى وخارج الطعام حتى لا تلمس الأيدي الطعام"},{"en":"Shared across multiple pans to save space","es":"Compartidos entre varias bandejas para ahorrar espacio","ru":"Общими для нескольких лотков, чтобы сэкономить место","tr":"Yer kazanmak için birden fazla kap arasında paylaşılmış","hi":"जगह बचाने के लिए कई पैन में साझा किए गए","ar":"مشتركة بين عدة صواني لتوفير المساحة"},{"en":"Removed entirely so guests use their hands","es":"Retirados por completo para que los invitados usen las manos","ru":"Полностью убранными, чтобы гости пользовались руками","tr":"Misafirlerin ellerini kullanması için tamamen kaldırılmış","hi":"पूरी तरह से हटा दिए गए ताकि मेहमान अपने हाथों का उपयोग करें","ar":"مُزالة تمامًا ليستخدم الضيوف أيديهم"}],"e":{"en":"Serving utensils should be stored with handles up and out of the food, and a separate utensil is used for each dish to prevent contamination.","es":"Los utensilios de servicio deben almacenarse con los mangos hacia arriba y fuera de la comida, y se usa un utensilio separado para cada plato para evitar la contaminación.","ru":"Сервировочную посуду следует хранить ручками вверх и наружу из еды, и для каждого блюда используется отдельный прибор для предотвращения загрязнения.","tr":"Servis aletleri sapları yukarı ve yiyeceğin dışında olacak şekilde saklanmalı ve kirlenmeyi önlemek için her yemek için ayrı bir alet kullanılmalıdır.","hi":"परोसने वाले बर्तनों को हैंडल ऊपर और भोजन से बाहर की ओर रखा जाना चाहिए, और दूषण रोकने के लिए प्रत्येक व्यंजन के लिए अलग बर्तन का उपयोग किया जाता है।","ar":"يجب تخزين أدوات التقديم بمقابض لأعلى وخارج الطعام، واستخدام أداة منفصلة لكل طبق لمنع التلوث."}},{"cat":"flow","a":3,"q":{"en":"A customer's table is being cleared. Which item may be re-served to another customer?","es":"Se está limpiando la mesa de un cliente. ¿Cuál artículo puede volver a servirse a otro cliente?","ru":"Стол клиента убирают. Какой предмет можно подать заново другому клиенту?","tr":"Bir müşterinin masası toplanıyor. Hangi ürün başka bir müşteriye tekrar servis edilebilir?","hi":"एक ग्राहक की मेज साफ की जा रही है। कौन सी वस्तु दूसरे ग्राहक को फिर से परोसी जा सकती है?","ar":"تُنظّف طاولة أحد الزبائن. أي صنف يمكن إعادة تقديمه لزبون آخر؟"},"o":[{"en":"A basket of bread rolls that were not touched","es":"Una canasta de panecillos que no fueron tocados","ru":"Корзина булочек, которых не касались","tr":"Dokunulmamış bir sepet ekmek","hi":"ब्रेड रोल की एक टोकरी जिन्हें छुआ नहीं गया","ar":"سلة من الخبز لم يُلمس"},{"en":"Opened but unused packets of jam","es":"Paquetes de mermelada abiertos pero sin usar","ru":"Открытые, но неиспользованные пакетики джема","tr":"Açılmış ama kullanılmamış reçel paketleri","hi":"खुले लेकिन अनुपयोगी जैम के पैकेट","ar":"أكياس مربى مفتوحة لكن غير مستخدمة"},{"en":"Garnishes left on a used plate","es":"Guarniciones dejadas en un plato usado","ru":"Гарнир, оставшийся на использованной тарелке","tr":"Kullanılmış tabakta kalan garnitürler","hi":"इस्तेमाल की गई प्लेट पर छोड़े गए गार्निश","ar":"زينة متروكة على طبق مستعمل"},{"en":"Unopened, prepackaged crackers still in their sealed wrapper","es":"Galletas preenvasadas sin abrir, todavía en su envoltorio sellado","ru":"Нераспечатанные, предварительно упакованные крекеры в запечатанной обёртке","tr":"Açılmamış, önceden paketlenmiş ve mühürlü ambalajındaki krakerler","hi":"बिना खोले, पहले से पैक किए गए क्रैकर्स अभी भी अपने सील किए गए रैपर में","ar":"بسكويت مُعبّأ مسبقًا غير مفتوح ولا يزال في غلافه المُحكم"}],"e":{"en":"Only unopened, prepackaged food in intact wrappers may be re-served; any food that was served on a plate, opened, or unwrapped must be discarded.","es":"Solo los alimentos preenvasados sin abrir en envoltorios intactos pueden volver a servirse; cualquier alimento que se sirvió en un plato, se abrió o se desenvolvió debe desecharse.","ru":"Заново можно подавать только нераспечатанные, предварительно упакованные продукты в целой обёртке; любую еду, которую подавали на тарелке, открывали или разворачивали, нужно выбросить.","tr":"Yalnızca açılmamış, sağlam ambalajlı önceden paketlenmiş gıda tekrar servis edilebilir; tabakta servis edilen, açılan veya ambalajı açılan gıda atılmalıdır.","hi":"केवल बिना खोले, बरकरार रैपर में पहले से पैक किए गए भोजन को फिर से परोसा जा सकता है; कोई भी भोजन जो प्लेट पर परोसा गया, खोला गया या खोला गया, उसे फेंक देना चाहिए।","ar":"يمكن إعادة تقديم الطعام المُعبّأ مسبقًا غير المفتوح فقط في أغلفة سليمة؛ أي طعام قُدّم على طبق أو فُتح أو أُزيل غلافه يجب التخلص منه."}},{"cat":"flow","a":0,"q":{"en":"When transporting hot TCS food for off-site catering, what is the primary requirement during delivery?","es":"Al transportar alimentos TCS calientes para catering fuera del lugar, ¿cuál es el requisito principal durante la entrega?","ru":"При транспортировке горячих продуктов TCS для выездного кейтеринга, каково основное требование во время доставки?","tr":"Dışarıda ikram için sıcak TCS gıda taşırken, teslimat sırasında birincil gereklilik nedir?","hi":"ऑफ-साइट कैटरिंग के लिए गर्म TCS भोजन ले जाते समय, डिलीवरी के दौरान प्राथमिक आवश्यकता क्या है?","ar":"عند نقل طعام TCS الساخن للتموين خارج الموقع، ما المتطلب الأساسي أثناء التوصيل؟"},"o":[{"en":"Keep hot food at 135°F or above using insulated, food-grade containers","es":"Mantener la comida caliente a 135°F o más usando recipientes aislados de grado alimenticio","ru":"Держать горячую еду при 135°F или выше, используя изолированные пищевые контейнеры","tr":"Sıcak yiyeceği yalıtımlı, gıdaya uygun kaplar kullanarak 135°F veya üzerinde tutmak","hi":"इंसुलेटेड, फूड-ग्रेड कंटेनरों का उपयोग करके गर्म भोजन को 135°F या उससे अधिक पर रखें","ar":"الحفاظ على الطعام الساخن عند 135°F أو أعلى باستخدام حاويات معزولة صالحة للطعام"},{"en":"Let the food cool during transport to save energy","es":"Dejar que la comida se enfríe durante el transporte para ahorrar energía","ru":"Дать еде остыть во время транспортировки для экономии энергии","tr":"Enerji tasarrufu için yiyeceğin taşıma sırasında soğumasına izin vermek","hi":"ऊर्जा बचाने के लिए परिवहन के दौरान भोजन को ठंडा होने दें","ar":"ترك الطعام يبرد أثناء النقل لتوفير الطاقة"},{"en":"Transport hot and cold foods together in one open container","es":"Transportar alimentos calientes y fríos juntos en un recipiente abierto","ru":"Перевозить горячую и холодную еду вместе в одном открытом контейнере","tr":"Sıcak ve soğuk yiyecekleri açık tek bir kapta birlikte taşımak","hi":"गर्म और ठंडे भोजन को एक खुले कंटेनर में एक साथ ले जाएं","ar":"نقل الأطعمة الساخنة والباردة معًا في حاوية مفتوحة واحدة"},{"en":"Hold hot food anywhere between 70°F and 135°F","es":"Mantener la comida caliente entre 70°F y 135°F","ru":"Держать горячую еду где-то между 70°F и 135°F","tr":"Sıcak yiyeceği 70°F ile 135°F arasında herhangi bir yerde tutmak","hi":"गर्म भोजन को 70°F और 135°F के बीच कहीं भी रखें","ar":"حفظ الطعام الساخن في أي مكان بين 70°F و135°F"}],"e":{"en":"During off-site transport, hot TCS food must be held at 135°F or above in insulated, food-grade containers to prevent it from entering the danger zone.","es":"Durante el transporte fuera del lugar, los alimentos TCS calientes deben mantenerse a 135°F o más en recipientes aislados de grado alimenticio para evitar que entren en la zona de peligro.","ru":"Во время выездной транспортировки горячие продукты TCS нужно держать при 135°F или выше в изолированных пищевых контейнерах, чтобы они не попали в опасную зону.","tr":"Dışarıya taşıma sırasında sıcak TCS gıda, tehlike bölgesine girmesini önlemek için yalıtımlı, gıdaya uygun kaplarda 135°F veya üzerinde tutulmalıdır.","hi":"ऑफ-साइट परिवहन के दौरान, गर्म TCS भोजन को खतरे के क्षेत्र में प्रवेश करने से रोकने के लिए इंसुलेटेड, फूड-ग्रेड कंटेनरों में 135°F या उससे अधिक पर रखा जाना चाहिए।","ar":"أثناء النقل خارج الموقع، يجب حفظ طعام TCS الساخن عند 135°F أو أعلى في حاويات معزولة صالحة للطعام لمنعه من دخول منطقة الخطر."}},{"cat":"flow","a":2,"q":{"en":"A large beef roast is being cooked. Under the Food Code, roasts may be cooked to a minimum internal temperature of:","es":"Se está cocinando un gran asado de res. Según el Código de Alimentos, los asados pueden cocinarse a una temperatura interna mínima de:","ru":"Готовится большой кусок говядины (ростбиф). Согласно Пищевому кодексу, ростбифы можно готовить до минимальной внутренней температуры:","tr":"Büyük bir dana rosto pişiriliyor. Gıda Kanunu'na göre rostolar minimum iç sıcaklık şu değere kadar pişirilebilir:","hi":"एक बड़ा गोमांस रोस्ट पकाया जा रहा है। फूड कोड के तहत, रोस्ट को न्यूनतम आंतरिक तापमान तक पकाया जा सकता है:","ar":"يُطهى قطعة لحم بقري كبيرة (روست). وفقًا لقانون الغذاء، يمكن طهي الروست إلى درجة حرارة داخلية دنيا قدرها:"},"o":[{"en":"165°F for 15 seconds","es":"165°F durante 15 segundos","ru":"165°F в течение 15 секунд","tr":"15 saniye boyunca 165°F","hi":"15 सेकंड के लिए 165°F","ar":"165°F لمدة 15 ثانية"},{"en":"155°F for 17 seconds","es":"155°F durante 17 segundos","ru":"155°F в течение 17 секунд","tr":"17 saniye boyunca 155°F","hi":"17 सेकंड के लिए 155°F","ar":"155°F لمدة 17 ثانية"},{"en":"145°F held for the required time based on a time-temperature table","es":"145°F mantenido durante el tiempo requerido según una tabla de tiempo-temperatura","ru":"145°F, выдержанные в течение требуемого времени согласно таблице время-температура","tr":"Zaman-sıcaklık tablosuna göre gereken süre boyunca tutulan 145°F","hi":"समय-तापमान तालिका के आधार पर आवश्यक समय के लिए रखा गया 145°F","ar":"145°F محفوظة للمدة المطلوبة وفق جدول الزمن-الحرارة"},{"en":"135°F with no holding time","es":"135°F sin tiempo de mantenimiento","ru":"135°F без времени выдержки","tr":"Bekletme süresi olmadan 135°F","hi":"बिना होल्डिंग समय के 135°F","ar":"135°F دون وقت حفظ"}],"e":{"en":"Whole-muscle roasts of beef, pork, and lamb may be cooked to 145°F if held for the appropriate time specified in the Food Code's time-temperature table.","es":"Los asados de músculo entero de res, cerdo y cordero pueden cocinarse a 145°F si se mantienen durante el tiempo apropiado especificado en la tabla de tiempo-temperatura del Código de Alimentos.","ru":"Цельномышечные ростбифы из говядины, свинины и баранины можно готовить до 145°F, если выдержать соответствующее время, указанное в таблице время-температура Пищевого кодекса.","tr":"Dana, domuz ve kuzunun bütün kas rostoları, Gıda Kanunu'nun zaman-sıcaklık tablosunda belirtilen uygun süre boyunca tutulursa 145°F'ye kadar pişirilebilir.","hi":"गोमांस, सूअर और भेड़ के साबुत-मांसपेशी रोस्ट को 145°F तक पकाया जा सकता है यदि फूड कोड की समय-तापमान तालिका में निर्दिष्ट उचित समय के लिए रखा जाए।","ar":"يمكن طهي روست العضلة الكاملة من البقر والخنزير والضأن إلى 145°F إذا حُفظت للمدة المناسبة المحددة في جدول الزمن-الحرارة في قانون الغذاء."}},{"cat":"flow","a":1,"q":{"en":"Which statement best describes purchasing food from an approved, reputable supplier?","es":"¿Cuál afirmación describe mejor la compra de alimentos de un proveedor aprobado y de buena reputación?","ru":"Какое утверждение лучше всего описывает закупку продуктов у одобренного, надёжного поставщика?","tr":"Hangi ifade, onaylı ve saygın bir tedarikçiden gıda satın almayı en iyi tanımlar?","hi":"कौन सा कथन एक अनुमोदित, प्रतिष्ठित आपूर्तिकर्ता से भोजन खरीदने का सबसे अच्छा वर्णन करता है?","ar":"أي عبارة تصف بشكل أفضل شراء الطعام من مورّد معتمد وموثوق؟"},"o":[{"en":"Any supplier is acceptable if the price is lowest","es":"Cualquier proveedor es aceptable si el precio es el más bajo","ru":"Любой поставщик приемлем, если цена самая низкая","tr":"Fiyat en düşükse herhangi bir tedarikçi kabul edilebilir","hi":"यदि कीमत सबसे कम है तो कोई भी आपूर्तिकर्ता स्वीकार्य है","ar":"أي مورّد مقبول إذا كان السعر هو الأدنى"},{"en":"The supplier is inspected and meets applicable local, state, and federal food safety laws","es":"El proveedor está inspeccionado y cumple con las leyes de seguridad alimentaria locales, estatales y federales aplicables","ru":"Поставщик проверяется и соответствует применимым местным, региональным и федеральным законам о безопасности пищевых продуктов","tr":"Tedarikçi denetlenir ve geçerli yerel, eyalet ve federal gıda güvenliği yasalarına uyar","hi":"आपूर्तिकर्ता का निरीक्षण किया जाता है और लागू स्थानीय, राज्य और संघीय खाद्य सुरक्षा कानूनों को पूरा करता है","ar":"المورّد مُفتّش ويلتزم بقوانين سلامة الغذاء المحلية والولائية والفيدرالية المعمول بها"},{"en":"Home-canned goods are preferred for freshness","es":"Los productos enlatados en casa se prefieren por su frescura","ru":"Домашние консервы предпочтительны из-за свежести","tr":"Ev konserveleri tazelik için tercih edilir","hi":"ताजगी के लिए घर में डिब्बाबंद सामान को प्राथमिकता दी जाती है","ar":"المعلبات المنزلية مفضّلة لنضارتها"},{"en":"Suppliers do not need inspection if food looks clean","es":"Los proveedores no necesitan inspección si la comida se ve limpia","ru":"Поставщикам не нужна проверка, если еда выглядит чистой","tr":"Yiyecek temiz görünüyorsa tedarikçilerin denetime ihtiyacı yoktur","hi":"यदि भोजन साफ दिखता है तो आपूर्तिकर्ताओं को निरीक्षण की आवश्यकता नहीं है","ar":"لا يحتاج المورّدون إلى تفتيش إذا بدا الطعام نظيفًا"}],"e":{"en":"Food must come from approved sources that are inspected and comply with applicable local, state, and federal food safety laws.","es":"Los alimentos deben provenir de fuentes aprobadas que están inspeccionadas y cumplen con las leyes de seguridad alimentaria locales, estatales y federales aplicables.","ru":"Продукты должны поступать из одобренных источников, которые проверяются и соответствуют применимым местным, региональным и федеральным законам о безопасности пищевых продуктов.","tr":"Gıda, denetlenen ve geçerli yerel, eyalet ve federal gıda güvenliği yasalarına uyan onaylı kaynaklardan gelmelidir.","hi":"भोजन अनुमोदित स्रोतों से आना चाहिए जिनका निरीक्षण किया जाता है और जो लागू स्थानीय, राज्य और संघीय खाद्य सुरक्षा कानूनों का पालन करते हैं।","ar":"يجب أن يأتي الطعام من مصادر معتمدة تخضع للتفتيش وتلتزم بقوانين سلامة الغذاء المحلية والولائية والفيدرالية المعمول بها."}},{"cat":"flow","a":3,"q":{"en":"A kitchen cooks mechanically tenderized (injected) beef steaks. What minimum internal temperature applies, unlike an intact whole cut?","es":"Una cocina cocina bistecs de res ablandados mecánicamente (inyectados). ¿Qué temperatura interna mínima aplica, a diferencia de un corte entero intacto?","ru":"На кухне готовят механически размягчённые (инъецированные) говяжьи стейки. Какая минимальная внутренняя температура применяется, в отличие от цельного нетронутого куска?","tr":"Bir mutfak mekanik olarak yumuşatılmış (enjekte edilmiş) dana bifteği pişiriyor. Sağlam bütün bir parçadan farklı olarak hangi minimum iç sıcaklık geçerlidir?","hi":"एक रसोई यांत्रिक रूप से नरम किए गए (इंजेक्टेड) गोमांस स्टेक पकाती है। एक बरकरार साबुत कट के विपरीत, कौन सा न्यूनतम आंतरिक तापमान लागू होता है?","ar":"يطهو مطبخ شرائح لحم بقري مطرّية ميكانيكيًا (محقونة). ما درجة الحرارة الداخلية الدنيا المطبّقة، بخلاف القطعة الكاملة السليمة؟"},"o":[{"en":"135°F for 15 seconds","es":"135°F durante 15 segundos","ru":"135°F в течение 15 секунд","tr":"15 saniye boyunca 135°F","hi":"15 सेकंड के लिए 135°F","ar":"135°F لمدة 15 ثانية"},{"en":"145°F for 15 seconds","es":"145°F durante 15 segundos","ru":"145°F в течение 15 секунд","tr":"15 saniye boyunca 145°F","hi":"15 सेकंड के लिए 145°F","ar":"145°F لمدة 15 ثانية"},{"en":"165°F for 15 seconds","es":"165°F durante 15 segundos","ru":"165°F в течение 15 секунд","tr":"15 saniye boyunca 165°F","hi":"15 सेकंड के लिए 165°F","ar":"165°F لمدة 15 ثانية"},{"en":"155°F because injecting can push surface bacteria into the interior","es":"155°F porque la inyección puede empujar bacterias de la superficie hacia el interior","ru":"155°F, потому что инъекция может занести поверхностные бактерии внутрь","tr":"155°F çünkü enjeksiyon yüzeydeki bakterileri iç kısma itebilir","hi":"155°F क्योंकि इंजेक्शन सतह के बैक्टीरिया को अंदर धकेल सकता है","ar":"155°F لأن الحقن قد يدفع بكتيريا السطح إلى الداخل"}],"e":{"en":"Mechanically tenderized or injected meats are treated like ground meat and must reach 155°F because the process can carry surface pathogens inside.","es":"Las carnes ablandadas mecánicamente o inyectadas se tratan como carne molida y deben alcanzar 155°F porque el proceso puede llevar patógenos de la superficie al interior.","ru":"Механически размягчённое или инъецированное мясо обрабатывается как фарш и должно достигать 155°F, потому что процесс может занести поверхностные патогены внутрь.","tr":"Mekanik olarak yumuşatılmış veya enjekte edilmiş etler kıyma gibi işlem görür ve 155°F'ye ulaşmalıdır çünkü işlem yüzeydeki patojenleri iç kısma taşıyabilir.","hi":"यांत्रिक रूप से नरम किए गए या इंजेक्टेड मांस को ग्राउंड मीट की तरह माना जाता है और 155°F तक पहुंचना चाहिए क्योंकि प्रक्रिया सतह के रोगजनकों को अंदर ले जा सकती है।","ar":"تُعامل اللحوم المطرّية ميكانيكيًا أو المحقونة مثل اللحم المفروم ويجب أن تصل إلى 155°F لأن العملية قد تنقل مسببات الأمراض من السطح إلى الداخل."}},{"cat":"flow","a":0,"q":{"en":"Cooked rice will be kept on a hot-holding line for service. What minimum internal cooking temperature applies to plant foods that will be hot-held?","es":"El arroz cocido se mantendrá en una línea de mantenimiento en caliente para el servicio. ¿Qué temperatura interna mínima de cocción aplica a los alimentos vegetales que se mantendrán calientes?","ru":"Приготовленный рис будет храниться на линии горячего хранения для подачи. Какая минимальная внутренняя температура приготовления применяется к растительным продуктам, которые будут храниться горячими?","tr":"Pişmiş pilav servis için sıcak muhafaza hattında tutulacak. Sıcak tutulacak bitkisel gıdalar için hangi minimum iç pişirme sıcaklığı geçerlidir?","hi":"पका हुआ चावल सेवा के लिए हॉट-होल्डिंग लाइन पर रखा जाएगा। जो पौधे-आधारित भोजन गर्म रखा जाएगा, उस पर कौन सा न्यूनतम आंतरिक खाना पकाने का तापमान लागू होता है?","ar":"سيُحفظ الأرز المطبوخ على خط الحفظ الساخن للتقديم. ما درجة حرارة الطهي الداخلية الدنيا المطبّقة على الأطعمة النباتية التي ستُحفظ ساخنة؟"},"o":[{"en":"135°F","es":"135°F","ru":"135°F","tr":"135°F","hi":"135°F","ar":"135°F"},{"en":"165°F","es":"165°F","ru":"165°F","tr":"165°F","hi":"165°F","ar":"165°F"},{"en":"155°F","es":"155°F","ru":"155°F","tr":"155°F","hi":"155°F","ar":"155°F"},{"en":"145°F","es":"145°F","ru":"145°F","tr":"145°F","hi":"145°F","ar":"145°F"}],"e":{"en":"Fruits, vegetables, grains, and legumes that will be hot-held must be cooked to a minimum internal temperature of 135°F.","es":"Las frutas, verduras, granos y legumbres que se mantendrán calientes deben cocinarse a una temperatura interna mínima de 135°F.","ru":"Фрукты, овощи, крупы и бобовые, которые будут храниться горячими, нужно готовить до минимальной внутренней температуры 135°F.","tr":"Sıcak tutulacak meyveler, sebzeler, tahıllar ve baklagiller minimum 135°F iç sıcaklığa kadar pişirilmelidir.","hi":"फल, सब्जियां, अनाज और फलियां जो गर्म रखी जाएंगी, उन्हें न्यूनतम आंतरिक तापमान 135°F तक पकाया जाना चाहिए।","ar":"يجب طهي الفواكه والخضروات والحبوب والبقوليات التي ستُحفظ ساخنة إلى درجة حرارة داخلية دنيا قدرها 135°F."}},{"cat":"haccp","a":0,"q":{"en":"What best describes 'active managerial control' in a food establishment?","es":"¿Qué describe mejor el 'control gerencial activo' en un establecimiento de alimentos?","ru":"Что лучше всего описывает «активный управленческий контроль» на предприятии питания?","tr":"Bir gıda işletmesinde 'aktif yönetimsel kontrol' en iyi nasıl tanımlanır?","hi":"किसी खाद्य प्रतिष्ठान में 'सक्रिय प्रबंधकीय नियंत्रण' का सबसे अच्छा वर्णन क्या है?","ar":"ما الذي يصف بشكل أفضل 'الرقابة الإدارية الفعّالة' في منشأة غذائية؟"},"o":[{"en":"A proactive, ongoing system in which management purposely controls the CDC risk factors for foodborne illness","es":"Un sistema proactivo y continuo en el que la gerencia controla deliberadamente los factores de riesgo de los CDC para enfermedades transmitidas por alimentos","ru":"Проактивная постоянная система, в которой руководство целенаправленно контролирует факторы риска пищевых заболеваний по классификации CDC","tr":"Yönetimin, CDC'nin gıda kaynaklı hastalık risk faktörlerini bilinçli olarak kontrol ettiği proaktif ve sürekli bir sistem","hi":"एक सक्रिय, निरंतर प्रणाली जिसमें प्रबंधन जानबूझकर खाद्य जनित बीमारी के CDC जोखिम कारकों को नियंत्रित करता है","ar":"نظام استباقي ومستمر تتحكم فيه الإدارة عمداً في عوامل الخطر لمرض منقول بالغذاء حسب تصنيف CDC"},{"en":"Waiting for the health inspector to identify problems and then fixing them","es":"Esperar a que el inspector de salud identifique los problemas y luego corregirlos","ru":"Ожидание, пока санитарный инспектор выявит проблемы, а затем их устранение","tr":"Sağlık müfettişinin sorunları belirlemesini bekleyip sonra düzeltmek","hi":"स्वास्थ्य निरीक्षक द्वारा समस्याओं की पहचान का इंतजार करना और फिर उन्हें ठीक करना","ar":"انتظار مفتش الصحة لتحديد المشكلات ثم إصلاحها"},{"en":"Assigning all food safety responsibility to hourly staff members","es":"Asignar toda la responsabilidad de seguridad alimentaria al personal por horas","ru":"Возложение всей ответственности за безопасность пищевых продуктов на почасовых сотрудников","tr":"Tüm gıda güvenliği sorumluluğunu saatlik çalışan personele yüklemek","hi":"सारी खाद्य सुरक्षा जिम्मेदारी घंटे के आधार पर काम करने वाले कर्मचारियों को सौंपना","ar":"إسناد كامل مسؤولية سلامة الغذاء إلى الموظفين بالساعة"},{"en":"Relying only on written policies with no monitoring or follow-up","es":"Depender únicamente de políticas escritas sin monitoreo ni seguimiento","ru":"Опора только на письменные правила без мониторинга и последующих действий","tr":"İzleme veya takip olmaksızın yalnızca yazılı politikalara güvenmek","hi":"बिना निगरानी या अनुवर्ती कार्रवाई के केवल लिखित नीतियों पर निर्भर रहना","ar":"الاعتماد فقط على السياسات المكتوبة دون مراقبة أو متابعة"}],"e":{"en":"Active managerial control is a proactive approach where the operator designs and manages systems to prevent the five CDC risk factors, rather than reacting after violations occur.","es":"El control gerencial activo es un enfoque proactivo en el que el operador diseña y gestiona sistemas para prevenir los cinco factores de riesgo de los CDC, en lugar de reaccionar después de que ocurran violaciones.","ru":"Активный управленческий контроль — это проактивный подход, при котором оператор разрабатывает и управляет системами для предотвращения пяти факторов риска CDC, а не реагирует после нарушений.","tr":"Aktif yönetimsel kontrol, işletmecinin ihlaller meydana geldikten sonra tepki vermek yerine beş CDC risk faktörünü önlemek için sistemler tasarlayıp yönettiği proaktif bir yaklaşımdır.","hi":"सक्रिय प्रबंधकीय नियंत्रण एक सक्रिय दृष्टिकोण है जिसमें संचालक उल्लंघन होने के बाद प्रतिक्रिया देने के बजाय पाँच CDC जोखिम कारकों को रोकने के लिए प्रणालियाँ डिज़ाइन और प्रबंधित करता है।","ar":"الرقابة الإدارية الفعّالة هي نهج استباقي يصمم فيه المشغّل ويدير أنظمة لمنع عوامل الخطر الخمسة لدى CDC بدلاً من رد الفعل بعد وقوع المخالفات."}},{"cat":"haccp","a":1,"q":{"en":"Which of the following is one of the CDC's five most common risk factors for foodborne illness?","es":"¿Cuál de los siguientes es uno de los cinco factores de riesgo más comunes de los CDC para enfermedades transmitidas por alimentos?","ru":"Что из перечисленного является одним из пяти наиболее распространённых факторов риска пищевых заболеваний по CDC?","tr":"Aşağıdakilerden hangisi CDC'nin gıda kaynaklı hastalık için en yaygın beş risk faktöründen biridir?","hi":"निम्नलिखित में से कौन सा CDC के खाद्य जनित बीमारी के पाँच सबसे आम जोखिम कारकों में से एक है?","ar":"أي مما يلي يُعد أحد عوامل الخطر الخمسة الأكثر شيوعاً لدى CDC للأمراض المنقولة بالغذاء؟"},"o":[{"en":"Serving food on cold, undecorated plates","es":"Servir alimentos en platos fríos y sin decorar","ru":"Подача еды на холодных, неукрашенных тарелках","tr":"Yemeği soğuk, süslenmemiş tabaklarda servis etmek","hi":"ठंडी, बिना सजावट वाली प्लेटों में भोजन परोसना","ar":"تقديم الطعام في أطباق باردة غير مزخرفة"},{"en":"Purchasing food from unsafe or unapproved sources","es":"Comprar alimentos de fuentes inseguras o no aprobadas","ru":"Закупка продуктов из небезопасных или неутверждённых источников","tr":"Gıdayı güvenli olmayan veya onaylanmamış kaynaklardan satın almak","hi":"असुरक्षित या अस्वीकृत स्रोतों से भोजन खरीदना","ar":"شراء الطعام من مصادر غير آمنة أو غير معتمدة"},{"en":"Using too many different menu items each day","es":"Usar demasiados platos diferentes en el menú cada día","ru":"Использование слишком большого количества различных блюд меню каждый день","tr":"Her gün çok fazla farklı menü öğesi kullanmak","hi":"हर दिन बहुत सारे अलग-अलग मेनू आइटम का उपयोग करना","ar":"استخدام عدد كبير جداً من أصناف القائمة كل يوم"},{"en":"Rotating stock using the FIFO method","es":"Rotar existencias usando el método PEPS (FIFO)","ru":"Ротация запасов методом FIFO","tr":"Stokları FIFO yöntemiyle döndürmek","hi":"FIFO विधि का उपयोग करके स्टॉक को घुमाना","ar":"تدوير المخزون باستخدام طريقة FIFO"}],"e":{"en":"The CDC identifies five risk factors: unsafe sources, inadequate cooking, improper holding temperatures, contaminated equipment, and poor personal hygiene. Purchasing from unapproved sources is one of them.","es":"Los CDC identifican cinco factores de riesgo: fuentes inseguras, cocción inadecuada, temperaturas de conservación incorrectas, equipo contaminado e higiene personal deficiente. Comprar de fuentes no aprobadas es uno de ellos.","ru":"CDC определяет пять факторов риска: небезопасные источники, недостаточная тепловая обработка, неправильные температуры хранения, загрязнённое оборудование и плохая личная гигиена. Закупка из неутверждённых источников — один из них.","tr":"CDC beş risk faktörü belirler: güvensiz kaynaklar, yetersiz pişirme, yanlış bekletme sıcaklıkları, kirlenmiş ekipman ve kötü kişisel hijyen. Onaylanmamış kaynaklardan satın almak bunlardan biridir.","hi":"CDC पाँच जोखिम कारकों की पहचान करता है: असुरक्षित स्रोत, अपर्याप्त पकाना, गलत होल्डिंग तापमान, दूषित उपकरण और खराब व्यक्तिगत स्वच्छता। अस्वीकृत स्रोतों से खरीदना उनमें से एक है।","ar":"يحدد CDC خمسة عوامل خطر: المصادر غير الآمنة، والطهي غير الكافي، ودرجات حرارة الحفظ غير السليمة، والمعدات الملوثة، وسوء النظافة الشخصية. والشراء من مصادر غير معتمدة أحدها."}},{"cat":"haccp","a":2,"q":{"en":"What is the FIRST of the seven HACCP principles?","es":"¿Cuál es el PRIMERO de los siete principios HACCP?","ru":"Каков ПЕРВЫЙ из семи принципов HACCP?","tr":"Yedi HACCP ilkesinin İLKİ nedir?","hi":"सात HACCP सिद्धांतों में से पहला कौन सा है?","ar":"ما هو المبدأ الأول من مبادئ HACCP السبعة؟"},"o":[{"en":"Establish critical limits","es":"Establecer límites críticos","ru":"Установить критические пределы","tr":"Kritik limitleri belirlemek","hi":"क्रांतिक सीमाएँ स्थापित करना","ar":"تحديد الحدود الحرجة"},{"en":"Determine the critical control points","es":"Determinar los puntos críticos de control","ru":"Определить критические контрольные точки","tr":"Kritik kontrol noktalarını belirlemek","hi":"क्रांतिक नियंत्रण बिंदु निर्धारित करना","ar":"تحديد نقاط التحكم الحرجة"},{"en":"Conduct a hazard analysis","es":"Realizar un análisis de peligros","ru":"Провести анализ опасностей","tr":"Tehlike analizi yapmak","hi":"खतरा विश्लेषण करना","ar":"إجراء تحليل المخاطر"},{"en":"Establish record-keeping procedures","es":"Establecer procedimientos de mantenimiento de registros","ru":"Установить процедуры ведения записей","tr":"Kayıt tutma prosedürlerini belirlemek","hi":"अभिलेख रखने की प्रक्रियाएँ स्थापित करना","ar":"وضع إجراءات حفظ السجلات"}],"e":{"en":"The first HACCP principle is to conduct a hazard analysis, identifying biological, chemical, and physical hazards at each step of the flow of food.","es":"El primer principio HACCP es realizar un análisis de peligros, identificando los peligros biológicos, químicos y físicos en cada etapa del flujo de alimentos.","ru":"Первый принцип HACCP — провести анализ опасностей, выявляя биологические, химические и физические опасности на каждом этапе движения продукта.","tr":"İlk HACCP ilkesi, gıda akışının her adımında biyolojik, kimyasal ve fiziksel tehlikeleri belirleyerek tehlike analizi yapmaktır.","hi":"पहला HACCP सिद्धांत खतरा विश्लेषण करना है, जिसमें भोजन के प्रवाह के प्रत्येक चरण पर जैविक, रासायनिक और भौतिक खतरों की पहचान की जाती है।","ar":"المبدأ الأول لـ HACCP هو إجراء تحليل المخاطر، وتحديد المخاطر البيولوجية والكيميائية والفيزيائية في كل خطوة من مسار الغذاء."}},{"cat":"haccp","a":3,"q":{"en":"Which sequence correctly lists the first three HACCP principles in order?","es":"¿Qué secuencia enumera correctamente los tres primeros principios HACCP en orden?","ru":"Какая последовательность правильно перечисляет первые три принципа HACCP по порядку?","tr":"Hangi sıralama ilk üç HACCP ilkesini doğru sırayla listeler?","hi":"कौन सा क्रम पहले तीन HACCP सिद्धांतों को सही क्रम में सूचीबद्ध करता है?","ar":"أي تسلسل يسرد بشكل صحيح مبادئ HACCP الثلاثة الأولى بالترتيب؟"},"o":[{"en":"Determine CCPs, conduct hazard analysis, establish critical limits","es":"Determinar PCC, realizar análisis de peligros, establecer límites críticos","ru":"Определить ККТ, провести анализ опасностей, установить критические пределы","tr":"KKN belirle, tehlike analizi yap, kritik limitleri belirle","hi":"CCP निर्धारित करें, खतरा विश्लेषण करें, क्रांतिक सीमाएँ स्थापित करें","ar":"تحديد نقاط التحكم الحرجة، إجراء تحليل المخاطر، تحديد الحدود الحرجة"},{"en":"Establish monitoring, conduct hazard analysis, determine CCPs","es":"Establecer monitoreo, realizar análisis de peligros, determinar PCC","ru":"Установить мониторинг, провести анализ опасностей, определить ККТ","tr":"İzleme belirle, tehlike analizi yap, KKN belirle","hi":"निगरानी स्थापित करें, खतरा विश्लेषण करें, CCP निर्धारित करें","ar":"وضع المراقبة، إجراء تحليل المخاطر، تحديد نقاط التحكم الحرجة"},{"en":"Conduct hazard analysis, establish critical limits, determine CCPs","es":"Realizar análisis de peligros, establecer límites críticos, determinar PCC","ru":"Провести анализ опасностей, установить критические пределы, определить ККТ","tr":"Tehlike analizi yap, kritik limitleri belirle, KKN belirle","hi":"खतरा विश्लेषण करें, क्रांतिक सीमाएँ स्थापित करें, CCP निर्धारित करें","ar":"إجراء تحليل المخاطر، تحديد الحدود الحرجة، تحديد نقاط التحكم الحرجة"},{"en":"Conduct hazard analysis, determine CCPs, establish critical limits","es":"Realizar análisis de peligros, determinar PCC, establecer límites críticos","ru":"Провести анализ опасностей, определить ККТ, установить критические пределы","tr":"Tehlike analizi yap, KKN belirle, kritik limitleri belirle","hi":"खतरा विश्लेषण करें, CCP निर्धारित करें, क्रांतिक सीमाएँ स्थापित करें","ar":"إجراء تحليل المخاطر، تحديد نقاط التحكم الحرجة، تحديد الحدود الحرجة"}],"e":{"en":"The correct order is: (1) hazard analysis, (2) determine CCPs, then (3) establish critical limits. Each principle builds on the previous one.","es":"El orden correcto es: (1) análisis de peligros, (2) determinar PCC, luego (3) establecer límites críticos. Cada principio se construye sobre el anterior.","ru":"Правильный порядок: (1) анализ опасностей, (2) определение ККТ, затем (3) установление критических пределов. Каждый принцип основан на предыдущем.","tr":"Doğru sıra: (1) tehlike analizi, (2) KKN belirleme, sonra (3) kritik limit belirleme. Her ilke bir öncekine dayanır.","hi":"सही क्रम है: (1) खतरा विश्लेषण, (2) CCP निर्धारित करना, फिर (3) क्रांतिक सीमाएँ स्थापित करना। प्रत्येक सिद्धांत पिछले पर आधारित है।","ar":"الترتيب الصحيح هو: (1) تحليل المخاطر، (2) تحديد نقاط التحكم الحرجة، ثم (3) تحديد الحدود الحرجة. كل مبدأ يبني على الذي قبله."}},{"cat":"haccp","a":0,"q":{"en":"In a HACCP plan, what is a critical control point (CCP)?","es":"En un plan HACCP, ¿qué es un punto crítico de control (PCC)?","ru":"Что такое критическая контрольная точка (ККТ) в плане HACCP?","tr":"Bir HACCP planında kritik kontrol noktası (KKN) nedir?","hi":"HACCP योजना में, क्रांतिक नियंत्रण बिंदु (CCP) क्या है?","ar":"في خطة HACCP، ما هي نقطة التحكم الحرجة (CCP)؟"},"o":[{"en":"A step where a hazard can be prevented, eliminated, or reduced to a safe level","es":"Un paso donde un peligro puede prevenirse, eliminarse o reducirse a un nivel seguro","ru":"Этап, на котором опасность может быть предотвращена, устранена или снижена до безопасного уровня","tr":"Bir tehlikenin önlenebildiği, ortadan kaldırılabildiği veya güvenli seviyeye indirilebildiği adım","hi":"एक चरण जहाँ किसी खतरे को रोका, समाप्त या सुरक्षित स्तर तक कम किया जा सकता है","ar":"خطوة يمكن عندها منع الخطر أو القضاء عليه أو خفضه إلى مستوى آمن"},{"en":"Any point in the process where employees take a break","es":"Cualquier punto del proceso donde los empleados toman un descanso","ru":"Любая точка процесса, где сотрудники делают перерыв","tr":"Sürecte çalışanların mola verdiği herhangi bir nokta","hi":"प्रक्रिया में कोई भी बिंदु जहाँ कर्मचारी विश्राम लेते हैं","ar":"أي نقطة في العملية يأخذ فيها الموظفون استراحة"},{"en":"The location where finished food is plated for service","es":"El lugar donde se emplata el alimento terminado para el servicio","ru":"Место, где готовая еда выкладывается на тарелки для подачи","tr":"Bitmiş yemeğin servis için tabaklandığı yer","hi":"वह स्थान जहाँ तैयार भोजन को परोसने के लिए प्लेट में रखा जाता है","ar":"الموقع الذي يُوضع فيه الطعام الجاهز في الأطباق للتقديم"},{"en":"The first delivery entrance used by suppliers","es":"La primera entrada de entregas usada por los proveedores","ru":"Первый вход для доставки, используемый поставщиками","tr":"Tedarikçilerin kullandığı ilk teslimat girişi","hi":"आपूर्तिकर्ताओं द्वारा उपयोग किया जाने वाला पहला डिलीवरी प्रवेश द्वार","ar":"مدخل التسليم الأول الذي يستخدمه الموردون"}],"e":{"en":"A CCP is a point in the flow of food where a specific hazard can be prevented, eliminated, or reduced to safe levels — for example, the cooking step for poultry.","es":"Un PCC es un punto en el flujo de alimentos donde un peligro específico puede prevenirse, eliminarse o reducirse a niveles seguros; por ejemplo, el paso de cocción de las aves.","ru":"ККТ — это точка в движении продукта, где конкретная опасность может быть предотвращена, устранена или снижена до безопасного уровня, например, этап тепловой обработки птицы.","tr":"KKN, belirli bir tehlikenin önlenebildiği, ortadan kaldırılabildiği veya güvenli seviyelere indirilebildiği gıda akışındaki bir noktadır — örneğin kümes hayvanlarının pişirilme adımı.","hi":"CCP भोजन के प्रवाह में एक बिंदु है जहाँ किसी विशिष्ट खतरे को रोका, समाप्त या सुरक्षित स्तर तक कम किया जा सकता है — उदाहरण के लिए, मुर्गी पकाने का चरण।","ar":"نقطة التحكم الحرجة هي نقطة في مسار الغذاء يمكن عندها منع خطر محدد أو القضاء عليه أو خفضه إلى مستويات آمنة — مثل خطوة طهي الدواجن."}},{"cat":"haccp","a":1,"q":{"en":"A restaurant identifies cooking chicken as a CCP. Which of the following is the appropriate CRITICAL LIMIT?","es":"Un restaurante identifica la cocción del pollo como un PCC. ¿Cuál de los siguientes es el LÍMITE CRÍTICO apropiado?","ru":"Ресторан определяет приготовление курицы как ККТ. Что из перечисленного является подходящим КРИТИЧЕСКИМ ПРЕДЕЛОМ?","tr":"Bir restoran tavuk pişirmeyi KKN olarak belirler. Aşağıdakilerden hangisi uygun KRİTİK LİMİTTİR?","hi":"एक रेस्तरां चिकन पकाने को CCP के रूप में पहचानता है। निम्नलिखित में से कौन सी उपयुक्त क्रांतिक सीमा है?","ar":"يحدد مطعم طهي الدجاج كنقطة تحكم حرجة. أي مما يلي هو الحد الحرج المناسب؟"},"o":[{"en":"Cook the chicken until the outside looks brown","es":"Cocinar el pollo hasta que el exterior se vea dorado","ru":"Готовить курицу, пока снаружи она не станет коричневой","tr":"Tavuğu dışı kahverengi görünene kadar pişirmek","hi":"चिकन को तब तक पकाएँ जब तक बाहर से भूरा न दिखे","ar":"طهي الدجاج حتى يظهر الخارج بنياً"},{"en":"Cook the chicken to an internal temperature of 165°F for 15 seconds","es":"Cocinar el pollo a una temperatura interna de 165°F durante 15 segundos","ru":"Приготовить курицу до внутренней температуры 165°F в течение 15 секунд","tr":"Tavuğu iç sıcaklığı 165°F olacak şekilde 15 saniye pişirmek","hi":"चिकन को 165°F के आंतरिक तापमान पर 15 सेकंड के लिए पकाएँ","ar":"طهي الدجاج حتى درجة حرارة داخلية 165°F لمدة 15 ثانية"},{"en":"Cook the chicken for at least 20 minutes regardless of temperature","es":"Cocinar el pollo durante al menos 20 minutos sin importar la temperatura","ru":"Готовить курицу не менее 20 минут независимо от температуры","tr":"Sıcaklık ne olursa olsun tavuğu en az 20 dakika pişirmek","hi":"तापमान की परवाह किए बिना चिकन को कम से कम 20 मिनट पकाएँ","ar":"طهي الدجاج لمدة 20 دقيقة على الأقل بغض النظر عن درجة الحرارة"},{"en":"Cook the chicken until the cook is satisfied it is done","es":"Cocinar el pollo hasta que el cocinero esté satisfecho de que está listo","ru":"Готовить курицу, пока повар не будет уверен, что она готова","tr":"Aşçı piştiğinden emin olana kadar tavuğu pişirmek","hi":"चिकन को तब तक पकाएँ जब तक रसोइया संतुष्ट न हो जाए कि यह पक गया है","ar":"طهي الدجاج حتى يقتنع الطاهي بأنه نضج"}],"e":{"en":"A critical limit must be a measurable value. Cooking chicken to 165°F for 15 seconds is the FDA Food Code minimum and can be objectively monitored with a thermometer.","es":"Un límite crítico debe ser un valor medible. Cocinar el pollo a 165°F durante 15 segundos es el mínimo del Código de Alimentos de la FDA y puede monitorearse objetivamente con un termómetro.","ru":"Критический предел должен быть измеримым значением. Приготовление курицы до 165°F в течение 15 секунд — минимум по Пищевому кодексу FDA, который можно объективно контролировать термометром.","tr":"Kritik limit ölçülebilir bir değer olmalıdır. Tavuğu 15 saniye 165°F'de pişirmek FDA Gıda Kodu minimumudur ve termometreyle nesnel olarak izlenebilir.","hi":"क्रांतिक सीमा एक मापने योग्य मान होना चाहिए। चिकन को 165°F पर 15 सेकंड पकाना FDA फूड कोड की न्यूनतम सीमा है और इसे थर्मामीटर से वस्तुनिष्ठ रूप से मॉनिटर किया जा सकता है।","ar":"يجب أن يكون الحد الحرج قيمة قابلة للقياس. طهي الدجاج حتى 165°F لمدة 15 ثانية هو الحد الأدنى في قانون الغذاء لـ FDA ويمكن مراقبته موضوعياً بميزان حرارة."}},{"cat":"haccp","a":2,"q":{"en":"A line cook records the internal temperature of cooked chicken on a log at each batch. This activity is an example of which HACCP principle?","es":"Un cocinero de línea registra la temperatura interna del pollo cocido en una bitácora en cada lote. ¿De qué principio HACCP es un ejemplo esta actividad?","ru":"Повар записывает внутреннюю температуру приготовленной курицы в журнал для каждой партии. Примером какого принципа HACCP является это действие?","tr":"Bir aşçı, her partide pişmiş tavuğun iç sıcaklığını bir kayda geçirir. Bu faaliyet hangi HACCP ilkesinin örneğidir?","hi":"एक लाइन कुक प्रत्येक बैच में पके हुए चिकन के आंतरिक तापमान को एक लॉग पर दर्ज करता है। यह गतिविधि किस HACCP सिद्धांत का उदाहरण है?","ar":"يسجّل طاهٍ درجة الحرارة الداخلية للدجاج المطهو في سجل عند كل دفعة. هذا النشاط مثال على أي مبدأ من مبادئ HACCP؟"},"o":[{"en":"Corrective action","es":"Acción correctiva","ru":"Корректирующее действие","tr":"Düzeltici faaliyet","hi":"सुधारात्मक कार्रवाई","ar":"الإجراء التصحيحي"},{"en":"Hazard analysis","es":"Análisis de peligros","ru":"Анализ опасностей","tr":"Tehlike analizi","hi":"खतरा विश्लेषण","ar":"تحليل المخاطر"},{"en":"Monitoring","es":"Monitoreo","ru":"Мониторинг","tr":"İzleme","hi":"निगरानी","ar":"المراقبة"},{"en":"Verification","es":"Verificación","ru":"Верификация","tr":"Doğrulama","hi":"सत्यापन","ar":"التحقق"}],"e":{"en":"Monitoring (principle 4) is the routine measuring and recording at a CCP to confirm the critical limit is met. Recording temperatures on a log at each batch is monitoring.","es":"El monitoreo (principio 4) es la medición y el registro rutinarios en un PCC para confirmar que se cumple el límite crítico. Registrar temperaturas en una bitácora en cada lote es monitoreo.","ru":"Мониторинг (принцип 4) — это регулярное измерение и запись в ККТ для подтверждения соблюдения критического предела. Запись температур в журнал для каждой партии — это мониторинг.","tr":"İzleme (ilke 4), kritik limitin karşılandığını doğrulamak için bir KKN'de rutin ölçme ve kaydetmedir. Her partide sıcaklığı kayda geçirmek izlemedir.","hi":"निगरानी (सिद्धांत 4) एक CCP पर नियमित माप और रिकॉर्डिंग है ताकि पुष्टि हो सके कि क्रांतिक सीमा पूरी हो रही है। प्रत्येक बैच में लॉग पर तापमान दर्ज करना निगरानी है।","ar":"المراقبة (المبدأ 4) هي القياس والتسجيل الروتيني عند نقطة التحكم الحرجة للتأكد من استيفاء الحد الحرج. تسجيل درجات الحرارة في سجل عند كل دفعة هو مراقبة."}},{"cat":"haccp","a":3,"q":{"en":"A cook checks a chicken breast and finds it reached only 150°F instead of 165°F, so it is returned to the oven to finish cooking. This response is an example of:","es":"Un cocinero revisa una pechuga de pollo y encuentra que solo alcanzó 150°F en lugar de 165°F, por lo que la regresa al horno para terminar de cocinarla. Esta respuesta es un ejemplo de:","ru":"Повар проверяет куриную грудку и обнаруживает, что она достигла только 150°F вместо 165°F, поэтому возвращает её в духовку для дальнейшего приготовления. Эта реакция является примером:","tr":"Bir aşçı tavuk göğsünü kontrol eder ve 165°F yerine yalnızca 150°F'ye ulaştığını görür, bu yüzden pişmeyi tamamlamak için fırına geri koyar. Bu tepki neyin örneğidir:","hi":"एक रसोइया चिकन ब्रेस्ट की जाँच करता है और पाता है कि यह 165°F के बजाय केवल 150°F तक पहुँचा है, इसलिए इसे पकाना पूरा करने के लिए ओवन में वापस रखा जाता है। यह प्रतिक्रिया किसका उदाहरण है:","ar":"يفحص طاهٍ صدر دجاج ويجد أنه بلغ 150°F فقط بدلاً من 165°F، فيعيده إلى الفرن لإكمال الطهي. هذه الاستجابة مثال على:"},"o":[{"en":"Verification","es":"Verificación","ru":"Верификация","tr":"Doğrulama","hi":"सत्यापन","ar":"التحقق"},{"en":"Hazard analysis","es":"Análisis de peligros","ru":"Анализ опасностей","tr":"Tehlike analizi","hi":"खतरा विश्लेषण","ar":"تحليل المخاطر"},{"en":"Record-keeping","es":"Mantenimiento de registros","ru":"Ведение записей","tr":"Kayıt tutma","hi":"अभिलेख रखना","ar":"حفظ السجلات"},{"en":"Corrective action","es":"Acción correctiva","ru":"Корректирующее действие","tr":"Düzeltici faaliyet","hi":"सुधारात्मक कार्रवाई","ar":"الإجراء التصحيحي"}],"e":{"en":"Corrective action (principle 5) is the predetermined response when a critical limit is not met. Continuing to cook the undercooked chicken back to 165°F is a corrective action.","es":"La acción correctiva (principio 5) es la respuesta predeterminada cuando no se cumple un límite crítico. Seguir cocinando el pollo poco cocido hasta 165°F es una acción correctiva.","ru":"Корректирующее действие (принцип 5) — это заранее определённая реакция, когда критический предел не соблюдён. Дальнейшее приготовление недоготовленной курицы до 165°F — корректирующее действие.","tr":"Düzeltici faaliyet (ilke 5), kritik limite ulaşılmadığında önceden belirlenmiş tepkidir. Az pişmiş tavuğu tekrar 165°F'ye kadar pişirmek düzeltici bir faaliyettir.","hi":"सुधारात्मक कार्रवाई (सिद्धांत 5) तब की पूर्व-निर्धारित प्रतिक्रिया है जब क्रांतिक सीमा पूरी नहीं होती। कम पके चिकन को फिर से 165°F तक पकाना एक सुधारात्मक कार्रवाई है।","ar":"الإجراء التصحيحي (المبدأ 5) هو الاستجابة المحددة مسبقاً عند عدم استيفاء الحد الحرج. مواصلة طهي الدجاج غير الناضج حتى 165°F هو إجراء تصحيحي."}},{"cat":"haccp","a":0,"q":{"en":"At the end of each week, the manager reviews the temperature logs, recalibrates thermometers, and confirms staff followed procedures. This is an example of which HACCP principle?","es":"Al final de cada semana, el gerente revisa las bitácoras de temperatura, recalibra los termómetros y confirma que el personal siguió los procedimientos. ¿De qué principio HACCP es un ejemplo?","ru":"В конце каждой недели менеджер проверяет журналы температур, повторно калибрует термометры и подтверждает, что персонал соблюдал процедуры. Примером какого принципа HACCP это является?","tr":"Her haftanın sonunda müdür sıcaklık kayıtlarını inceler, termometreleri yeniden kalibre eder ve personelin prosedürlere uyduğunu doğrular. Bu hangi HACCP ilkesinin örneğidir?","hi":"प्रत्येक सप्ताह के अंत में, प्रबंधक तापमान लॉग की समीक्षा करता है, थर्मामीटर को पुनः कैलिब्रेट करता है, और पुष्टि करता है कि कर्मचारियों ने प्रक्रियाओं का पालन किया। यह किस HACCP सिद्धांत का उदाहरण है?","ar":"في نهاية كل أسبوع، يراجع المدير سجلات الحرارة ويعيد معايرة موازين الحرارة ويتأكد من أن الموظفين اتبعوا الإجراءات. هذا مثال على أي مبدأ من مبادئ HACCP؟"},"o":[{"en":"Verification","es":"Verificación","ru":"Верификация","tr":"Doğrulama","hi":"सत्यापन","ar":"التحقق"},{"en":"Monitoring","es":"Monitoreo","ru":"Мониторинг","tr":"İzleme","hi":"निगरानी","ar":"المراقبة"},{"en":"Establishing critical limits","es":"Establecer límites críticos","ru":"Установление критических пределов","tr":"Kritik limitleri belirleme","hi":"क्रांतिक सीमाएँ स्थापित करना","ar":"تحديد الحدود الحرجة"},{"en":"Determining critical control points","es":"Determinar puntos críticos de control","ru":"Определение критических контрольных точек","tr":"Kritik kontrol noktalarını belirleme","hi":"क्रांतिक नियंत्रण बिंदु निर्धारित करना","ar":"تحديد نقاط التحكم الحرجة"}],"e":{"en":"Verification (principle 6) confirms the HACCP system is working as intended — reviewing logs, recalibrating equipment, and checking that procedures are followed are verification activities.","es":"La verificación (principio 6) confirma que el sistema HACCP funciona según lo previsto: revisar bitácoras, recalibrar equipos y comprobar que se siguen los procedimientos son actividades de verificación.","ru":"Верификация (принцип 6) подтверждает, что система HACCP работает как задумано — проверка журналов, повторная калибровка оборудования и контроль соблюдения процедур являются действиями по верификации.","tr":"Doğrulama (ilke 6), HACCP sisteminin amaçlandığı gibi çalıştığını teyit eder — kayıtları incelemek, ekipmanı yeniden kalibre etmek ve prosedürlere uyulduğunu kontrol etmek doğrulama faaliyetleridir.","hi":"सत्यापन (सिद्धांत 6) पुष्टि करता है कि HACCP प्रणाली इच्छित रूप से काम कर रही है — लॉग की समीक्षा करना, उपकरण को पुनः कैलिब्रेट करना और यह जाँचना कि प्रक्रियाओं का पालन किया जा रहा है, सत्यापन गतिविधियाँ हैं।","ar":"التحقق (المبدأ 6) يؤكد أن نظام HACCP يعمل كما هو مقصود — مراجعة السجلات وإعادة معايرة المعدات والتأكد من اتباع الإجراءات كلها أنشطة تحقق."}},{"cat":"haccp","a":1,"q":{"en":"Which specialized process generally requires a variance AND a HACCP plan before an operation may perform it?","es":"¿Qué proceso especializado generalmente requiere una variación Y un plan HACCP antes de que una operación pueda realizarlo?","ru":"Какой специализированный процесс обычно требует получения отклонения (variance) И плана HACCP, прежде чем предприятие сможет его выполнять?","tr":"Hangi özel işlem, bir işletmenin bunu gerçekleştirebilmesi için genellikle hem varyans HEM DE bir HACCP planı gerektirir?","hi":"कौन सी विशेष प्रक्रिया आमतौर पर किसी संचालन द्वारा इसे करने से पहले एक विचलन (variance) और एक HACCP योजना दोनों की आवश्यकता होती है?","ar":"أي عملية متخصصة تتطلب عموماً استثناءً (variance) وخطة HACCP قبل أن يتمكن المشغل من تنفيذها؟"},"o":[{"en":"Grilling steaks to order for immediate service","es":"Asar filetes a pedido para servicio inmediato","ru":"Приготовление стейков на гриле на заказ для немедленной подачи","tr":"Biftekleri anında servis için siparişe göre ızgara yapmak","hi":"तत्काल सेवा के लिए ऑर्डर पर स्टेक ग्रिल करना","ar":"شوي شرائح اللحم حسب الطلب للتقديم الفوري"},{"en":"Packaging food using reduced-oxygen packaging (ROP) such as sous vide","es":"Empacar alimentos usando envasado con oxígeno reducido (ROP) como el sous vide","ru":"Упаковка продуктов с использованием упаковки с пониженным содержанием кислорода (ROP), например су-вид","tr":"Sous vide gibi azaltılmış oksijenli paketleme (ROP) kullanarak gıda paketlemek","hi":"सूस-वीड जैसी कम-ऑक्सीजन पैकेजिंग (ROP) का उपयोग करके भोजन पैक करना","ar":"تعبئة الطعام باستخدام التعبئة منخفضة الأكسجين (ROP) مثل السوس فيد"},{"en":"Storing dry goods on shelving six inches off the floor","es":"Almacenar productos secos en estantes a seis pulgadas del suelo","ru":"Хранение сухих продуктов на полках на высоте шести дюймов от пола","tr":"Kuru gıdaları zeminden altı inç yükseklikteki raflarda depolamak","hi":"सूखे सामान को फर्श से छह इंच ऊपर शेल्फ पर संग्रहीत करना","ar":"تخزين السلع الجافة على أرفف على ارتفاع ست بوصات من الأرض"},{"en":"Reheating soup to 165°F for hot holding","es":"Recalentar sopa a 165°F para mantenimiento en caliente","ru":"Разогрев супа до 165°F для горячего хранения","tr":"Çorbayı sıcak bekletme için 165°F'ye yeniden ısıtmak","hi":"गर्म रखने के लिए सूप को 165°F तक फिर से गर्म करना","ar":"إعادة تسخين الحساء إلى 165°F للحفظ الساخن"}],"e":{"en":"Reduced-oxygen packaging, including sous vide and cook-chill, poses a botulism risk and generally requires both a variance from the regulatory authority and a HACCP plan.","es":"El envasado con oxígeno reducido, incluidos el sous vide y el cook-chill, presenta riesgo de botulismo y generalmente requiere tanto una variación de la autoridad reguladora como un plan HACCP.","ru":"Упаковка с пониженным содержанием кислорода, включая су-вид и cook-chill, создаёт риск ботулизма и обычно требует как отклонения от регулирующего органа, так и плана HACCP.","tr":"Sous vide ve cook-chill dahil azaltılmış oksijenli paketleme botulizm riski taşır ve genellikle hem düzenleyici otoriteden varyans hem de bir HACCP planı gerektirir.","hi":"कम-ऑक्सीजन पैकेजिंग, जिसमें सूस-वीड और कुक-चिल शामिल हैं, बोटुलिज़्म का जोखिम पैदा करती है और आमतौर पर नियामक प्राधिकरण से विचलन और HACCP योजना दोनों की आवश्यकता होती है।","ar":"التعبئة منخفضة الأكسجين، بما في ذلك السوس فيد والطهي-التبريد، تشكل خطر التسمم الوشيقي وتتطلب عموماً استثناءً من الجهة التنظيمية وخطة HACCP معاً."}},{"cat":"haccp","a":2,"q":{"en":"A sewage backup floods the kitchen floor during service. According to the Food Code, what must the person in charge do?","es":"Un desbordamiento de aguas residuales inunda el piso de la cocina durante el servicio. Según el Código de Alimentos, ¿qué debe hacer la persona a cargo?","ru":"Обратный поток сточных вод затапливает пол кухни во время работы. Согласно Пищевому кодексу, что должно сделать ответственное лицо?","tr":"Servis sırasında bir kanalizasyon geri tepmesi mutfak zeminini basar. Gıda Koduna göre, sorumlu kişi ne yapmalıdır?","hi":"सेवा के दौरान सीवेज बैकअप रसोई के फर्श को भर देता है। फूड कोड के अनुसार, प्रभारी व्यक्ति को क्या करना चाहिए?","ar":"يفيض ارتداد الصرف الصحي على أرضية المطبخ أثناء الخدمة. وفقاً لقانون الغذاء، ماذا يجب على الشخص المسؤول أن يفعل؟"},"o":[{"en":"Continue service but keep customers away from the affected area","es":"Continuar el servicio pero mantener a los clientes alejados del área afectada","ru":"Продолжить обслуживание, но держать клиентов подальше от затронутой зоны","tr":"Servise devam etmek ama müşterileri etkilenen alandan uzak tutmak","hi":"सेवा जारी रखें लेकिन ग्राहकों को प्रभावित क्षेत्र से दूर रखें","ar":"متابعة الخدمة مع إبعاد الزبائن عن المنطقة المتضررة"},{"en":"Mop up the sewage and continue cooking as usual","es":"Trapear las aguas residuales y continuar cocinando como de costumbre","ru":"Убрать сточные воды и продолжить готовить как обычно","tr":"Kanalizasyonu paspaslayıp her zamanki gibi pişirmeye devam etmek","hi":"सीवेज को पोंछें और हमेशा की तरह खाना बनाना जारी रखें","ar":"مسح مياه الصرف ومتابعة الطهي كالمعتاد"},{"en":"Immediately stop operations and notify the regulatory authority, as this is an imminent health hazard","es":"Detener inmediatamente las operaciones y notificar a la autoridad reguladora, ya que es un peligro inminente para la salud","ru":"Немедленно прекратить работу и уведомить регулирующий орган, поскольку это неминуемая угроза здоровью","tr":"Bunun yakın bir sağlık tehlikesi olması nedeniyle faaliyetleri derhal durdurmak ve düzenleyici otoriteyi bilgilendirmek","hi":"तुरंत संचालन बंद करें और नियामक प्राधिकरण को सूचित करें, क्योंकि यह एक आसन्न स्वास्थ्य खतरा है","ar":"إيقاف العمليات فوراً وإخطار الجهة التنظيمية، لأن هذا خطر صحي وشيك"},{"en":"Wait until the end of the shift to assess the damage","es":"Esperar hasta el final del turno para evaluar el daño","ru":"Подождать до конца смены, чтобы оценить ущерб","tr":"Hasarı değerlendirmek için vardiyanın sonuna kadar beklemek","hi":"क्षति का आकलन करने के लिए शिफ्ट के अंत तक प्रतीक्षा करें","ar":"الانتظار حتى نهاية الوردية لتقييم الأضرار"}],"e":{"en":"A sewage backup is an imminent health hazard. The operation must immediately cease operations, discard exposed food, and notify the regulatory authority before reopening.","es":"Un desbordamiento de aguas residuales es un peligro inminente para la salud. La operación debe cesar inmediatamente, desechar los alimentos expuestos y notificar a la autoridad reguladora antes de reabrir.","ru":"Обратный поток сточных вод — неминуемая угроза здоровью. Предприятие должно немедленно прекратить работу, выбросить подвергшуюся воздействию еду и уведомить регулирующий орган перед возобновлением работы.","tr":"Kanalizasyon geri tepmesi yakın bir sağlık tehlikesidir. İşletme derhal faaliyetleri durdurmalı, açığa çıkan gıdayı atmalı ve yeniden açılmadan önce düzenleyici otoriteyi bilgilendirmelidir.","hi":"सीवेज बैकअप एक आसन्न स्वास्थ्य खतरा है। संचालन को तुरंत बंद करना चाहिए, उजागर भोजन को फेंक देना चाहिए, और फिर से खोलने से पहले नियामक प्राधिकरण को सूचित करना चाहिए।","ar":"ارتداد الصرف الصحي خطر صحي وشيك. يجب على المنشأة إيقاف العمليات فوراً والتخلص من الطعام المكشوف وإخطار الجهة التنظيمية قبل إعادة الفتح."}},{"cat":"haccp","a":3,"q":{"en":"A restaurant offers hamburgers cooked to order at temperatures below 155°F. Which public health intervention does the Food Code require them to provide?","es":"Un restaurante ofrece hamburguesas cocinadas a pedido a temperaturas inferiores a 155°F. ¿Qué intervención de salud pública exige el Código de Alimentos que proporcionen?","ru":"Ресторан предлагает гамбургеры, приготовленные на заказ при температуре ниже 155°F. Какое вмешательство общественного здравоохранения требует от них Пищевой кодекс?","tr":"Bir restoran 155°F'nin altındaki sıcaklıklarda siparişe göre pişirilen hamburgerler sunar. Gıda Kodu onların hangi halk sağlığı müdahalesini sağlamasını gerektirir?","hi":"एक रेस्तरां 155°F से कम तापमान पर ऑर्डर के अनुसार पकाए गए हैमबर्गर प्रदान करता है। फूड कोड उन्हें कौन सा सार्वजनिक स्वास्थ्य हस्तक्षेप प्रदान करने की आवश्यकता है?","ar":"يقدم مطعم برجر يُطهى حسب الطلب في درجات حرارة أقل من 155°F. ما هو التدخل الصحي العام الذي يطلب قانون الغذاء منهم تقديمه؟"},"o":[{"en":"A HACCP plan approved by the manufacturer","es":"Un plan HACCP aprobado por el fabricante","ru":"План HACCP, утверждённый производителем","tr":"Üretici tarafından onaylanmış bir HACCP planı","hi":"निर्माता द्वारा अनुमोदित एक HACCP योजना","ar":"خطة HACCP معتمدة من الشركة المصنّعة"},{"en":"A variance from the local fire department","es":"Una variación del departamento de bomberos local","ru":"Отклонение от местной пожарной службы","tr":"Yerel itfaiyeden bir varyans","hi":"स्थानीय अग्निशमन विभाग से एक विचलन","ar":"استثناء من إدارة الإطفاء المحلية"},{"en":"A written employee health policy posted in the dining room","es":"Una política escrita de salud de los empleados publicada en el comedor","ru":"Письменная политика здоровья сотрудников, размещённая в обеденном зале","tr":"Yemek salonuna asılmış yazılı bir çalışan sağlığı politikası","hi":"भोजन कक्ष में लगाई गई एक लिखित कर्मचारी स्वास्थ्य नीति","ar":"سياسة مكتوبة لصحة الموظفين معلّقة في صالة الطعام"},{"en":"A consumer advisory that discloses the raw/undercooked item and reminds of the risk","es":"Un aviso al consumidor que revele el alimento crudo/poco cocido y recuerde el riesgo","ru":"Уведомление для потребителей, раскрывающее сырое/недоготовленное блюдо и напоминающее о риске","tr":"Çiğ/az pişmiş öğeyi açıklayan ve riski hatırlatan bir tüketici uyarısı","hi":"एक उपभोक्ता सलाह जो कच्चे/कम पके आइटम का खुलासा करती है और जोखिम की याद दिलाती है","ar":"إشعار للمستهلك يكشف الصنف النيء/غير المطهو جيداً ويذكّر بالخطر"}],"e":{"en":"When raw or undercooked animal foods are served, the Food Code requires a consumer advisory with both a disclosure and a reminder about the increased risk of foodborne illness.","es":"Cuando se sirven alimentos de origen animal crudos o poco cocidos, el Código de Alimentos exige un aviso al consumidor con una divulgación y un recordatorio sobre el mayor riesgo de enfermedad transmitida por alimentos.","ru":"Когда подаются сырые или недоготовленные продукты животного происхождения, Пищевой кодекс требует уведомления для потребителей с раскрытием информации и напоминанием о повышенном риске пищевого заболевания.","tr":"Çiğ veya az pişmiş hayvansal gıdalar sunulduğunda, Gıda Kodu hem açıklama hem de artan gıda kaynaklı hastalık riski hakkında hatırlatma içeren bir tüketici uyarısı gerektirir.","hi":"जब कच्चे या कम पके पशु-आधारित खाद्य पदार्थ परोसे जाते हैं, तो फूड कोड को उपभोक्ता सलाह की आवश्यकता होती है जिसमें खुलासा और खाद्य जनित बीमारी के बढ़े हुए जोखिम की याद दिलाना दोनों शामिल हैं।","ar":"عند تقديم أطعمة حيوانية نيئة أو غير مطهوة جيداً، يتطلب قانون الغذاء إشعاراً للمستهلك يتضمن كلاً من الإفصاح والتذكير بزيادة خطر المرض المنقول بالغذاء."}},{"cat":"haccp","a":0,"q":{"en":"A manager receives notice that a supplier's ground beef is being recalled for E. coli contamination. What is the correct first action?","es":"Un gerente recibe un aviso de que la carne molida de un proveedor está siendo retirada del mercado por contaminación con E. coli. ¿Cuál es la primera acción correcta?","ru":"Менеджер получает уведомление о том, что говяжий фарш поставщика отзывается из-за загрязнения E. coli. Каково правильное первое действие?","tr":"Bir müdür, bir tedarikçinin kıymasının E. coli bulaşması nedeniyle geri çağrıldığına dair bildirim alır. Doğru ilk eylem nedir?","hi":"एक प्रबंधक को सूचना मिलती है कि एक आपूर्तिकर्ता के कीमा बीफ को E. coli संदूषण के लिए वापस मंगाया जा रहा है। सही पहली कार्रवाई क्या है?","ar":"يتلقى مدير إشعاراً بأن اللحم المفروم من أحد الموردين يُسحب بسبب تلوث بـ E. coli. ما هو الإجراء الأول الصحيح؟"},"o":[{"en":"Identify the recalled product using the ID/lot information, remove it from service, and store it separately labeled 'Do Not Use'","es":"Identificar el producto retirado usando la información de ID/lote, retirarlo del servicio y almacenarlo por separado etiquetado como 'No Usar'","ru":"Идентифицировать отозванный продукт по идентификационной информации/номеру партии, изъять его из использования и хранить отдельно с маркировкой «Не использовать»","tr":"Geri çağrılan ürünü kimlik/parti bilgisiyle belirlemek, servisten çıkarmak ve 'Kullanmayın' etiketiyle ayrı depolamak","hi":"ID/लॉट जानकारी का उपयोग करके वापस मंगाए गए उत्पाद की पहचान करें, इसे सेवा से हटाएँ, और 'उपयोग न करें' लेबल के साथ अलग से संग्रहीत करें","ar":"تحديد المنتج المسحوب باستخدام معلومات الهوية/الدفعة، وإزالته من الخدمة، وتخزينه منفصلاً بعلامة 'لا تستخدم'"},{"en":"Cook the beef to a higher temperature to make it safe and keep serving it","es":"Cocinar la carne a una temperatura más alta para hacerla segura y seguir sirviéndola","ru":"Приготовить говядину при более высокой температуре, чтобы сделать её безопасной, и продолжать подавать","tr":"Sığır etini güvenli hale getirmek için daha yüksek sıcaklıkta pişirip servis etmeye devam etmek","hi":"बीफ को सुरक्षित बनाने के लिए उच्च तापमान पर पकाएँ और इसे परोसना जारी रखें","ar":"طهي اللحم في درجة حرارة أعلى لجعله آمناً ومواصلة تقديمه"},{"en":"Throw the product in the regular trash without any records","es":"Tirar el producto a la basura común sin ningún registro","ru":"Выбросить продукт в обычный мусор без каких-либо записей","tr":"Ürünü herhangi bir kayıt olmadan normal çöpe atmak","hi":"बिना किसी रिकॉर्ड के उत्पाद को नियमित कचरे में फेंक दें","ar":"رمي المنتج في القمامة العادية دون أي سجلات"},{"en":"Ignore the notice unless a customer complains","es":"Ignorar el aviso a menos que un cliente se queje","ru":"Игнорировать уведомление, пока не пожалуется клиент","tr":"Bir müşteri şikayet etmedikçe bildirimi görmezden gelmek","hi":"जब तक कोई ग्राहक शिकायत न करे तब तक नोटिस को अनदेखा करें","ar":"تجاهل الإشعار ما لم يشتكِ زبون"}],"e":{"en":"During a recall, identify the affected product by its label/lot number, immediately remove it from use, and segregate it clearly labeled to prevent accidental service while awaiting instructions.","es":"Durante un retiro, identifique el producto afectado por su etiqueta/número de lote, retírelo inmediatamente del uso y sepárelo claramente etiquetado para evitar su servicio accidental mientras espera instrucciones.","ru":"Во время отзыва идентифицируйте затронутый продукт по этикетке/номеру партии, немедленно изымите его из использования и отделите с чёткой маркировкой, чтобы предотвратить случайную подачу в ожидании инструкций.","tr":"Geri çağırma sırasında etkilenen ürünü etiket/parti numarasıyla belirleyin, hemen kullanımdan kaldırın ve talimat beklerken kazara servisi önlemek için açıkça etiketlenmiş şekilde ayırın.","hi":"रिकॉल के दौरान, प्रभावित उत्पाद को उसके लेबल/लॉट नंबर से पहचानें, तुरंत इसे उपयोग से हटाएँ, और निर्देशों की प्रतीक्षा करते समय आकस्मिक सेवा को रोकने के लिए इसे स्पष्ट रूप से लेबल करके अलग करें।","ar":"أثناء السحب، حدّد المنتج المتأثر بواسطة ملصقه/رقم دفعته، وأزله فوراً من الاستخدام، واعزله بعلامة واضحة لمنع تقديمه عن طريق الخطأ أثناء انتظار التعليمات."}},{"cat":"haccp","a":1,"q":{"en":"Which statement best describes the difference between a formal HACCP plan and active managerial control?","es":"¿Qué afirmación describe mejor la diferencia entre un plan HACCP formal y el control gerencial activo?","ru":"Какое утверждение лучше всего описывает разницу между формальным планом HACCP и активным управленческим контролем?","tr":"Hangi ifade resmi bir HACCP planı ile aktif yönetimsel kontrol arasındaki farkı en iyi açıklar?","hi":"कौन सा कथन औपचारिक HACCP योजना और सक्रिय प्रबंधकीय नियंत्रण के बीच के अंतर का सबसे अच्छा वर्णन करता है?","ar":"أي عبارة تصف بشكل أفضل الفرق بين خطة HACCP الرسمية والرقابة الإدارية الفعّالة؟"},"o":[{"en":"They are identical terms with no practical difference","es":"Son términos idénticos sin diferencia práctica","ru":"Это идентичные термины без практической разницы","tr":"Pratik bir farkı olmayan aynı terimlerdir","hi":"वे बिना किसी व्यावहारिक अंतर के समान शब्द हैं","ar":"هما مصطلحان متطابقان دون فرق عملي"},{"en":"A HACCP plan is a formal written document built on the 7 principles, while active managerial control is the broader overall approach to controlling risk factors","es":"Un plan HACCP es un documento escrito formal basado en los 7 principios, mientras que el control gerencial activo es el enfoque general más amplio para controlar los factores de riesgo","ru":"План HACCP — это формальный письменный документ, построенный на 7 принципах, тогда как активный управленческий контроль — это более широкий общий подход к контролю факторов риска","tr":"HACCP planı, 7 ilke üzerine kurulu resmi yazılı bir belgedir, aktif yönetimsel kontrol ise risk faktörlerini kontrol etmeye yönelik daha geniş genel yaklaşımdır","hi":"HACCP योजना 7 सिद्धांतों पर बना एक औपचारिक लिखित दस्तावेज़ है, जबकि सक्रिय प्रबंधकीय नियंत्रण जोखिम कारकों को नियंत्रित करने का व्यापक समग्र दृष्टिकोण है","ar":"خطة HACCP وثيقة مكتوبة رسمية مبنية على المبادئ السبعة، بينما الرقابة الإدارية الفعّالة هي النهج العام الأوسع للتحكم في عوامل الخطر"},{"en":"Active managerial control applies only to warehouses, not restaurants","es":"El control gerencial activo se aplica solo a almacenes, no a restaurantes","ru":"Активный управленческий контроль применяется только к складам, а не к ресторанам","tr":"Aktif yönetimsel kontrol yalnızca depolara uygulanır, restoranlara değil","hi":"सक्रिय प्रबंधकीय नियंत्रण केवल गोदामों पर लागू होता है, रेस्तरां पर नहीं","ar":"الرقابة الإدارية الفعّالة تنطبق فقط على المستودعات وليس المطاعم"},{"en":"A HACCP plan can never include record-keeping","es":"Un plan HACCP nunca puede incluir el mantenimiento de registros","ru":"План HACCP никогда не может включать ведение записей","tr":"Bir HACCP planı asla kayıt tutmayı içeremez","hi":"एक HACCP योजना में कभी भी अभिलेख रखना शामिल नहीं हो सकता","ar":"خطة HACCP لا يمكن أبداً أن تتضمن حفظ السجلات"}],"e":{"en":"HACCP is a formal, documented food safety system based on the seven principles, often required for specialized processes. Active managerial control is the broader everyday practice of controlling the CDC risk factors.","es":"HACCP es un sistema formal y documentado de seguridad alimentaria basado en los siete principios, a menudo requerido para procesos especializados. El control gerencial activo es la práctica cotidiana más amplia de controlar los factores de riesgo de los CDC.","ru":"HACCP — это формальная, документированная система безопасности пищевых продуктов, основанная на семи принципах, часто требуемая для специализированных процессов. Активный управленческий контроль — это более широкая повседневная практика контроля факторов риска CDC.","tr":"HACCP, yedi ilkeye dayanan, genellikle özel işlemler için gereken resmi, belgelenmiş bir gıda güvenliği sistemidir. Aktif yönetimsel kontrol ise CDC risk faktörlerini kontrol etmenin daha geniş günlük uygulamasıdır.","hi":"HACCP सात सिद्धांतों पर आधारित एक औपचारिक, प्रलेखित खाद्य सुरक्षा प्रणाली है, जो अक्सर विशेष प्रक्रियाओं के लिए आवश्यक होती है। सक्रिय प्रबंधकीय नियंत्रण CDC जोखिम कारकों को नियंत्रित करने का व्यापक रोज़मर्रा का अभ्यास है।","ar":"HACCP نظام رسمي موثّق لسلامة الغذاء مبني على المبادئ السبعة، وكثيراً ما يُطلب للعمليات المتخصصة. أما الرقابة الإدارية الفعّالة فهي الممارسة اليومية الأوسع للتحكم في عوامل الخطر لدى CDC."}},{"cat":"haccp","a":2,"q":{"en":"When conducting a hazard analysis (HACCP principle 1), what is the operator primarily looking for?","es":"Al realizar un análisis de peligros (principio 1 de HACCP), ¿qué busca principalmente el operador?","ru":"При проведении анализа опасностей (принцип 1 HACCP) что в первую очередь ищет оператор?","tr":"Bir tehlike analizi yaparken (HACCP ilke 1), işletmeci öncelikle neyi arar?","hi":"खतरा विश्लेषण (HACCP सिद्धांत 1) करते समय, संचालक मुख्य रूप से क्या खोज रहा है?","ar":"عند إجراء تحليل المخاطر (المبدأ الأول لـ HACCP)، ما الذي يبحث عنه المشغل أساساً؟"},"o":[{"en":"The cheapest suppliers for each ingredient","es":"Los proveedores más baratos para cada ingrediente","ru":"Самых дешёвых поставщиков для каждого ингредиента","tr":"Her malzeme için en ucuz tedarikçileri","hi":"प्रत्येक सामग्री के लिए सबसे सस्ते आपूर्तिकर्ता","ar":"أرخص الموردين لكل مكوّن"},{"en":"Which menu items sell the most each week","es":"Qué platos del menú se venden más cada semana","ru":"Какие блюда меню продаются больше всего каждую неделю","tr":"Her hafta en çok hangi menü öğelerinin satıldığı","hi":"कौन से मेनू आइटम हर सप्ताह सबसे अधिक बिकते हैं","ar":"أي أصناف القائمة تُباع أكثر كل أسبوع"},{"en":"The biological, chemical, and physical hazards likely to occur at each step in the flow of food","es":"Los peligros biológicos, químicos y físicos que probablemente ocurran en cada etapa del flujo de alimentos","ru":"Биологические, химические и физические опасности, которые могут возникнуть на каждом этапе движения продукта","tr":"Gıda akışının her adımında meydana gelmesi muhtemel biyolojik, kimyasal ve fiziksel tehlikeler","hi":"जैविक, रासायनिक और भौतिक खतरे जो भोजन के प्रवाह के प्रत्येक चरण में होने की संभावना है","ar":"المخاطر البيولوجية والكيميائية والفيزيائية المحتمل حدوثها في كل خطوة من مسار الغذاء"},{"en":"The most popular plating and garnish styles","es":"Los estilos de emplatado y guarnición más populares","ru":"Самые популярные стили сервировки и украшения","tr":"En popüler tabaklama ve süsleme tarzları","hi":"सबसे लोकप्रिय प्लेटिंग और गार्निश शैलियाँ","ar":"أكثر أساليب التقديم والتزيين شعبية"}],"e":{"en":"A hazard analysis identifies the biological, chemical, and physical hazards that could occur at each step of a food's flow, so the operator can decide where control is critical.","es":"Un análisis de peligros identifica los peligros biológicos, químicos y físicos que podrían ocurrir en cada etapa del flujo de un alimento, para que el operador pueda decidir dónde el control es crítico.","ru":"Анализ опасностей выявляет биологические, химические и физические опасности, которые могут возникнуть на каждом этапе движения продукта, чтобы оператор мог решить, где контроль критичен.","tr":"Tehlike analizi, bir gıdanın akışının her adımında meydana gelebilecek biyolojik, kimyasal ve fiziksel tehlikeleri belirler, böylece işletmeci kontrolün nerede kritik olduğuna karar verebilir.","hi":"खतरा विश्लेषण उन जैविक, रासायनिक और भौतिक खतरों की पहचान करता है जो भोजन के प्रवाह के प्रत्येक चरण में हो सकते हैं, ताकि संचालक तय कर सके कि नियंत्रण कहाँ क्रांतिक है।","ar":"يحدد تحليل المخاطر المخاطر البيولوجية والكيميائية والفيزيائية التي قد تحدث في كل خطوة من مسار الغذاء، حتى يقرر المشغل أين تكون الرقابة حرجة."}},{"cat":"haccp","a":3,"q":{"en":"Several customers report similar gastrointestinal illness after eating at an establishment on the same day. What is the manager's most important immediate step?","es":"Varios clientes reportan una enfermedad gastrointestinal similar después de comer en un establecimiento el mismo día. ¿Cuál es el paso inmediato más importante del gerente?","ru":"Несколько клиентов сообщают о схожем желудочно-кишечном заболевании после еды в заведении в один и тот же день. Каков самый важный незамедлительный шаг менеджера?","tr":"Birkaç müşteri aynı gün bir işletmede yemek yedikten sonra benzer bir mide-bağırsak hastalığı bildirir. Müdürün en önemli acil adımı nedir?","hi":"कई ग्राहक एक ही दिन एक प्रतिष्ठान में खाना खाने के बाद समान गैस्ट्रोइंटेस्टाइनल बीमारी की रिपोर्ट करते हैं। प्रबंधक का सबसे महत्वपूर्ण तत्काल कदम क्या है?","ar":"يبلّغ عدة زبائن عن مرض معوي متشابه بعد تناول الطعام في منشأة في اليوم نفسه. ما هي أهم خطوة فورية للمدير؟"},"o":[{"en":"Fire the cook who prepared the suspected dish","es":"Despedir al cocinero que preparó el plato sospechoso","ru":"Уволить повара, приготовившего подозрительное блюдо","tr":"Şüpheli yemeği hazırlayan aşçıyı işten çıkarmak","hi":"संदिग्ध व्यंजन तैयार करने वाले रसोइये को नौकरी से निकाल दें","ar":"طرد الطاهي الذي أعدّ الطبق المشتبه به"},{"en":"Throw away all food evidence immediately to protect the business","es":"Desechar toda la evidencia de alimentos inmediatamente para proteger el negocio","ru":"Немедленно выбросить все пищевые улики, чтобы защитить бизнес","tr":"İşi korumak için tüm gıda kanıtlarını hemen atmak","hi":"व्यवसाय की रक्षा के लिए तुरंत सभी खाद्य साक्ष्य फेंक दें","ar":"التخلص من جميع أدلة الطعام فوراً لحماية العمل"},{"en":"Tell customers it must have been something they ate elsewhere","es":"Decir a los clientes que debe haber sido algo que comieron en otro lugar","ru":"Сказать клиентам, что это, должно быть, что-то, что они съели в другом месте","tr":"Müşterilere başka bir yerde yedikleri bir şey olmalı demek","hi":"ग्राहकों को बताएं कि यह कुछ ऐसा रहा होगा जो उन्होंने कहीं और खाया","ar":"إخبار الزبائن أنه لا بد أن يكون شيئاً تناولوه في مكان آخر"},{"en":"Contact the local regulatory authority and cooperate, while preserving suspect food and records","es":"Contactar a la autoridad reguladora local y cooperar, conservando los alimentos y registros sospechosos","ru":"Связаться с местным регулирующим органом и сотрудничать, сохраняя подозрительную еду и записи","tr":"Şüpheli gıdayı ve kayıtları koruyarak yerel düzenleyici otoriteyle iletişime geçmek ve işbirliği yapmak","hi":"स्थानीय नियामक प्राधिकरण से संपर्क करें और सहयोग करें, जबकि संदिग्ध भोजन और रिकॉर्ड को संरक्षित रखें","ar":"الاتصال بالجهة التنظيمية المحلية والتعاون معها، مع الحفاظ على الطعام المشتبه به والسجلات"}],"e":{"en":"When a foodborne illness outbreak is suspected, the manager should notify the regulatory authority, cooperate with the investigation, and preserve suspect food and records rather than destroying evidence.","es":"Cuando se sospecha un brote de enfermedad transmitida por alimentos, el gerente debe notificar a la autoridad reguladora, cooperar con la investigación y conservar los alimentos y registros sospechosos en lugar de destruir la evidencia.","ru":"При подозрении на вспышку пищевого заболевания менеджер должен уведомить регулирующий орган, сотрудничать в расследовании и сохранять подозрительную еду и записи, а не уничтожать улики.","tr":"Gıda kaynaklı bir hastalık salgınından şüphelenildiğinde, müdür düzenleyici otoriteyi bilgilendirmeli, soruşturmayla işbirliği yapmalı ve kanıtları yok etmek yerine şüpheli gıdayı ve kayıtları korumalıdır.","hi":"जब खाद्य जनित बीमारी के प्रकोप का संदेह हो, तो प्रबंधक को नियामक प्राधिकरण को सूचित करना चाहिए, जाँच में सहयोग करना चाहिए, और साक्ष्य नष्ट करने के बजाय संदिग्ध भोजन और रिकॉर्ड को संरक्षित रखना चाहिए।","ar":"عند الاشتباه في تفشٍّ لمرض منقول بالغذاء، ينبغي للمدير إخطار الجهة التنظيمية والتعاون في التحقيق والحفاظ على الطعام المشتبه به والسجلات بدلاً من إتلاف الأدلة."}},{"cat":"haccp","a":0,"q":{"en":"An operation wants to smoke fish as a method of preservation (not just for flavor). What is generally required before doing so?","es":"Una operación quiere ahumar pescado como método de conservación (no solo por sabor). ¿Qué se requiere generalmente antes de hacerlo?","ru":"Предприятие хочет коптить рыбу как метод консервирования (а не только для вкуса). Что обычно требуется перед этим?","tr":"Bir işletme balığı bir koruma yöntemi olarak (yalnızca lezzet için değil) tütsülemek istiyor. Bunu yapmadan önce genellikle ne gereklidir?","hi":"एक संचालन मछली को संरक्षण की एक विधि के रूप में (केवल स्वाद के लिए नहीं) धूम्रपान करना चाहता है। ऐसा करने से पहले आम तौर पर क्या आवश्यक है?","ar":"تريد منشأة تدخين السمك كوسيلة للحفظ (وليس فقط للنكهة). ما الذي يُطلب عموماً قبل القيام بذلك؟"},"o":[{"en":"A variance from the regulatory authority, usually with a HACCP plan","es":"Una variación de la autoridad reguladora, generalmente con un plan HACCP","ru":"Отклонение от регулирующего органа, обычно с планом HACCP","tr":"Genellikle bir HACCP planıyla birlikte düzenleyici otoriteden bir varyans","hi":"नियामक प्राधिकरण से एक विचलन, आमतौर पर HACCP योजना के साथ","ar":"استثناء من الجهة التنظيمية، عادةً مع خطة HACCP"},{"en":"Nothing; smoking food never requires any approval","es":"Nada; ahumar alimentos nunca requiere ninguna aprobación","ru":"Ничего; копчение продуктов никогда не требует одобрения","tr":"Hiçbir şey; gıda tütsüleme asla onay gerektirmez","hi":"कुछ नहीं; भोजन धूम्रपान करने के लिए कभी अनुमोदन की आवश्यकता नहीं होती","ar":"لا شيء؛ تدخين الطعام لا يتطلب أي موافقة أبداً"},{"en":"Only a consumer advisory on the menu","es":"Solo un aviso al consumidor en el menú","ru":"Только уведомление для потребителей в меню","tr":"Yalnızca menüde bir tüketici uyarısı","hi":"केवल मेनू पर एक उपभोक्ता सलाह","ar":"فقط إشعار للمستهلك في القائمة"},{"en":"Written approval from the fire marshal only","es":"Solo la aprobación escrita del jefe de bomberos","ru":"Только письменное одобрение начальника пожарной охраны","tr":"Yalnızca itfaiye amirinden yazılı onay","hi":"केवल अग्नि मार्शल से लिखित अनुमोदन","ar":"موافقة كتابية من مسؤول الإطفاء فقط"}],"e":{"en":"Smoking or curing food specifically to preserve it is a specialized process that requires a variance from the regulatory authority, typically supported by a HACCP plan.","es":"Ahumar o curar alimentos específicamente para conservarlos es un proceso especializado que requiere una variación de la autoridad reguladora, generalmente respaldada por un plan HACCP.","ru":"Копчение или посол продуктов именно для их консервирования — это специализированный процесс, требующий отклонения от регулирующего органа, обычно подкреплённого планом HACCP.","tr":"Gıdayı özellikle korumak için tütsülemek veya kürlemek, düzenleyici otoriteden bir varyans gerektiren ve genellikle bir HACCP planıyla desteklenen özel bir işlemdir.","hi":"भोजन को विशेष रूप से संरक्षित करने के लिए धूम्रपान या इलाज करना एक विशेष प्रक्रिया है जिसके लिए नियामक प्राधिकरण से विचलन की आवश्यकता होती है, जो आमतौर पर HACCP योजना द्वारा समर्थित होती है।","ar":"تدخين أو تمليح الطعام تحديداً لحفظه هو عملية متخصصة تتطلب استثناءً من الجهة التنظيمية، وعادةً ما يكون مدعوماً بخطة HACCP."}},{"cat":"haccp","a":1,"q":{"en":"'Controlling hands as a vehicle of contamination' is one of the FDA's public health interventions. Which practice most directly supports it?","es":"'Controlar las manos como vehículo de contaminación' es una de las intervenciones de salud pública de la FDA. ¿Qué práctica la respalda más directamente?","ru":"«Контроль рук как переносчика загрязнения» — одно из вмешательств общественного здравоохранения FDA. Какая практика наиболее прямо его поддерживает?","tr":"'Elleri bir bulaşma aracı olarak kontrol etmek' FDA'nın halk sağlığı müdahalelerinden biridir. Hangi uygulama bunu en doğrudan destekler?","hi":"'हाथों को संदूषण के वाहन के रूप में नियंत्रित करना' FDA के सार्वजनिक स्वास्थ्य हस्तक्षेपों में से एक है। कौन सा अभ्यास इसका सबसे प्रत्यक्ष समर्थन करता है?","ar":"'التحكم في الأيدي كوسيلة للتلوث' هو أحد تدخلات الصحة العامة لدى FDA. أي ممارسة تدعمه بشكل مباشر أكثر؟"},"o":[{"en":"Cooking all foods to 165°F","es":"Cocinar todos los alimentos a 165°F","ru":"Приготовление всех продуктов до 165°F","tr":"Tüm gıdaları 165°F'ye kadar pişirmek","hi":"सभी खाद्य पदार्थों को 165°F तक पकाना","ar":"طهي جميع الأطعمة إلى 165°F"},{"en":"Requiring proper handwashing and no bare-hand contact with ready-to-eat food","es":"Exigir el lavado de manos adecuado y ningún contacto de manos desnudas con alimentos listos para comer","ru":"Требование правильного мытья рук и отсутствия контакта голыми руками с готовой к употреблению едой","tr":"Uygun el yıkamayı ve yemeye hazır gıdayla çıplak el temasının olmamasını zorunlu kılmak","hi":"उचित हाथ धोने और खाने के लिए तैयार भोजन के साथ नंगे हाथ के संपर्क न होने की आवश्यकता","ar":"اشتراط غسل اليدين بشكل صحيح وعدم ملامسة الطعام الجاهز للأكل باليدين العاريتين"},{"en":"Buying food only from approved suppliers","es":"Comprar alimentos solo de proveedores aprobados","ru":"Покупка продуктов только у утверждённых поставщиков","tr":"Gıdayı yalnızca onaylı tedarikçilerden satın almak","hi":"केवल अनुमोदित आपूर्तिकर्ताओं से भोजन खरीदना","ar":"شراء الطعام فقط من موردين معتمدين"},{"en":"Posting a consumer advisory for raw oysters","es":"Publicar un aviso al consumidor para ostras crudas","ru":"Размещение уведомления для потребителей о сырых устрицах","tr":"Çiğ istiridyeler için bir tüketici uyarısı asmak","hi":"कच्चे सीप के लिए एक उपभोक्ता सलाह पोस्ट करना","ar":"نشر إشعار للمستهلك بشأن المحار النيء"}],"e":{"en":"Controlling hands as a vehicle of contamination is achieved through proper handwashing and prohibiting bare-hand contact with ready-to-eat food, which prevents transfer of pathogens like Norovirus.","es":"Controlar las manos como vehículo de contaminación se logra mediante el lavado de manos adecuado y la prohibición del contacto de manos desnudas con alimentos listos para comer, lo que evita la transferencia de patógenos como el Norovirus.","ru":"Контроль рук как переносчика загрязнения достигается через правильное мытьё рук и запрет контакта голыми руками с готовой к употреблению едой, что предотвращает передачу патогенов, таких как норовирус.","tr":"Elleri bir bulaşma aracı olarak kontrol etmek, uygun el yıkama ve yemeye hazır gıdayla çıplak el temasının yasaklanmasıyla sağlanır; bu, Norovirüs gibi patojenlerin geçişini önler.","hi":"हाथों को संदूषण के वाहन के रूप में नियंत्रित करना उचित हाथ धोने और खाने के लिए तैयार भोजन के साथ नंगे हाथ के संपर्क पर प्रतिबंध के माध्यम से प्राप्त किया जाता है, जो नोरोवायरस जैसे रोगजनकों के हस्तांतरण को रोकता है।","ar":"يتحقق التحكم في الأيدي كوسيلة للتلوث من خلال غسل اليدين بشكل صحيح وحظر ملامسة الطعام الجاهز للأكل باليدين العاريتين، مما يمنع انتقال مسببات الأمراض مثل النوروفيروس."}},{"cat":"haccp","a":2,"q":{"en":"Which of the following is a key TIME/TEMPERATURE parameter used as a public health intervention?","es":"¿Cuál de los siguientes es un parámetro clave de TIEMPO/TEMPERATURA usado como intervención de salud pública?","ru":"Что из перечисленного является ключевым параметром ВРЕМЯ/ТЕМПЕРАТУРА, используемым как вмешательство общественного здравоохранения?","tr":"Aşağıdakilerden hangisi halk sağlığı müdahalesi olarak kullanılan önemli bir SÜRE/SICAKLIK parametresidir?","hi":"निम्नलिखित में से कौन सा एक प्रमुख समय/तापमान पैरामीटर है जिसे सार्वजनिक स्वास्थ्य हस्तक्षेप के रूप में उपयोग किया जाता है?","ar":"أي مما يلي هو معلمة رئيسية للوقت/الحرارة تُستخدم كتدخل صحي عام؟"},"o":[{"en":"Serving all cold food within 30 minutes of plating","es":"Servir todos los alimentos fríos dentro de los 30 minutos de emplatarlos","ru":"Подача всей холодной еды в течение 30 минут после выкладывания","tr":"Tüm soğuk yemekleri tabaklamadan sonraki 30 dakika içinde servis etmek","hi":"सभी ठंडे भोजन को प्लेटिंग के 30 मिनट के भीतर परोसना","ar":"تقديم جميع الأطعمة الباردة خلال 30 دقيقة من وضعها في الأطباق"},{"en":"Keeping all foods frozen until the moment of service","es":"Mantener todos los alimentos congelados hasta el momento del servicio","ru":"Хранение всех продуктов замороженными до момента подачи","tr":"Tüm gıdaları servis anına kadar dondurulmuş tutmak","hi":"सभी खाद्य पदार्थों को सेवा के क्षण तक जमे हुए रखना","ar":"إبقاء جميع الأطعمة مجمّدة حتى لحظة التقديم"},{"en":"Holding hot TCS food at 135°F or above and cold TCS food at 41°F or below","es":"Mantener los alimentos TCS calientes a 135°F o más y los alimentos TCS fríos a 41°F o menos","ru":"Хранение горячей TCS-еды при 135°F или выше и холодной TCS-еды при 41°F или ниже","tr":"Sıcak TCS gıdasını 135°F veya üzerinde, soğuk TCS gıdasını 41°F veya altında tutmak","hi":"गर्म TCS भोजन को 135°F या उससे अधिक और ठंडे TCS भोजन को 41°F या उससे कम पर रखना","ar":"حفظ طعام TCS الساخن عند 135°F أو أعلى وطعام TCS البارد عند 41°F أو أقل"},{"en":"Reheating food only once per day","es":"Recalentar los alimentos solo una vez al día","ru":"Разогрев еды только один раз в день","tr":"Yemeği günde yalnızca bir kez yeniden ısıtmak","hi":"भोजन को दिन में केवल एक बार फिर से गर्म करना","ar":"إعادة تسخين الطعام مرة واحدة فقط في اليوم"}],"e":{"en":"Time and temperature parameters — such as holding hot TCS food at 135°F or above and cold at 41°F or below — are core public health interventions that limit pathogen growth.","es":"Los parámetros de tiempo y temperatura, como mantener los alimentos TCS calientes a 135°F o más y los fríos a 41°F o menos, son intervenciones de salud pública fundamentales que limitan el crecimiento de patógenos.","ru":"Параметры времени и температуры — например, хранение горячей TCS-еды при 135°F или выше и холодной при 41°F или ниже — являются основными вмешательствами общественного здравоохранения, ограничивающими рост патогенов.","tr":"Süre ve sıcaklık parametreleri — sıcak TCS gıdasını 135°F veya üzerinde, soğuğu 41°F veya altında tutmak gibi — patojen üremesini sınırlayan temel halk sağlığı müdahaleleridir.","hi":"समय और तापमान पैरामीटर — जैसे गर्म TCS भोजन को 135°F या उससे अधिक और ठंडे को 41°F या उससे कम पर रखना — मुख्य सार्वजनिक स्वास्थ्य हस्तक्षेप हैं जो रोगज़नक़ वृद्धि को सीमित करते हैं।","ar":"معلمات الوقت والحرارة — مثل حفظ طعام TCS الساخن عند 135°F أو أعلى والبارد عند 41°F أو أقل — هي تدخلات صحية عامة أساسية تحد من نمو مسببات الأمراض."}},{"cat":"haccp","a":3,"q":{"en":"A power outage lasting several hours knocks out all refrigeration. What is the manager's most appropriate response for the affected cold TCS foods?","es":"Un corte de energía de varias horas deja sin funcionar toda la refrigeración. ¿Cuál es la respuesta más apropiada del gerente para los alimentos TCS fríos afectados?","ru":"Отключение электроэнергии на несколько часов выводит из строя всё охлаждение. Какова наиболее подходящая реакция менеджера в отношении затронутых холодных TCS-продуктов?","tr":"Birkaç saat süren elektrik kesintisi tüm soğutmayı devre dışı bırakır. Etkilenen soğuk TCS gıdaları için müdürün en uygun tepkisi nedir?","hi":"कई घंटों तक चलने वाली बिजली की कटौती सभी प्रशीतन को बंद कर देती है। प्रभावित ठंडे TCS खाद्य पदार्थों के लिए प्रबंधक की सबसे उपयुक्त प्रतिक्रिया क्या है?","ar":"انقطاع للتيار الكهربائي لعدة ساعات يعطّل جميع أنظمة التبريد. ما هي الاستجابة الأنسب للمدير بشأن أطعمة TCS الباردة المتأثرة؟"},"o":[{"en":"Keep serving the food since it looks and smells fine","es":"Seguir sirviendo los alimentos ya que se ven y huelen bien","ru":"Продолжать подавать еду, поскольку она выглядит и пахнет нормально","tr":"Görünüşü ve kokusu iyi olduğu için yemeği servis etmeye devam etmek","hi":"भोजन परोसना जारी रखें क्योंकि यह देखने और सूँघने में ठीक लगता है","ar":"متابعة تقديم الطعام لأنه يبدو ورائحته جيدة"},{"en":"Move the food to the dining room where it is cooler","es":"Mover los alimentos al comedor donde hace más fresco","ru":"Переместить еду в обеденный зал, где прохладнее","tr":"Yemeği daha serin olan yemek salonuna taşımak","hi":"भोजन को भोजन कक्ष में ले जाएँ जहाँ यह ठंडा है","ar":"نقل الطعام إلى صالة الطعام حيث تكون أبرد"},{"en":"Refreeze everything as soon as power returns","es":"Volver a congelar todo tan pronto como regrese la energía","ru":"Заморозить всё снова, как только вернётся электричество","tr":"Elektrik gelir gelmez her şeyi yeniden dondurmak","hi":"बिजली वापस आते ही सब कुछ फिर से जमा दें","ar":"إعادة تجميد كل شيء بمجرد عودة الكهرباء"},{"en":"Assess time/temperature exposure; discard TCS food that exceeded safe limits and consider whether operations must cease","es":"Evaluar la exposición de tiempo/temperatura; desechar los alimentos TCS que superaron los límites seguros y considerar si las operaciones deben cesar","ru":"Оценить воздействие времени/температуры; выбросить TCS-еду, превысившую безопасные пределы, и рассмотреть, следует ли прекратить работу","tr":"Süre/sıcaklık maruziyetini değerlendirmek; güvenli limitleri aşan TCS gıdasını atmak ve faaliyetlerin durdurulup durdurulmayacağını değerlendirmek","hi":"समय/तापमान जोखिम का आकलन करें; सुरक्षित सीमा से अधिक TCS भोजन को फेंक दें और विचार करें कि क्या संचालन बंद करना चाहिए","ar":"تقييم التعرّض للوقت/الحرارة؛ والتخلص من طعام TCS الذي تجاوز الحدود الآمنة، والنظر في ما إذا كان يجب إيقاف العمليات"}],"e":{"en":"Loss of refrigeration can create an imminent health hazard. The manager must evaluate how long TCS food was in the danger zone, discard unsafe food, and may need to cease operations and notify the authority.","es":"La pérdida de refrigeración puede crear un peligro inminente para la salud. El gerente debe evaluar cuánto tiempo estuvieron los alimentos TCS en la zona de peligro, desechar los alimentos inseguros y quizás deba cesar operaciones y notificar a la autoridad.","ru":"Потеря охлаждения может создать неминуемую угрозу здоровью. Менеджер должен оценить, как долго TCS-еда находилась в опасной зоне, выбросить небезопасную еду и, возможно, прекратить работу и уведомить орган.","tr":"Soğutma kaybı yakın bir sağlık tehlikesi yaratabilir. Müdür TCS gıdasının tehlike bölgesinde ne kadar kaldığını değerlendirmeli, güvensiz gıdayı atmalı ve faaliyetleri durdurup otoriteyi bilgilendirmesi gerekebilir.","hi":"प्रशीतन की हानि एक आसन्न स्वास्थ्य खतरा पैदा कर सकती है। प्रबंधक को यह आकलन करना चाहिए कि TCS भोजन कितने समय तक खतरे के क्षेत्र में था, असुरक्षित भोजन को फेंक देना चाहिए, और संचालन बंद करके प्राधिकरण को सूचित करने की आवश्यकता हो सकती है।","ar":"قد يشكّل فقدان التبريد خطراً صحياً وشيكاً. يجب على المدير تقييم مدة بقاء طعام TCS في منطقة الخطر، والتخلص من الطعام غير الآمن، وقد يحتاج إلى إيقاف العمليات وإخطار الجهة المختصة."}},{"cat":"haccp","a":0,"q":{"en":"Which HACCP principle involves keeping temperature logs, monitoring charts, and corrective-action records on file?","es":"¿Qué principio HACCP implica mantener archivadas las bitácoras de temperatura, los cuadros de monitoreo y los registros de acciones correctivas?","ru":"Какой принцип HACCP предполагает хранение журналов температур, графиков мониторинга и записей о корректирующих действиях?","tr":"Hangi HACCP ilkesi sıcaklık kayıtlarını, izleme çizelgelerini ve düzeltici faaliyet kayıtlarını dosyada tutmayı içerir?","hi":"कौन सा HACCP सिद्धांत तापमान लॉग, निगरानी चार्ट और सुधारात्मक-कार्रवाई रिकॉर्ड को फ़ाइल में रखना शामिल करता है?","ar":"أي مبدأ من مبادئ HACCP يتضمن حفظ سجلات الحرارة وجداول المراقبة وسجلات الإجراءات التصحيحية في الملف؟"},"o":[{"en":"Establishing record-keeping and documentation procedures (principle 7)","es":"Establecer procedimientos de mantenimiento de registros y documentación (principio 7)","ru":"Установление процедур ведения записей и документации (принцип 7)","tr":"Kayıt tutma ve belgeleme prosedürlerini belirlemek (ilke 7)","hi":"अभिलेख रखने और प्रलेखन प्रक्रियाएँ स्थापित करना (सिद्धांत 7)","ar":"وضع إجراءات حفظ السجلات والتوثيق (المبدأ 7)"},{"en":"Conducting a hazard analysis (principle 1)","es":"Realizar un análisis de peligros (principio 1)","ru":"Проведение анализа опасностей (принцип 1)","tr":"Tehlike analizi yapmak (ilke 1)","hi":"खतरा विश्लेषण करना (सिद्धांत 1)","ar":"إجراء تحليل المخاطر (المبدأ 1)"},{"en":"Determining critical control points (principle 2)","es":"Determinar puntos críticos de control (principio 2)","ru":"Определение критических контрольных точек (принцип 2)","tr":"Kritik kontrol noktalarını belirlemek (ilke 2)","hi":"क्रांतिक नियंत्रण बिंदु निर्धारित करना (सिद्धांत 2)","ar":"تحديد نقاط التحكم الحرجة (المبدأ 2)"},{"en":"Establishing critical limits (principle 3)","es":"Establecer límites críticos (principio 3)","ru":"Установление критических пределов (принцип 3)","tr":"Kritik limitleri belirlemek (ilke 3)","hi":"क्रांतिक सीमाएँ स्थापित करना (सिद्धांत 3)","ar":"تحديد الحدود الحرجة (المبدأ 3)"}],"e":{"en":"Principle 7, record-keeping and documentation, requires maintaining records such as monitoring logs and corrective actions to demonstrate the HACCP system is functioning.","es":"El principio 7, mantenimiento de registros y documentación, exige mantener registros como bitácoras de monitoreo y acciones correctivas para demostrar que el sistema HACCP está funcionando.","ru":"Принцип 7, ведение записей и документация, требует хранения таких записей, как журналы мониторинга и корректирующие действия, чтобы продемонстрировать функционирование системы HACCP.","tr":"İlke 7, kayıt tutma ve belgeleme, HACCP sisteminin çalıştığını göstermek için izleme kayıtları ve düzeltici faaliyetler gibi kayıtların tutulmasını gerektirir.","hi":"सिद्धांत 7, अभिलेख रखना और प्रलेखन, HACCP प्रणाली के कार्य करने को प्रदर्शित करने के लिए निगरानी लॉग और सुधारात्मक कार्रवाइयों जैसे रिकॉर्ड बनाए रखने की आवश्यकता होती है।","ar":"المبدأ 7، حفظ السجلات والتوثيق، يتطلب الاحتفاظ بسجلات مثل سجلات المراقبة والإجراءات التصحيحية لإثبات أن نظام HACCP يعمل."}},{"cat":"haccp","a":1,"q":{"en":"To control the CDC risk factor of 'contaminated equipment' through active managerial control, a manager should primarily focus on:","es":"Para controlar el factor de riesgo de los CDC de 'equipo contaminado' mediante el control gerencial activo, un gerente debe enfocarse principalmente en:","ru":"Чтобы контролировать фактор риска CDC «загрязнённое оборудование» с помощью активного управленческого контроля, менеджер должен в первую очередь сосредоточиться на:","tr":"'Kirlenmiş ekipman' CDC risk faktörünü aktif yönetimsel kontrol yoluyla kontrol etmek için, bir müdür öncelikle neye odaklanmalıdır:","hi":"सक्रिय प्रबंधकीय नियंत्रण के माध्यम से 'दूषित उपकरण' के CDC जोखिम कारक को नियंत्रित करने के लिए, एक प्रबंधक को मुख्य रूप से किस पर ध्यान केंद्रित करना चाहिए:","ar":"للتحكم في عامل الخطر لدى CDC المتمثل في 'المعدات الملوثة' من خلال الرقابة الإدارية الفعّالة، ينبغي للمدير التركيز أساساً على:"},"o":[{"en":"Reducing the number of menu items offered","es":"Reducir la cantidad de platos ofrecidos en el menú","ru":"Сокращение количества предлагаемых блюд меню","tr":"Sunulan menü öğesi sayısını azaltmak","hi":"पेश किए गए मेनू आइटम की संख्या कम करना","ar":"تقليل عدد أصناف القائمة المقدمة"},{"en":"Cleaning and sanitizing procedures and preventing cross-contamination","es":"Los procedimientos de limpieza y desinfección y la prevención de la contaminación cruzada","ru":"Процедурах очистки и дезинфекции и предотвращении перекрёстного загрязнения","tr":"Temizlik ve dezenfeksiyon prosedürleri ve çapraz bulaşmayı önleme","hi":"सफाई और स्वच्छता प्रक्रियाओं और क्रॉस-संदूषण को रोकना","ar":"إجراءات التنظيف والتطهير ومنع التلوث المتبادل"},{"en":"Lowering the thermostat in the dining room","es":"Bajar el termostato en el comedor","ru":"Понижение термостата в обеденном зале","tr":"Yemek salonundaki termostatı düşürmek","hi":"भोजन कक्ष में थर्मोस्टेट कम करना","ar":"خفض منظم الحرارة في صالة الطعام"},{"en":"Increasing portion sizes for customers","es":"Aumentar el tamaño de las porciones para los clientes","ru":"Увеличение размеров порций для клиентов","tr":"Müşteriler için porsiyon boyutlarını artırmak","hi":"ग्राहकों के लिए भाग के आकार बढ़ाना","ar":"زيادة أحجام الحصص للزبائن"}],"e":{"en":"The 'contaminated equipment' risk factor is controlled by proper cleaning and sanitizing schedules and by preventing cross-contamination between raw and ready-to-eat foods.","es":"El factor de riesgo de 'equipo contaminado' se controla mediante horarios adecuados de limpieza y desinfección y evitando la contaminación cruzada entre alimentos crudos y listos para comer.","ru":"Фактор риска «загрязнённое оборудование» контролируется правильными графиками очистки и дезинфекции и предотвращением перекрёстного загрязнения между сырыми и готовыми к употреблению продуктами.","tr":"'Kirlenmiş ekipman' risk faktörü, uygun temizlik ve dezenfeksiyon programlarıyla ve çiğ ile yemeye hazır gıdalar arasında çapraz bulaşmanın önlenmesiyle kontrol edilir.","hi":"'दूषित उपकरण' जोखिम कारक को उचित सफाई और स्वच्छता कार्यक्रमों और कच्चे तथा खाने के लिए तैयार खाद्य पदार्थों के बीच क्रॉस-संदूषण को रोककर नियंत्रित किया जाता है।","ar":"يتم التحكم في عامل خطر 'المعدات الملوثة' من خلال جداول التنظيف والتطهير المناسبة ومنع التلوث المتبادل بين الأطعمة النيئة والجاهزة للأكل."}},{"cat":"haccp","a":2,"q":{"en":"Which of the following activities would typically require a variance from the regulatory authority?","es":"¿Cuál de las siguientes actividades normalmente requeriría una variación de la autoridad reguladora?","ru":"Какая из следующих деятельностей обычно требует отклонения от регулирующего органа?","tr":"Aşağıdaki faaliyetlerden hangisi genellikle düzenleyici otoriteden bir varyans gerektirir?","hi":"निम्नलिखित में से कौन सी गतिविधि आमतौर पर नियामक प्राधिकरण से विचलन की आवश्यकता होगी?","ar":"أي من الأنشطة التالية يتطلب عادةً استثناءً من الجهة التنظيمية؟"},"o":[{"en":"Reheating leftover chili to 165°F for hot holding","es":"Recalentar el chili sobrante a 165°F para mantenimiento en caliente","ru":"Разогрев оставшегося чили до 165°F для горячего хранения","tr":"Artan chili'yi sıcak bekletme için 165°F'ye yeniden ısıtmak","hi":"बचे हुए चिली को गर्म रखने के लिए 165°F तक फिर से गर्म करना","ar":"إعادة تسخين بقايا التشيلي إلى 165°F للحفظ الساخن"},{"en":"Storing raw chicken below ready-to-eat foods in the cooler","es":"Almacenar pollo crudo debajo de los alimentos listos para comer en el refrigerador","ru":"Хранение сырой курицы под готовыми к употреблению продуктами в холодильнике","tr":"Soğutucuda çiğ tavuğu yemeye hazır gıdaların altında depolamak","hi":"कूलर में खाने के लिए तैयार खाद्य पदार्थों के नीचे कच्चा चिकन संग्रहीत करना","ar":"تخزين الدجاج النيء أسفل الأطعمة الجاهزة للأكل في المبرّد"},{"en":"Sprouting seeds or beans for sale to the public","es":"Germinar semillas o frijoles para la venta al público","ru":"Проращивание семян или бобов для продажи населению","tr":"Halka satış için tohum veya fasulye filizlendirmek","hi":"जनता को बिक्री के लिए बीज या फलियाँ अंकुरित करना","ar":"إنبات البذور أو الفاصولياء للبيع للجمهور"},{"en":"Slicing deli meat on a clean, sanitized slicer","es":"Cortar fiambre en una rebanadora limpia y desinfectada","ru":"Нарезка мясной нарезки на чистом, продезинфицированном слайсере","tr":"Şarküteri etini temiz, dezenfekte edilmiş bir dilimleyicide dilimlemek","hi":"एक साफ, स्वच्छ स्लाइसर पर डेली मीट काटना","ar":"تقطيع لحم الأطعمة الجاهزة على قطّاعة نظيفة ومطهّرة"}],"e":{"en":"Sprouting seeds or beans is a specialized process that supports pathogen growth and typically requires a variance, often with a HACCP plan. The other options are routine safe practices.","es":"Germinar semillas o frijoles es un proceso especializado que favorece el crecimiento de patógenos y normalmente requiere una variación, a menudo con un plan HACCP. Las otras opciones son prácticas seguras rutinarias.","ru":"Проращивание семян или бобов — это специализированный процесс, поддерживающий рост патогенов, и обычно требует отклонения, часто с планом HACCP. Другие варианты — обычные безопасные практики.","tr":"Tohum veya fasulye filizlendirmek, patojen üremesini destekleyen ve genellikle bir varyans (çoğunlukla bir HACCP planıyla) gerektiren özel bir işlemdir. Diğer seçenekler rutin güvenli uygulamalardır.","hi":"बीज या फलियाँ अंकुरित करना एक विशेष प्रक्रिया है जो रोगज़नक़ वृद्धि का समर्थन करती है और आमतौर पर विचलन की आवश्यकता होती है, अक्सर HACCP योजना के साथ। अन्य विकल्प नियमित सुरक्षित अभ्यास हैं।","ar":"إنبات البذور أو الفاصولياء عملية متخصصة تدعم نمو مسببات الأمراض وتتطلب عادةً استثناءً، غالباً مع خطة HACCP. الخيارات الأخرى ممارسات آمنة روتينية."}},{"cat":"haccp","a":3,"q":{"en":"An operation plans to add nitrites as a curing agent to preserve its house-made bacon. This is an example of a process that:","es":"Una operación planea agregar nitritos como agente de curado para conservar su tocino casero. Este es un ejemplo de un proceso que:","ru":"Предприятие планирует добавлять нитриты в качестве посолочного агента для консервирования бекона собственного производства. Это пример процесса, который:","tr":"Bir işletme, kendi ürettiği pastırmayı korumak için kürleme maddesi olarak nitrit eklemeyi planlıyor. Bu, şu tür bir işlemin örneğidir:","hi":"एक संचालन अपने घर के बने बेकन को संरक्षित करने के लिए इलाज एजेंट के रूप में नाइट्राइट जोड़ने की योजना बना रहा है। यह एक ऐसी प्रक्रिया का उदाहरण है जो:","ar":"تخطط منشأة لإضافة النتريت كعامل تمليح لحفظ لحم الخنزير المقدد المُعدّ منزلياً. هذا مثال على عملية:"},"o":[{"en":"Never needs any regulatory oversight","es":"Nunca necesita ninguna supervisión reguladora","ru":"Никогда не нуждается в надзоре со стороны регулятора","tr":"Asla herhangi bir düzenleyici denetim gerektirmez","hi":"कभी किसी नियामक निगरानी की आवश्यकता नहीं होती","ar":"لا تحتاج أبداً إلى أي إشراف تنظيمي"},{"en":"Only requires a consumer advisory","es":"Solo requiere un aviso al consumidor","ru":"Требует только уведомления для потребителей","tr":"Yalnızca bir tüketici uyarısı gerektirir","hi":"केवल एक उपभोक्ता सलाह की आवश्यकता होती है","ar":"تتطلب فقط إشعاراً للمستهلك"},{"en":"Is identical to simply seasoning meat with salt","es":"Es idéntico a simplemente sazonar la carne con sal","ru":"Идентичен простому приправлению мяса солью","tr":"Eti sadece tuzla baharatlamakla aynıdır","hi":"मांस को केवल नमक के साथ मसाला लगाने के समान है","ar":"مطابق لمجرد تتبيل اللحم بالملح"},{"en":"Uses food additives to preserve food and generally requires a variance and a HACCP plan","es":"Usa aditivos alimentarios para conservar los alimentos y generalmente requiere una variación y un plan HACCP","ru":"Использует пищевые добавки для консервирования и обычно требует отклонения и плана HACCP","tr":"Gıdayı korumak için gıda katkı maddeleri kullanır ve genellikle bir varyans ve HACCP planı gerektirir","hi":"भोजन को संरक्षित करने के लिए खाद्य योजकों का उपयोग करता है और आमतौर पर विचलन और HACCP योजना की आवश्यकता होती है","ar":"تستخدم المضافات الغذائية لحفظ الطعام وتتطلب عموماً استثناءً وخطة HACCP"}],"e":{"en":"Using food additives or curing agents such as nitrites to preserve food is a specialized process that generally requires a variance from the regulatory authority and a supporting HACCP plan.","es":"Usar aditivos alimentarios o agentes de curado como los nitritos para conservar alimentos es un proceso especializado que generalmente requiere una variación de la autoridad reguladora y un plan HACCP de respaldo.","ru":"Использование пищевых добавок или посолочных агентов, таких как нитриты, для консервирования пищи — это специализированный процесс, обычно требующий отклонения от регулирующего органа и подкрепляющего плана HACCP.","tr":"Gıdayı korumak için nitrit gibi gıda katkı maddeleri veya kürleme maddeleri kullanmak, genellikle düzenleyici otoriteden bir varyans ve destekleyici bir HACCP planı gerektiren özel bir işlemdir.","hi":"भोजन को संरक्षित करने के लिए नाइट्राइट जैसे खाद्य योजकों या इलाज एजेंटों का उपयोग एक विशेष प्रक्रिया है जिसके लिए आमतौर पर नियामक प्राधिकरण से विचलन और एक सहायक HACCP योजना की आवश्यकता होती है।","ar":"استخدام المضافات الغذائية أو عوامل التمليح مثل النتريت لحفظ الطعام هو عملية متخصصة تتطلب عموماً استثناءً من الجهة التنظيمية وخطة HACCP داعمة."}},{"cat":"haccp","a":0,"q":{"en":"The FDA public health intervention of 'demonstration of knowledge' is best satisfied when:","es":"La intervención de salud pública de la FDA de 'demostración de conocimiento' se cumple mejor cuando:","ru":"Вмешательство общественного здравоохранения FDA «демонстрация знаний» лучше всего выполняется, когда:","tr":"FDA'nın 'bilgi gösterimi' halk sağlığı müdahalesi en iyi ne zaman karşılanır:","hi":"FDA का 'ज्ञान का प्रदर्शन' सार्वजनिक स्वास्थ्य हस्तक्षेप सबसे अच्छा तब पूरा होता है जब:","ar":"يتحقق تدخل الصحة العامة لدى FDA المتمثل في 'إثبات المعرفة' بشكل أفضل عندما:"},"o":[{"en":"The person in charge can demonstrate food safety knowledge, such as being a certified food protection manager","es":"La persona a cargo puede demostrar conocimiento de seguridad alimentaria, como ser un gerente certificado de protección de alimentos","ru":"Ответственное лицо может продемонстрировать знания по безопасности пищевых продуктов, например, будучи сертифицированным менеджером по защите пищевых продуктов","tr":"Sorumlu kişi, sertifikalı bir gıda koruma müdürü olmak gibi gıda güvenliği bilgisini gösterebildiğinde","hi":"प्रभारी व्यक्ति खाद्य सुरक्षा ज्ञान का प्रदर्शन कर सकता है, जैसे प्रमाणित खाद्य संरक्षण प्रबंधक होना","ar":"يستطيع الشخص المسؤول إثبات معرفته بسلامة الغذاء، مثل كونه مدير حماية غذاء معتمداً"},{"en":"Every customer signs a liability waiver","es":"Cada cliente firma una exención de responsabilidad","ru":"Каждый клиент подписывает отказ от ответственности","tr":"Her müşteri bir sorumluluk feragatnamesi imzaladığında","hi":"प्रत्येक ग्राहक एक देयता छूट पर हस्ताक्षर करता है","ar":"يوقّع كل زبون على إعفاء من المسؤولية"},{"en":"The kitchen posts its menu prices publicly","es":"La cocina publica sus precios de menú públicamente","ru":"Кухня публично размещает цены своего меню","tr":"Mutfak menü fiyatlarını halka açık şekilde ilan ettiğinde","hi":"रसोई अपने मेनू मूल्य सार्वजनिक रूप से पोस्ट करती है","ar":"يعلن المطبخ أسعار قائمته للجمهور"},{"en":"The dining room passes a fire inspection","es":"El comedor pasa una inspección de incendios","ru":"Обеденный зал проходит противопожарную проверку","tr":"Yemek salonu bir yangın denetiminden geçtiğinde","hi":"भोजन कक्ष अग्नि निरीक्षण पास करता है","ar":"تجتاز صالة الطعام تفتيش الحرائق"}],"e":{"en":"Demonstration of knowledge is met when the person in charge can show food safety competence — commonly by holding a Certified Food Protection Manager credential or answering an inspector's questions correctly.","es":"La demostración de conocimiento se cumple cuando la persona a cargo puede mostrar competencia en seguridad alimentaria, comúnmente al tener una credencial de Gerente Certificado de Protección de Alimentos o responder correctamente las preguntas de un inspector.","ru":"Демонстрация знаний выполняется, когда ответственное лицо может показать компетентность в безопасности пищевых продуктов — обычно имея сертификат менеджера по защите пищевых продуктов или правильно отвечая на вопросы инспектора.","tr":"Bilgi gösterimi, sorumlu kişi gıda güvenliği yetkinliğini gösterebildiğinde karşılanır — genellikle Sertifikalı Gıda Koruma Müdürü belgesine sahip olarak veya bir müfettişin sorularını doğru yanıtlayarak.","hi":"ज्ञान का प्रदर्शन तब पूरा होता है जब प्रभारी व्यक्ति खाद्य सुरक्षा दक्षता दिखा सकता है — आमतौर पर प्रमाणित खाद्य संरक्षण प्रबंधक प्रमाणपत्र रखकर या निरीक्षक के प्रश्नों का सही उत्तर देकर।","ar":"يتحقق إثبات المعرفة عندما يستطيع الشخص المسؤول إظهار كفاءته في سلامة الغذاء — عادةً بحمل شهادة مدير حماية غذاء معتمد أو الإجابة الصحيحة على أسئلة المفتش."}},{"cat":"haccp","a":1,"q":{"en":"As part of the 'employee health controls' public health intervention, a manager should ensure that the establishment has:","es":"Como parte de la intervención de salud pública de 'controles de salud de los empleados', un gerente debe asegurarse de que el establecimiento tenga:","ru":"В рамках вмешательства общественного здравоохранения «контроль здоровья сотрудников» менеджер должен обеспечить, чтобы у заведения было:","tr":"'Çalışan sağlığı kontrolleri' halk sağlığı müdahalesinin bir parçası olarak, bir müdür işletmenin şuna sahip olmasını sağlamalıdır:","hi":"'कर्मचारी स्वास्थ्य नियंत्रण' सार्वजनिक स्वास्थ्य हस्तक्षेप के भाग के रूप में, एक प्रबंधक को यह सुनिश्चित करना चाहिए कि प्रतिष्ठान के पास हो:","ar":"كجزء من تدخل الصحة العامة المتمثل في 'ضوابط صحة الموظفين'، ينبغي للمدير التأكد من أن المنشأة لديها:"},"o":[{"en":"A rule allowing sick employees to keep working if they wear gloves","es":"Una regla que permita a los empleados enfermos seguir trabajando si usan guantes","ru":"Правило, позволяющее больным сотрудникам продолжать работать, если они носят перчатки","tr":"Hasta çalışanların eldiven giyerlerse çalışmaya devam etmelerine izin veren bir kural","hi":"एक नियम जो बीमार कर्मचारियों को दस्ताने पहनने पर काम जारी रखने की अनुमति देता है","ar":"قاعدة تسمح للموظفين المرضى بمواصلة العمل إذا ارتدوا القفازات"},{"en":"A written policy requiring employees to report symptoms and specified illnesses, with exclusion or restriction as needed","es":"Una política escrita que exija a los empleados reportar síntomas y enfermedades específicas, con exclusión o restricción según sea necesario","ru":"Письменную политику, требующую от сотрудников сообщать о симптомах и определённых заболеваниях, с отстранением или ограничением по мере необходимости","tr":"Çalışanların semptomları ve belirli hastalıkları bildirmesini gerektiren, gerektiğinde uzaklaştırma veya kısıtlama içeren yazılı bir politika","hi":"एक लिखित नीति जिसमें कर्मचारियों को लक्षणों और निर्दिष्ट बीमारियों की रिपोर्ट करने की आवश्यकता होती है, आवश्यकतानुसार बहिष्कार या प्रतिबंध के साथ","ar":"سياسة مكتوبة تُلزم الموظفين بالإبلاغ عن الأعراض والأمراض المحددة، مع الاستبعاد أو التقييد حسب الحاجة"},{"en":"A policy that only tracks employee attendance, not health","es":"Una política que solo controle la asistencia de los empleados, no la salud","ru":"Политику, отслеживающую только посещаемость сотрудников, а не здоровье","tr":"Yalnızca çalışan devamını izleyen, sağlığı izlemeyen bir politika","hi":"एक नीति जो केवल कर्मचारी उपस्थिति को ट्रैक करती है, स्वास्थ्य को नहीं","ar":"سياسة تتابع حضور الموظفين فقط وليس صحتهم"},{"en":"A verbal understanding that employees decide on their own when to stay home","es":"Un entendimiento verbal de que los empleados deciden por sí mismos cuándo quedarse en casa","ru":"Устную договорённость о том, что сотрудники сами решают, когда оставаться дома","tr":"Çalışanların evde ne zaman kalacaklarına kendilerinin karar verdiğine dair sözlü bir anlayış","hi":"एक मौखिक समझ कि कर्मचारी स्वयं तय करते हैं कि घर पर कब रहना है","ar":"تفاهم شفهي بأن الموظفين يقررون بأنفسهم متى يبقون في المنزل"}],"e":{"en":"Employee health controls require a written policy in which employees report symptoms (like vomiting or diarrhea) and diagnosed illnesses, so the person in charge can restrict or exclude them as the Food Code requires.","es":"Los controles de salud de los empleados requieren una política escrita en la que los empleados reporten síntomas (como vómitos o diarrea) y enfermedades diagnosticadas, para que la persona a cargo pueda restringirlos o excluirlos según lo exige el Código de Alimentos.","ru":"Контроль здоровья сотрудников требует письменной политики, по которой сотрудники сообщают о симптомах (таких как рвота или диарея) и диагностированных заболеваниях, чтобы ответственное лицо могло ограничить или отстранить их согласно Пищевому кодексу.","tr":"Çalışan sağlığı kontrolleri, çalışanların semptomları (kusma veya ishal gibi) ve teşhis edilen hastalıkları bildirdiği yazılı bir politika gerektirir; böylece sorumlu kişi Gıda Kodu'nun gerektirdiği gibi onları kısıtlayabilir veya uzaklaştırabilir.","hi":"कर्मचारी स्वास्थ्य नियंत्रण के लिए एक लिखित नीति की आवश्यकता होती है जिसमें कर्मचारी लक्षणों (जैसे उल्टी या दस्त) और निदान की गई बीमारियों की रिपोर्ट करते हैं, ताकि प्रभारी व्यक्ति फूड कोड के अनुसार उन्हें प्रतिबंधित या बहिष्कृत कर सके।","ar":"تتطلب ضوابط صحة الموظفين سياسة مكتوبة يبلّغ فيها الموظفون عن الأعراض (مثل القيء أو الإسهال) والأمراض المشخّصة، حتى يتمكن الشخص المسؤول من تقييدهم أو استبعادهم كما يقتضي قانون الغذاء."}},{"cat":"haccp","a":2,"q":{"en":"'Establishing monitoring procedures' (HACCP principle 4) requires the operator to decide:","es":"'Establecer procedimientos de monitoreo' (principio 4 de HACCP) requiere que el operador decida:","ru":"«Установление процедур мониторинга» (принцип 4 HACCP) требует, чтобы оператор решил:","tr":"'İzleme prosedürlerini belirlemek' (HACCP ilke 4), işletmecinin şuna karar vermesini gerektirir:","hi":"'निगरानी प्रक्रियाएँ स्थापित करना' (HACCP सिद्धांत 4) के लिए संचालक को यह तय करने की आवश्यकता होती है:","ar":"'وضع إجراءات المراقبة' (المبدأ 4 لـ HACCP) يتطلب من المشغل أن يقرر:"},"o":[{"en":"Which employees to promote to management","es":"Qué empleados ascender a la gerencia","ru":"Каких сотрудников повысить до руководства","tr":"Hangi çalışanların yönetime terfi ettirileceğini","hi":"किन कर्मचारियों को प्रबंधन में पदोन्नत करना है","ar":"أي الموظفين تتم ترقيتهم إلى الإدارة"},{"en":"How to advertise the menu to new customers","es":"Cómo publicitar el menú a nuevos clientes","ru":"Как рекламировать меню новым клиентам","tr":"Menünün yeni müşterilere nasıl reklamının yapılacağını","hi":"नए ग्राहकों को मेनू का विज्ञापन कैसे करें","ar":"كيفية الإعلان عن القائمة للزبائن الجدد"},{"en":"How, when, and by whom each CCP's critical limit will be measured and recorded","es":"Cómo, cuándo y por quién se medirá y registrará el límite crítico de cada PCC","ru":"Как, когда и кем будет измеряться и записываться критический предел каждой ККТ","tr":"Her KKN'nin kritik limitinin nasıl, ne zaman ve kim tarafından ölçülüp kaydedileceğini","hi":"प्रत्येक CCP की क्रांतिक सीमा को कैसे, कब और किसके द्वारा मापा और रिकॉर्ड किया जाएगा","ar":"كيف ومتى ومن سيقيس ويسجّل الحد الحرج لكل نقطة تحكم حرجة"},{"en":"Which suppliers offer the lowest prices","es":"Qué proveedores ofrecen los precios más bajos","ru":"Какие поставщики предлагают самые низкие цены","tr":"Hangi tedarikçilerin en düşük fiyatları sunduğunu","hi":"कौन से आपूर्तिकर्ता सबसे कम कीमतें प्रदान करते हैं","ar":"أي الموردين يقدمون أدنى الأسعار"}],"e":{"en":"Monitoring procedures specify how, when, and by whom each CCP is checked against its critical limit, ensuring problems are detected before unsafe food reaches customers.","es":"Los procedimientos de monitoreo especifican cómo, cuándo y por quién se verifica cada PCC contra su límite crítico, asegurando que los problemas se detecten antes de que los alimentos inseguros lleguen a los clientes.","ru":"Процедуры мониторинга определяют, как, когда и кем проверяется каждая ККТ на соответствие критическому пределу, обеспечивая выявление проблем до того, как небезопасная еда достигнет клиентов.","tr":"İzleme prosedürleri, her KKN'nin kritik limitine göre nasıl, ne zaman ve kim tarafından kontrol edileceğini belirler; böylece güvensiz gıda müşterilere ulaşmadan önce sorunlar tespit edilir.","hi":"निगरानी प्रक्रियाएँ निर्दिष्ट करती हैं कि प्रत्येक CCP को उसकी क्रांतिक सीमा के विरुद्ध कैसे, कब और किसके द्वारा जाँचा जाता है, यह सुनिश्चित करते हुए कि असुरक्षित भोजन ग्राहकों तक पहुँचने से पहले समस्याओं का पता लगाया जाए।","ar":"تحدد إجراءات المراقبة كيف ومتى ومن يفحص كل نقطة تحكم حرجة مقابل حدها الحرج، مما يضمن اكتشاف المشكلات قبل وصول الطعام غير الآمن إلى الزبائن."}},{"cat":"haccp","a":3,"q":{"en":"After a kitchen fire is extinguished, the manager is unsure whether food and surfaces were contaminated by smoke and chemicals. What is the best course of action?","es":"Después de extinguir un incendio en la cocina, el gerente no está seguro de si los alimentos y las superficies fueron contaminados por humo y químicos. ¿Cuál es el mejor curso de acción?","ru":"После того как пожар на кухне потушен, менеджер не уверен, были ли еда и поверхности загрязнены дымом и химикатами. Каков наилучший план действий?","tr":"Bir mutfak yangını söndürüldükten sonra, müdür gıda ve yüzeylerin duman ve kimyasallarla kirlenip kirlenmediğinden emin değil. En iyi hareket tarzı nedir?","hi":"रसोई की आग बुझने के बाद, प्रबंधक अनिश्चित है कि क्या भोजन और सतहें धुएं और रसायनों से दूषित हो गई थीं। कार्रवाई का सबसे अच्छा तरीका क्या है?","ar":"بعد إخماد حريق في المطبخ، المدير غير متأكد مما إذا كان الطعام والأسطح قد تلوثا بالدخان والمواد الكيميائية. ما هو أفضل مسار للعمل؟"},"o":[{"en":"Serve any food that does not look damaged","es":"Servir cualquier alimento que no parezca dañado","ru":"Подавать любую еду, которая не выглядит повреждённой","tr":"Hasarlı görünmeyen herhangi bir yemeği servis etmek","hi":"कोई भी भोजन परोसें जो क्षतिग्रस्त न दिखे","ar":"تقديم أي طعام لا يبدو تالفاً"},{"en":"Wipe surfaces quickly and reopen within the hour","es":"Limpiar rápidamente las superficies y reabrir dentro de la hora","ru":"Быстро протереть поверхности и открыться в течение часа","tr":"Yüzeyleri hızlıca silip bir saat içinde yeniden açmak","hi":"सतहों को जल्दी से पोंछें और एक घंटे के भीतर फिर से खोलें","ar":"مسح الأسطح بسرعة وإعادة الفتح خلال ساعة"},{"en":"Only discard food that was directly touched by flames","es":"Desechar solo los alimentos que fueron tocados directamente por las llamas","ru":"Выбросить только еду, которой напрямую коснулось пламя","tr":"Yalnızca alevlerin doğrudan dokunduğu yemeği atmak","hi":"केवल वह भोजन फेंकें जिसे आग ने सीधे छुआ था","ar":"التخلص فقط من الطعام الذي لامسته النيران مباشرة"},{"en":"Treat it as an imminent health hazard: cease operations, discard affected food, clean and sanitize, and consult the regulatory authority before reopening","es":"Tratarlo como un peligro inminente para la salud: cesar operaciones, desechar los alimentos afectados, limpiar y desinfectar, y consultar a la autoridad reguladora antes de reabrir","ru":"Рассматривать это как неминуемую угрозу здоровью: прекратить работу, выбросить затронутую еду, очистить и продезинфицировать и проконсультироваться с регулирующим органом перед открытием","tr":"Bunu yakın bir sağlık tehlikesi olarak ele almak: faaliyetleri durdurmak, etkilenen gıdayı atmak, temizleyip dezenfekte etmek ve yeniden açılmadan önce düzenleyici otoriteye danışmak","hi":"इसे एक आसन्न स्वास्थ्य खतरे के रूप में मानें: संचालन बंद करें, प्रभावित भोजन को फेंक दें, साफ और स्वच्छ करें, और फिर से खोलने से पहले नियामक प्राधिकरण से परामर्श करें","ar":"التعامل معه كخطر صحي وشيك: إيقاف العمليات، والتخلص من الطعام المتأثر، والتنظيف والتطهير، واستشارة الجهة التنظيمية قبل إعادة الفتح"}],"e":{"en":"A fire (like a flood or sewage backup) is an imminent health hazard. The operation should stop, discard contaminated food, clean and sanitize, and coordinate with the regulatory authority before reopening.","es":"Un incendio (como una inundación o desbordamiento de aguas residuales) es un peligro inminente para la salud. La operación debe detenerse, desechar los alimentos contaminados, limpiar y desinfectar, y coordinar con la autoridad reguladora antes de reabrir.","ru":"Пожар (как наводнение или обратный поток сточных вод) — неминуемая угроза здоровью. Предприятие должно остановиться, выбросить загрязнённую еду, очистить и продезинфицировать и согласовать с регулирующим органом перед открытием.","tr":"Bir yangın (sel veya kanalizasyon geri tepmesi gibi) yakın bir sağlık tehlikesidir. İşletme durmalı, kirlenmiş gıdayı atmalı, temizleyip dezenfekte etmeli ve yeniden açılmadan önce düzenleyici otoriteyle koordinasyon sağlamalıdır.","hi":"आग (बाढ़ या सीवेज बैकअप की तरह) एक आसन्न स्वास्थ्य खतरा है। संचालन को रुकना चाहिए, दूषित भोजन को फेंकना चाहिए, साफ और स्वच्छ करना चाहिए, और फिर से खोलने से पहले नियामक प्राधिकरण के साथ समन्वय करना चाहिए।","ar":"الحريق (مثل الفيضان أو ارتداد الصرف الصحي) خطر صحي وشيك. ينبغي للمنشأة التوقف، والتخلص من الطعام الملوث، والتنظيف والتطهير، والتنسيق مع الجهة التنظيمية قبل إعادة الفتح."}},{"cat":"staff","a":2,"q":{"en":"During which hours must a person in charge (PIC) be present at a food establishment?","es":"¿Durante qué horas debe estar presente una persona a cargo (PIC) en un establecimiento de alimentos?","ru":"В течение каких часов ответственное лицо (PIC) должно присутствовать на предприятии питания?","tr":"Bir gıda işletmesinde sorumlu kişi (PIC) hangi saatlerde bulunmalıdır?","hi":"खाद्य प्रतिष्ठान में प्रभारी व्यक्ति (PIC) को किन घंटों के दौरान उपस्थित रहना चाहिए?","ar":"خلال أي ساعات يجب أن يكون الشخص المسؤول (PIC) حاضرًا في منشأة الأغذية؟"},"o":[{"en":"Only during health inspections","es":"Solo durante las inspecciones sanitarias","ru":"Только во время санитарных проверок","tr":"Yalnızca sağlık denetimleri sırasında","hi":"केवल स्वास्थ्य निरीक्षण के दौरान","ar":"فقط أثناء عمليات التفتيش الصحي"},{"en":"Only during peak meal periods","es":"Solo durante los periodos de mayor afluencia","ru":"Только в часы пик","tr":"Yalnızca yoğun yemek saatlerinde","hi":"केवल भोजन के व्यस्ततम समय के दौरान","ar":"فقط خلال أوقات الذروة"},{"en":"During all hours of operation","es":"Durante todas las horas de operación","ru":"В течение всех часов работы","tr":"İşletmenin tüm çalışma saatleri boyunca","hi":"संचालन के सभी घंटों के दौरान","ar":"خلال جميع ساعات العمل"},{"en":"Only when new employees are training","es":"Solo cuando se capacita a nuevos empleados","ru":"Только когда обучаются новые сотрудники","tr":"Yalnızca yeni çalışanlar eğitilirken","hi":"केवल जब नए कर्मचारी प्रशिक्षण ले रहे हों","ar":"فقط عند تدريب الموظفين الجدد"}],"e":{"en":"The FDA Food Code requires a PIC to be present during all hours of operation to actively manage food safety and demonstrate knowledge.","es":"El Código de Alimentos de la FDA exige que un PIC esté presente durante todas las horas de operación para gestionar activamente la seguridad alimentaria y demostrar conocimiento.","ru":"Продовольственный кодекс FDA требует присутствия PIC в течение всех часов работы для активного управления безопасностью пищевых продуктов и демонстрации знаний.","tr":"FDA Gıda Kodu, gıda güvenliğini aktif olarak yönetmek ve bilgi göstermek için bir PIC'nin tüm çalışma saatleri boyunca hazır bulunmasını gerektirir.","hi":"एफडीए फूड कोड के अनुसार खाद्य सुरक्षा का सक्रिय रूप से प्रबंधन करने और ज्ञान प्रदर्शित करने के लिए PIC को संचालन के सभी घंटों के दौरान उपस्थित रहना आवश्यक है।","ar":"يتطلب قانون الغذاء لهيئة الغذاء والدواء وجود الشخص المسؤول خلال جميع ساعات العمل لإدارة سلامة الأغذية بفعالية وإظهار المعرفة."}},{"cat":"staff","a":1,"q":{"en":"A cook reports diarrhea. The operation does NOT serve a highly susceptible population. What must the PIC do?","es":"Un cocinero reporta diarrea. La operación NO atiende a una población altamente susceptible. ¿Qué debe hacer el PIC?","ru":"Повар сообщает о диарее. Заведение НЕ обслуживает высоко восприимчивую группу населения. Что должен сделать PIC?","tr":"Bir aşçı ishal bildiriyor. İşletme yüksek riskli bir nüfusa hizmet ETMİYOR. PIC ne yapmalıdır?","hi":"एक रसोइया दस्त की सूचना देता है। प्रतिष्ठान अत्यधिक संवेदनशील आबादी की सेवा नहीं करता। PIC को क्या करना चाहिए?","ar":"يبلغ طاهٍ عن إصابته بالإسهال. المنشأة لا تخدم فئة شديدة التأثر. ماذا يجب أن يفعل الشخص المسؤول؟"},"o":[{"en":"Restrict the cook to non-food duties","es":"Restringir al cocinero a tareas sin alimentos","ru":"Ограничить повара работой, не связанной с едой","tr":"Aşçıyı gıda dışı görevlerle sınırlamak","hi":"रसोइए को गैर-खाद्य कार्यों तक सीमित करना","ar":"تقييد الطاهي بمهام غير متعلقة بالطعام"},{"en":"Exclude the cook from the establishment","es":"Excluir al cocinero del establecimiento","ru":"Отстранить повара от работы на предприятии","tr":"Aşçıyı işletmeden uzaklaştırmak (dışlamak)","hi":"रसोइए को प्रतिष्ठान से बाहर करना","ar":"استبعاد الطاهي من المنشأة"},{"en":"Let the cook keep working with gloves","es":"Dejar que el cocinero siga trabajando con guantes","ru":"Позволить повару продолжать работать в перчатках","tr":"Aşçının eldivenle çalışmaya devam etmesine izin vermek","hi":"रसोइए को दस्ताने पहनकर काम करने देना","ar":"السماح للطاهي بمواصلة العمل مع القفازات"},{"en":"Do nothing until a diagnosis is made","es":"No hacer nada hasta que haya un diagnóstico","ru":"Ничего не делать до постановки диагноза","tr":"Teşhis konana kadar hiçbir şey yapmamak","hi":"निदान होने तक कुछ न करना","ar":"عدم فعل أي شيء حتى يتم التشخيص"}],"e":{"en":"Vomiting and diarrhea are exclusion symptoms in every operation because they signal a high risk of transmitting foodborne pathogens.","es":"Los vómitos y la diarrea son síntomas de exclusión en toda operación porque indican un alto riesgo de transmitir patógenos alimentarios.","ru":"Рвота и диарея являются симптомами для отстранения на любом предприятии, поскольку сигнализируют о высоком риске передачи пищевых патогенов.","tr":"Kusma ve ishal her işletmede dışlama semptomlarıdır çünkü gıda kaynaklı patojenleri bulaştırma riskinin yüksek olduğunu gösterir.","hi":"उल्टी और दस्त हर प्रतिष्ठान में बहिष्करण के लक्षण हैं क्योंकि ये खाद्य जनित रोगजनकों के संचरण के उच्च जोखिम का संकेत देते हैं।","ar":"القيء والإسهال من أعراض الاستبعاد في كل منشأة لأنها تشير إلى خطر كبير لانتقال مسببات الأمراض المنقولة بالغذاء."}},{"cat":"staff","a":3,"q":{"en":"A food employee is diagnosed with jaundice. What must the PIC do?","es":"A un empleado de alimentos se le diagnostica ictericia. ¿Qué debe hacer el PIC?","ru":"У сотрудника, работающего с пищевыми продуктами, диагностирована желтуха. Что должен сделать PIC?","tr":"Bir gıda çalışanına sarılık teşhisi konur. PIC ne yapmalıdır?","hi":"एक खाद्य कर्मचारी को पीलिया का निदान होता है। PIC को क्या करना चाहिए?","ar":"يُشخَّص أحد العاملين في الغذاء بالإصابة باليرقان. ماذا يجب أن يفعل الشخص المسؤول؟"},"o":[{"en":"Restrict the employee and continue as normal","es":"Restringir al empleado y continuar con normalidad","ru":"Ограничить сотрудника и работать в обычном режиме","tr":"Çalışanı kısıtlamak ve normal şekilde devam etmek","hi":"कर्मचारी को प्रतिबंधित करके सामान्य रूप से जारी रखना","ar":"تقييد الموظف والاستمرار كالمعتاد"},{"en":"Send the employee home for one shift only","es":"Enviar al empleado a casa por un solo turno","ru":"Отправить сотрудника домой только на одну смену","tr":"Çalışanı yalnızca bir vardiya için eve göndermek","hi":"कर्मचारी को केवल एक शिफ्ट के लिए घर भेजना","ar":"إرسال الموظف إلى المنزل لنوبة عمل واحدة فقط"},{"en":"Cover any wounds and allow work","es":"Cubrir cualquier herida y permitir el trabajo","ru":"Закрыть любые раны и разрешить работу","tr":"Yaraları kapatıp çalışmasına izin vermek","hi":"किसी भी घाव को ढककर काम करने देना","ar":"تغطية أي جروح والسماح بالعمل"},{"en":"Exclude the employee and notify the regulatory authority","es":"Excluir al empleado y notificar a la autoridad reguladora","ru":"Отстранить сотрудника и уведомить регулирующий орган","tr":"Çalışanı dışlamak ve düzenleyici otoriteye bildirmek","hi":"कर्मचारी को बाहर करना और नियामक प्राधिकरण को सूचित करना","ar":"استبعاد الموظف وإخطار الجهة التنظيمية"}],"e":{"en":"Jaundice that has appeared within the last 7 days requires exclusion, and the PIC must notify the regulatory authority because it may indicate Hepatitis A.","es":"La ictericia que ha aparecido en los últimos 7 días requiere exclusión, y el PIC debe notificar a la autoridad reguladora porque puede indicar hepatitis A.","ru":"Желтуха, появившаяся в течение последних 7 дней, требует отстранения, и PIC должен уведомить регулирующий орган, поскольку это может указывать на гепатит А.","tr":"Son 7 gün içinde ortaya çıkan sarılık dışlama gerektirir ve PIC, Hepatit A'ya işaret edebileceği için düzenleyici otoriteye bildirmelidir.","hi":"पिछले 7 दिनों में प्रकट हुआ पीलिया बहिष्करण की आवश्यकता रखता है, और PIC को नियामक प्राधिकरण को सूचित करना चाहिए क्योंकि यह हेपेटाइटिस A का संकेत हो सकता है।","ar":"اليرقان الذي ظهر خلال الأيام السبعة الماضية يتطلب الاستبعاد، ويجب على الشخص المسؤول إخطار الجهة التنظيمية لأنه قد يشير إلى التهاب الكبد A."}},{"cat":"staff","a":0,"q":{"en":"A server reports a sore throat with fever. The operation serves a highly susceptible population (HSP). What is the required action?","es":"Un mesero reporta dolor de garganta con fiebre. La operación atiende a una población altamente susceptible (HSP). ¿Cuál es la acción requerida?","ru":"Официант сообщает о боли в горле с температурой. Заведение обслуживает высоко восприимчивую группу населения (HSP). Какое действие требуется?","tr":"Bir garson ateşle birlikte boğaz ağrısı bildiriyor. İşletme yüksek riskli bir nüfusa (HSP) hizmet ediyor. Gereken eylem nedir?","hi":"एक सर्वर बुखार के साथ गले में खराश की सूचना देता है। प्रतिष्ठान अत्यधिक संवेदनशील आबादी (HSP) की सेवा करता है। आवश्यक कार्रवाई क्या है?","ar":"يبلغ نادل عن التهاب في الحلق مصحوب بحمى. المنشأة تخدم فئة شديدة التأثر (HSP). ما هو الإجراء المطلوب؟"},"o":[{"en":"Exclude the server from the establishment","es":"Excluir al mesero del establecimiento","ru":"Отстранить официанта от работы на предприятии","tr":"Garsonu işletmeden dışlamak","hi":"सर्वर को प्रतिष्ठान से बाहर करना","ar":"استبعاد النادل من المنشأة"},{"en":"Restrict the server from bussing tables","es":"Restringir al mesero de recoger mesas","ru":"Ограничить официанту уборку столов","tr":"Garsonun masa toplamasını kısıtlamak","hi":"सर्वर को टेबल साफ करने से प्रतिबंधित करना","ar":"تقييد النادل من تنظيف الطاولات"},{"en":"Allow work with a face mask","es":"Permitir el trabajo con mascarilla","ru":"Разрешить работу в маске для лица","tr":"Yüz maskesiyle çalışmasına izin vermek","hi":"फेस मास्क के साथ काम करने देना","ar":"السماح بالعمل مع ارتداء كمامة"},{"en":"Take no action; a cough is not reportable","es":"No tomar ninguna acción; la tos no es reportable","ru":"Не предпринимать действий; кашель не подлежит регистрации","tr":"Hiçbir işlem yapmamak; öksürük bildirilmez","hi":"कोई कार्रवाई न करना; खांसी रिपोर्ट करने योग्य नहीं है","ar":"عدم اتخاذ أي إجراء؛ السعال لا يستوجب الإبلاغ"}],"e":{"en":"A sore throat with fever normally warrants restriction, but when serving a highly susceptible population the employee must be excluded until medically cleared.","es":"El dolor de garganta con fiebre normalmente justifica la restricción, pero al atender a una población altamente susceptible el empleado debe ser excluido hasta contar con autorización médica.","ru":"Боль в горле с температурой обычно требует ограничения, но при обслуживании высоко восприимчивой группы сотрудник должен быть отстранён до получения медицинского допуска.","tr":"Ateşle birlikte boğaz ağrısı normalde kısıtlama gerektirir, ancak yüksek riskli bir nüfusa hizmet edilirken çalışan tıbbi onay alana kadar dışlanmalıdır.","hi":"बुखार के साथ गले में खराश आमतौर पर प्रतिबंध की मांग करती है, लेकिन अत्यधिक संवेदनशील आबादी की सेवा करते समय कर्मचारी को चिकित्सकीय मंजूरी मिलने तक बाहर रखा जाना चाहिए।","ar":"التهاب الحلق مع الحمى يستوجب عادةً التقييد، ولكن عند خدمة فئة شديدة التأثر يجب استبعاد الموظف حتى الحصول على موافقة طبية."}},{"cat":"staff","a":1,"q":{"en":"An employee has an infected, open wound with pus on the finger. Which action best follows the Food Code?","es":"Un empleado tiene una herida abierta e infectada con pus en el dedo. ¿Qué acción cumple mejor con el Código de Alimentos?","ru":"У сотрудника инфицированная открытая рана с гноем на пальце. Какое действие лучше всего соответствует Продовольственному кодексу?","tr":"Bir çalışanın parmağında iltihaplı, açık ve cerahatli bir yara var. Hangi eylem Gıda Kodu'na en uygun olanıdır?","hi":"एक कर्मचारी की उंगली पर मवाद के साथ संक्रमित, खुला घाव है। कौन सी कार्रवाई फूड कोड का सर्वोत्तम पालन करती है?","ar":"لدى موظف جرح مفتوح ملتهب به صديد في الإصبع. أي إجراء يتوافق بشكل أفضل مع قانون الغذاء؟"},"o":[{"en":"Exclude the employee from all work","es":"Excluir al empleado de todo trabajo","ru":"Отстранить сотрудника от всей работы","tr":"Çalışanı tüm işlerden dışlamak","hi":"कर्मचारी को सभी कार्यों से बाहर करना","ar":"استبعاد الموظف من كل العمل"},{"en":"Cover with an impermeable bandage and single-use glove","es":"Cubrir con un vendaje impermeable y un guante de un solo uso","ru":"Закрыть непромокаемой повязкой и одноразовой перчаткой","tr":"Su geçirmez bir bandaj ve tek kullanımlık eldivenle kapatmak","hi":"अभेद्य पट्टी और एकल-उपयोग दस्ताने से ढकना","ar":"التغطية بضمادة غير منفذة وقفاز أحادي الاستخدام"},{"en":"Send the employee home for 24 hours","es":"Enviar al empleado a casa por 24 horas","ru":"Отправить сотрудника домой на 24 часа","tr":"Çalışanı 24 saat eve göndermek","hi":"कर्मचारी को 24 घंटे के लिए घर भेजना","ar":"إرسال الموظف إلى المنزل لمدة 24 ساعة"},{"en":"Allow work if the wound is only rinsed","es":"Permitir el trabajo si la herida solo se enjuaga","ru":"Разрешить работу, если рану только промыть","tr":"Yara yalnızca durulanırsa çalışmasına izin vermek","hi":"यदि घाव केवल धोया जाए तो काम करने देना","ar":"السماح بالعمل إذا تم شطف الجرح فقط"}],"e":{"en":"An infected lesion containing pus on the hand must be covered with an impermeable bandage plus a single-use glove or finger cot before the employee handles food.","es":"Una lesión infectada con pus en la mano debe cubrirse con un vendaje impermeable más un guante de un solo uso o dedil antes de que el empleado manipule alimentos.","ru":"Инфицированное поражение с гноем на руке необходимо закрыть непромокаемой повязкой и одноразовой перчаткой или напальчником, прежде чем сотрудник будет работать с пищей.","tr":"Elde cerahat içeren iltihaplı bir lezyon, çalışan gıdaya dokunmadan önce su geçirmez bir bandaj ve tek kullanımlık eldiven veya parmaklıkla kapatılmalıdır.","hi":"हाथ पर मवाद वाले संक्रमित घाव को कर्मचारी द्वारा भोजन संभालने से पहले अभेद्य पट्टी और एकल-उपयोग दस्ताने या फिंगर कॉट से ढका जाना चाहिए।","ar":"يجب تغطية الآفة الملتهبة التي تحتوي على صديد في اليد بضمادة غير منفذة بالإضافة إلى قفاز أحادي الاستخدام أو غطاء إصبع قبل أن يتعامل الموظف مع الطعام."}},{"cat":"staff","a":2,"q":{"en":"An employee excluded for vomiting and diarrhea has no diagnosed illness. When may they generally return to work?","es":"Un empleado excluido por vómitos y diarrea no tiene enfermedad diagnosticada. ¿Cuándo puede regresar al trabajo por lo general?","ru":"Сотрудник, отстранённый из-за рвоты и диареи, не имеет диагностированного заболевания. Когда он обычно может вернуться к работе?","tr":"Kusma ve ishal nedeniyle dışlanan bir çalışanın teşhis konmuş bir hastalığı yok. Genellikle ne zaman işe dönebilir?","hi":"उल्टी और दस्त के कारण बाहर किए गए कर्मचारी को कोई निदान की गई बीमारी नहीं है। वे आमतौर पर कब काम पर लौट सकते हैं?","ar":"موظف تم استبعاده بسبب القيء والإسهال ليس لديه مرض مُشخَّص. متى يمكنه عمومًا العودة إلى العمل؟"},"o":[{"en":"Immediately once they feel a little better","es":"Inmediatamente cuando se sientan un poco mejor","ru":"Сразу, как только почувствуют себя немного лучше","tr":"Biraz iyileşir iyileşmez hemen","hi":"जैसे ही थोड़ा बेहतर महसूस करें, तुरंत","ar":"فورًا بمجرد أن يشعروا بتحسن قليل"},{"en":"After a written note from any coworker","es":"Después de una nota escrita de cualquier compañero","ru":"После письменной записки от любого коллеги","tr":"Herhangi bir iş arkadaşından yazılı bir not aldıktan sonra","hi":"किसी भी सहकर्मी से लिखित नोट के बाद","ar":"بعد مذكرة مكتوبة من أي زميل عمل"},{"en":"After being symptom-free for at least 24 hours","es":"Después de estar sin síntomas durante al menos 24 horas","ru":"После отсутствия симптомов в течение не менее 24 часов","tr":"En az 24 saat semptomsuz kaldıktan sonra","hi":"कम से कम 24 घंटे लक्षण-मुक्त रहने के बाद","ar":"بعد الخلو من الأعراض لمدة 24 ساعة على الأقل"},{"en":"After exactly 72 hours regardless of symptoms","es":"Después de exactamente 72 horas sin importar los síntomas","ru":"Ровно через 72 часа независимо от симптомов","tr":"Semptomlara bakılmaksızın tam 72 saat sonra","hi":"लक्षणों की परवाह किए बिना ठीक 72 घंटे बाद","ar":"بعد 72 ساعة بالضبط بغض النظر عن الأعراض"}],"e":{"en":"With no diagnosed pathogen, an employee excluded for vomiting or diarrhea may return once symptom-free for at least 24 hours, or with written medical release.","es":"Sin patógeno diagnosticado, un empleado excluido por vómitos o diarrea puede regresar una vez sin síntomas durante al menos 24 horas, o con autorización médica escrita.","ru":"При отсутствии диагностированного патогена сотрудник, отстранённый из-за рвоты или диареи, может вернуться после отсутствия симптомов в течение не менее 24 часов или с письменным медицинским разрешением.","tr":"Teşhis konmuş bir patojen yoksa, kusma veya ishal nedeniyle dışlanan bir çalışan en az 24 saat semptomsuz kaldığında ya da yazılı tıbbi onayla işe dönebilir.","hi":"किसी निदान किए गए रोगजनक के बिना, उल्टी या दस्त के कारण बाहर किया गया कर्मचारी कम से कम 24 घंटे लक्षण-मुक्त रहने पर या लिखित चिकित्सा मंजूरी के साथ लौट सकता है।","ar":"في حال عدم وجود مسبب مرضي مُشخَّص، يمكن للموظف المُستبعَد بسبب القيء أو الإسهال العودة بعد الخلو من الأعراض لمدة 24 ساعة على الأقل، أو بموافقة طبية مكتوبة."}},{"cat":"staff","a":3,"q":{"en":"A cook is diagnosed with nontyphoidal Salmonella. Before returning to work, what is generally required?","es":"A un cocinero se le diagnostica Salmonella no tifoidea. Antes de regresar al trabajo, ¿qué se requiere generalmente?","ru":"У повара диагностирован нетифоидный сальмонеллёз. Что обычно требуется перед возвращением к работе?","tr":"Bir aşçıya tifo dışı Salmonella teşhisi konur. İşe dönmeden önce genellikle ne gereklidir?","hi":"एक रसोइए को गैर-टाइफाइड साल्मोनेला का निदान होता है। काम पर लौटने से पहले आमतौर पर क्या आवश्यक है?","ar":"يُشخَّص طاهٍ بالإصابة بالسالمونيلا غير التيفية. قبل العودة إلى العمل، ما المطلوب عمومًا؟"},"o":[{"en":"Nothing beyond feeling better","es":"Nada más que sentirse mejor","ru":"Ничего, кроме улучшения самочувствия","tr":"Kendini iyi hissetmekten başka bir şey değil","hi":"बेहतर महसूस करने के अलावा कुछ नहीं","ar":"لا شيء سوى الشعور بالتحسن"},{"en":"A single symptom-free hour","es":"Una sola hora sin síntomas","ru":"Один час без симптомов","tr":"Tek bir semptomsuz saat","hi":"एक ही लक्षण-मुक्त घंटा","ar":"ساعة واحدة خالية من الأعراض"},{"en":"Permission from a coworker","es":"Permiso de un compañero de trabajo","ru":"Разрешение от коллеги","tr":"Bir iş arkadaşından izin","hi":"एक सहकर्मी से अनुमति","ar":"إذن من زميل عمل"},{"en":"Approval from the regulatory authority or a medical release","es":"Aprobación de la autoridad reguladora o una autorización médica","ru":"Одобрение регулирующего органа или медицинское разрешение","tr":"Düzenleyici otoritenin onayı veya tıbbi bir onay","hi":"नियामक प्राधिकरण से अनुमोदन या चिकित्सा मंजूरी","ar":"موافقة الجهة التنظيمية أو موافقة طبية"}],"e":{"en":"Employees diagnosed with a listed pathogen such as nontyphoidal Salmonella are excluded and generally need regulatory-authority approval or a written medical release to return.","es":"Los empleados diagnosticados con un patógeno de la lista, como Salmonella no tifoidea, son excluidos y generalmente necesitan la aprobación de la autoridad reguladora o una autorización médica escrita para regresar.","ru":"Сотрудники с диагностированным перечисленным патогеном, таким как нетифоидная сальмонелла, отстраняются и обычно нуждаются в одобрении регулирующего органа или письменном медицинском разрешении для возвращения.","tr":"Tifo dışı Salmonella gibi listelenmiş bir patojen teşhisi konan çalışanlar dışlanır ve dönmek için genellikle düzenleyici otoritenin onayına veya yazılı tıbbi onaya ihtiyaç duyar.","hi":"गैर-टाइफाइड साल्मोनेला जैसे सूचीबद्ध रोगजनक से निदान किए गए कर्मचारियों को बाहर किया जाता है और लौटने के लिए आमतौर पर नियामक प्राधिकरण की मंजूरी या लिखित चिकित्सा मंजूरी की आवश्यकता होती है।","ar":"الموظفون الذين يُشخَّصون بمسبب مرضي مُدرَج مثل السالمونيلا غير التيفية يُستبعَدون ويحتاجون عمومًا إلى موافقة الجهة التنظيمية أو موافقة طبية مكتوبة للعودة."}},{"cat":"staff","a":0,"q":{"en":"Which set correctly lists the FDA \"Big 6\" reportable illnesses a PIC must be aware of?","es":"¿Qué conjunto enumera correctamente las enfermedades reportables de los \"6 Grandes\" de la FDA que un PIC debe conocer?","ru":"В каком наборе правильно перечислены подлежащие регистрации болезни FDA «Большой шестёрки», о которых должен знать PIC?","tr":"Hangi grup, bir PIC'nin bilmesi gereken FDA \"Büyük 6\" bildirilebilir hastalıklarını doğru şekilde listeler?","hi":"कौन सा समूह एफडीए के \"बिग 6\" रिपोर्ट करने योग्य बीमारियों को सही ढंग से सूचीबद्ध करता है जिनके बारे में PIC को पता होना चाहिए?","ar":"أي مجموعة تسرد بشكل صحيح أمراض \"الستة الكبار\" الواجب الإبلاغ عنها التي يجب أن يعرفها الشخص المسؤول؟"},"o":[{"en":"Norovirus, Hepatitis A, Shigella, nontyphoidal Salmonella, STEC, Salmonella Typhi","es":"Norovirus, hepatitis A, Shigella, Salmonella no tifoidea, STEC, Salmonella Typhi","ru":"Норовирус, гепатит А, шигелла, нетифоидная сальмонелла, STEC, Salmonella Typhi","tr":"Norovirüs, Hepatit A, Shigella, tifo dışı Salmonella, STEC, Salmonella Typhi","hi":"नोरोवायरस, हेपेटाइटिस A, शिगेला, गैर-टाइफाइड साल्मोनेला, STEC, साल्मोनेला टाइफी","ar":"نوروفيروس، التهاب الكبد A، الشيغيلا، السالمونيلا غير التيفية، STEC، السالمونيلا التيفية"},{"en":"Listeria, Botulism, E. coli O157, Giardia, Norovirus, Rotavirus","es":"Listeria, botulismo, E. coli O157, Giardia, norovirus, rotavirus","ru":"Листерия, ботулизм, E. coli O157, лямблии, норовирус, ротавирус","tr":"Listeria, Botulizm, E. coli O157, Giardia, Norovirüs, Rotavirüs","hi":"लिस्टेरिया, बोटुलिज़्म, E. coli O157, जिआर्डिया, नोरोवायरस, रोटावायरस","ar":"الليستيريا، التسمم الغذائي، إي كولاي O157، الجيارديا، نوروفيروس، فيروس الروتا"},{"en":"Staphylococcus, Campylobacter, Hepatitis B, Cholera, Mumps, Measles","es":"Estafilococo, Campylobacter, hepatitis B, cólera, paperas, sarampión","ru":"Стафилококк, кампилобактер, гепатит B, холера, свинка, корь","tr":"Stafilokok, Campylobacter, Hepatit B, Kolera, Kabakulak, Kızamık","hi":"स्टैफिलोकोकस, कैम्पिलोबैक्टर, हेपेटाइटिस B, हैजा, गलसुआ, खसरा","ar":"المكورات العنقودية، العطيفة، التهاب الكبد B، الكوليرا، النكاف، الحصبة"},{"en":"Salmonella Typhi, Trichinella, Vibrio, Yersinia, Anisakis, Cyclospora","es":"Salmonella Typhi, Trichinella, Vibrio, Yersinia, Anisakis, Cyclospora","ru":"Salmonella Typhi, трихинелла, вибрион, иерсиния, анизакида, циклоспора","tr":"Salmonella Typhi, Trichinella, Vibrio, Yersinia, Anisakis, Cyclospora","hi":"साल्मोनेला टाइफी, ट्राइकिनेला, विब्रियो, यर्सिनिया, एनिसाकिस, साइक्लोस्पोरा","ar":"السالمونيلا التيفية، الشعرية، الضمة، اليرسينيا، الأنيساكيس، السيكلوسبورا"}],"e":{"en":"The Big 6 are Norovirus, Hepatitis A, Shigella spp., nontyphoidal Salmonella, Shiga toxin-producing E. coli (STEC), and Salmonella Typhi.","es":"Los 6 Grandes son norovirus, hepatitis A, Shigella spp., Salmonella no tifoidea, E. coli productora de toxina Shiga (STEC) y Salmonella Typhi.","ru":"«Большая шестёрка» — это норовирус, гепатит А, Shigella spp., нетифоидная сальмонелла, шига-токсин-продуцирующая E. coli (STEC) и Salmonella Typhi.","tr":"Büyük 6; Norovirüs, Hepatit A, Shigella spp., tifo dışı Salmonella, Shiga toksini üreten E. coli (STEC) ve Salmonella Typhi'dir.","hi":"बिग 6 हैं नोरोवायरस, हेपेटाइटिस A, शिगेला प्रजाति, गैर-टाइफाइड साल्मोनेला, शिगा टॉक्सिन-उत्पादक E. coli (STEC), और साल्मोनेला टाइफी।","ar":"الستة الكبار هي: النوروفيروس، التهاب الكبد A، الشيغيلا، السالمونيلا غير التيفية، الإشريكية القولونية المنتجة لسم الشيغا (STEC)، والسالمونيلا التيفية."}},{"cat":"staff","a":1,"q":{"en":"A cook was excluded after vomiting. Under the Food Code, when may they generally return to working with food?","es":"Un cocinero fue excluido tras vomitar. Según el Food Code, ¿cuándo puede por lo general volver a trabajar con alimentos?","ru":"Повара отстранили после рвоты. Согласно Food Code, когда ему обычно разрешено вернуться к работе с пищей?","tr":"Bir aşçı kustuktan sonra işten uzaklaştırıldı. Food Code'a göre genellikle gıdayla çalışmaya ne zaman dönebilir?","hi":"उल्टी के बाद एक रसोइये को बाहर कर दिया गया। Food Code के अनुसार, वे आम तौर पर भोजन के साथ काम पर कब लौट सकते हैं?","ar":"استُبعد طاهٍ بعد التقيؤ. وفقًا لقانون الغذاء، متى يمكنه عمومًا العودة للعمل مع الطعام؟"},"o":[{"en":"As soon as they feel well enough to work","es":"Tan pronto como se sienta con fuerzas para trabajar","ru":"Как только почувствует себя достаточно хорошо","tr":"Kendini çalışacak kadar iyi hisseder hissetmez","hi":"जैसे ही वे काम करने लायक महसूस करें","ar":"بمجرد أن يشعر بأنه بخير بما يكفي للعمل"},{"en":"When they have been symptom-free for at least 24 hours or have written medical approval","es":"Cuando haya estado sin síntomas al menos 24 horas o tenga aprobación médica por escrito","ru":"Когда не будет симптомов не менее 24 часов или будет письменное разрешение врача","tr":"En az 24 saat belirtisiz kaldığında veya yazılı tıbbi onay aldığında","hi":"जब वे कम से कम 24 घंटे तक लक्षण-मुक्त रहें या लिखित चिकित्सा अनुमति हो","ar":"عندما يخلو من الأعراض لمدة 24 ساعة على الأقل أو يحصل على موافقة طبية مكتوبة"},{"en":"After washing their hands twice","es":"Después de lavarse las manos dos veces","ru":"После двукратного мытья рук","tr":"Ellerini iki kez yıkadıktan sonra","hi":"अपने हाथ दो बार धोने के बाद","ar":"بعد غسل يديه مرتين"},{"en":"Only after a full 7 days off","es":"Solo después de 7 días completos de ausencia","ru":"Только после 7 полных дней отсутствия","tr":"Yalnızca tam 7 gün izinden sonra","hi":"केवल पूरे 7 दिन की छुट्टी के बाद","ar":"فقط بعد 7 أيام كاملة من الغياب"}],"e":{"en":"For vomiting or diarrhea with no diagnosed illness, an employee may return once they have been symptom-free for at least 24 hours or provide written medical documentation.","es":"Para vómito o diarrea sin enfermedad diagnosticada, el empleado puede volver cuando haya estado sin síntomas al menos 24 horas o presente documentación médica por escrito.","ru":"При рвоте или диарее без диагностированного заболевания сотрудник может вернуться, когда не будет симптомов не менее 24 часов или предоставит письменное медицинское заключение.","tr":"Tanı konmamış kusma veya ishalde çalışan, en az 24 saat belirtisiz kaldığında ya da yazılı tıbbi belge sunduğunda işe dönebilir.","hi":"बिना निदान वाली बीमारी में उल्टी या दस्त के लिए, कर्मचारी तब लौट सकता है जब वह कम से कम 24 घंटे लक्षण-मुक्त रहे या लिखित चिकित्सा दस्तावेज़ दे।","ar":"في حالة التقيؤ أو الإسهال دون مرض مُشخَّص، يمكن للموظف العودة بعد خلوّه من الأعراض 24 ساعة على الأقل أو تقديم وثيقة طبية مكتوبة."}},{"cat":"staff","a":2,"q":{"en":"A food employee reports a diagnosis of Hepatitis A. When may they typically return to work?","es":"Un empleado de alimentos reporta un diagnóstico de hepatitis A. ¿Cuándo puede regresar típicamente al trabajo?","ru":"Сотрудник, работающий с пищевыми продуктами, сообщает о диагнозе гепатита А. Когда он обычно может вернуться к работе?","tr":"Bir gıda çalışanı Hepatit A teşhisi bildiriyor. Genellikle ne zaman işe dönebilir?","hi":"एक खाद्य कर्मचारी हेपेटाइटिस A के निदान की सूचना देता है। वे आमतौर पर कब काम पर लौट सकते हैं?","ar":"يبلغ أحد العاملين في الغذاء عن تشخيص بالتهاب الكبد A. متى يمكنه عادةً العودة إلى العمل؟"},"o":[{"en":"After being symptom-free for 24 hours","es":"Después de estar sin síntomas durante 24 horas","ru":"После отсутствия симптомов в течение 24 часов","tr":"24 saat semptomsuz kaldıktan sonra","hi":"24 घंटे लक्षण-मुक्त रहने के बाद","ar":"بعد الخلو من الأعراض لمدة 24 ساعة"},{"en":"As soon as jaundice appears","es":"Tan pronto como aparezca la ictericia","ru":"Как только появится желтуха","tr":"Sarılık ortaya çıkar çıkmaz","hi":"जैसे ही पीलिया प्रकट हो","ar":"بمجرد ظهور اليرقان"},{"en":"Only with approval from the regulatory authority","es":"Solo con la aprobación de la autoridad reguladora","ru":"Только с одобрения регулирующего органа","tr":"Yalnızca düzenleyici otoritenin onayıyla","hi":"केवल नियामक प्राधिकरण की मंजूरी के साथ","ar":"فقط بموافقة الجهة التنظيمية"},{"en":"After washing hands twice","es":"Después de lavarse las manos dos veces","ru":"После двукратного мытья рук","tr":"Ellerini iki kez yıkadıktan sonra","hi":"दो बार हाथ धोने के बाद","ar":"بعد غسل اليدين مرتين"}],"e":{"en":"Hepatitis A is a Big 6 pathogen; the employee is excluded and may return only when the regulatory authority approves, per the Food Code.","es":"La hepatitis A es un patógeno de los 6 Grandes; el empleado es excluido y solo puede regresar cuando la autoridad reguladora lo apruebe, según el Código de Alimentos.","ru":"Гепатит А входит в «Большую шестёрку»; сотрудник отстраняется и может вернуться только с одобрения регулирующего органа согласно Продовольственному кодексу.","tr":"Hepatit A bir Büyük 6 patojenidir; çalışan dışlanır ve Gıda Kodu'na göre yalnızca düzenleyici otorite onayladığında işe dönebilir.","hi":"हेपेटाइटिस A एक बिग 6 रोगजनक है; कर्मचारी को बाहर किया जाता है और फूड कोड के अनुसार केवल नियामक प्राधिकरण की मंजूरी मिलने पर ही लौट सकता है।","ar":"التهاب الكبد A من مسببات الستة الكبار؛ يُستبعَد الموظف ولا يمكنه العودة إلا بموافقة الجهة التنظيمية، وفقًا لقانون الغذاء."}},{"cat":"staff","a":3,"q":{"en":"Which is the correct minimum scrub time and step order the PIC should train staff to follow when handwashing?","es":"¿Cuál es el tiempo mínimo de fregado y el orden de pasos correctos que el PIC debe enseñar al personal para el lavado de manos?","ru":"Какое минимальное время намыливания и порядок действий должен PIC обучить персонал соблюдать при мытье рук?","tr":"PIC, personele el yıkarken uygulamaları için hangi doğru minimum ovma süresini ve adım sırasını öğretmelidir?","hi":"हाथ धोते समय PIC को स्टाफ को किस सही न्यूनतम स्क्रब समय और चरण क्रम का पालन करना सिखाना चाहिए?","ar":"ما هو الحد الأدنى الصحيح لمدة الفرك وترتيب الخطوات التي يجب أن يدرب الشخص المسؤول الموظفين على اتباعها عند غسل اليدين؟"},"o":[{"en":"Rinse, dry, then apply sanitizer for 5 seconds","es":"Enjuagar, secar, luego aplicar desinfectante por 5 segundos","ru":"Ополоснуть, высушить, затем нанести дезинфектант на 5 секунд","tr":"Durulamak, kurulamak, sonra 5 saniye dezenfektan uygulamak","hi":"धोना, सुखाना, फिर 5 सेकंड के लिए सैनिटाइज़र लगाना","ar":"الشطف والتجفيف ثم وضع المطهر لمدة 5 ثوانٍ"},{"en":"Apply hand sanitizer only for 10 seconds","es":"Aplicar solo desinfectante de manos por 10 segundos","ru":"Нанести только антисептик для рук на 10 секунд","tr":"Yalnızca 10 saniye el dezenfektanı uygulamak","hi":"केवल 10 सेकंड के लिए हैंड सैनिटाइज़र लगाना","ar":"وضع معقم اليدين فقط لمدة 10 ثوانٍ"},{"en":"Wet, scrub 5 seconds, rinse, dry","es":"Mojar, fregar 5 segundos, enjuagar, secar","ru":"Смочить, тереть 5 секунд, ополоснуть, высушить","tr":"Islatmak, 5 saniye ovmak, durulamak, kurulamak","hi":"गीला करना, 5 सेकंड रगड़ना, धोना, सुखाना","ar":"الترطيب، الفرك 5 ثوانٍ، الشطف، التجفيف"},{"en":"Wet, apply soap and scrub 20 seconds, rinse, dry","es":"Mojar, aplicar jabón y fregar 20 segundos, enjuagar, secar","ru":"Смочить, нанести мыло и тереть 20 секунд, ополоснуть, высушить","tr":"Islatmak, sabun sürüp 20 saniye ovmak, durulamak, kurulamak","hi":"गीला करना, साबुन लगाना और 20 सेकंड रगड़ना, धोना, सुखाना","ar":"الترطيب، وضع الصابون والفرك 20 ثانية، الشطف، التجفيف"}],"e":{"en":"Proper handwashing is wet, soap and vigorous scrub for at least 20 seconds, rinse, and dry; sanitizer is never a substitute for washing.","es":"El lavado de manos correcto es mojar, jabón y fregar vigorosamente durante al menos 20 segundos, enjuagar y secar; el desinfectante nunca sustituye al lavado.","ru":"Правильное мытьё рук: смочить, нанести мыло и энергично тереть не менее 20 секунд, ополоснуть и высушить; антисептик никогда не заменяет мытьё.","tr":"Doğru el yıkama; ıslatmak, sabun sürüp en az 20 saniye güçlüce ovmak, durulamak ve kurulamaktır; dezenfektan asla yıkamanın yerini tutmaz.","hi":"सही हाथ धुलाई है गीला करना, साबुन लगाना और कम से कम 20 सेकंड जोर से रगड़ना, धोना और सुखाना; सैनिटाइज़र कभी धोने का विकल्प नहीं है।","ar":"غسل اليدين الصحيح هو الترطيب ووضع الصابون والفرك بقوة لمدة 20 ثانية على الأقل ثم الشطف والتجفيف؛ والمطهر ليس بديلاً عن الغسل أبدًا."}},{"cat":"staff","a":0,"q":{"en":"A manager observes staff rinsing produce in the designated handwashing sink. What should the manager do?","es":"Un gerente observa que el personal enjuaga productos en el lavamanos designado. ¿Qué debe hacer el gerente?","ru":"Менеджер замечает, что персонал моет продукты в раковине, предназначенной для мытья рук. Что должен сделать менеджер?","tr":"Bir yönetici, personelin ürünleri el yıkamaya ayrılmış lavaboda yıkadığını görür. Yönetici ne yapmalıdır?","hi":"एक प्रबंधक देखता है कि स्टाफ निर्दिष्ट हाथ धोने वाले सिंक में उपज धो रहा है। प्रबंधक को क्या करना चाहिए?","ar":"يلاحظ مدير أن الموظفين يغسلون المنتجات في حوض غسل اليدين المخصص. ماذا يجب أن يفعل المدير؟"},"o":[{"en":"Stop the practice; handwashing sinks are only for washing hands","es":"Detener la práctica; los lavamanos son solo para lavarse las manos","ru":"Прекратить это; раковины для мытья рук предназначены только для мытья рук","tr":"Bu uygulamayı durdurmak; el yıkama lavaboları yalnızca el yıkamak içindir","hi":"इस प्रथा को रोकें; हाथ धोने के सिंक केवल हाथ धोने के लिए हैं","ar":"إيقاف هذه الممارسة؛ أحواض غسل اليدين مخصصة لغسل اليدين فقط"},{"en":"Allow it if the produce is rinsed quickly","es":"Permitirlo si el producto se enjuaga rápidamente","ru":"Разрешить, если продукты моются быстро","tr":"Ürünler hızlıca yıkanırsa buna izin vermek","hi":"यदि उपज जल्दी धोई जाती है तो अनुमति दें","ar":"السماح بذلك إذا تم شطف المنتجات بسرعة"},{"en":"Allow it only during busy periods","es":"Permitirlo solo durante periodos ocupados","ru":"Разрешить только в часы пик","tr":"Yalnızca yoğun dönemlerde izin vermek","hi":"केवल व्यस्त अवधि के दौरान अनुमति दें","ar":"السماح بذلك فقط خلال أوقات الانشغال"},{"en":"Allow it if the sink is sanitized after","es":"Permitirlo si el lavamanos se desinfecta después","ru":"Разрешить, если раковину продезинфицировать после","tr":"Sonrasında lavabo dezenfekte edilirse izin vermek","hi":"यदि सिंक बाद में सैनिटाइज़ किया जाए तो अनुमति दें","ar":"السماح بذلك إذا تم تطهير الحوض بعد ذلك"}],"e":{"en":"Handwashing sinks must be used only for handwashing, not for washing food, filling pots, or dumping liquids, to prevent contamination.","es":"Los lavamanos deben usarse solo para lavarse las manos, no para lavar alimentos, llenar ollas o vaciar líquidos, para evitar la contaminación.","ru":"Раковины для мытья рук должны использоваться только для мытья рук, а не для мытья продуктов, наполнения кастрюль или слива жидкостей, чтобы избежать загрязнения.","tr":"El yıkama lavaboları, kirlenmeyi önlemek için yalnızca el yıkamak için kullanılmalıdır; gıda yıkamak, tencere doldurmak veya sıvı dökmek için değil.","hi":"संदूषण रोकने के लिए हाथ धोने के सिंक का उपयोग केवल हाथ धोने के लिए किया जाना चाहिए, न कि भोजन धोने, बर्तन भरने या तरल पदार्थ डालने के लिए।","ar":"يجب استخدام أحواض غسل اليدين لغسل اليدين فقط، وليس لغسل الطعام أو ملء القدور أو التخلص من السوائل، لمنع التلوث."}},{"cat":"staff","a":1,"q":{"en":"How should a PIC treat the use of hand antiseptic (sanitizer) in the food safety program?","es":"¿Cómo debe tratar un PIC el uso de antiséptico (desinfectante) para manos en el programa de seguridad alimentaria?","ru":"Как PIC должен относиться к использованию антисептика для рук в программе безопасности пищевых продуктов?","tr":"Bir PIC, gıda güvenliği programında el antiseptiği (dezenfektan) kullanımını nasıl ele almalıdır?","hi":"PIC को खाद्य सुरक्षा कार्यक्रम में हैंड एंटीसेप्टिक (सैनिटाइज़र) के उपयोग को कैसे संभालना चाहिए?","ar":"كيف يجب أن يتعامل الشخص المسؤول مع استخدام مطهر اليدين في برنامج سلامة الأغذية؟"},"o":[{"en":"As a full replacement for handwashing when busy","es":"Como un reemplazo total del lavado de manos cuando hay mucho trabajo","ru":"Как полную замену мытья рук в занятые периоды","tr":"Yoğun olunduğunda el yıkamanın tam yerine geçen bir şey olarak","hi":"व्यस्त होने पर हाथ धोने के पूर्ण विकल्प के रूप में","ar":"كبديل كامل لغسل اليدين عند الانشغال"},{"en":"Only after proper handwashing, never instead of it","es":"Solo después del lavado de manos adecuado, nunca en su lugar","ru":"Только после правильного мытья рук, никогда вместо него","tr":"Yalnızca uygun el yıkamadan sonra, asla onun yerine değil","hi":"केवल उचित हाथ धुलाई के बाद, कभी उसके बजाय नहीं","ar":"فقط بعد غسل اليدين بشكل صحيح، وليس بديلاً عنه أبدًا"},{"en":"Only for employees who wear gloves","es":"Solo para empleados que usan guantes","ru":"Только для сотрудников, носящих перчатки","tr":"Yalnızca eldiven takan çalışanlar için","hi":"केवल दस्ताने पहनने वाले कर्मचारियों के लिए","ar":"فقط للموظفين الذين يرتدون القفازات"},{"en":"As the primary method before touching raw meat","es":"Como método principal antes de tocar carne cruda","ru":"Как основной метод перед прикосновением к сырому мясу","tr":"Çiğ ete dokunmadan önce birincil yöntem olarak","hi":"कच्चे मांस को छूने से पहले प्राथमिक विधि के रूप में","ar":"كطريقة أساسية قبل لمس اللحوم النيئة"}],"e":{"en":"Hand antiseptics may be applied only after hands are properly washed and dried; they are a supplement, never a substitute for handwashing.","es":"Los antisépticos para manos solo pueden aplicarse después de lavar y secar las manos correctamente; son un complemento, nunca un sustituto del lavado.","ru":"Антисептики для рук можно применять только после того, как руки правильно вымыты и высушены; они являются дополнением, а не заменой мытья рук.","tr":"El antiseptikleri yalnızca eller uygun şekilde yıkanıp kurulandıktan sonra uygulanabilir; el yıkamanın yerine değil, tamamlayıcısı olarak kullanılır.","hi":"हैंड एंटीसेप्टिक केवल हाथ ठीक से धोने और सुखाने के बाद ही लगाए जा सकते हैं; ये एक पूरक हैं, कभी हाथ धोने का विकल्प नहीं।","ar":"لا يجوز استخدام مطهرات اليدين إلا بعد غسل اليدين وتجفيفهما بشكل صحيح؛ فهي مكمل وليست بديلاً عن غسل اليدين أبدًا."}},{"cat":"staff","a":2,"q":{"en":"Which statement best reflects the Food Code rule the PIC must enforce for ready-to-eat (RTE) food?","es":"¿Qué afirmación refleja mejor la regla del Código de Alimentos que el PIC debe hacer cumplir para los alimentos listos para comer (RTE)?","ru":"Какое утверждение лучше всего отражает правило Продовольственного кодекса, которое PIC должен обеспечивать для готовых к употреблению (RTE) продуктов?","tr":"Hangi ifade, PIC'nin yemeye hazır (RTE) gıdalar için uygulaması gereken Gıda Kodu kuralını en iyi şekilde yansıtır?","hi":"कौन सा कथन खाने-के-लिए-तैयार (RTE) भोजन के लिए PIC द्वारा लागू किए जाने वाले फूड कोड नियम को सबसे अच्छी तरह दर्शाता है?","ar":"أي عبارة تعكس بشكل أفضل قاعدة قانون الغذاء التي يجب أن يطبقها الشخص المسؤول للأطعمة الجاهزة للأكل (RTE)؟"},"o":[{"en":"Bare-hand contact is fine if hands were just washed","es":"El contacto con las manos desnudas está bien si acaban de lavarse","ru":"Контакт голыми руками допустим, если руки только что вымыты","tr":"Eller yeni yıkandıysa çıplak elle temas uygundur","hi":"यदि हाथ अभी धोए गए हों तो नंगे हाथ का संपर्क ठीक है","ar":"التلامس باليد المجردة مقبول إذا كانت اليدان قد غُسلتا للتو"},{"en":"Bare-hand contact is allowed for cold RTE food only","es":"El contacto con las manos desnudas se permite solo para alimentos RTE fríos","ru":"Контакт голыми руками разрешён только для холодной RTE-пищи","tr":"Çıplak elle temasa yalnızca soğuk RTE gıdalar için izin verilir","hi":"नंगे हाथ का संपर्क केवल ठंडे RTE भोजन के लिए अनुमत है","ar":"يُسمح بالتلامس باليد المجردة للأطعمة الجاهزة الباردة فقط"},{"en":"No bare-hand contact with RTE food; use gloves, tongs, or utensils","es":"Sin contacto con las manos desnudas con alimentos RTE; usar guantes, pinzas o utensilios","ru":"Никакого контакта голыми руками с RTE-пищей; использовать перчатки, щипцы или посуду","tr":"RTE gıdalarla çıplak elle temas olmaz; eldiven, maşa veya alet kullanın","hi":"RTE भोजन के साथ नंगे हाथ का संपर्क नहीं; दस्ताने, चिमटे या बर्तन का उपयोग करें","ar":"لا تلامس باليد المجردة مع الأطعمة الجاهزة؛ استخدم القفازات أو الملقط أو الأدوات"},{"en":"Gloves may be reused between tasks if they look clean","es":"Los guantes pueden reutilizarse entre tareas si se ven limpios","ru":"Перчатки можно повторно использовать между задачами, если они выглядят чистыми","tr":"Eldivenler temiz görünüyorsa görevler arasında yeniden kullanılabilir","hi":"यदि दस्ताने साफ दिखें तो कार्यों के बीच पुन: उपयोग किए जा सकते हैं","ar":"يمكن إعادة استخدام القفازات بين المهام إذا بدت نظيفة"}],"e":{"en":"The Food Code prohibits bare-hand contact with ready-to-eat food; employees must use suitable barriers such as single-use gloves, tongs, or utensils.","es":"El Código de Alimentos prohíbe el contacto con las manos desnudas con alimentos listos para comer; los empleados deben usar barreras adecuadas como guantes de un solo uso, pinzas o utensilios.","ru":"Продовольственный кодекс запрещает контакт голыми руками с готовой к употреблению пищей; сотрудники должны использовать подходящие барьеры, такие как одноразовые перчатки, щипцы или посуду.","tr":"Gıda Kodu, yemeye hazır gıdalarla çıplak elle teması yasaklar; çalışanlar tek kullanımlık eldiven, maşa veya alet gibi uygun bariyerler kullanmalıdır.","hi":"फूड कोड खाने-के-लिए-तैयार भोजन के साथ नंगे हाथ के संपर्क को प्रतिबंधित करता है; कर्मचारियों को एकल-उपयोग दस्ताने, चिमटे या बर्तन जैसे उपयुक्त अवरोधकों का उपयोग करना चाहिए।","ar":"يحظر قانون الغذاء التلامس باليد المجردة مع الأطعمة الجاهزة للأكل؛ يجب على الموظفين استخدام حواجز مناسبة مثل القفازات أحادية الاستخدام أو الملاقط أو الأدوات."}},{"cat":"staff","a":0,"q":{"en":"How can a PIC BEST demonstrate the required knowledge of food safety to a health inspector?","es":"¿Cómo puede un PIC demostrar MEJOR el conocimiento requerido de seguridad alimentaria a un inspector de salud?","ru":"Как PIC может ЛУЧШЕ всего продемонстрировать инспектору требуемые знания о безопасности пищевых продуктов?","tr":"Bir PIC, bir sağlık müfettişine gerekli gıda güvenliği bilgisini EN İYİ nasıl gösterebilir?","hi":"एक PIC स्वास्थ्य निरीक्षक को खाद्य सुरक्षा का आवश्यक ज्ञान सबसे अच्छे तरीके से कैसे प्रदर्शित कर सकता है?","ar":"كيف يمكن للشخص المسؤول أن يُظهر بشكل أفضل المعرفة المطلوبة بسلامة الأغذية لمفتش صحي؟"},"o":[{"en":"By answering questions correctly and complying with the Food Code, often via certification","es":"Respondiendo correctamente las preguntas y cumpliendo el Código de Alimentos, a menudo mediante certificación","ru":"Правильно отвечая на вопросы и соблюдая Продовольственный кодекс, часто через сертификацию","tr":"Soruları doğru yanıtlayarak ve Gıda Kodu'na uyarak, genellikle sertifikasyon yoluyla","hi":"प्रश्नों का सही उत्तर देकर और फूड कोड का पालन करके, अक्सर प्रमाणन के माध्यम से","ar":"بالإجابة على الأسئلة بشكل صحيح والالتزام بقانون الغذاء، غالبًا عبر الحصول على شهادة"},{"en":"By showing the last three payroll records","es":"Mostrando los últimos tres registros de nómina","ru":"Показав последние три платёжные ведомости","tr":"Son üç bordro kaydını göstererek","hi":"पिछले तीन वेतन रिकॉर्ड दिखाकर","ar":"بعرض آخر ثلاثة سجلات رواتب"},{"en":"By pointing to the posted business license","es":"Señalando la licencia comercial exhibida","ru":"Указав на вывешенную бизнес-лицензию","tr":"Asılı işletme ruhsatını göstererek","hi":"प्रदर्शित व्यवसाय लाइसेंस की ओर इशारा करके","ar":"بالإشارة إلى رخصة العمل المعلقة"},{"en":"By deferring all questions to a corporate hotline","es":"Remitiendo todas las preguntas a una línea directa corporativa","ru":"Переадресовав все вопросы на корпоративную горячую линию","tr":"Tüm soruları kurumsal bir hatta yönlendirerek","hi":"सभी प्रश्नों को कॉर्पोरेट हॉटलाइन पर भेजकर","ar":"بإحالة جميع الأسئلة إلى خط اتصال مؤسسي"}],"e":{"en":"The PIC demonstrates knowledge by correctly answering the inspector's questions about safe food handling and by having the operation in compliance; a valid certification is one accepted way.","es":"El PIC demuestra conocimiento respondiendo correctamente las preguntas del inspector sobre el manejo seguro de alimentos y manteniendo la operación en cumplimiento; una certificación válida es una forma aceptada.","ru":"PIC демонстрирует знания, правильно отвечая на вопросы инспектора о безопасном обращении с пищей и поддерживая соответствие предприятия требованиям; действующая сертификация — один из принятых способов.","tr":"PIC, müfettişin güvenli gıda işleme hakkındaki sorularını doğru yanıtlayarak ve işletmeyi mevzuata uygun tutarak bilgisini gösterir; geçerli bir sertifika kabul edilen yollardan biridir.","hi":"PIC सुरक्षित भोजन संचालन के बारे में निरीक्षक के प्रश्नों का सही उत्तर देकर और प्रतिष्ठान को अनुपालन में रखकर ज्ञान प्रदर्शित करता है; एक वैध प्रमाणन एक स्वीकृत तरीका है।","ar":"يُظهر الشخص المسؤول معرفته بالإجابة الصحيحة على أسئلة المفتش حول التعامل الآمن مع الطعام وبالحفاظ على امتثال المنشأة؛ والشهادة السارية إحدى الطرق المقبولة."}},{"cat":"staff","a":1,"q":{"en":"What is the most effective way for a manager to build a strong food safety culture?","es":"¿Cuál es la forma más efectiva de que un gerente construya una sólida cultura de seguridad alimentaria?","ru":"Каков наиболее эффективный способ для менеджера сформировать сильную культуру безопасности пищевых продуктов?","tr":"Bir yöneticinin güçlü bir gıda güvenliği kültürü oluşturmasının en etkili yolu nedir?","hi":"एक प्रबंधक के लिए मजबूत खाद्य सुरक्षा संस्कृति बनाने का सबसे प्रभावी तरीका क्या है?","ar":"ما هي الطريقة الأكثر فعالية لبناء المدير ثقافة قوية لسلامة الأغذية؟"},"o":[{"en":"Posting rules and assuming staff will follow them","es":"Publicar reglas y suponer que el personal las seguirá","ru":"Вывесить правила и предполагать, что персонал будет им следовать","tr":"Kuralları asıp personelin bunlara uyacağını varsaymak","hi":"नियम पोस्ट करना और मान लेना कि स्टाफ उनका पालन करेगा","ar":"نشر القواعد وافتراض أن الموظفين سيتبعونها"},{"en":"Modeling safe behavior, communicating expectations, and holding everyone accountable","es":"Modelar el comportamiento seguro, comunicar las expectativas y responsabilizar a todos","ru":"Демонстрировать безопасное поведение, сообщать ожидания и обеспечивать ответственность каждого","tr":"Güvenli davranışı örnek olarak sergilemek, beklentileri iletmek ve herkesi sorumlu tutmak","hi":"सुरक्षित व्यवहार का उदाहरण प्रस्तुत करना, अपेक्षाएं बताना और सभी को जवाबदेह ठहराना","ar":"أن يكون قدوة في السلوك الآمن، وإيصال التوقعات، ومحاسبة الجميع"},{"en":"Focusing only on passing the annual inspection","es":"Enfocarse solo en aprobar la inspección anual","ru":"Сосредоточиться только на прохождении ежегодной проверки","tr":"Yalnızca yıllık denetimi geçmeye odaklanmak","hi":"केवल वार्षिक निरीक्षण पास करने पर ध्यान केंद्रित करना","ar":"التركيز فقط على اجتياز التفتيش السنوي"},{"en":"Delegating all food safety to the newest employee","es":"Delegar toda la seguridad alimentaria al empleado más nuevo","ru":"Делегировать всю безопасность пищи самому новому сотруднику","tr":"Tüm gıda güvenliğini en yeni çalışana devretmek","hi":"सभी खाद्य सुरक्षा को सबसे नए कर्मचारी को सौंपना","ar":"تفويض كل مسؤولية سلامة الأغذية لأحدث موظف"}],"e":{"en":"A strong food safety culture depends on leadership modeling safe behavior, clear communication, shared values, and holding all staff accountable.","es":"Una sólida cultura de seguridad alimentaria depende del liderazgo que modela el comportamiento seguro, la comunicación clara, los valores compartidos y la responsabilidad de todo el personal.","ru":"Сильная культура безопасности пищи зависит от руководства, демонстрирующего безопасное поведение, чёткой коммуникации, общих ценностей и ответственности всего персонала.","tr":"Güçlü bir gıda güvenliği kültürü; liderliğin güvenli davranışı örnek göstermesine, açık iletişime, ortak değerlere ve tüm personelin sorumlu tutulmasına bağlıdır.","hi":"एक मजबूत खाद्य सुरक्षा संस्कृति नेतृत्व द्वारा सुरक्षित व्यवहार का उदाहरण, स्पष्ट संचार, साझा मूल्यों और सभी स्टाफ की जवाबदेही पर निर्भर करती है।","ar":"تعتمد ثقافة سلامة الأغذية القوية على أن تكون القيادة قدوة في السلوك الآمن، والتواصل الواضح، والقيم المشتركة، ومحاسبة جميع الموظفين."}},{"cat":"staff","a":3,"q":{"en":"Why should a PIC document employee food safety training?","es":"¿Por qué debe un PIC documentar la capacitación en seguridad alimentaria de los empleados?","ru":"Почему PIC должен документировать обучение сотрудников безопасности пищевых продуктов?","tr":"Bir PIC neden çalışanların gıda güvenliği eğitimini belgelemelidir?","hi":"PIC को कर्मचारी खाद्य सुरक्षा प्रशिक्षण का दस्तावेज़ीकरण क्यों करना चाहिए?","ar":"لماذا يجب على الشخص المسؤول توثيق تدريب الموظفين على سلامة الأغذية؟"},"o":[{"en":"It replaces the need for ongoing training","es":"Reemplaza la necesidad de capacitación continua","ru":"Это заменяет необходимость постоянного обучения","tr":"Sürekli eğitim ihtiyacının yerini alır","hi":"यह चल रहे प्रशिक्षण की आवश्यकता को प्रतिस्थापित करता है","ar":"لأنه يغني عن الحاجة إلى التدريب المستمر"},{"en":"It guarantees no employee will ever get sick","es":"Garantiza que ningún empleado se enfermará jamás","ru":"Это гарантирует, что ни один сотрудник никогда не заболеет","tr":"Hiçbir çalışanın asla hastalanmayacağını garanti eder","hi":"यह गारंटी देता है कि कोई कर्मचारी कभी बीमार नहीं होगा","ar":"لأنه يضمن ألا يمرض أي موظف أبدًا"},{"en":"It is only needed for the head chef","es":"Solo es necesario para el chef principal","ru":"Это нужно только для шеф-повара","tr":"Yalnızca baş aşçı için gereklidir","hi":"यह केवल हेड शेफ के लिए आवश्यक है","ar":"لأنه مطلوب فقط لرئيس الطهاة"},{"en":"It verifies training occurred, supports accountability, and aids inspections","es":"Verifica que la capacitación ocurrió, apoya la responsabilidad y ayuda en las inspecciones","ru":"Это подтверждает, что обучение проводилось, поддерживает ответственность и помогает при проверках","tr":"Eğitimin gerçekleştiğini doğrular, hesap verebilirliği destekler ve denetimlere yardımcı olur","hi":"यह सत्यापित करता है कि प्रशिक्षण हुआ, जवाबदेही का समर्थन करता है और निरीक्षण में सहायता करता है","ar":"لأنه يتحقق من حدوث التدريب، ويدعم المساءلة، ويساعد في عمليات التفتيش"}],"e":{"en":"Documented training provides evidence that employees were trained, supports accountability and corrective coaching, and demonstrates active managerial control to inspectors.","es":"La capacitación documentada proporciona evidencia de que los empleados fueron capacitados, apoya la responsabilidad y el entrenamiento correctivo, y demuestra el control gerencial activo a los inspectores.","ru":"Документированное обучение служит доказательством того, что сотрудники прошли обучение, поддерживает ответственность и корректирующее наставничество и демонстрирует инспекторам активный управленческий контроль.","tr":"Belgelenmiş eğitim, çalışanların eğitildiğine dair kanıt sağlar, hesap verebilirliği ve düzeltici koçluğu destekler ve müfettişlere aktif yönetimsel kontrolü gösterir.","hi":"दस्तावेज़ीकृत प्रशिक्षण इस बात का प्रमाण देता है कि कर्मचारियों को प्रशिक्षित किया गया, जवाबदेही और सुधारात्मक कोचिंग का समर्थन करता है, और निरीक्षकों को सक्रिय प्रबंधकीय नियंत्रण प्रदर्शित करता है।","ar":"التدريب الموثق يوفر دليلاً على أن الموظفين قد تدربوا، ويدعم المساءلة والتوجيه التصحيحي، ويُظهر للمفتشين السيطرة الإدارية الفعالة."}},{"cat":"staff","a":2,"q":{"en":"A cook diagnosed with Shigella wants to return to work. What does the Food Code generally require?","es":"Un cocinero diagnosticado con Shigella quiere regresar al trabajo. ¿Qué requiere generalmente el Código de Alimentos?","ru":"Повар с диагнозом шигеллёз хочет вернуться к работе. Что обычно требует Продовольственный кодекс?","tr":"Shigella teşhisi konan bir aşçı işe dönmek istiyor. Gıda Kodu genellikle ne gerektirir?","hi":"शिगेला से निदान किया गया रसोइया काम पर लौटना चाहता है। फूड कोड आमतौर पर क्या आवश्यक करता है?","ar":"يريد طاهٍ شُخِّص بالإصابة بالشيغيلا العودة إلى العمل. ماذا يتطلب قانون الغذاء عمومًا؟"},"o":[{"en":"Return once he no longer feels tired","es":"Regresar cuando ya no se sienta cansado","ru":"Вернуться, как только перестанет чувствовать усталость","tr":"Artık yorgun hissetmediğinde dönmek","hi":"जब वह अब थका हुआ महसूस न करे तब लौटना","ar":"العودة بمجرد ألا يعود يشعر بالتعب"},{"en":"Return after wearing gloves for one shift","es":"Regresar después de usar guantes por un turno","ru":"Вернуться после ношения перчаток в течение одной смены","tr":"Bir vardiya eldiven taktıktan sonra dönmek","hi":"एक शिफ्ट के लिए दस्ताने पहनने के बाद लौटना","ar":"العودة بعد ارتداء القفازات لنوبة عمل واحدة"},{"en":"Exclusion until cleared by the regulatory authority or medical documentation","es":"Exclusión hasta ser autorizado por la autoridad reguladora o documentación médica","ru":"Отстранение до получения разрешения регулирующего органа или медицинской документации","tr":"Düzenleyici otorite veya tıbbi belge onaylayana kadar dışlama","hi":"नियामक प्राधिकरण या चिकित्सा दस्तावेज़ीकरण द्वारा मंजूरी मिलने तक बहिष्करण","ar":"الاستبعاد حتى الحصول على موافقة الجهة التنظيمية أو وثائق طبية"},{"en":"No action is required for Shigella","es":"No se requiere ninguna acción para Shigella","ru":"Для шигеллы никаких действий не требуется","tr":"Shigella için herhangi bir işlem gerekmez","hi":"शिगेला के लिए कोई कार्रवाई आवश्यक नहीं है","ar":"لا يلزم اتخاذ أي إجراء بشأن الشيغيلا"}],"e":{"en":"Shigella is a Big 6 pathogen requiring exclusion; the employee returns only with regulatory-authority approval or acceptable medical documentation.","es":"Shigella es un patógeno de los 6 Grandes que requiere exclusión; el empleado regresa solo con la aprobación de la autoridad reguladora o documentación médica aceptable.","ru":"Шигелла — патоген «Большой шестёрки», требующий отстранения; сотрудник возвращается только с одобрения регулирующего органа или приемлемой медицинской документации.","tr":"Shigella, dışlama gerektiren bir Büyük 6 patojenidir; çalışan yalnızca düzenleyici otorite onayı veya kabul edilebilir tıbbi belgeyle döner.","hi":"शिगेला एक बिग 6 रोगजनक है जिसमें बहिष्करण आवश्यक है; कर्मचारी केवल नियामक प्राधिकरण की मंजूरी या स्वीकार्य चिकित्सा दस्तावेज़ीकरण के साथ लौटता है।","ar":"الشيغيلا من مسببات الستة الكبار التي تتطلب الاستبعاد؛ ولا يعود الموظف إلا بموافقة الجهة التنظيمية أو وثائق طبية مقبولة."}},{"cat":"staff","a":0,"q":{"en":"Which set lists the five symptoms an employee must report to the PIC?","es":"¿Qué conjunto enumera los cinco síntomas que un empleado debe reportar al PIC?","ru":"В каком наборе перечислены пять симптомов, о которых сотрудник должен сообщить PIC?","tr":"Hangi grup, bir çalışanın PIC'ye bildirmesi gereken beş semptomu listeler?","hi":"कौन सा समूह उन पांच लक्षणों को सूचीबद्ध करता है जिन्हें कर्मचारी को PIC को रिपोर्ट करना चाहिए?","ar":"أي مجموعة تسرد الأعراض الخمسة التي يجب على الموظف إبلاغها للشخص المسؤول؟"},"o":[{"en":"Vomiting, diarrhea, jaundice, sore throat with fever, infected draining wound","es":"Vómitos, diarrea, ictericia, dolor de garganta con fiebre, herida infectada con drenaje","ru":"Рвота, диарея, желтуха, боль в горле с температурой, инфицированная гноящаяся рана","tr":"Kusma, ishal, sarılık, ateşle boğaz ağrısı, akıntılı iltihaplı yara","hi":"उल्टी, दस्त, पीलिया, बुखार के साथ गले में खराश, संक्रमित बहता घाव","ar":"القيء، الإسهال، اليرقان، التهاب الحلق مع الحمى، جرح ملتهب نازّ"},{"en":"Headache, mild cough, tiredness, dry skin, sneezing","es":"Dolor de cabeza, tos leve, cansancio, piel seca, estornudos","ru":"Головная боль, лёгкий кашель, усталость, сухость кожи, чихание","tr":"Baş ağrısı, hafif öksürük, yorgunluk, kuru cilt, hapşırma","hi":"सिरदर्द, हल्की खांसी, थकान, सूखी त्वचा, छींक","ar":"الصداع، السعال الخفيف، التعب، جفاف الجلد، العطس"},{"en":"Muscle ache, watery eyes, hiccups, cold hands, yawning","es":"Dolor muscular, ojos llorosos, hipo, manos frías, bostezos","ru":"Мышечная боль, слезящиеся глаза, икота, холодные руки, зевота","tr":"Kas ağrısı, sulanan gözler, hıçkırık, soğuk eller, esneme","hi":"मांसपेशियों में दर्द, आंखों से पानी, हिचकी, ठंडे हाथ, जम्हाई","ar":"ألم العضلات، دموع العينين، الفواق، برودة اليدين، التثاؤب"},{"en":"Runny nose, itchy eyes, mild rash, stiff neck, chills","es":"Nariz que gotea, ojos con picazón, sarpullido leve, cuello rígido, escalofríos","ru":"Насморк, зуд в глазах, лёгкая сыпь, скованность шеи, озноб","tr":"Burun akıntısı, kaşıntılı gözler, hafif döküntü, boyun tutulması, üşüme","hi":"बहती नाक, खुजली वाली आंखें, हल्के दाने, गर्दन में अकड़न, ठंड लगना","ar":"سيلان الأنف، حكة العينين، طفح خفيف، تيبس الرقبة، قشعريرة"}],"e":{"en":"The five reportable symptoms are vomiting, diarrhea, jaundice, sore throat with fever, and an infected lesion containing pus that is open and draining.","es":"Los cinco síntomas reportables son vómitos, diarrea, ictericia, dolor de garganta con fiebre y una lesión infectada con pus que está abierta y drenando.","ru":"Пять симптомов, подлежащих сообщению: рвота, диарея, желтуха, боль в горле с температурой и инфицированное поражение с гноем, которое открыто и гноится.","tr":"Bildirilmesi gereken beş semptom; kusma, ishal, sarılık, ateşle boğaz ağrısı ve açık ve akıntılı, cerahat içeren iltihaplı bir lezyondur.","hi":"पांच रिपोर्ट करने योग्य लक्षण हैं उल्टी, दस्त, पीलिया, बुखार के साथ गले में खराश, और मवाद युक्त संक्रमित घाव जो खुला और बहता हो।","ar":"الأعراض الخمسة الواجب الإبلاغ عنها هي: القيء، الإسهال، اليرقان، التهاب الحلق مع الحمى، وآفة ملتهبة تحتوي على صديد ومفتوحة ونازّة."}},{"cat":"staff","a":1,"q":{"en":"Why does the PIC treat Salmonella Typhi (typhoid) return-to-work more strictly than many other conditions?","es":"¿Por qué el PIC trata el regreso al trabajo por Salmonella Typhi (tifoidea) de forma más estricta que muchas otras condiciones?","ru":"Почему PIC относится к возвращению к работе после Salmonella Typhi (брюшной тиф) строже, чем к многим другим состояниям?","tr":"Bir PIC, Salmonella Typhi (tifo) sonrası işe dönüşü neden diğer birçok durumdan daha katı ele alır?","hi":"PIC साल्मोनेला टाइफी (टाइफाइड) के बाद काम पर वापसी को कई अन्य स्थितियों की तुलना में अधिक सख्ती से क्यों मानता है?","ar":"لماذا يتعامل الشخص المسؤول مع العودة إلى العمل بعد الإصابة بالسالمونيلا التيفية (التيفوئيد) بصرامة أكبر من العديد من الحالات الأخرى؟"},"o":[{"en":"It is not contagious once symptoms fade","es":"No es contagiosa una vez que los síntomas desaparecen","ru":"Она не заразна после исчезновения симптомов","tr":"Semptomlar geçtiğinde bulaşıcı değildir","hi":"लक्षण समाप्त होने पर यह संक्रामक नहीं होती","ar":"لا تكون معدية بمجرد زوال الأعراض"},{"en":"It can be shed for a long time and infected people may become carriers","es":"Puede ser eliminada durante mucho tiempo y las personas infectadas pueden convertirse en portadoras","ru":"Она может выделяться длительное время, а инфицированные люди могут стать носителями","tr":"Uzun süre saçılabilir ve enfekte kişiler taşıyıcı olabilir","hi":"यह लंबे समय तक फैल सकती है और संक्रमित लोग वाहक बन सकते हैं","ar":"يمكن أن يُطرح لفترة طويلة وقد يصبح المصابون حاملين للعدوى"},{"en":"It only affects the skin","es":"Solo afecta la piel","ru":"Она поражает только кожу","tr":"Yalnızca cildi etkiler","hi":"यह केवल त्वचा को प्रभावित करती है","ar":"يؤثر على الجلد فقط"},{"en":"It is destroyed easily by handwashing alone","es":"Se destruye fácilmente solo con el lavado de manos","ru":"Она легко уничтожается только мытьём рук","tr":"Yalnızca el yıkamayla kolayca yok edilir","hi":"यह केवल हाथ धोने से आसानी से नष्ट हो जाती है","ar":"يُقضى عليه بسهولة بغسل اليدين وحده"}],"e":{"en":"Salmonella Typhi can be shed for extended periods and people can become long-term carriers, so return requires regulatory-authority approval and often medical clearance.","es":"Salmonella Typhi puede eliminarse durante periodos prolongados y las personas pueden convertirse en portadoras a largo plazo, por lo que el regreso requiere aprobación de la autoridad reguladora y a menudo autorización médica.","ru":"Salmonella Typhi может выделяться в течение длительного времени, и люди могут стать долговременными носителями, поэтому возвращение требует одобрения регулирующего органа и часто медицинского допуска.","tr":"Salmonella Typhi uzun süre saçılabilir ve kişiler uzun vadeli taşıyıcı olabilir; bu nedenle işe dönüş düzenleyici otorite onayı ve genellikle tıbbi izin gerektirir.","hi":"साल्मोनेला टाइफी लंबी अवधि तक फैल सकती है और लोग दीर्घकालिक वाहक बन सकते हैं, इसलिए वापसी के लिए नियामक प्राधिकरण की मंजूरी और अक्सर चिकित्सा मंजूरी की आवश्यकता होती है।","ar":"يمكن أن تُطرح السالمونيلا التيفية لفترات طويلة وقد يصبح الأشخاص حاملين لها على المدى الطويل، لذا تتطلب العودة موافقة الجهة التنظيمية وغالبًا موافقة طبية."}},{"cat":"staff","a":2,"q":{"en":"A cook finishes handling raw beef, then must plate a salad. Beyond changing gloves, what must the PIC ensure happens?","es":"Un cocinero termina de manipular carne de res cruda y luego debe emplatar una ensalada. Además de cambiar los guantes, ¿qué debe asegurar el PIC?","ru":"Повар заканчивает работу с сырой говядиной, затем должен выложить салат. Помимо смены перчаток, что должен обеспечить PIC?","tr":"Bir aşçı çiğ dana etiyle işi bitirip ardından bir salatayı tabağa koymalıdır. Eldiven değiştirmenin ötesinde, PIC neyin yapıldığından emin olmalıdır?","hi":"एक रसोइया कच्चे गोमांस को संभालना समाप्त करता है, फिर एक सलाद को प्लेट करना होता है। दस्ताने बदलने के अलावा, PIC को क्या सुनिश्चित करना चाहिए?","ar":"ينتهي طاهٍ من التعامل مع لحم بقري نيء ثم عليه تقديم سلطة. إلى جانب تغيير القفازات، ماذا يجب أن يضمن الشخص المسؤول حدوثه؟"},"o":[{"en":"That the cook only wipes hands on a towel","es":"Que el cocinero solo se limpie las manos con una toalla","ru":"Чтобы повар только вытер руки полотенцем","tr":"Aşçının ellerini yalnızca havluyla silmesi","hi":"कि रसोइया केवल तौलिये पर हाथ पोंछे","ar":"أن يمسح الطاهي يديه بمنشفة فقط"},{"en":"That the cook applies sanitizer instead of washing","es":"Que el cocinero aplique desinfectante en lugar de lavarse","ru":"Чтобы повар нанёс антисептик вместо мытья","tr":"Aşçının yıkamak yerine dezenfektan uygulaması","hi":"कि रसोइया धोने के बजाय सैनिटाइज़र लगाए","ar":"أن يضع الطاهي المطهر بدلاً من الغسل"},{"en":"That the cook washes hands before donning the new gloves","es":"Que el cocinero se lave las manos antes de ponerse los nuevos guantes","ru":"Чтобы повар вымыл руки перед надеванием новых перчаток","tr":"Aşçının yeni eldivenleri takmadan önce ellerini yıkaması","hi":"कि रसोइया नए दस्ताने पहनने से पहले हाथ धोए","ar":"أن يغسل الطاهي يديه قبل ارتداء القفازات الجديدة"},{"en":"That the cook keeps the same gloves but rinses them","es":"Que el cocinero conserve los mismos guantes pero los enjuague","ru":"Чтобы повар оставил те же перчатки, но ополоснул их","tr":"Aşçının aynı eldivenleri tutup durulaması","hi":"कि रसोइया वही दस्ताने रखे लेकिन उन्हें धो ले","ar":"أن يبقي الطاهي القفازات نفسها لكن يشطفها"}],"e":{"en":"Gloves are not a substitute for handwashing; hands must be washed when changing tasks and before putting on a fresh pair of gloves.","es":"Los guantes no sustituyen el lavado de manos; las manos deben lavarse al cambiar de tarea y antes de ponerse un par de guantes nuevo.","ru":"Перчатки не заменяют мытьё рук; руки необходимо мыть при смене задач и перед надеванием новой пары перчаток.","tr":"Eldivenler el yıkamanın yerini tutmaz; görev değiştirirken ve yeni bir çift eldiven takmadan önce eller yıkanmalıdır.","hi":"दस्ताने हाथ धोने का विकल्प नहीं हैं; कार्य बदलते समय और नए दस्ताने पहनने से पहले हाथ धोए जाने चाहिए।","ar":"القفازات ليست بديلاً عن غسل اليدين؛ يجب غسل اليدين عند تغيير المهام وقبل ارتداء زوج جديد من القفازات."}},{"cat":"staff","a":3,"q":{"en":"Which jewelry is generally acceptable on the hands during food preparation under a manager's hygiene policy?","es":"¿Qué joyería es generalmente aceptable en las manos durante la preparación de alimentos según la política de higiene de un gerente?","ru":"Какие украшения на руках обычно допустимы во время приготовления пищи согласно гигиенической политике менеджера?","tr":"Bir yöneticinin hijyen politikasına göre, gıda hazırlığı sırasında eller üzerinde genellikle hangi takı kabul edilebilir?","hi":"प्रबंधक की स्वच्छता नीति के तहत भोजन तैयार करते समय हाथों पर आमतौर पर कौन सा आभूषण स्वीकार्य है?","ar":"ما هي المجوهرات المقبولة عمومًا على اليدين أثناء تحضير الطعام وفقًا لسياسة النظافة لدى المدير؟"},"o":[{"en":"A wristwatch and a bracelet","es":"Un reloj de pulsera y una pulsera","ru":"Наручные часы и браслет","tr":"Bir kol saati ve bir bilezik","hi":"एक कलाई घड़ी और एक कंगन","ar":"ساعة يد وسوار"},{"en":"A ring with a raised stone setting","es":"Un anillo con una piedra engastada en alto","ru":"Кольцо с выступающим камнем","tr":"Kabartmalı taşlı bir yüzük","hi":"उभरे हुए पत्थर की सेटिंग वाली अंगूठी","ar":"خاتم بفص حجر بارز"},{"en":"Several rings and a medical alert bracelet","es":"Varios anillos y una pulsera de alerta médica","ru":"Несколько колец и медицинский браслет","tr":"Birkaç yüzük ve tıbbi uyarı bilekliği","hi":"कई अंगूठियां और एक चिकित्सा अलर्ट कंगन","ar":"عدة خواتم وسوار تنبيه طبي"},{"en":"A plain band ring","es":"Un anillo de banda lisa","ru":"Простое обручальное кольцо","tr":"Düz bir alyans","hi":"एक सादा बैंड अंगूठी","ar":"خاتم سادة بدون فص"}],"e":{"en":"The Food Code allows only a plain band ring on the hands during food prep; watches, bracelets, and stone rings can harbor pathogens or fall into food.","es":"El Código de Alimentos permite solo un anillo de banda lisa en las manos durante la preparación; relojes, pulseras y anillos con piedras pueden albergar patógenos o caer en la comida.","ru":"Продовольственный кодекс разрешает на руках при приготовлении пищи только простое обручальное кольцо; часы, браслеты и кольца с камнями могут содержать патогены или упасть в еду.","tr":"Gıda Kodu, gıda hazırlığı sırasında ellerde yalnızca düz bir alyansa izin verir; saatler, bilezikler ve taşlı yüzükler patojen barındırabilir veya gıdaya düşebilir.","hi":"फूड कोड भोजन तैयार करते समय हाथों पर केवल एक सादा बैंड अंगूठी की अनुमति देता है; घड़ियां, कंगन और पत्थर वाली अंगूठियां रोगजनकों को आश्रय दे सकती हैं या भोजन में गिर सकती हैं।","ar":"يسمح قانون الغذاء بارتداء خاتم سادة فقط على اليدين أثناء تحضير الطعام؛ فالساعات والأساور والخواتم ذات الأحجار قد تؤوي مسببات الأمراض أو تسقط في الطعام."}},{"cat":"staff","a":0,"q":{"en":"What should a manager instruct staff to do with their apron before using the restroom?","es":"¿Qué debe indicar un gerente al personal que haga con su delantal antes de usar el baño?","ru":"Что менеджер должен поручить персоналу делать с фартуком перед посещением туалета?","tr":"Bir yönetici, tuvalete gitmeden önce personele önlükleriyle ne yapmalarını söylemelidir?","hi":"प्रबंधक को शौचालय का उपयोग करने से पहले स्टाफ को अपने एप्रन के साथ क्या करने का निर्देश देना चाहिए?","ar":"ماذا يجب أن يوجه المدير الموظفين لفعله بمريلتهم قبل استخدام الحمام؟"},"o":[{"en":"Remove it and leave it out of the restroom","es":"Quitárselo y dejarlo fuera del baño","ru":"Снять его и оставить вне туалета","tr":"Çıkarmak ve tuvaletin dışında bırakmak","hi":"इसे उतारकर शौचालय से बाहर छोड़ना","ar":"خلعها وتركها خارج الحمام"},{"en":"Tuck it into their waistband","es":"Metérselo en la cintura","ru":"Заправить его за пояс","tr":"Bel kısmına sıkıştırmak","hi":"इसे अपनी कमरबंद में खोंसना","ar":"دسّها في حزام الخصر"},{"en":"Wear it and wash it later","es":"Usarlo y lavarlo después","ru":"Носить его и постирать позже","tr":"Giymek ve sonra yıkamak","hi":"इसे पहनना और बाद में धोना","ar":"ارتداؤها وغسلها لاحقًا"},{"en":"Turn it inside out and keep wearing it","es":"Voltearlo al revés y seguir usándolo","ru":"Вывернуть наизнанку и продолжать носить","tr":"Ters çevirip giymeye devam etmek","hi":"इसे उल्टा करके पहनते रहना","ar":"قلبها من الداخل ومواصلة ارتدائها"}],"e":{"en":"Aprons and other soiled outer garments should be removed before leaving prep areas and especially before using the restroom to prevent contamination.","es":"Los delantales y otras prendas exteriores sucias deben quitarse antes de salir de las áreas de preparación y especialmente antes de usar el baño para evitar la contaminación.","ru":"Фартуки и другую загрязнённую верхнюю одежду следует снимать перед выходом из зон приготовления и особенно перед посещением туалета для предотвращения загрязнения.","tr":"Önlükler ve diğer kirli dış giysiler, kirlenmeyi önlemek için hazırlık alanlarından çıkmadan ve özellikle tuvalete gitmeden önce çıkarılmalıdır.","hi":"संदूषण रोकने के लिए एप्रन और अन्य गंदे बाहरी कपड़े तैयारी क्षेत्रों को छोड़ने से पहले और विशेष रूप से शौचालय का उपयोग करने से पहले उतार दिए जाने चाहिए।","ar":"يجب خلع المرايل والملابس الخارجية المتسخة الأخرى قبل مغادرة مناطق التحضير وخاصة قبل استخدام الحمام لمنع التلوث."}},{"cat":"staff","a":1,"q":{"en":"When monitoring staff, which observed behavior most clearly requires immediate corrective coaching by the manager?","es":"Al monitorear al personal, ¿qué comportamiento observado requiere más claramente un entrenamiento correctivo inmediato por parte del gerente?","ru":"При наблюдении за персоналом какое замеченное поведение наиболее явно требует немедленного корректирующего наставничества со стороны менеджера?","tr":"Personeli izlerken, gözlemlenen hangi davranış yönetici tarafından acil düzeltici koçluğu en açık şekilde gerektirir?","hi":"स्टाफ की निगरानी करते समय, कौन सा देखा गया व्यवहार प्रबंधक द्वारा तत्काल सुधारात्मक कोचिंग की सबसे स्पष्ट रूप से आवश्यकता रखता है?","ar":"عند مراقبة الموظفين، أي سلوك ملاحَظ يتطلب بوضوح توجيهًا تصحيحيًا فوريًا من المدير؟"},"o":[{"en":"An employee wearing a hair restraint","es":"Un empleado que usa una redecilla para el cabello","ru":"Сотрудник в головном уборе для волос","tr":"Saç filesi takan bir çalışan","hi":"बाल प्रतिबंधक पहने एक कर्मचारी","ar":"موظف يرتدي غطاء شعر"},{"en":"An employee handling ready-to-eat bread with bare hands","es":"Un empleado que manipula pan listo para comer con las manos desnudas","ru":"Сотрудник, берущий готовый к употреблению хлеб голыми руками","tr":"Yemeye hazır ekmeği çıplak elle tutan bir çalışan","hi":"खाने के लिए तैयार रोटी को नंगे हाथों से संभालने वाला कर्मचारी","ar":"موظف يتعامل مع خبز جاهز للأكل بيديه المجردتين"},{"en":"An employee using tongs to serve rolls","es":"Un empleado que usa pinzas para servir panecillos","ru":"Сотрудник, использующий щипцы для подачи булочек","tr":"Ekmek servisi için maşa kullanan bir çalışan","hi":"रोल परोसने के लिए चिमटे का उपयोग करने वाला कर्मचारी","ar":"موظف يستخدم ملقطًا لتقديم الخبز"},{"en":"An employee washing hands after a break","es":"Un empleado que se lava las manos después de un descanso","ru":"Сотрудник, моющий руки после перерыва","tr":"Moladan sonra ellerini yıkayan bir çalışan","hi":"ब्रेक के बाद हाथ धोने वाला कर्मचारी","ar":"موظف يغسل يديه بعد الاستراحة"}],"e":{"en":"Bare-hand contact with ready-to-eat food violates the Food Code and creates immediate contamination risk, so the manager must correct it at once.","es":"El contacto con las manos desnudas con alimentos listos para comer viola el Código de Alimentos y crea un riesgo inmediato de contaminación, por lo que el gerente debe corregirlo de inmediato.","ru":"Контакт голыми руками с готовой к употреблению пищей нарушает Продовольственный кодекс и создаёт непосредственный риск загрязнения, поэтому менеджер должен немедленно это исправить.","tr":"Yemeye hazır gıdayla çıplak elle temas Gıda Kodu'nu ihlal eder ve anında kirlenme riski oluşturur; bu nedenle yönetici bunu hemen düzeltmelidir.","hi":"खाने-के-लिए-तैयार भोजन के साथ नंगे हाथ का संपर्क फूड कोड का उल्लंघन करता है और तत्काल संदूषण जोखिम पैदा करता है, इसलिए प्रबंधक को इसे तुरंत सुधारना चाहिए।","ar":"التلامس باليد المجردة مع الأطعمة الجاهزة للأكل ينتهك قانون الغذاء ويخلق خطر تلوث فوري، لذا يجب على المدير تصحيحه على الفور."}},{"cat":"staff","a":2,"q":{"en":"A manager must decide about an employee diagnosed with STEC (Shiga toxin-producing E. coli). What is required?","es":"Un gerente debe decidir sobre un empleado diagnosticado con STEC (E. coli productora de toxina Shiga). ¿Qué se requiere?","ru":"Менеджер должен принять решение относительно сотрудника с диагнозом STEC (шига-токсин-продуцирующая E. coli). Что требуется?","tr":"Bir yönetici, STEC (Shiga toksini üreten E. coli) teşhisi konan bir çalışan hakkında karar vermelidir. Ne gereklidir?","hi":"एक प्रबंधक को STEC (शिगा टॉक्सिन-उत्पादक E. coli) से निदान किए गए कर्मचारी के बारे में निर्णय लेना है। क्या आवश्यक है?","ar":"على المدير أن يتخذ قرارًا بشأن موظف شُخِّص بالإصابة بـ STEC (الإشريكية القولونية المنتجة لسم الشيغا). ما المطلوب؟"},"o":[{"en":"Restriction only, with gloves","es":"Solo restricción, con guantes","ru":"Только ограничение, с перчатками","tr":"Yalnızca kısıtlama, eldivenle","hi":"केवल प्रतिबंध, दस्ताने के साथ","ar":"التقييد فقط، مع القفازات"},{"en":"No action if the employee feels fine","es":"Ninguna acción si el empleado se siente bien","ru":"Никаких действий, если сотрудник чувствует себя хорошо","tr":"Çalışan iyi hissediyorsa hiçbir işlem yok","hi":"यदि कर्मचारी ठीक महसूस करे तो कोई कार्रवाई नहीं","ar":"لا إجراء إذا كان الموظف يشعر أنه بخير"},{"en":"Exclusion and reporting, with return per regulatory-authority approval","es":"Exclusión y reporte, con regreso según la aprobación de la autoridad reguladora","ru":"Отстранение и уведомление, с возвращением по одобрению регулирующего органа","tr":"Dışlama ve bildirim, düzenleyici otorite onayına göre dönüş","hi":"बहिष्करण और रिपोर्टिंग, नियामक प्राधिकरण की मंजूरी के अनुसार वापसी","ar":"الاستبعاد والإبلاغ، والعودة بموافقة الجهة التنظيمية"},{"en":"Send home for exactly 12 hours","es":"Enviar a casa por exactamente 12 horas","ru":"Отправить домой ровно на 12 часов","tr":"Tam 12 saat eve göndermek","hi":"ठीक 12 घंटे के लिए घर भेजना","ar":"إرساله إلى المنزل لمدة 12 ساعة بالضبط"}],"e":{"en":"STEC is a Big 6 pathogen; the employee must be excluded, the diagnosis reported to the regulatory authority, and return allowed only with that authority's approval.","es":"STEC es un patógeno de los 6 Grandes; el empleado debe ser excluido, el diagnóstico reportado a la autoridad reguladora, y el regreso permitido solo con la aprobación de dicha autoridad.","ru":"STEC — патоген «Большой шестёрки»; сотрудник должен быть отстранён, диагноз сообщён регулирующему органу, а возвращение разрешено только с одобрения этого органа.","tr":"STEC bir Büyük 6 patojenidir; çalışan dışlanmalı, teşhis düzenleyici otoriteye bildirilmeli ve dönüşe yalnızca o otoritenin onayıyla izin verilmelidir.","hi":"STEC एक बिग 6 रोगजनक है; कर्मचारी को बाहर किया जाना चाहिए, निदान नियामक प्राधिकरण को रिपोर्ट किया जाना चाहिए, और वापसी केवल उस प्राधिकरण की मंजूरी के साथ ही अनुमत है।","ar":"STEC من مسببات الستة الكبار؛ يجب استبعاد الموظف وإبلاغ التشخيص للجهة التنظيمية، ولا يُسمح بالعودة إلا بموافقة تلك الجهة."}},{"cat":"staff","a":3,"q":{"en":"Which practice should a manager require to keep the employee health policy effective?","es":"¿Qué práctica debe exigir un gerente para mantener efectiva la política de salud de los empleados?","ru":"Какую практику должен требовать менеджер, чтобы политика здоровья сотрудников оставалась эффективной?","tr":"Bir yönetici, çalışan sağlığı politikasını etkili tutmak için hangi uygulamayı zorunlu kılmalıdır?","hi":"कर्मचारी स्वास्थ्य नीति को प्रभावी बनाए रखने के लिए प्रबंधक को कौन सी प्रथा की आवश्यकता होनी चाहिए?","ar":"أي ممارسة يجب أن يشترطها المدير للحفاظ على فعالية سياسة صحة الموظفين؟"},"o":[{"en":"Employees decide on their own whether to report symptoms","es":"Los empleados deciden por sí mismos si reportar los síntomas","ru":"Сотрудники сами решают, сообщать ли о симптомах","tr":"Çalışanlar semptomları bildirip bildirmemeye kendileri karar verir","hi":"कर्मचारी स्वयं तय करते हैं कि लक्षणों की रिपोर्ट करनी है या नहीं","ar":"يقرر الموظفون بأنفسهم ما إذا كانوا سيبلغون عن الأعراض"},{"en":"Only full-time staff are covered by the policy","es":"Solo el personal de tiempo completo está cubierto por la política","ru":"Политика распространяется только на штатных сотрудников","tr":"Politika yalnızca tam zamanlı personeli kapsar","hi":"नीति में केवल पूर्णकालिक स्टाफ शामिल है","ar":"تشمل السياسة الموظفين بدوام كامل فقط"},{"en":"Reporting is required only after a customer complains","es":"El reporte es necesario solo después de que un cliente se queje","ru":"Сообщение требуется только после жалобы клиента","tr":"Bildirim yalnızca bir müşteri şikayet ettikten sonra gereklidir","hi":"रिपोर्टिंग केवल ग्राहक की शिकायत के बाद आवश्यक है","ar":"الإبلاغ مطلوب فقط بعد شكوى العميل"},{"en":"Employees must report listed symptoms and diagnoses to the PIC, who acts on them","es":"Los empleados deben reportar los síntomas y diagnósticos listados al PIC, quien actúa en consecuencia","ru":"Сотрудники должны сообщать о перечисленных симптомах и диагнозах PIC, который принимает меры","tr":"Çalışanlar listelenen semptom ve teşhisleri, harekete geçen PIC'ye bildirmelidir","hi":"कर्मचारियों को सूचीबद्ध लक्षण और निदान PIC को रिपोर्ट करने चाहिए, जो उन पर कार्रवाई करता है","ar":"يجب على الموظفين إبلاغ الأعراض والتشخيصات المدرجة للشخص المسؤول الذي يتخذ الإجراء اللازم"}],"e":{"en":"An effective health policy requires all food employees to report listed symptoms and diagnoses to the PIC, who then applies the correct exclusion or restriction.","es":"Una política de salud efectiva requiere que todos los empleados de alimentos reporten los síntomas y diagnósticos listados al PIC, quien luego aplica la exclusión o restricción correcta.","ru":"Эффективная политика здоровья требует, чтобы все сотрудники, работающие с пищей, сообщали о перечисленных симптомах и диагнозах PIC, который затем применяет правильное отстранение или ограничение.","tr":"Etkili bir sağlık politikası, tüm gıda çalışanlarının listelenen semptom ve teşhisleri PIC'ye bildirmesini gerektirir; PIC de doğru dışlama veya kısıtlamayı uygular.","hi":"एक प्रभावी स्वास्थ्य नीति के लिए सभी खाद्य कर्मचारियों को सूचीबद्ध लक्षण और निदान PIC को रिपोर्ट करना आवश्यक है, जो फिर सही बहिष्करण या प्रतिबंध लागू करता है।","ar":"تتطلب سياسة الصحة الفعالة أن يبلغ جميع العاملين في الغذاء الأعراض والتشخيصات المدرجة للشخص المسؤول، الذي يطبق بعد ذلك الاستبعاد أو التقييد الصحيح."}},{"cat":"staff","a":0,"q":{"en":"An employee has a persistent cough but no fever, and the operation serves a general population. Under the Food Code, is this a reportable symptom the PIC must act on?","es":"Un empleado tiene tos persistente pero sin fiebre, y la operación atiende a la población general. Según el Código de Alimentos, ¿es este un síntoma reportable sobre el cual el PIC debe actuar?","ru":"У сотрудника постоянный кашель, но без температуры, и заведение обслуживает общее население. Согласно Продовольственному кодексу, является ли это симптомом, о котором PIC должен принять меры?","tr":"Bir çalışanın inatçı öksürüğü var ama ateşi yok ve işletme genel bir nüfusa hizmet ediyor. Gıda Kodu'na göre bu, PIC'nin harekete geçmesi gereken bildirilebilir bir semptom mudur?","hi":"एक कर्मचारी को लगातार खांसी है लेकिन बुखार नहीं है, और प्रतिष्ठान सामान्य आबादी की सेवा करता है। फूड कोड के तहत, क्या यह एक रिपोर्ट करने योग्य लक्षण है जिस पर PIC को कार्रवाई करनी चाहिए?","ar":"لدى موظف سعال مستمر لكن دون حمى، والمنشأة تخدم عامة الناس. وفقًا لقانون الغذاء، هل هذا عرض واجب الإبلاغ يجب أن يتصرف بشأنه الشخص المسؤول؟"},"o":[{"en":"No; a cough alone is not one of the five reportable symptoms","es":"No; la tos por sí sola no es uno de los cinco síntomas reportables","ru":"Нет; один кашель не входит в пять симптомов, подлежащих сообщению","tr":"Hayır; tek başına öksürük beş bildirilebilir semptomdan biri değildir","hi":"नहीं; अकेली खांसी पांच रिपोर्ट करने योग्य लक्षणों में से एक नहीं है","ar":"لا؛ السعال وحده ليس من الأعراض الخمسة الواجب الإبلاغ عنها"},{"en":"Yes; the employee must be excluded immediately","es":"Sí; el empleado debe ser excluido de inmediato","ru":"Да; сотрудник должен быть немедленно отстранён","tr":"Evet; çalışan hemen dışlanmalıdır","hi":"हां; कर्मचारी को तुरंत बाहर किया जाना चाहिए","ar":"نعم؛ يجب استبعاد الموظف فورًا"},{"en":"Yes; the diagnosis must be reported to the regulatory authority","es":"Sí; el diagnóstico debe reportarse a la autoridad reguladora","ru":"Да; диагноз должен быть сообщён регулирующему органу","tr":"Evet; teşhis düzenleyici otoriteye bildirilmelidir","hi":"हां; निदान नियामक प्राधिकरण को रिपोर्ट किया जाना चाहिए","ar":"نعم؛ يجب إبلاغ التشخيص للجهة التنظيمية"},{"en":"Yes; the employee must be restricted from all duties","es":"Sí; el empleado debe ser restringido de todas las tareas","ru":"Да; сотрудник должен быть ограничен во всех обязанностях","tr":"Evet; çalışan tüm görevlerden kısıtlanmalıdır","hi":"हां; कर्मचारी को सभी कार्यों से प्रतिबंधित किया जाना चाहिए","ar":"نعم؛ يجب تقييد الموظف من جميع المهام"}],"e":{"en":"A cough by itself is not among the five reportable symptoms; only sore throat with fever triggers action, so the PIC takes no formal exclusion here.","es":"La tos por sí sola no está entre los cinco síntomas reportables; solo el dolor de garganta con fiebre desencadena acción, por lo que el PIC no toma una exclusión formal aquí.","ru":"Кашель сам по себе не входит в пять симптомов, подлежащих сообщению; только боль в горле с температурой требует действий, поэтому PIC здесь не применяет формальное отстранение.","tr":"Öksürük tek başına beş bildirilebilir semptomdan biri değildir; yalnızca ateşle boğaz ağrısı harekete geçmeyi gerektirir, bu yüzden PIC burada resmi bir dışlama yapmaz.","hi":"अकेली खांसी पांच रिपोर्ट करने योग्य लक्षणों में नहीं है; केवल बुखार के साथ गले में खराश कार्रवाई शुरू करती है, इसलिए PIC यहां औपचारिक बहिष्करण नहीं करता।","ar":"السعال وحده ليس من الأعراض الخمسة الواجب الإبلاغ عنها؛ فقط التهاب الحلق مع الحمى يستدعي إجراءً، لذا لا يتخذ الشخص المسؤول استبعادًا رسميًا هنا."}},{"cat":"staff","a":1,"q":{"en":"How does the Food Code direct a PIC to handle a double handwash requirement after using the restroom, where local jurisdiction requires it?","es":"¿Cómo indica el Código de Alimentos que un PIC maneje el requisito de doble lavado de manos después de usar el baño, donde la jurisdicción local lo exige?","ru":"Как Продовольственный кодекс предписывает PIC соблюдать требование двойного мытья рук после посещения туалета там, где этого требует местная юрисдикция?","tr":"Yerel yetki alanının gerektirdiği durumlarda, Gıda Kodu bir PIC'ye tuvaleti kullandıktan sonra çift el yıkama gereksinimini nasıl ele almasını yönlendirir?","hi":"जहां स्थानीय क्षेत्राधिकार इसकी आवश्यकता रखता है, वहां शौचालय के उपयोग के बाद दोहरे हाथ धोने की आवश्यकता को संभालने के लिए फूड कोड PIC को कैसे निर्देशित करता है?","ar":"كيف يوجه قانون الغذاء الشخص المسؤول للتعامل مع اشتراط غسل اليدين مرتين بعد استخدام الحمام، حيث تشترط ذلك السلطة المحلية؟"},"o":[{"en":"Wash once at any sink is always sufficient","es":"Lavarse una vez en cualquier lavamanos siempre es suficiente","ru":"Однократного мытья в любой раковине всегда достаточно","tr":"Herhangi bir lavaboda bir kez yıkamak her zaman yeterlidir","hi":"किसी भी सिंक पर एक बार धोना हमेशा पर्याप्त है","ar":"الغسل مرة واحدة في أي حوض يكفي دائمًا"},{"en":"Wash in the restroom, then wash again at a handwashing sink upon returning to the prep area","es":"Lavarse en el baño, luego lavarse de nuevo en un lavamanos al regresar al área de preparación","ru":"Вымыть в туалете, затем вымыть снова у раковины для мытья рук по возвращении в зону приготовления","tr":"Tuvalette yıkamak, ardından hazırlık alanına dönünce el yıkama lavabosunda tekrar yıkamak","hi":"शौचालय में धोना, फिर तैयारी क्षेत्र में लौटने पर हाथ धोने के सिंक पर फिर से धोना","ar":"الغسل في الحمام، ثم الغسل مرة أخرى في حوض غسل اليدين عند العودة إلى منطقة التحضير"},{"en":"Use hand sanitizer twice instead of washing","es":"Usar desinfectante de manos dos veces en lugar de lavarse","ru":"Использовать антисептик дважды вместо мытья","tr":"Yıkamak yerine iki kez el dezenfektanı kullanmak","hi":"धोने के बजाय दो बार हैंड सैनिटाइज़र का उपयोग करना","ar":"استخدام معقم اليدين مرتين بدلاً من الغسل"},{"en":"Wash only if the hands look visibly soiled","es":"Lavarse solo si las manos se ven visiblemente sucias","ru":"Мыть только если руки выглядят заметно грязными","tr":"Yalnızca eller gözle görülür şekilde kirliyse yıkamak","hi":"केवल तभी धोना जब हाथ स्पष्ट रूप से गंदे दिखें","ar":"الغسل فقط إذا بدت اليدان متسختين بشكل واضح"}],"e":{"en":"Where a jurisdiction requires double handwashing, employees wash in the restroom and again at a dedicated handwashing sink after returning, before handling food.","es":"Donde una jurisdicción exige el doble lavado de manos, los empleados se lavan en el baño y de nuevo en un lavamanos designado al regresar, antes de manipular alimentos.","ru":"Там, где юрисдикция требует двойного мытья рук, сотрудники моют руки в туалете и снова у специальной раковины для мытья рук после возвращения, прежде чем работать с пищей.","tr":"Bir yetki alanının çift el yıkamayı zorunlu kıldığı yerlerde, çalışanlar tuvalette ve döndükten sonra gıdaya dokunmadan önce ayrılmış bir el yıkama lavabosunda tekrar yıkanır.","hi":"जहां क्षेत्राधिकार दोहरे हाथ धोने की आवश्यकता रखता है, वहां कर्मचारी शौचालय में धोते हैं और लौटने के बाद भोजन संभालने से पहले एक समर्पित हाथ धोने के सिंक पर फिर से धोते हैं।","ar":"حيث تشترط السلطة غسل اليدين مرتين، يغسل الموظفون أيديهم في الحمام ومرة أخرى في حوض غسل يدين مخصص بعد العودة، قبل التعامل مع الطعام."}},{"cat":"facilities","a":1,"q":{"en":"A manager is purchasing new foodservice equipment. What is the best assurance that the equipment meets sanitation design standards?","es":"Un gerente está comprando equipo nuevo para el servicio de alimentos. ¿Cuál es la mejor garantía de que el equipo cumple con las normas de diseño sanitario?","ru":"Менеджер закупает новое оборудование для предприятия питания. Что лучше всего гарантирует, что оборудование соответствует санитарным стандартам конструкции?","tr":"Bir müdür yeni yiyecek servisi ekipmanı satın alıyor. Ekipmanın sanitasyon tasarım standartlarını karşıladığının en iyi güvencesi nedir?","hi":"एक प्रबंधक नया फूडसर्विस उपकरण खरीद रहा है। इसका सबसे अच्छा आश्वासन क्या है कि उपकरण स्वच्छता डिज़ाइन मानकों को पूरा करता है?","ar":"يشتري مدير معدات جديدة لخدمة الطعام. ما هو أفضل ضمان بأن المعدات تفي بمعايير التصميم الصحي؟"},"o":[{"en":"The equipment is the least expensive option available","es":"El equipo es la opción más económica disponible","ru":"Оборудование является самым дешёвым доступным вариантом","tr":"Ekipman mevcut en ucuz seçenektir","hi":"उपकरण उपलब्ध सबसे सस्ता विकल्प है","ar":"المعدات هي الخيار الأقل تكلفة المتاح"},{"en":"It is certified or approved by an accredited program such as NSF International","es":"Está certificado o aprobado por un programa acreditado como NSF International","ru":"Оно сертифицировано или одобрено аккредитованной программой, например NSF International","tr":"NSF International gibi akredite bir program tarafından sertifikalandırılmış veya onaylanmıştır","hi":"यह NSF International जैसे मान्यता प्राप्त कार्यक्रम द्वारा प्रमाणित या अनुमोदित है","ar":"أنها معتمدة أو موافق عليها من قبل برنامج معتمد مثل NSF International"},{"en":"It has a stainless-steel exterior","es":"Tiene un exterior de acero inoxidable","ru":"У него корпус из нержавеющей стали","tr":"Paslanmaz çelik dış yüzeye sahiptir","hi":"इसका बाहरी हिस्सा स्टेनलेस स्टील का है","ar":"لها سطح خارجي من الفولاذ المقاوم للصدأ"},{"en":"The supplier says it is commercial grade","es":"El proveedor dice que es de grado comercial","ru":"Поставщик утверждает, что оно коммерческого класса","tr":"Tedarikçi ticari sınıf olduğunu söylüyor","hi":"आपूर्तिकर्ता कहता है कि यह वाणिज्यिक ग्रेड का है","ar":"يقول المورد إنها من الدرجة التجارية"}],"e":{"en":"Foodservice equipment should be certified or classified for sanitation by an accredited program such as NSF International (or ANSI/UL). This assures food-contact surfaces are smooth, nonabsorbent, durable, corrosion-resistant, and easy to clean.","es":"El equipo de servicio de alimentos debe estar certificado o clasificado en cuanto a higiene por un programa acreditado como NSF International (o ANSI/UL). Esto asegura que las superficies en contacto con alimentos sean lisas, no absorbentes, duraderas, resistentes a la corrosión y fáciles de limpiar.","ru":"Оборудование для предприятий питания должно быть сертифицировано по санитарным нормам аккредитованной программой, например NSF International (или ANSI/UL). Это гарантирует, что поверхности, контактирующие с пищей, гладкие, непроницаемые, прочные, коррозионностойкие и легко очищаются.","tr":"Yiyecek servisi ekipmanı, NSF International (veya ANSI/UL) gibi akredite bir program tarafından sanitasyon açısından sertifikalandırılmalı veya sınıflandırılmalıdır. Bu, gıdayla temas eden yüzeylerin pürüzsüz, emici olmayan, dayanıklı, korozyona dayanıklı ve temizlenmesi kolay olmasını sağlar.","hi":"फूडसर्विस उपकरण को NSF International (या ANSI/UL) जैसे मान्यता प्राप्त कार्यक्रम द्वारा स्वच्छता के लिए प्रमाणित या वर्गीकृत होना चाहिए। यह सुनिश्चित करता है कि खाद्य-संपर्क सतहें चिकनी, गैर-अवशोषक, टिकाऊ, संक्षारण-प्रतिरोधी और साफ करने में आसान हों।","ar":"يجب أن تكون معدات خدمة الطعام معتمدة أو مصنفة من حيث الصحة من قبل برنامج معتمد مثل NSF International (أو ANSI/UL). وهذا يضمن أن تكون الأسطح الملامسة للطعام ملساء وغير ماصة ومتينة ومقاومة للتآكل وسهلة التنظيف."}},{"cat":"facilities","a":2,"q":{"en":"How must floor-mounted equipment that is not sealed to a masonry base be installed?","es":"¿Cómo debe instalarse el equipo montado en el piso que no está sellado a una base de mampostería?","ru":"Как должно устанавливаться напольное оборудование, не загерметизированное к каменному основанию?","tr":"Duvar örgüsü tabanına yalıtılmamış, zemine monte edilen ekipman nasıl kurulmalıdır?","hi":"फर्श पर लगाया गया उपकरण जो चिनाई वाले आधार से सील नहीं है, उसे कैसे स्थापित किया जाना चाहिए?","ar":"كيف يجب تركيب المعدات المثبتة على الأرض التي ليست محكمة الغلق على قاعدة بناء؟"},"o":[{"en":"Flat on the floor to prevent tipping","es":"Plano sobre el piso para evitar que se vuelque","ru":"Плашмя на полу, чтобы не опрокинулось","tr":"Devrilmeyi önlemek için zemine düz şekilde","hi":"पलटने से रोकने के लिए फर्श पर सपाट","ar":"مسطحة على الأرض لمنع الانقلاب"},{"en":"On casters only, with no minimum clearance","es":"Solo sobre ruedas, sin espacio libre mínimo","ru":"Только на роликах, без минимального зазора","tr":"Yalnızca tekerlekler üzerinde, minimum boşluk olmadan","hi":"केवल पहियों पर, बिना किसी न्यूनतम अंतराल के","ar":"على عجلات فقط، دون حد أدنى من الخلوص"},{"en":"On legs that provide at least 6 inches of clearance between the floor and the equipment","es":"Sobre patas que proporcionen al menos 6 pulgadas de espacio entre el piso y el equipo","ru":"На ножках, обеспечивающих зазор не менее 6 inches между полом и оборудованием","tr":"Zemin ile ekipman arasında en az 6 inches boşluk sağlayan ayaklar üzerinde","hi":"ऐसे पैरों पर जो फर्श और उपकरण के बीच कम से कम 6 inches का अंतराल प्रदान करें","ar":"على أرجل توفر مسافة لا تقل عن 6 inches بين الأرض والمعدات"},{"en":"Directly against the wall with no gap behind it","es":"Directamente contra la pared sin espacio detrás","ru":"Вплотную к стене без зазора позади","tr":"Arkasında boşluk olmadan doğrudan duvara dayalı","hi":"दीवार से सटाकर बिना पीछे कोई अंतराल के","ar":"مباشرة على الحائط دون فجوة خلفها"}],"e":{"en":"Floor-mounted equipment must be elevated on legs providing at least 6 inches of clearance, or sealed to a masonry base, so the floor beneath can be cleaned and inspected for pests.","es":"El equipo montado en el piso debe elevarse sobre patas que proporcionen al menos 6 pulgadas de espacio, o sellarse a una base de mampostería, para poder limpiar el piso debajo e inspeccionarlo en busca de plagas.","ru":"Напольное оборудование должно быть приподнято на ножках с зазором не менее 6 inches или загерметизировано к каменному основанию, чтобы пол под ним можно было чистить и проверять на наличие вредителей.","tr":"Zemine monte ekipman, altındaki zeminin temizlenip haşere açısından denetlenebilmesi için en az 6 inches boşluk sağlayan ayaklar üzerine yükseltilmeli veya duvar örgüsü tabanına yalıtılmalıdır.","hi":"फर्श पर लगे उपकरण को कम से कम 6 inches का अंतराल देने वाले पैरों पर ऊपर उठाया जाना चाहिए, या चिनाई वाले आधार से सील किया जाना चाहिए, ताकि नीचे के फर्श को साफ किया जा सके और कीटों के लिए जांचा जा सके।","ar":"يجب رفع المعدات المثبتة على الأرض على أرجل توفر مسافة لا تقل عن 6 inches، أو إحكام غلقها على قاعدة بناء، حتى يمكن تنظيف الأرضية تحتها وفحصها بحثًا عن الآفات."}},{"cat":"facilities","a":3,"q":{"en":"Tabletop equipment that is not sealed to the countertop must be mounted on legs providing a clearance of at least:","es":"El equipo de sobremesa que no está sellado a la encimera debe montarse sobre patas que proporcionen un espacio libre de al menos:","ru":"Настольное оборудование, не загерметизированное к столешнице, должно устанавливаться на ножках с зазором не менее:","tr":"Tezgaha yalıtılmamış tezgah üstü ekipman, en az şu kadar boşluk sağlayan ayaklar üzerine monte edilmelidir:","hi":"टेबलटॉप उपकरण जो काउंटरटॉप से सील नहीं है, उसे कम से कम इतना अंतराल देने वाले पैरों पर लगाया जाना चाहिए:","ar":"يجب تركيب المعدات المكتبية غير المحكمة الغلق على سطح الطاولة على أرجل توفر خلوصًا لا يقل عن:"},"o":[{"en":"1 inch","es":"1 pulgada","ru":"1 inch","tr":"1 inch","hi":"1 inch","ar":"1 inch"},{"en":"2 inches","es":"2 pulgadas","ru":"2 inches","tr":"2 inches","hi":"2 inches","ar":"2 inches"},{"en":"6 inches","es":"6 pulgadas","ru":"6 inches","tr":"6 inches","hi":"6 inches","ar":"6 inches"},{"en":"4 inches","es":"4 pulgadas","ru":"4 inches","tr":"4 inches","hi":"4 inches","ar":"4 inches"}],"e":{"en":"Tabletop or counter-mounted equipment must be sealed to the counter or elevated on 4-inch legs so the surface underneath can be cleaned.","es":"El equipo de sobremesa o montado en mostrador debe sellarse al mostrador o elevarse sobre patas de 4 pulgadas para poder limpiar la superficie de debajo.","ru":"Настольное или установленное на прилавке оборудование должно быть загерметизировано к прилавку или приподнято на ножках высотой 4 inches, чтобы поверхность под ним можно было чистить.","tr":"Tezgah üstü veya tezgaha monte ekipman, altındaki yüzeyin temizlenebilmesi için tezgaha yalıtılmalı veya 4 inches ayaklar üzerine yükseltilmelidir.","hi":"टेबलटॉप या काउंटर पर लगे उपकरण को काउंटर से सील किया जाना चाहिए या 4 inches के पैरों पर ऊपर उठाया जाना चाहिए ताकि नीचे की सतह को साफ किया जा सके।","ar":"يجب إحكام غلق المعدات المكتبية أو المثبتة على المنضدة على المنضدة أو رفعها على أرجل بارتفاع 4 inches حتى يمكن تنظيف السطح تحتها."}},{"cat":"facilities","a":0,"q":{"en":"How should a manager verify that a high-temperature dish machine is sanitizing effectively during service?","es":"¿Cómo debe verificar un gerente que una máquina lavavajillas de alta temperatura desinfecta eficazmente durante el servicio?","ru":"Как менеджеру убедиться, что высокотемпературная посудомоечная машина эффективно дезинфицирует во время работы?","tr":"Bir yönetici, yüksek sıcaklıklı bulaşık makinesinin servis sırasında etkili şekilde dezenfekte ettiğini nasıl doğrulamalı?","hi":"एक प्रबंधक कैसे सत्यापित करे कि उच्च तापमान वाली बर्तन मशीन सेवा के दौरान प्रभावी ढंग से सैनिटाइज़ कर रही है?","ar":"كيف يتحقق المدير من أن آلة غسل الأطباق ذات الحرارة العالية تُطهِّر بفعالية أثناء الخدمة؟"},"o":[{"en":"Use a temperature-sensitive label or maximum-registering thermometer to confirm the dish surface reaches 160°F","es":"Usar una etiqueta sensible a la temperatura o un termómetro de registro máximo para confirmar que la superficie del plato alcanza 160°F","ru":"Использовать термочувствительную наклейку или термометр максимальной регистрации, чтобы подтвердить, что поверхность посуды достигает 160°F","tr":"Tabak yüzeyinin 160°F'a ulaştığını doğrulamak için sıcaklığa duyarlı etiket veya maksimum kaydeden termometre kullanmak","hi":"तापमान-संवेदनशील लेबल या अधिकतम-रिकॉर्डिंग थर्मामीटर से पुष्टि करना कि बर्तन की सतह 160°F तक पहुंचती है","ar":"استخدام ملصق حساس للحرارة أو ميزان حرارة يسجّل القيمة القصوى للتأكد من أن سطح الطبق يبلغ 160°F"},{"en":"Feel the dishes with a bare hand to see if they are hot","es":"Tocar los platos con la mano desnuda para ver si están calientes","ru":"Потрогать посуду голой рукой, чтобы понять, горячая ли она","tr":"Tabakların sıcak olup olmadığını çıplak elle yoklamak","hi":"यह देखने के लिए बर्तनों को नंगे हाथ से छूना कि वे गर्म हैं","ar":"لمس الأطباق باليد المجردة لمعرفة ما إذا كانت ساخنة"},{"en":"Assume it works if the machine turns on","es":"Suponer que funciona si la máquina enciende","ru":"Считать, что она работает, если машина включается","tr":"Makine çalışıyorsa işe yaradığını varsaymak","hi":"यह मान लेना कि यदि मशीन चालू होती है तो वह काम कर रही है","ar":"افتراض أنها تعمل طالما أن الآلة تشتغل"},{"en":"Add extra detergent to the wash tank","es":"Agregar detergente adicional al tanque de lavado","ru":"Добавить больше моющего средства в моечный бак","tr":"Yıkama tankına fazladan deterjan eklemek","hi":"वॉश टैंक में अतिरिक्त डिटर्जेंट डालना","ar":"إضافة منظف إضافي إلى خزان الغسيل"}],"e":{"en":"High-temperature machines sanitize with heat, so the manager confirms the dish surface reaches 160°F using a temperature-sensitive label or maximum-registering thermometer, and checks the machine's data-plate temperatures/pressure.","es":"Las máquinas de alta temperatura desinfectan con calor, por lo que el gerente confirma que la superficie del plato alcanza 160°F con una etiqueta sensible a la temperatura o un termómetro de registro máximo, y revisa las temperaturas/presión de la placa de datos.","ru":"Высокотемпературные машины дезинфицируют теплом, поэтому менеджер подтверждает, что поверхность посуды достигает 160°F, с помощью термочувствительной наклейки или термометра максимальной регистрации и проверяет температуру/давление по заводской табличке.","tr":"Yüksek sıcaklıklı makineler ısıyla dezenfekte eder; bu yüzden yönetici, tabak yüzeyinin 160°F'a ulaştığını sıcaklığa duyarlı etiket veya maksimum kaydeden termometreyle doğrular ve makinenin bilgi plakasındaki sıcaklık/basıncı kontrol eder.","hi":"उच्च तापमान वाली मशीनें गर्मी से सैनिटाइज़ करती हैं, इसलिए प्रबंधक तापमान-संवेदनशील लेबल या अधिकतम-रिकॉर्डिंग थर्मामीटर से पुष्टि करता है कि बर्तन की सतह 160°F तक पहुंचती है, और मशीन की डेटा-प्लेट तापमान/दबाव जांचता है।","ar":"الآلات ذات الحرارة العالية تُطهِّر بالحرارة، لذا يتأكد المدير من وصول سطح الطبق إلى 160°F باستخدام ملصق حساس للحرارة أو ميزان حرارة يسجّل القيمة القصوى، ويراجع درجات الحرارة/الضغط على لوحة بيانات الآلة."}},{"cat":"facilities","a":2,"q":{"en":"For chlorine used as a food-contact sanitizer, which combination of concentration and contact time is generally correct?","es":"Para el cloro usado como desinfectante en contacto con alimentos, ¿qué combinación de concentración y tiempo de contacto es generalmente correcta?","ru":"Для хлора, используемого как дезинфектант поверхностей, контактирующих с пищей, какое сочетание концентрации и времени контакта в целом верно?","tr":"Gıdayla temas eden dezenfektan olarak kullanılan klor için hangi konsantrasyon ve temas süresi kombinasyonu genellikle doğrudur?","hi":"खाद्य-संपर्क सैनिटाइज़र के रूप में उपयोग किए जाने वाले क्लोरीन के लिए, सांद्रता और संपर्क समय का कौन सा संयोजन आम तौर पर सही है?","ar":"بالنسبة للكلور المستخدم كمطهر ملامس للطعام، أي مزيج من التركيز ووقت التلامس صحيح بشكل عام؟"},"o":[{"en":"200 ppm for about 30 seconds","es":"200 ppm durante unos 30 segundos","ru":"200 ppm примерно 30 seconds","tr":"yaklaşık 30 seconds boyunca 200 ppm","hi":"लगभग 30 seconds के लिए 200 ppm","ar":"200 ppm لمدة نحو 30 seconds"},{"en":"12.5–25 ppm for about 30 seconds","es":"12.5–25 ppm durante unos 30 segundos","ru":"12.5–25 ppm примерно 30 seconds","tr":"yaklaşık 30 seconds boyunca 12.5–25 ppm","hi":"लगभग 30 seconds के लिए 12.5–25 ppm","ar":"12.5–25 ppm لمدة نحو 30 seconds"},{"en":"50–99 ppm for about 7 seconds","es":"50–99 ppm durante unos 7 segundos","ru":"50–99 ppm примерно 7 seconds","tr":"yaklaşık 7 seconds boyunca 50–99 ppm","hi":"लगभग 7 seconds के लिए 50–99 ppm","ar":"50–99 ppm لمدة نحو 7 seconds"},{"en":"500–1000 ppm for about 60 seconds","es":"500–1000 ppm durante unos 60 segundos","ru":"500–1000 ppm примерно 60 seconds","tr":"yaklaşık 60 seconds boyunca 500–1000 ppm","hi":"लगभग 60 seconds के लिए 500–1000 ppm","ar":"500–1000 ppm لمدة نحو 60 seconds"}],"e":{"en":"Chlorine sanitizer is typically used at 50–99 ppm with a contact time of about 7 seconds. Higher concentrations are unnecessary and can leave a residue or be corrosive.","es":"El desinfectante de cloro se usa típicamente a 50–99 ppm con un tiempo de contacto de unos 7 segundos. Concentraciones más altas son innecesarias y pueden dejar residuo o ser corrosivas.","ru":"Хлорный дезинфектант обычно применяется в концентрации 50–99 ppm с временем контакта около 7 seconds. Более высокие концентрации не нужны и могут оставлять налёт или вызывать коррозию.","tr":"Klor dezenfektanı genellikle 50–99 ppm konsantrasyonda, yaklaşık 7 seconds temas süresiyle kullanılır. Daha yüksek konsantrasyonlar gereksizdir ve kalıntı bırakabilir veya aşındırıcı olabilir.","hi":"क्लोरीन सैनिटाइज़र आमतौर पर 50–99 ppm पर लगभग 7 seconds के संपर्क समय के साथ उपयोग किया जाता है। अधिक सांद्रता अनावश्यक है और अवशेष छोड़ सकती है या संक्षारक हो सकती है।","ar":"يُستخدم مطهر الكلور عادةً بتركيز 50–99 ppm مع وقت تلامس نحو 7 seconds. التركيزات الأعلى غير ضرورية وقد تترك بقايا أو تكون أكّالة."}},{"cat":"facilities","a":1,"q":{"en":"A manager sets up a quaternary ammonium (quat) sanitizer solution. Which combination reflects typical requirements?","es":"Un gerente prepara una solución desinfectante de amonio cuaternario (quat). ¿Qué combinación refleja los requisitos típicos?","ru":"Менеджер готовит дезинфицирующий раствор четвертичного аммония (кват). Какое сочетание отражает типичные требования?","tr":"Bir müdür kuaterner amonyum (quat) dezenfektan çözeltisi hazırlar. Hangi kombinasyon tipik gereksinimleri yansıtır?","hi":"एक प्रबंधक क्वाटरनरी अमोनियम (क्वाट) सैनिटाइज़र घोल तैयार करता है। कौन सा संयोजन विशिष्ट आवश्यकताओं को दर्शाता है?","ar":"يقوم مدير بإعداد محلول مطهر من الأمونيوم الرباعي (كوات). أي مزيج يعكس المتطلبات النموذجية؟"},"o":[{"en":"50 ppm, water at least 55°F, contact time 7 seconds","es":"50 ppm, agua de al menos 55°F, tiempo de contacto 7 segundos","ru":"50 ppm, вода не ниже 55°F, время контакта 7 seconds","tr":"50 ppm, su en az 55°F, temas süresi 7 seconds","hi":"50 ppm, पानी कम से कम 55°F, संपर्क समय 7 seconds","ar":"50 ppm، ماء لا يقل عن 55°F، وقت التلامس 7 seconds"},{"en":"About 200 ppm per manufacturer, water at least 75°F, contact time about 30 seconds","es":"Aproximadamente 200 ppm según el fabricante, agua de al menos 75°F, tiempo de contacto de unos 30 segundos","ru":"Около 200 ppm по инструкции производителя, вода не ниже 75°F, время контакта около 30 seconds","tr":"Üreticiye göre yaklaşık 200 ppm, su en az 75°F, temas süresi yaklaşık 30 seconds","hi":"निर्माता के अनुसार लगभग 200 ppm, पानी कम से कम 75°F, संपर्क समय लगभग 30 seconds","ar":"نحو 200 ppm وفق الشركة المصنعة، ماء لا يقل عن 75°F، وقت التلامس نحو 30 seconds"},{"en":"12.5 ppm, water at least 68°F, contact time 30 seconds","es":"12.5 ppm, agua de al menos 68°F, tiempo de contacto 30 segundos","ru":"12.5 ppm, вода не ниже 68°F, время контакта 30 seconds","tr":"12.5 ppm, su en az 68°F, temas süresi 30 seconds","hi":"12.5 ppm, पानी कम से कम 68°F, संपर्क समय 30 seconds","ar":"12.5 ppm، ماء لا يقل عن 68°F، وقت التلامس 30 seconds"},{"en":"1000 ppm, water at least 110°F, contact time 60 seconds","es":"1000 ppm, agua de al menos 110°F, tiempo de contacto 60 segundos","ru":"1000 ppm, вода не ниже 110°F, время контакта 60 seconds","tr":"1000 ppm, su en az 110°F, temas süresi 60 seconds","hi":"1000 ppm, पानी कम से कम 110°F, संपर्क समय 60 seconds","ar":"1000 ppm، ماء لا يقل عن 110°F، وقت التلامس 60 seconds"}],"e":{"en":"Quat sanitizer is typically used near 200 ppm (per the manufacturer), with water at least 75°F and a contact time of about 30 seconds. Always follow the manufacturer's label and verify with a test kit.","es":"El desinfectante quat se usa típicamente cerca de 200 ppm (según el fabricante), con agua de al menos 75°F y un tiempo de contacto de unos 30 segundos. Siga siempre la etiqueta del fabricante y verifique con un kit de prueba.","ru":"Кватовый дезинфектант обычно применяется около 200 ppm (по инструкции производителя), с водой не ниже 75°F и временем контакта около 30 seconds. Всегда следуйте этикетке производителя и проверяйте тест-набором.","tr":"Quat dezenfektanı genellikle yaklaşık 200 ppm (üreticiye göre), en az 75°F su ve yaklaşık 30 seconds temas süresiyle kullanılır. Her zaman üretici etiketini izleyin ve test kitiyle doğrulayın.","hi":"क्वाट सैनिटाइज़र आमतौर पर लगभग 200 ppm (निर्माता के अनुसार), कम से कम 75°F पानी और लगभग 30 seconds के संपर्क समय के साथ उपयोग किया जाता है। हमेशा निर्माता के लेबल का पालन करें और टेस्ट किट से पुष्टि करें।","ar":"يُستخدم مطهر الكوات عادةً بتركيز نحو 200 ppm (وفق الشركة المصنعة)، مع ماء لا يقل عن 75°F ووقت تلامس نحو 30 seconds. اتبع دائمًا ملصق الشركة المصنعة وتحقق باستخدام عدة اختبار."}},{"cat":"facilities","a":3,"q":{"en":"For an iodine-based sanitizer, which set of parameters is correct?","es":"Para un desinfectante a base de yodo, ¿qué conjunto de parámetros es correcto?","ru":"Для дезинфектанта на основе йода какой набор параметров верен?","tr":"İyot bazlı bir dezenfektan için hangi parametre kümesi doğrudur?","hi":"आयोडीन-आधारित सैनिटाइज़र के लिए, कौन सा पैरामीटर सेट सही है?","ar":"بالنسبة لمطهر يعتمد على اليود، أي مجموعة من المعايير صحيحة؟"},"o":[{"en":"50–99 ppm, water at least 55°F, pH ≤ 5.0","es":"50–99 ppm, agua de al menos 55°F, pH ≤ 5.0","ru":"50–99 ppm, вода не ниже 55°F, pH ≤ 5.0","tr":"50–99 ppm, su en az 55°F, pH ≤ 5.0","hi":"50–99 ppm, पानी कम से कम 55°F, pH ≤ 5.0","ar":"50–99 ppm، ماء لا يقل عن 55°F، الرقم الهيدروجيني ≤ 5.0"},{"en":"200 ppm, water at least 75°F, pH ≤ 5.0","es":"200 ppm, agua de al menos 75°F, pH ≤ 5.0","ru":"200 ppm, вода не ниже 75°F, pH ≤ 5.0","tr":"200 ppm, su en az 75°F, pH ≤ 5.0","hi":"200 ppm, पानी कम से कम 75°F, pH ≤ 5.0","ar":"200 ppm، ماء لا يقل عن 75°F، الرقم الهيدروجيني ≤ 5.0"},{"en":"12.5–25 ppm, water at least 100°F, pH ≤ 8.0","es":"12.5–25 ppm, agua de al menos 100°F, pH ≤ 8.0","ru":"12.5–25 ppm, вода не ниже 100°F, pH ≤ 8.0","tr":"12.5–25 ppm, su en az 100°F, pH ≤ 8.0","hi":"12.5–25 ppm, पानी कम से कम 100°F, pH ≤ 8.0","ar":"12.5–25 ppm، ماء لا يقل عن 100°F، الرقم الهيدروجيني ≤ 8.0"},{"en":"12.5–25 ppm, water at least 68°F, pH ≤ 5.0, contact time about 30 seconds","es":"12.5–25 ppm, agua de al menos 68°F, pH ≤ 5.0, tiempo de contacto de unos 30 segundos","ru":"12.5–25 ppm, вода не ниже 68°F, pH ≤ 5.0, время контакта около 30 seconds","tr":"12.5–25 ppm, su en az 68°F, pH ≤ 5.0, temas süresi yaklaşık 30 seconds","hi":"12.5–25 ppm, पानी कम से कम 68°F, pH ≤ 5.0, संपर्क समय लगभग 30 seconds","ar":"12.5–25 ppm، ماء لا يقل عن 68°F، الرقم الهيدروجيني ≤ 5.0، وقت التلامس نحو 30 seconds"}],"e":{"en":"Iodine sanitizers work at 12.5–25 ppm, water at least 68°F, a pH of 5.0 or lower, and a contact time of about 30 seconds. Water that is too warm can cause iodine to leave the solution.","es":"Los desinfectantes de yodo funcionan a 12.5–25 ppm, agua de al menos 68°F, un pH de 5.0 o menor y un tiempo de contacto de unos 30 segundos. El agua demasiado caliente puede hacer que el yodo se salga de la solución.","ru":"Йодные дезинфектанты действуют при 12.5–25 ppm, воде не ниже 68°F, pH 5.0 или ниже и времени контакта около 30 seconds. Слишком тёплая вода может привести к улетучиванию йода из раствора.","tr":"İyot dezenfektanları 12.5–25 ppm, en az 68°F su, 5.0 veya daha düşük pH ve yaklaşık 30 seconds temas süresiyle etki eder. Çok sıcak su iyodun çözeltiden ayrılmasına neden olabilir.","hi":"आयोडीन सैनिटाइज़र 12.5–25 ppm, कम से कम 68°F पानी, 5.0 या उससे कम pH और लगभग 30 seconds के संपर्क समय पर काम करते हैं। बहुत गर्म पानी आयोडीन को घोल से बाहर निकाल सकता है।","ar":"تعمل مطهرات اليود بتركيز 12.5–25 ppm، وماء لا يقل عن 68°F، ورقم هيدروجيني 5.0 أو أقل، ووقت تلامس نحو 30 seconds. الماء شديد السخونة قد يجعل اليود يتطاير من المحلول."}},{"cat":"facilities","a":0,"q":{"en":"Which factor does NOT directly affect the effectiveness of a chemical sanitizer?","es":"¿Qué factor NO afecta directamente la eficacia de un desinfectante químico?","ru":"Какой фактор НЕ влияет напрямую на эффективность химического дезинфектанта?","tr":"Hangi faktör kimyasal bir dezenfektanın etkinliğini doğrudan ETKİLEMEZ?","hi":"कौन सा कारक रासायनिक सैनिटाइज़र की प्रभावशीलता को सीधे प्रभावित नहीं करता है?","ar":"أي عامل لا يؤثر بشكل مباشر على فعالية المطهر الكيميائي؟"},"o":[{"en":"The color of the wiping cloth used","es":"El color del paño de limpieza utilizado","ru":"Цвет используемой протирочной салфетки","tr":"Kullanılan silme bezinin rengi","hi":"उपयोग किए गए पोंछने वाले कपड़े का रंग","ar":"لون قطعة القماش المستخدمة في المسح"},{"en":"Concentration of the sanitizer","es":"Concentración del desinfectante","ru":"Концентрация дезинфектанта","tr":"Dezenfektanın konsantrasyonu","hi":"सैनिटाइज़र की सांद्रता","ar":"تركيز المطهر"},{"en":"Water temperature","es":"Temperatura del agua","ru":"Температура воды","tr":"Su sıcaklığı","hi":"पानी का तापमान","ar":"درجة حرارة الماء"},{"en":"Contact time and water hardness/pH","es":"Tiempo de contacto y dureza/pH del agua","ru":"Время контакта и жёсткость/pH воды","tr":"Temas süresi ve su sertliği/pH","hi":"संपर्क समय और पानी की कठोरता/pH","ar":"وقت التلامس وعسر الماء/الرقم الهيدروجيني"}],"e":{"en":"Sanitizer effectiveness depends on concentration, water temperature, contact time, and water hardness/pH. The color of a wiping cloth has no bearing on how well the chemical works.","es":"La eficacia del desinfectante depende de la concentración, la temperatura del agua, el tiempo de contacto y la dureza/pH del agua. El color de un paño de limpieza no influye en el funcionamiento del químico.","ru":"Эффективность дезинфектанта зависит от концентрации, температуры воды, времени контакта и жёсткости/pH воды. Цвет протирочной салфетки не влияет на действие химиката.","tr":"Dezenfektanın etkinliği konsantrasyona, su sıcaklığına, temas süresine ve su sertliği/pH'ına bağlıdır. Silme bezinin rengi kimyasalın ne kadar iyi çalıştığını etkilemez.","hi":"सैनिटाइज़र की प्रभावशीलता सांद्रता, पानी के तापमान, संपर्क समय और पानी की कठोरता/pH पर निर्भर करती है। पोंछने वाले कपड़े का रंग रसायन के काम करने पर कोई असर नहीं डालता।","ar":"تعتمد فعالية المطهر على التركيز ودرجة حرارة الماء ووقت التلامس وعسر الماء/الرقم الهيدروجيني. لون قطعة قماش المسح لا علاقة له بمدى فعالية المادة الكيميائية."}},{"cat":"facilities","a":1,"q":{"en":"When manually washing dishes, how often should the sanitizer solution in the third compartment be checked and changed?","es":"Al lavar platos manualmente, ¿con qué frecuencia se debe revisar y cambiar la solución desinfectante del tercer compartimento?","ru":"При ручном мытье посуды как часто нужно проверять и менять дезинфицирующий раствор в третьей секции?","tr":"Bulaşıklar elde yıkanırken üçüncü bölmedeki dezenfektan çözeltisi ne sıklıkla kontrol edilip değiştirilmelidir?","hi":"बर्तन हाथ से धोते समय, तीसरे कम्पार्टमेंट में सैनिटाइज़र घोल को कितनी बार जांचना और बदलना चाहिए?","ar":"عند غسل الأطباق يدويًا، كم مرة ينبغي فحص وتغيير محلول التطهير في المقصورة الثالثة؟"},"o":[{"en":"Only once at the start of the shift","es":"Solo una vez al inicio del turno","ru":"Только один раз в начале смены","tr":"Yalnızca vardiya başında bir kez","hi":"केवल एक बार शिफ्ट की शुरुआत में","ar":"مرة واحدة فقط في بداية الوردية"},{"en":"Regularly with a test kit, and changed whenever it is dirty or below the required concentration","es":"Con regularidad usando un kit de prueba, y cambiada cuando esté sucia o por debajo de la concentración requerida","ru":"Регулярно с помощью тест-набора и менять, когда он загрязнён или ниже нужной концентрации","tr":"Bir test kitiyle düzenli olarak ve kirlendiğinde ya da gerekli konsantrasyonun altına düştüğünde değiştirilerek","hi":"टेस्ट किट से नियमित रूप से, और जब भी यह गंदा हो या आवश्यक सांद्रता से कम हो तब बदला जाए","ar":"بانتظام باستخدام عدّة اختبار، وتُغيَّر كلما اتسخت أو انخفضت عن التركيز المطلوب"},{"en":"Once a day at closing","es":"Una vez al día al cerrar","ru":"Один раз в день при закрытии","tr":"Kapanışta günde bir kez","hi":"बंद करते समय दिन में एक बार","ar":"مرة واحدة يوميًا عند الإغلاق"},{"en":"Never, as long as it still smells like bleach","es":"Nunca, mientras siga oliendo a cloro","ru":"Никогда, пока он пахнет хлором","tr":"Çamaşır suyu gibi koktuğu sürece hiç","hi":"कभी नहीं, जब तक इसमें ब्लीच जैसी गंध आती रहे","ar":"أبدًا، طالما لا تزال رائحته كالكلور"}],"e":{"en":"Sanitizer strength drops as the solution is used and soiled, so it must be checked frequently with a test kit and replaced when dirty or below the required concentration.","es":"La potencia del desinfectante disminuye a medida que la solución se usa y se ensucia, por lo que debe revisarse con frecuencia con un kit de prueba y reemplazarse cuando esté sucia o por debajo de la concentración requerida.","ru":"Сила дезинфектанта снижается по мере использования и загрязнения раствора, поэтому его нужно часто проверять тест-набором и заменять при загрязнении или падении концентрации ниже требуемой.","tr":"Çözelti kullanıldıkça ve kirlendikçe dezenfektan gücü azalır; bu nedenle sık sık test kitiyle kontrol edilmeli ve kirlendiğinde ya da gerekli konsantrasyonun altına düştüğünde değiştirilmelidir.","hi":"घोल के उपयोग और गंदे होने पर सैनिटाइज़र की क्षमता घट जाती है, इसलिए इसे टेस्ट किट से बार-बार जांचना चाहिए और गंदा होने या आवश्यक सांद्रता से कम होने पर बदलना चाहिए।","ar":"تنخفض قوة المطهِّر مع استخدام المحلول واتساخه، لذا يجب فحصه بشكل متكرر بعدّة اختبار واستبداله عند اتساخه أو انخفاضه عن التركيز المطلوب."}},{"cat":"facilities","a":2,"q":{"en":"What is considered the most reliable method of backflow prevention for a potable water supply?","es":"¿Cuál se considera el método más confiable de prevención de reflujo para un suministro de agua potable?","ru":"Что считается самым надёжным способом предотвращения обратного потока в системе питьевой воды?","tr":"İçilebilir su kaynağı için geri akışı önlemenin en güvenilir yöntemi hangisidir?","hi":"पीने योग्य पानी की आपूर्ति के लिए बैकफ्लो रोकथाम की सबसे विश्वसनीय विधि कौन सी मानी जाती है?","ar":"ما الذي يُعتبر الطريقة الأكثر موثوقية لمنع التدفق العكسي لإمداد المياه الصالحة للشرب؟"},"o":[{"en":"A vacuum breaker on every faucet","es":"Un rompedor de vacío en cada grifo","ru":"Вакуумный прерыватель на каждом кране","tr":"Her muslukta bir vakum kırıcı","hi":"हर नल पर एक वैक्यूम ब्रेकर","ar":"كاسر تفريغ على كل صنبور"},{"en":"A grease trap in the drain line","es":"Una trampa de grasa en la línea de desagüe","ru":"Жироуловитель в дренажной линии","tr":"Tahliye hattında bir yağ tutucu","hi":"नाली लाइन में एक ग्रीस ट्रैप","ar":"مصيدة شحوم في خط الصرف"},{"en":"An air gap between the water supply outlet and any potentially contaminated surface","es":"Un espacio de aire entre la salida del suministro de agua y cualquier superficie potencialmente contaminada","ru":"Воздушный зазор между выпуском водоснабжения и любой потенциально загрязнённой поверхностью","tr":"Su besleme çıkışı ile potansiyel olarak kirlenmiş herhangi bir yüzey arasında bir hava boşluğu","hi":"पानी की आपूर्ति के आउटलेट और किसी भी संभावित दूषित सतह के बीच एक एयर गैप","ar":"فجوة هوائية بين مخرج إمداد المياه وأي سطح يحتمل أن يكون ملوثًا"},{"en":"Closing all faucets when the kitchen is not in use","es":"Cerrar todos los grifos cuando la cocina no está en uso","ru":"Закрытие всех кранов, когда кухня не используется","tr":"Mutfak kullanılmadığında tüm muslukları kapatmak","hi":"जब रसोई उपयोग में न हो तो सभी नलों को बंद करना","ar":"إغلاق جميع الصنابير عندما لا يكون المطبخ قيد الاستخدام"}],"e":{"en":"An air gap—an unobstructed vertical space between the water outlet and the flood-rim level of a sink—physically prevents backflow and is the most reliable protection. It must be at least twice the diameter of the supply inlet and at least 1 inch.","es":"Un espacio de aire—un espacio vertical sin obstrucciones entre la salida de agua y el nivel del borde del fregadero—previene físicamente el reflujo y es la protección más confiable. Debe ser al menos el doble del diámetro de la entrada de suministro y al menos 1 pulgada.","ru":"Воздушный зазор — беспрепятственное вертикальное расстояние между выпуском воды и уровнем перелива мойки — физически предотвращает обратный поток и является самой надёжной защитой. Он должен быть не менее удвоенного диаметра подающего отверстия и не менее 1 inch.","tr":"Hava boşluğu—su çıkışı ile evyenin taşma seviyesi arasındaki engelsiz dikey mesafe—geri akışı fiziksel olarak önler ve en güvenilir korumadır. Besleme girişinin çapının en az iki katı ve en az 1 inch olmalıdır.","hi":"एयर गैप—पानी के आउटलेट और सिंक के फ्लड-रिम स्तर के बीच एक निर्बाध ऊर्ध्वाधर स्थान—भौतिक रूप से बैकफ्लो को रोकता है और सबसे विश्वसनीय सुरक्षा है। यह आपूर्ति इनलेट के व्यास से कम से कम दोगुना और कम से कम 1 inch होना चाहिए।","ar":"الفجوة الهوائية—مسافة رأسية غير معاقة بين مخرج الماء ومستوى حافة الفيضان للحوض—تمنع التدفق العكسي فيزيائيًا وهي الحماية الأكثر موثوقية. يجب أن تكون على الأقل ضعف قطر مدخل الإمداد وألا تقل عن 1 inch."}},{"cat":"facilities","a":3,"q":{"en":"A cross-connection exists when:","es":"Existe una conexión cruzada cuando:","ru":"Перекрёстное соединение существует, когда:","tr":"Çapraz bağlantı ne zaman oluşur:","hi":"क्रॉस-कनेक्शन तब मौजूद होता है जब:","ar":"يوجد اتصال متقاطع عندما:"},"o":[{"en":"Two ovens are plugged into the same outlet","es":"Dos hornos están enchufados en el mismo tomacorriente","ru":"Две духовки подключены к одной розетке","tr":"İki fırın aynı prize takılıdır","hi":"दो ओवन एक ही आउटलेट में प्लग किए गए हैं","ar":"يتم توصيل فرنين بنفس المقبس"},{"en":"Hot and cold water lines run parallel to each other","es":"Las líneas de agua caliente y fría corren paralelas entre sí","ru":"Линии горячей и холодной воды идут параллельно друг другу","tr":"Sıcak ve soğuk su hatları birbirine paralel uzanır","hi":"गर्म और ठंडे पानी की लाइनें एक-दूसरे के समानांतर चलती हैं","ar":"تسير خطوط الماء الساخن والبارد بالتوازي مع بعضها"},{"en":"A refrigerator drains into a floor drain","es":"Un refrigerador drena en un desagüe de piso","ru":"Холодильник сливается в напольный трап","tr":"Bir buzdolabı zemin giderine boşalır","hi":"एक रेफ्रिजरेटर फर्श की नाली में बहता है","ar":"تصرف ثلاجة في مصرف أرضي"},{"en":"A physical link joins potable water with a source of contamination, such as a hose submerged in a mop bucket","es":"Un enlace físico une el agua potable con una fuente de contaminación, como una manguera sumergida en un cubo de trapear","ru":"Физическое соединение связывает питьевую воду с источником загрязнения, например шланг, погружённый в ведро для мытья полов","tr":"Fiziksel bir bağlantı içilebilir suyu bir kirlilik kaynağına bağlar, örneğin bir paspas kovasına daldırılmış bir hortum","hi":"एक भौतिक संबंध पीने योग्य पानी को दूषण के स्रोत से जोड़ता है, जैसे पोछा बाल्टी में डूबी हुई नली","ar":"رابط فيزيائي يصل الماء الصالح للشرب بمصدر تلوث، مثل خرطوم مغمور في دلو ممسحة"}],"e":{"en":"A cross-connection is a physical link between safe drinking water and a possible source of contamination. A common example is a hose left submerged in a mop bucket or utility sink, allowing backflow of dirty water into the supply.","es":"Una conexión cruzada es un enlace físico entre el agua potable segura y una posible fuente de contaminación. Un ejemplo común es una manguera dejada sumergida en un cubo de trapear o fregadero de servicio, permitiendo el reflujo de agua sucia al suministro.","ru":"Перекрёстное соединение — это физическая связь между безопасной питьевой водой и возможным источником загрязнения. Типичный пример — шланг, оставленный погружённым в ведро для мытья полов или хозяйственную мойку, что допускает обратный поток грязной воды в систему.","tr":"Çapraz bağlantı, güvenli içme suyu ile olası bir kirlilik kaynağı arasındaki fiziksel bir bağlantıdır. Yaygın bir örnek, bir paspas kovasında veya servis evyesinde daldırılmış bırakılan ve kirli suyun besleme hattına geri akmasına izin veren bir hortumdur.","hi":"क्रॉस-कनेक्शन सुरक्षित पीने के पानी और दूषण के संभावित स्रोत के बीच एक भौतिक संबंध है। एक सामान्य उदाहरण पोछा बाल्टी या उपयोगिता सिंक में डूबी छोड़ी गई नली है, जो गंदे पानी को आपूर्ति में वापस बहने देती है।","ar":"الاتصال المتقاطع هو رابط فيزيائي بين مياه الشرب الآمنة ومصدر محتمل للتلوث. مثال شائع هو خرطوم يُترك مغمورًا في دلو ممسحة أو حوض خدمة، مما يسمح بتدفق الماء المتسخ عكسيًا إلى الإمداد."}},{"cat":"facilities","a":0,"q":{"en":"What is the approximate minimum lighting intensity required at food preparation surfaces?","es":"¿Cuál es la intensidad mínima aproximada de iluminación requerida en las superficies de preparación de alimentos?","ru":"Какова примерная минимальная интенсивность освещения, требуемая на поверхностях приготовления пищи?","tr":"Yiyecek hazırlama yüzeylerinde gereken yaklaşık minimum aydınlatma şiddeti nedir?","hi":"खाद्य तैयारी सतहों पर आवश्यक अनुमानित न्यूनतम प्रकाश तीव्रता क्या है?","ar":"ما هي شدة الإضاءة الدنيا التقريبية المطلوبة على أسطح تحضير الطعام؟"},"o":[{"en":"50 foot-candles","es":"50 pies-candela","ru":"50 foot-candles","tr":"50 foot-candle","hi":"50 foot-candles","ar":"50 foot-candles"},{"en":"20 foot-candles","es":"20 pies-candela","ru":"20 foot-candles","tr":"20 foot-candle","hi":"20 foot-candles","ar":"20 foot-candles"},{"en":"10 foot-candles","es":"10 pies-candela","ru":"10 foot-candles","tr":"10 foot-candle","hi":"10 foot-candles","ar":"10 foot-candles"},{"en":"5 foot-candles","es":"5 pies-candela","ru":"5 foot-candles","tr":"5 foot-candle","hi":"5 foot-candles","ar":"5 foot-candles"}],"e":{"en":"Food prep surfaces require about 50 foot-candles of light so employees can work safely and see soils. Handwashing, warewashing, and storage areas need about 20 foot-candles, and walk-ins/dry storage about 10 foot-candles.","es":"Las superficies de preparación de alimentos requieren unos 50 pies-candela de luz para que los empleados trabajen con seguridad y vean la suciedad. Las áreas de lavado de manos, lavado de vajilla y almacenamiento necesitan unos 20 pies-candela, y las cámaras frigoríficas/almacenamiento seco unos 10 pies-candela.","ru":"Поверхности для приготовления пищи требуют около 50 foot-candles освещения, чтобы сотрудники могли безопасно работать и видеть загрязнения. Зоны мытья рук, мойки посуды и хранения нуждаются примерно в 20 foot-candles, а холодильные камеры/сухое хранение — около 10 foot-candles.","tr":"Yiyecek hazırlama yüzeyleri, çalışanların güvenle çalışıp kirleri görebilmesi için yaklaşık 50 foot-candle ışık gerektirir. El yıkama, bulaşık yıkama ve depolama alanları yaklaşık 20 foot-candle, soğuk odalar/kuru depolama ise yaklaşık 10 foot-candle gerektirir.","hi":"खाद्य तैयारी सतहों को लगभग 50 foot-candles प्रकाश की आवश्यकता होती है ताकि कर्मचारी सुरक्षित रूप से काम कर सकें और गंदगी देख सकें। हाथ धोने, बर्तन धोने और भंडारण क्षेत्रों को लगभग 20 foot-candles, और वॉक-इन/सूखे भंडारण को लगभग 10 foot-candles की आवश्यकता होती है।","ar":"تتطلب أسطح تحضير الطعام نحو 50 foot-candles من الإضاءة حتى يعمل الموظفون بأمان ويرون الأوساخ. تحتاج مناطق غسل اليدين وغسل الأواني والتخزين نحو 20 foot-candles، والغرف المبردة/التخزين الجاف نحو 10 foot-candles."}},{"cat":"facilities","a":1,"q":{"en":"Why must light bulbs over food prep, storage, and service areas be shatter-resistant or shielded?","es":"¿Por qué las bombillas sobre las áreas de preparación, almacenamiento y servicio de alimentos deben ser resistentes a roturas o estar protegidas?","ru":"Почему лампы над зонами приготовления, хранения и подачи пищи должны быть ударопрочными или защищёнными?","tr":"Yiyecek hazırlama, depolama ve servis alanlarının üzerindeki ampuller neden kırılmaya dayanıklı veya korumalı olmalıdır?","hi":"खाद्य तैयारी, भंडारण और सेवा क्षेत्रों के ऊपर के बल्ब शैटर-प्रतिरोधी या ढके हुए क्यों होने चाहिए?","ar":"لماذا يجب أن تكون المصابيح فوق مناطق تحضير الطعام والتخزين والخدمة مقاومة للتحطم أو محمية؟"},"o":[{"en":"To make the bulbs last longer","es":"Para que las bombillas duren más","ru":"Чтобы лампы служили дольше","tr":"Ampullerin daha uzun ömürlü olması için","hi":"बल्बों को अधिक समय तक चलाने के लिए","ar":"لجعل المصابيح تدوم لفترة أطول"},{"en":"To prevent glass fragments from contaminating food if a bulb breaks","es":"Para evitar que fragmentos de vidrio contaminen los alimentos si una bombilla se rompe","ru":"Чтобы осколки стекла не загрязнили пищу, если лампа разобьётся","tr":"Bir ampul kırılırsa cam parçalarının yiyeceği kirletmesini önlemek için","hi":"यदि बल्ब टूट जाए तो कांच के टुकड़ों को भोजन को दूषित करने से रोकने के लिए","ar":"لمنع شظايا الزجاج من تلويث الطعام إذا انكسر مصباح"},{"en":"To reduce electricity costs","es":"Para reducir los costos de electricidad","ru":"Чтобы снизить расходы на электроэнергию","tr":"Elektrik maliyetlerini azaltmak için","hi":"बिजली की लागत कम करने के लिए","ar":"لتقليل تكاليف الكهرباء"},{"en":"To provide brighter light","es":"Para proporcionar una luz más brillante","ru":"Чтобы обеспечить более яркий свет","tr":"Daha parlak ışık sağlamak için","hi":"अधिक चमकदार प्रकाश प्रदान करने के लिए","ar":"لتوفير إضاءة أكثر سطوعًا"}],"e":{"en":"Shatter-resistant or shielded bulbs prevent broken glass from becoming a physical hazard in food if a bulb breaks. This is a common requirement in prep, storage, and service areas.","es":"Las bombillas resistentes a roturas o protegidas evitan que el vidrio roto se convierta en un peligro físico en los alimentos si una bombilla se rompe. Este es un requisito común en las áreas de preparación, almacenamiento y servicio.","ru":"Ударопрочные или защищённые лампы предотвращают попадание разбитого стекла как физической опасности в пищу при поломке лампы. Это распространённое требование в зонах приготовления, хранения и подачи.","tr":"Kırılmaya dayanıklı veya korumalı ampuller, bir ampul kırılırsa kırık camın yiyecekte fiziksel bir tehlike olmasını önler. Bu, hazırlık, depolama ve servis alanlarında yaygın bir gerekliliktir.","hi":"शैटर-प्रतिरोधी या ढके हुए बल्ब यह रोकते हैं कि यदि बल्ब टूट जाए तो टूटा हुआ कांच भोजन में एक भौतिक खतरा न बने। यह तैयारी, भंडारण और सेवा क्षेत्रों में एक सामान्य आवश्यकता है।","ar":"المصابيح المقاومة للتحطم أو المحمية تمنع الزجاج المكسور من أن يصبح خطرًا فيزيائيًا في الطعام إذا انكسر مصباح. هذا مطلب شائع في مناطق التحضير والتخزين والخدمة."}},{"cat":"facilities","a":2,"q":{"en":"What is the primary purpose of a ventilation hood system over cooking equipment?","es":"¿Cuál es el propósito principal de un sistema de campana de ventilación sobre el equipo de cocción?","ru":"Какова основная цель системы вытяжного зонта над кухонным оборудованием?","tr":"Pişirme ekipmanının üzerindeki havalandırma davlumbaz sisteminin birincil amacı nedir?","hi":"खाना पकाने के उपकरण के ऊपर वेंटिलेशन हुड प्रणाली का मुख्य उद्देश्य क्या है?","ar":"ما هو الغرض الأساسي من نظام غطاء التهوية فوق معدات الطهي؟"},"o":[{"en":"To keep cooked food warm","es":"Para mantener caliente la comida cocinada","ru":"Чтобы держать приготовленную пищу тёплой","tr":"Pişmiş yiyeceği sıcak tutmak için","hi":"पके हुए भोजन को गर्म रखने के लिए","ar":"للحفاظ على الطعام المطبوخ ساخنًا"},{"en":"To speed up cooking","es":"Para acelerar la cocción","ru":"Чтобы ускорить приготовление","tr":"Pişirmeyi hızlandırmak için","hi":"खाना पकाने में तेजी लाने के लिए","ar":"لتسريع الطهي"},{"en":"To remove grease, smoke, heat, and condensation from the air","es":"Para eliminar grasa, humo, calor y condensación del aire","ru":"Чтобы удалять из воздуха жир, дым, тепло и конденсат","tr":"Havadan yağ, duman, ısı ve yoğuşmayı gidermek için","hi":"हवा से ग्रीस, धुआं, गर्मी और संघनन को हटाने के लिए","ar":"لإزالة الشحوم والدخان والحرارة والتكثيف من الهواء"},{"en":"To provide additional lighting over the range","es":"Para proporcionar iluminación adicional sobre la estufa","ru":"Чтобы обеспечить дополнительное освещение над плитой","tr":"Ocağın üzerinde ek aydınlatma sağlamak için","hi":"रेंज के ऊपर अतिरिक्त प्रकाश प्रदान करने के लिए","ar":"لتوفير إضاءة إضافية فوق الموقد"}],"e":{"en":"Ventilation hoods remove grease, smoke, heat, and condensation from cooking areas. Preventing grease and moisture buildup reduces fire risk, mold, and contamination; hood filters must be cleaned on a schedule.","es":"Las campanas de ventilación eliminan grasa, humo, calor y condensación de las áreas de cocción. Evitar la acumulación de grasa y humedad reduce el riesgo de incendio, moho y contaminación; los filtros de la campana deben limpiarse según un programa.","ru":"Вытяжные зонты удаляют жир, дым, тепло и конденсат из зон приготовления. Предотвращение скопления жира и влаги снижает риск пожара, плесени и загрязнения; фильтры зонта нужно чистить по графику.","tr":"Havalandırma davlumbazları pişirme alanlarından yağ, duman, ısı ve yoğuşmayı giderir. Yağ ve nem birikimini önlemek yangın riskini, küfü ve kirlenmeyi azaltır; davlumbaz filtreleri bir programa göre temizlenmelidir.","hi":"वेंटिलेशन हुड खाना पकाने के क्षेत्रों से ग्रीस, धुआं, गर्मी और संघनन हटाते हैं। ग्रीस और नमी के जमाव को रोकने से आग का जोखिम, फफूंद और दूषण कम होता है; हुड फ़िल्टर को एक कार्यक्रम के अनुसार साफ किया जाना चाहिए।","ar":"تزيل أغطية التهوية الشحوم والدخان والحرارة والتكثيف من مناطق الطهي. منع تراكم الشحوم والرطوبة يقلل من خطر الحريق والعفن والتلوث؛ ويجب تنظيف فلاتر الغطاء وفق جدول زمني."}},{"cat":"facilities","a":3,"q":{"en":"What information should a master cleaning schedule contain?","es":"¿Qué información debe contener un programa maestro de limpieza?","ru":"Какую информацию должен содержать основной график уборки?","tr":"Bir ana temizlik programı hangi bilgileri içermelidir?","hi":"एक मास्टर सफाई कार्यक्रम में कौन सी जानकारी होनी चाहिए?","ar":"ما المعلومات التي يجب أن يحتويها جدول التنظيف الرئيسي؟"},"o":[{"en":"Only the names of employees on duty","es":"Solo los nombres de los empleados de turno","ru":"Только имена дежурных сотрудников","tr":"Yalnızca görevdeki çalışanların isimleri","hi":"केवल ड्यूटी पर मौजूद कर्मचारियों के नाम","ar":"فقط أسماء الموظفين في العمل"},{"en":"Only which chemicals are stored on site","es":"Solo qué químicos se almacenan en el lugar","ru":"Только какие химикаты хранятся на объекте","tr":"Yalnızca sahada hangi kimyasalların depolandığı","hi":"केवल यह कि साइट पर कौन से रसायन संग्रहीत हैं","ar":"فقط المواد الكيميائية المخزنة في الموقع"},{"en":"Only the daily sales figures","es":"Solo las cifras de ventas diarias","ru":"Только ежедневные показатели продаж","tr":"Yalnızca günlük satış rakamları","hi":"केवल दैनिक बिक्री आंकड़े","ar":"فقط أرقام المبيعات اليومية"},{"en":"What must be cleaned, when, who cleans it, and how (including chemicals and equipment)","es":"Qué se debe limpiar, cuándo, quién lo limpia y cómo (incluidos químicos y equipo)","ru":"Что нужно чистить, когда, кто это делает и как (включая химикаты и оборудование)","tr":"Neyin, ne zaman, kim tarafından ve nasıl temizleneceği (kimyasallar ve ekipman dahil)","hi":"क्या साफ करना है, कब, कौन साफ करता है, और कैसे (रसायनों और उपकरणों सहित)","ar":"ما الذي يجب تنظيفه، ومتى، ومن ينظفه، وكيف (بما في ذلك المواد الكيميائية والمعدات)"}],"e":{"en":"A master cleaning schedule specifies what must be cleaned, when, who is responsible, and how (including the chemicals and tools to use). The manager maintains it so nothing is missed and cleaning is consistent.","es":"Un programa maestro de limpieza especifica qué se debe limpiar, cuándo, quién es responsable y cómo (incluidos los químicos y las herramientas a usar). El gerente lo mantiene para que no se pase nada por alto y la limpieza sea constante.","ru":"Основной график уборки определяет, что нужно чистить, когда, кто отвечает и как (включая используемые химикаты и инструменты). Менеджер поддерживает его, чтобы ничего не упустить и обеспечить последовательность уборки.","tr":"Bir ana temizlik programı neyin, ne zaman, kimin sorumluluğunda ve nasıl (kullanılacak kimyasallar ve araçlar dahil) temizleneceğini belirtir. Müdür, hiçbir şeyin atlanmaması ve temizliğin tutarlı olması için bunu sürdürür.","hi":"एक मास्टर सफाई कार्यक्रम निर्दिष्ट करता है कि क्या साफ करना है, कब, कौन जिम्मेदार है, और कैसे (उपयोग किए जाने वाले रसायनों और उपकरणों सहित)। प्रबंधक इसे बनाए रखता है ताकि कुछ भी छूटे नहीं और सफाई सुसंगत हो।","ar":"يحدد جدول التنظيف الرئيسي ما الذي يجب تنظيفه، ومتى، ومن المسؤول، وكيف (بما في ذلك المواد الكيميائية والأدوات المستخدمة). يحافظ المدير عليه حتى لا يُغفل أي شيء ويكون التنظيف متسقًا."}},{"cat":"facilities","a":0,"q":{"en":"Which describes the best overall approach to integrated pest management (IPM)?","es":"¿Cuál describe el mejor enfoque general del manejo integrado de plagas (MIP)?","ru":"Что описывает наилучший общий подход к интегрированной борьбе с вредителями (IPM)?","tr":"Entegre haşere yönetimine (IPM) yönelik en iyi genel yaklaşımı hangisi tanımlar?","hi":"एकीकृत कीट प्रबंधन (IPM) के लिए सर्वोत्तम समग्र दृष्टिकोण कौन सा वर्णन करता है?","ar":"أي مما يلي يصف أفضل نهج شامل للإدارة المتكاملة للآفات (IPM)؟"},"o":[{"en":"Deny pests access, deny them food/water/shelter, and work with a licensed Pest Control Operator","es":"Negar el acceso a las plagas, negarles alimento/agua/refugio y trabajar con un operador de control de plagas con licencia","ru":"Не допускать проникновения вредителей, лишать их пищи/воды/укрытия и работать с лицензированным оператором по борьбе с вредителями","tr":"Haşerelerin girişini engellemek, onlara yiyecek/su/barınak vermemek ve lisanslı bir Haşere Kontrol Operatörüyle çalışmak","hi":"कीटों की पहुंच को रोकना, उन्हें भोजन/पानी/आश्रय से वंचित करना, और एक लाइसेंस प्राप्त कीट नियंत्रण ऑपरेटर के साथ काम करना","ar":"منع وصول الآفات وحرمانها من الطعام/الماء/المأوى والعمل مع مشغل مكافحة آفات مرخص"},{"en":"Spray pesticides throughout the kitchen every night","es":"Rociar pesticidas por toda la cocina cada noche","ru":"Распылять пестициды по всей кухне каждую ночь","tr":"Her gece mutfağın her yerine pestisit püskürtmek","hi":"हर रात पूरे रसोई में कीटनाशकों का छिड़काव करना","ar":"رش المبيدات في جميع أنحاء المطبخ كل ليلة"},{"en":"Wait until pests are seen before taking any action","es":"Esperar hasta ver plagas antes de tomar cualquier acción","ru":"Ждать, пока не появятся вредители, прежде чем принимать меры","tr":"Herhangi bir işlem yapmadan önce haşerelerin görülmesini beklemek","hi":"कोई कार्रवाई करने से पहले कीटों के दिखने तक इंतजार करना","ar":"الانتظار حتى تُرى الآفات قبل اتخاذ أي إجراء"},{"en":"Rely only on keeping the back door open for airflow","es":"Depender solo de mantener la puerta trasera abierta para la ventilación","ru":"Полагаться только на открытую заднюю дверь для проветривания","tr":"Yalnızca hava akışı için arka kapıyı açık tutmaya güvenmek","hi":"केवल हवा के प्रवाह के लिए पिछले दरवाजे को खुला रखने पर निर्भर रहना","ar":"الاعتماد فقط على ترك الباب الخلفي مفتوحًا لتدفق الهواء"}],"e":{"en":"IPM rests on three pillars: deny pests access to the building, deny them food, water, and shelter, and partner with a licensed Pest Control Operator (PCO). It is proactive, not reactive.","es":"El MIP se basa en tres pilares: negar a las plagas el acceso al edificio, negarles alimento, agua y refugio, y asociarse con un operador de control de plagas (PCO) con licencia. Es proactivo, no reactivo.","ru":"IPM опирается на три принципа: не допускать проникновения вредителей в здание, лишать их пищи, воды и укрытия и сотрудничать с лицензированным оператором по борьбе с вредителями (PCO). Это упреждающий, а не реактивный подход.","tr":"IPM üç temele dayanır: haşerelerin binaya girişini engellemek, onlara yiyecek, su ve barınak vermemek ve lisanslı bir Haşere Kontrol Operatörü (PCO) ile ortaklık kurmak. Reaktif değil, proaktiftir.","hi":"IPM तीन स्तंभों पर टिका है: कीटों को इमारत में पहुंच से वंचित करना, उन्हें भोजन, पानी और आश्रय से वंचित करना, और एक लाइसेंस प्राप्त कीट नियंत्रण ऑपरेटर (PCO) के साथ साझेदारी करना। यह प्रतिक्रियात्मक नहीं, बल्कि सक्रिय है।","ar":"تقوم الإدارة المتكاملة للآفات على ثلاث ركائز: منع وصول الآفات إلى المبنى، وحرمانها من الطعام والماء والمأوى، والشراكة مع مشغل مكافحة آفات مرخص (PCO). إنها استباقية وليست تفاعلية."}},{"cat":"facilities","a":1,"q":{"en":"During an inspection a manager finds capsule-shaped droppings, gnaw marks on packaging, and greasy rub marks along a wall. These are most likely signs of:","es":"Durante una inspección, un gerente encuentra excrementos con forma de cápsula, marcas de roeduras en el embalaje y marcas grasientas de roce a lo largo de una pared. Estos son muy probablemente signos de:","ru":"Во время проверки менеджер обнаруживает капсуловидный помёт, следы погрызов на упаковке и жирные следы вдоль стены. Это, скорее всего, признаки:","tr":"Bir denetim sırasında müdür, kapsül şeklinde pislikler, ambalajda kemirme izleri ve duvar boyunca yağlı sürtünme izleri bulur. Bunlar büyük olasılıkla neyin işaretidir:","hi":"एक निरीक्षण के दौरान एक प्रबंधक कैप्सूल के आकार की बूंदें, पैकेजिंग पर कुतरने के निशान और दीवार के साथ चिकने रगड़ के निशान पाता है। ये सबसे अधिक संभावना किसके संकेत हैं:","ar":"أثناء التفتيش يجد مدير فضلات على شكل كبسولة وعلامات قضم على العبوات وعلامات احتكاك دهنية على طول الجدار. هذه على الأرجح علامات على:"},"o":[{"en":"Cockroaches","es":"Cucarachas","ru":"Тараканы","tr":"Hamamböcekleri","hi":"तिलचट्टे","ar":"الصراصير"},{"en":"Rodents (mice or rats)","es":"Roedores (ratones o ratas)","ru":"Грызуны (мыши или крысы)","tr":"Kemirgenler (fareler veya sıçanlar)","hi":"कृंतक (चूहे या चुहिया)","ar":"القوارض (الفئران أو الجرذان)"},{"en":"Flies","es":"Moscas","ru":"Мухи","tr":"Sinekler","hi":"मक्खियाँ","ar":"الذباب"},{"en":"Ants","es":"Hormigas","ru":"Муравьи","tr":"Karıncalar","hi":"चींटियाँ","ar":"النمل"}],"e":{"en":"Rodent infestations are marked by capsule-shaped droppings, gnaw marks on packaging and structures, tracks, and greasy rub marks left as they travel along walls. Nests may also be found in hidden areas.","es":"Las infestaciones de roedores se caracterizan por excrementos con forma de cápsula, marcas de roeduras en embalajes y estructuras, huellas y marcas grasientas de roce que dejan al desplazarse a lo largo de las paredes. También pueden encontrarse nidos en áreas ocultas.","ru":"Заражение грызунами определяется капсуловидным помётом, следами погрызов на упаковке и конструкциях, следами лап и жирными следами, оставляемыми при движении вдоль стен. В укромных местах также могут находиться гнёзда.","tr":"Kemirgen istilaları kapsül şeklinde pisliklerle, ambalaj ve yapılardaki kemirme izleriyle, ayak izleriyle ve duvarlar boyunca hareket ederken bıraktıkları yağlı sürtünme izleriyle belirlenir. Gizli alanlarda yuvalar da bulunabilir.","hi":"कृंतक संक्रमण कैप्सूल के आकार की बूंदों, पैकेजिंग और संरचनाओं पर कुतरने के निशानों, पैरों के निशानों, और दीवारों के साथ चलते समय छोड़े गए चिकने रगड़ के निशानों से चिह्नित होते हैं। छिपे हुए क्षेत्रों में घोंसले भी मिल सकते हैं।","ar":"تتميز إصابات القوارض بفضلات على شكل كبسولة وعلامات قضم على العبوات والهياكل وآثار أقدام وعلامات احتكاك دهنية تتركها أثناء تنقلها على طول الجدران. وقد توجد أعشاش أيضًا في المناطق المخفية."}},{"cat":"facilities","a":2,"q":{"en":"A strong oily odor together with dark, pepper-like specks and capsule-shaped egg cases in cracks most likely indicates:","es":"Un fuerte olor aceitoso junto con manchas oscuras parecidas a pimienta y cápsulas de huevos con forma de cápsula en las grietas indica muy probablemente:","ru":"Сильный маслянистый запах вместе с тёмными, похожими на перец крупинками и капсуловидными яйцевыми оболочками в щелях, скорее всего, указывает на:","tr":"Güçlü yağlı bir koku ile birlikte çatlaklarda koyu, biber benzeri lekeler ve kapsül şeklinde yumurta kılıfları büyük olasılıkla neyi gösterir:","hi":"दरारों में तेज तैलीय गंध के साथ गहरे, काली मिर्च जैसे कण और कैप्सूल के आकार के अंडे के केस सबसे अधिक संभावना क्या दर्शाते हैं:","ar":"رائحة زيتية قوية مع بقع داكنة تشبه الفلفل وأكياس بيض على شكل كبسولة في الشقوق تشير على الأرجح إلى:"},"o":[{"en":"Rodents","es":"Roedores","ru":"Грызуны","tr":"Kemirgenler","hi":"कृंतक","ar":"القوارض"},{"en":"Fruit flies","es":"Moscas de la fruta","ru":"Плодовые мушки","tr":"Meyve sinekleri","hi":"फल मक्खियाँ","ar":"ذباب الفاكهة"},{"en":"A cockroach infestation","es":"Una infestación de cucarachas","ru":"Заражение тараканами","tr":"Bir hamamböceği istilası","hi":"तिलचट्टे का संक्रमण","ar":"إصابة بالصراصير"},{"en":"Birds nesting nearby","es":"Pájaros anidando cerca","ru":"Птицы, гнездящиеся поблизости","tr":"Yakınlarda yuva yapan kuşlar","hi":"पास में घोंसला बनाते पक्षी","ar":"طيور تعشش في مكان قريب"}],"e":{"en":"Cockroaches leave a strong oily odor, dark droppings that look like pepper specks, and capsule-shaped egg cases in cracks and hidden spaces. Because roaches hide by day, daytime sightings often mean a heavy infestation.","es":"Las cucarachas dejan un fuerte olor aceitoso, excrementos oscuros que parecen manchas de pimienta y cápsulas de huevos con forma de cápsula en grietas y espacios ocultos. Como las cucarachas se esconden de día, verlas durante el día suele indicar una infestación grave.","ru":"Тараканы оставляют сильный маслянистый запах, тёмный помёт, похожий на крупинки перца, и капсуловидные яйцевые оболочки в щелях и укромных местах. Поскольку тараканы прячутся днём, их появление днём часто означает сильное заражение.","tr":"Hamamböcekleri güçlü yağlı bir koku, biber lekelerine benzeyen koyu pislikler ve çatlaklarla gizli alanlarda kapsül şeklinde yumurta kılıfları bırakır. Hamamböcekleri gündüz saklandığından, gündüz görülmeleri genellikle yoğun bir istila anlamına gelir.","hi":"तिलचट्टे तेज तैलीय गंध, काली मिर्च के कणों जैसी गहरी बूंदें, और दरारों तथा छिपे स्थानों में कैप्सूल के आकार के अंडे के केस छोड़ते हैं। चूंकि तिलचट्टे दिन में छिपते हैं, दिन में उन्हें देखना अक्सर भारी संक्रमण का संकेत होता है।","ar":"تترك الصراصير رائحة زيتية قوية وفضلات داكنة تشبه بقع الفلفل وأكياس بيض على شكل كبسولة في الشقوق والأماكن المخفية. ولأن الصراصير تختبئ نهارًا، فإن رؤيتها نهارًا غالبًا ما تعني إصابة شديدة."}},{"cat":"facilities","a":3,"q":{"en":"How should garbage containers used in a food establishment be characterized?","es":"¿Cómo deben caracterizarse los recipientes de basura utilizados en un establecimiento de alimentos?","ru":"Какими должны быть мусорные контейнеры, используемые на предприятии питания?","tr":"Bir yiyecek işletmesinde kullanılan çöp kaplarının özellikleri nasıl olmalıdır?","hi":"खाद्य प्रतिष्ठान में उपयोग किए जाने वाले कचरा कंटेनरों की विशेषता कैसी होनी चाहिए?","ar":"كيف يجب أن تتصف حاويات القمامة المستخدمة في منشأة غذائية؟"},"o":[{"en":"Made of cardboard so they can be discarded when full","es":"Hechos de cartón para poder desecharlos cuando estén llenos","ru":"Из картона, чтобы их можно было выбросить, когда наполнятся","tr":"Dolduğunda atılabilmesi için kartondan yapılmış","hi":"कार्डबोर्ड से बने ताकि भरने पर उन्हें फेंका जा सके","ar":"مصنوعة من الكرتون بحيث يمكن التخلص منها عند الامتلاء"},{"en":"Left uncovered so employees can add trash easily","es":"Dejados destapados para que los empleados puedan agregar basura fácilmente","ru":"Оставленными открытыми, чтобы сотрудники легко добавляли мусор","tr":"Çalışanların kolayca çöp ekleyebilmesi için üstü açık bırakılmış","hi":"बिना ढके छोड़े गए ताकि कर्मचारी आसानी से कचरा डाल सकें","ar":"متروكة مكشوفة حتى يتمكن الموظفون من إضافة القمامة بسهولة"},{"en":"Cleaned only once per month","es":"Limpiados solo una vez al mes","ru":"Очищаемыми только раз в месяц","tr":"Yalnızca ayda bir kez temizlenmiş","hi":"केवल महीने में एक बार साफ किए गए","ar":"تُنظّف مرة واحدة فقط في الشهر"},{"en":"Leakproof, waterproof, pest-proof, and kept covered with tight-fitting lids","es":"A prueba de fugas, impermeables, a prueba de plagas y cubiertos con tapas ajustadas","ru":"Герметичными, водонепроницаемыми, защищёнными от вредителей и закрытыми плотно прилегающими крышками","tr":"Sızdırmaz, su geçirmez, haşereye dayanıklı ve sıkıca oturan kapaklarla kapalı tutulmuş","hi":"रिसाव-रोधी, जलरोधक, कीट-रोधी, और कसकर फिट होने वाले ढक्कनों से ढके हुए","ar":"مانعة للتسرب ومقاومة للماء ومقاومة للآفات ومغطاة بأغطية محكمة"}],"e":{"en":"Indoor and outdoor garbage containers must be leakproof, waterproof, pest-proof, easy to clean, and kept covered with tight lids. Containers and the surrounding area should be cleaned frequently and dumpster lids kept closed.","es":"Los recipientes de basura interiores y exteriores deben ser a prueba de fugas, impermeables, a prueba de plagas, fáciles de limpiar y mantenerse cubiertos con tapas ajustadas. Los recipientes y el área circundante deben limpiarse con frecuencia y mantener cerradas las tapas del contenedor de basura.","ru":"Внутренние и наружные мусорные контейнеры должны быть герметичными, водонепроницаемыми, защищёнными от вредителей, легко очищаемыми и закрытыми плотными крышками. Контейнеры и прилегающую территорию следует часто чистить, а крышки мусорных баков держать закрытыми.","tr":"İç ve dış çöp kapları sızdırmaz, su geçirmez, haşereye dayanıklı, temizlenmesi kolay ve sıkı kapaklarla kapalı olmalıdır. Kaplar ve çevresindeki alan sık sık temizlenmeli ve çöp konteyneri kapakları kapalı tutulmalıdır.","hi":"इनडोर और आउटडोर कचरा कंटेनर रिसाव-रोधी, जलरोधक, कीट-रोधी, साफ करने में आसान होने चाहिए और कसकर फिट होने वाले ढक्कनों से ढके रखे जाने चाहिए। कंटेनर और आसपास के क्षेत्र को बार-बार साफ किया जाना चाहिए और डम्पस्टर के ढक्कन बंद रखे जाने चाहिए।","ar":"يجب أن تكون حاويات القمامة الداخلية والخارجية مانعة للتسرب ومقاومة للماء ومقاومة للآفات وسهلة التنظيف ومغطاة بأغطية محكمة. ويجب تنظيف الحاويات والمنطقة المحيطة بها بشكل متكرر وإبقاء أغطية حاوية القمامة مغلقة."}},{"cat":"facilities","a":0,"q":{"en":"A food-contact surface used continuously with the same TCS food at room temperature must be cleaned and sanitized at least every:","es":"Una superficie en contacto con alimentos usada continuamente con el mismo alimento TCS a temperatura ambiente debe limpiarse y desinfectarse al menos cada:","ru":"Поверхность, контактирующая с пищей, используемая непрерывно с одним и тем же продуктом TCS при комнатной температуре, должна очищаться и дезинфицироваться не реже чем каждые:","tr":"Oda sıcaklığında aynı TCS gıdayla sürekli kullanılan, gıdayla temas eden bir yüzey en az kaç saatte bir temizlenip dezenfekte edilmelidir:","hi":"कमरे के तापमान पर एक ही TCS भोजन के साथ लगातार उपयोग की जाने वाली खाद्य-संपर्क सतह को कम से कम हर कितने समय में साफ और सैनिटाइज़ किया जाना चाहिए:","ar":"يجب تنظيف وتطهير السطح الملامس للطعام المستخدم باستمرار مع نفس طعام TCS في درجة حرارة الغرفة على الأقل كل:"},"o":[{"en":"4 hours","es":"4 horas","ru":"4 hours","tr":"4 hours","hi":"4 hours","ar":"4 hours"},{"en":"8 hours","es":"8 horas","ru":"8 hours","tr":"8 hours","hi":"8 hours","ar":"8 hours"},{"en":"12 hours","es":"12 horas","ru":"12 hours","tr":"12 hours","hi":"12 hours","ar":"12 hours"},{"en":"24 hours","es":"24 horas","ru":"24 hours","tr":"24 hours","hi":"24 hours","ar":"24 hours"}],"e":{"en":"Food-contact surfaces in continuous use must be cleaned and sanitized at least every 4 hours. They must also be cleaned whenever contamination could occur, such as when switching between raw and ready-to-eat foods.","es":"Las superficies en contacto con alimentos en uso continuo deben limpiarse y desinfectarse al menos cada 4 horas. También deben limpiarse siempre que pueda ocurrir contaminación, como al cambiar entre alimentos crudos y listos para comer.","ru":"Поверхности, контактирующие с пищей, при непрерывном использовании должны очищаться и дезинфицироваться не реже чем каждые 4 hours. Их также нужно очищать при любой возможности загрязнения, например при переходе между сырыми и готовыми к употреблению продуктами.","tr":"Sürekli kullanımdaki gıdayla temas eden yüzeyler en az her 4 hours bir temizlenip dezenfekte edilmelidir. Ayrıca çiğ ve yenmeye hazır gıdalar arasında geçiş gibi kirlenme olabileceği her durumda temizlenmelidir.","hi":"लगातार उपयोग में आने वाली खाद्य-संपर्क सतहों को कम से कम हर 4 hours में साफ और सैनिटाइज़ किया जाना चाहिए। जब भी दूषण हो सकता है, जैसे कच्चे और खाने-के-लिए-तैयार भोजन के बीच बदलते समय, उन्हें भी साफ किया जाना चाहिए।","ar":"يجب تنظيف وتطهير الأسطح الملامسة للطعام قيد الاستخدام المستمر على الأقل كل 4 hours. كما يجب تنظيفها كلما أمكن حدوث تلوث، مثل التبديل بين الأطعمة النيئة والجاهزة للأكل."}},{"cat":"facilities","a":1,"q":{"en":"A low-temperature (chemical) warewashing machine achieves sanitizing primarily by:","es":"Una máquina lavavajillas de baja temperatura (química) logra la desinfección principalmente mediante:","ru":"Низкотемпературная (химическая) посудомоечная машина осуществляет дезинфекцию главным образом за счёт:","tr":"Düşük sıcaklıklı (kimyasal) bulaşık yıkama makinesi dezenfeksiyonu esas olarak neyle sağlar:","hi":"एक कम-तापमान (रासायनिक) बर्तन धोने की मशीन मुख्य रूप से किसके द्वारा सैनिटाइजेशन प्राप्त करती है:","ar":"تحقق آلة غسل الأواني ذات الحرارة المنخفضة (الكيميائية) التطهير بشكل أساسي عن طريق:"},"o":[{"en":"A final rinse at 180°F","es":"Un enjuague final a 180°F","ru":"Финального ополаскивания при 180°F","tr":"180°F'da son bir durulama","hi":"180°F पर अंतिम रिंस","ar":"شطف نهائي عند 180°F"},{"en":"A chemical sanitizer injected into the rinse per the manufacturer's specifications","es":"Un desinfectante químico inyectado en el enjuague según las especificaciones del fabricante","ru":"Химического дезинфектанта, вводимого в ополаскивание согласно спецификациям производителя","tr":"Üreticinin özelliklerine göre durulamaya enjekte edilen bir kimyasal dezenfektan","hi":"निर्माता की विशिष्टताओं के अनुसार रिंस में इंजेक्ट किया गया रासायनिक सैनिटाइज़र","ar":"مطهر كيميائي يُحقن في الشطف وفق مواصفات الشركة المصنعة"},{"en":"Steam applied for 60 seconds","es":"Vapor aplicado durante 60 segundos","ru":"Пара, применяемого в течение 60 seconds","tr":"60 seconds boyunca uygulanan buhar","hi":"60 seconds के लिए लागू भाप","ar":"بخار يُطبّق لمدة 60 seconds"},{"en":"Ultraviolet light in the wash chamber","es":"Luz ultravioleta en la cámara de lavado","ru":"Ультрафиолетового света в моечной камере","tr":"Yıkama haznesinde ultraviyole ışık","hi":"धुलाई कक्ष में पराबैंगनी प्रकाश","ar":"أشعة فوق بنفسجية في حجرة الغسيل"}],"e":{"en":"Low-temperature machines sanitize with a chemical sanitizer (often chlorine) in the final rinse, following the manufacturer's specifications for concentration and temperature. High-temperature machines instead rely on a 180°F rinse.","es":"Las máquinas de baja temperatura desinfectan con un desinfectante químico (a menudo cloro) en el enjuague final, siguiendo las especificaciones del fabricante para la concentración y la temperatura. Las máquinas de alta temperatura, en cambio, dependen de un enjuague a 180°F.","ru":"Низкотемпературные машины дезинфицируют химическим дезинфектантом (часто хлором) в финальном ополаскивании, согласно спецификациям производителя по концентрации и температуре. Высокотемпературные машины вместо этого используют ополаскивание при 180°F.","tr":"Düşük sıcaklıklı makineler, konsantrasyon ve sıcaklık için üreticinin özelliklerine uyarak son durulamada kimyasal bir dezenfektanla (genellikle klor) dezenfekte eder. Yüksek sıcaklıklı makineler ise 180°F durulamaya dayanır.","hi":"कम-तापमान वाली मशीनें अंतिम रिंस में रासायनिक सैनिटाइज़र (अक्सर क्लोरीन) से सैनिटाइज़ करती हैं, सांद्रता और तापमान के लिए निर्माता की विशिष्टताओं का पालन करते हुए। उच्च-तापमान वाली मशीनें इसके बजाय 180°F रिंस पर निर्भर करती हैं।","ar":"تعقّم الآلات ذات الحرارة المنخفضة بمطهر كيميائي (غالبًا الكلور) في الشطف النهائي، وفق مواصفات الشركة المصنعة للتركيز ودرجة الحرارة. أما الآلات ذات الحرارة العالية فتعتمد على شطف عند 180°F."}},{"cat":"facilities","a":2,"q":{"en":"Where should pesticides be stored in a food establishment, and who should apply them?","es":"¿Dónde deben almacenarse los pesticidas en un establecimiento de alimentos y quién debe aplicarlos?","ru":"Где следует хранить пестициды на предприятии питания и кто должен их применять?","tr":"Bir yiyecek işletmesinde pestisitler nerede saklanmalı ve kim uygulamalıdır?","hi":"खाद्य प्रतिष्ठान में कीटनाशकों को कहाँ संग्रहीत किया जाना चाहिए, और उन्हें कौन लगाना चाहिए?","ar":"أين يجب تخزين المبيدات في منشأة غذائية، ومن الذي يجب أن يطبّقها؟"},"o":[{"en":"Above the prep table, applied by any available employee","es":"Encima de la mesa de preparación, aplicados por cualquier empleado disponible","ru":"Над разделочным столом, применяются любым свободным сотрудником","tr":"Hazırlık masasının üzerinde, mevcut herhangi bir çalışan tarafından uygulanır","hi":"प्रेप टेबल के ऊपर, किसी भी उपलब्ध कर्मचारी द्वारा लगाया गया","ar":"فوق طاولة التحضير، ويطبّقها أي موظف متاح"},{"en":"In the dry storage room next to flour, applied by the manager","es":"En el almacén seco junto a la harina, aplicados por el gerente","ru":"В сухом складе рядом с мукой, применяются менеджером","tr":"Kuru depoda unun yanında, müdür tarafından uygulanır","hi":"सूखे भंडारण कक्ष में आटे के बगल में, प्रबंधक द्वारा लगाया गया","ar":"في غرفة التخزين الجاف بجوار الدقيق، ويطبّقها المدير"},{"en":"In a dedicated, secure area away from food and food equipment, applied by a licensed applicator","es":"En un área dedicada y segura lejos de alimentos y equipo, aplicados por un aplicador con licencia","ru":"В отдельной, защищённой зоне вдали от пищи и оборудования, применяются лицензированным специалистом","tr":"Gıda ve gıda ekipmanlarından uzakta, özel ve güvenli bir alanda, lisanslı bir uygulayıcı tarafından uygulanır","hi":"भोजन और खाद्य उपकरण से दूर एक समर्पित, सुरक्षित क्षेत्र में, एक लाइसेंस प्राप्त लगाने वाले द्वारा लगाया गया","ar":"في منطقة مخصصة وآمنة بعيدًا عن الطعام ومعدات الطعام، ويطبّقها فنّي مرخص"},{"en":"Anywhere convenient, applied whenever pests are seen","es":"En cualquier lugar conveniente, aplicados cuando se vean plagas","ru":"В любом удобном месте, применяются, когда замечены вредители","tr":"Uygun herhangi bir yerde, haşere görüldüğünde uygulanır","hi":"किसी भी सुविधाजनक स्थान पर, जब भी कीट दिखें तब लगाया गया","ar":"في أي مكان مناسب، وتُطبّق كلما شوهدت الآفات"}],"e":{"en":"Pesticides must be stored in their original labeled containers in a secure area away from food, utensils, and equipment, and applied only by a licensed Pest Control Operator. This protects food from chemical contamination.","es":"Los pesticidas deben almacenarse en sus recipientes originales etiquetados en un área segura lejos de alimentos, utensilios y equipo, y aplicarse solo por un operador de control de plagas con licencia. Esto protege los alimentos de la contaminación química.","ru":"Пестициды следует хранить в оригинальной маркированной таре в защищённой зоне вдали от пищи, посуды и оборудования и применять только лицензированным оператором по борьбе с вредителями. Это защищает пищу от химического загрязнения.","tr":"Pestisitler orijinal etiketli kaplarında, gıda, mutfak eşyaları ve ekipmandan uzakta güvenli bir alanda saklanmalı ve yalnızca lisanslı bir Haşere Kontrol Operatörü tarafından uygulanmalıdır. Bu, gıdayı kimyasal kirlenmeden korur.","hi":"कीटनाशकों को उनके मूल लेबल वाले कंटेनरों में भोजन, बर्तनों और उपकरण से दूर एक सुरक्षित क्षेत्र में संग्रहीत किया जाना चाहिए, और केवल एक लाइसेंस प्राप्त कीट नियंत्रण ऑपरेटर द्वारा लगाया जाना चाहिए। यह भोजन को रासायनिक दूषण से बचाता है।","ar":"يجب تخزين المبيدات في عبواتها الأصلية المُلصقة في منطقة آمنة بعيدًا عن الطعام والأدوات والمعدات، وأن يطبّقها فقط مشغل مكافحة آفات مرخص. وهذا يحمي الطعام من التلوث الكيميائي."}},{"cat":"facilities","a":3,"q":{"en":"For clean-in-place (CIP) equipment such as a soft-serve machine, what is essential to sanitary operation?","es":"Para equipos de limpieza en el lugar (CIP), como una máquina de helado suave, ¿qué es esencial para una operación sanitaria?","ru":"Для оборудования с очисткой на месте (CIP), например автомата для мягкого мороженого, что необходимо для санитарной эксплуатации?","tr":"Yumuşak dondurma makinesi gibi yerinde temizlenen (CIP) ekipmanlar için hijyenik çalışma açısından temel olan nedir?","hi":"क्लीन-इन-प्लेस (CIP) उपकरण जैसे सॉफ्ट-सर्व मशीन के लिए, स्वच्छ संचालन के लिए क्या आवश्यक है?","ar":"بالنسبة للمعدات التي تُنظّف في مكانها (CIP) مثل آلة الآيس كريم الطري، ما الأساسي للتشغيل الصحي؟"},"o":[{"en":"It never needs to be disassembled or cleaned","es":"Nunca necesita desmontarse ni limpiarse","ru":"Его никогда не нужно разбирать или чистить","tr":"Asla sökülmesi veya temizlenmesi gerekmez","hi":"इसे कभी भी अलग करने या साफ करने की आवश्यकता नहीं होती","ar":"لا تحتاج أبدًا إلى التفكيك أو التنظيف"},{"en":"Only the exterior surfaces need cleaning","es":"Solo las superficies exteriores necesitan limpieza","ru":"Чистить нужно только внешние поверхности","tr":"Yalnızca dış yüzeylerin temizlenmesi gerekir","hi":"केवल बाहरी सतहों को सफाई की आवश्यकता होती है","ar":"الأسطح الخارجية فقط تحتاج إلى تنظيف"},{"en":"It can be cleaned with plain hot water alone","es":"Puede limpiarse solo con agua caliente","ru":"Его можно чистить только горячей водой","tr":"Yalnızca sade sıcak suyla temizlenebilir","hi":"इसे केवल सादे गर्म पानी से साफ किया जा सकता है","ar":"يمكن تنظيفها بالماء الساخن العادي فقط"},{"en":"Cleaning and sanitizing solutions are circulated through it on the schedule and per the manufacturer's directions","es":"Las soluciones de limpieza y desinfección se hacen circular a través de él según el programa y las instrucciones del fabricante","ru":"Через него по графику и согласно инструкции производителя циркулируют моющие и дезинфицирующие растворы","tr":"Temizleme ve dezenfekte çözeltileri, program dahilinde ve üreticinin talimatlarına göre içinden dolaştırılır","hi":"सफाई और सैनिटाइजिंग घोल इसके माध्यम से कार्यक्रम के अनुसार और निर्माता के निर्देशों के अनुसार परिचालित किए जाते हैं","ar":"تُدار محاليل التنظيف والتطهير خلالها وفق الجدول وتعليمات الشركة المصنعة"}],"e":{"en":"Clean-in-place equipment is cleaned and sanitized by circulating cleaning and sanitizing solutions through it without full disassembly, following the manufacturer's directions and the cleaning schedule. Some parts may still require periodic disassembly.","es":"El equipo de limpieza en el lugar se limpia y desinfecta haciendo circular soluciones de limpieza y desinfección a través de él sin desmontarlo por completo, siguiendo las instrucciones del fabricante y el programa de limpieza. Algunas piezas aún pueden requerir desmontaje periódico.","ru":"Оборудование с очисткой на месте очищают и дезинфицируют, прогоняя через него моющие и дезинфицирующие растворы без полной разборки, следуя инструкциям производителя и графику уборки. Некоторые детали всё же могут требовать периодической разборки.","tr":"Yerinde temizlenen ekipman, tam sökülmeden içinden temizleme ve dezenfekte çözeltileri dolaştırılarak, üreticinin talimatlarına ve temizlik programına uyularak temizlenip dezenfekte edilir. Bazı parçalar yine de periyodik sökme gerektirebilir.","hi":"क्लीन-इन-प्लेस उपकरण को पूरी तरह से अलग किए बिना उसके माध्यम से सफाई और सैनिटाइजिंग घोल परिचालित करके, निर्माता के निर्देशों और सफाई कार्यक्रम का पालन करते हुए साफ और सैनिटाइज़ किया जाता है। कुछ भागों को अभी भी समय-समय पर अलग करने की आवश्यकता हो सकती है।","ar":"تُنظّف وتُطهّر المعدات التي تُنظّف في مكانها عن طريق تدوير محاليل التنظيف والتطهير خلالها دون تفكيك كامل، وفق تعليمات الشركة المصنعة وجدول التنظيف. وقد لا تزال بعض الأجزاء تتطلب تفكيكًا دوريًا."}},{"cat":"facilities","a":0,"q":{"en":"In a high-temperature warewasher, what must the dish surface temperature reach for effective sanitizing?","es":"En una lavavajillas de alta temperatura, ¿qué temperatura de superficie del plato debe alcanzarse para una desinfección eficaz?","ru":"В высокотемпературной посудомоечной машине какой температуры должна достигать поверхность посуды для эффективной дезинфекции?","tr":"Yüksek sıcaklıklı bulaşık makinesinde etkili dezenfeksiyon için tabak yüzey sıcaklığı hangi değere ulaşmalıdır?","hi":"उच्च-तापमान वाली बर्तन धोने की मशीन में, प्रभावी सैनिटाइजिंग के लिए बर्तन की सतह का तापमान क्या पहुंचना चाहिए?","ar":"في غسالة الأواني ذات الحرارة العالية، ما درجة حرارة سطح الطبق التي يجب أن تصل إليها للتطهير الفعّال؟"},"o":[{"en":"160°F","es":"160°F","ru":"160°F","tr":"160°F","hi":"160°F","ar":"160°F"},{"en":"110°F","es":"110°F","ru":"110°F","tr":"110°F","hi":"110°F","ar":"110°F"},{"en":"135°F","es":"135°F","ru":"135°F","tr":"135°F","hi":"135°F","ar":"135°F"},{"en":"212°F","es":"212°F","ru":"212°F","tr":"212°F","hi":"212°F","ar":"212°F"}],"e":{"en":"While the final sanitizing rinse in a high-temperature machine must be at least 180°F, the goal is for the dish surface itself to reach 160°F. A temperature-sensitive label placed on a dish can confirm the surface temperature.","es":"Aunque el enjuague final de desinfección en una máquina de alta temperatura debe ser de al menos 180°F, el objetivo es que la superficie del plato alcance 160°F. Una etiqueta sensible a la temperatura colocada en un plato puede confirmar la temperatura de la superficie.","ru":"Хотя финальное дезинфицирующее ополаскивание в высокотемпературной машине должно быть не менее 180°F, цель — чтобы сама поверхность посуды достигла 160°F. Термочувствительная наклейка на посуде подтвердит температуру поверхности.","tr":"Yüksek sıcaklıklı makinede son dezenfekte durulaması en az 180°F olmalıysa da, amaç tabak yüzeyinin kendisinin 160°F'a ulaşmasıdır. Tabağa yerleştirilen sıcaklığa duyarlı bir etiket yüzey sıcaklığını doğrulayabilir.","hi":"यद्यपि उच्च-तापमान वाली मशीन में अंतिम सैनिटाइजिंग रिंस कम से कम 180°F होनी चाहिए, लक्ष्य यह है कि बर्तन की सतह स्वयं 160°F तक पहुंचे। बर्तन पर रखा एक तापमान-संवेदनशील लेबल सतह के तापमान की पुष्टि कर सकता है।","ar":"بينما يجب أن يكون الشطف النهائي للتطهير في الآلة ذات الحرارة العالية عند 180°F على الأقل، فإن الهدف هو أن يصل سطح الطبق نفسه إلى 160°F. يمكن لملصق حساس للحرارة موضوع على الطبق تأكيد درجة حرارة السطح."}},{"cat":"facilities","a":1,"q":{"en":"Which non-food-contact surface still requires regular cleaning on the master cleaning schedule?","es":"¿Qué superficie que no está en contacto con alimentos aún requiere limpieza regular en el programa maestro de limpieza?","ru":"Какая поверхность, не контактирующая с пищей, всё же требует регулярной уборки по основному графику?","tr":"Gıdayla temas etmeyen hangi yüzey yine de ana temizlik programında düzenli temizlik gerektirir?","hi":"कौन सी गैर-खाद्य-संपर्क सतह अभी भी मास्टर सफाई कार्यक्रम पर नियमित सफाई की आवश्यकता रखती है?","ar":"أي سطح غير ملامس للطعام لا يزال يتطلب تنظيفًا منتظمًا ضمن جدول التنظيف الرئيسي؟"},"o":[{"en":"The inside of a cutting board's food-contact face","es":"La cara en contacto con alimentos de una tabla de cortar","ru":"Рабочая поверхность разделочной доски, контактирующая с пищей","tr":"Bir kesme tahtasının gıdayla temas eden yüzü","hi":"कटिंग बोर्ड की खाद्य-संपर्क सतह","ar":"الوجه الملامس للطعام من لوح التقطيع"},{"en":"Floors, walls, ceilings, and the exteriors of equipment","es":"Pisos, paredes, techos y los exteriores del equipo","ru":"Полы, стены, потолки и внешние поверхности оборудования","tr":"Zeminler, duvarlar, tavanlar ve ekipmanların dış yüzeyleri","hi":"फर्श, दीवारें, छत, और उपकरण के बाहरी हिस्से","ar":"الأرضيات والجدران والأسقف والأسطح الخارجية للمعدات"},{"en":"The interior of a mixing bowl","es":"El interior de un tazón de mezclar","ru":"Внутренняя поверхность миски для смешивания","tr":"Bir karıştırma kabının içi","hi":"मिक्सिंग बाउल का आंतरिक भाग","ar":"الجزء الداخلي من وعاء الخلط"},{"en":"The blade of a slicer","es":"La cuchilla de una rebanadora","ru":"Лезвие слайсера","tr":"Bir dilimleyicinin bıçağı","hi":"स्लाइसर का ब्लेड","ar":"شفرة آلة التقطيع"}],"e":{"en":"Non-food-contact surfaces such as floors, walls, ceilings, and equipment exteriors do not touch food but still collect dust, grease, and debris that attract pests. They must be cleaned regularly per the master cleaning schedule.","es":"Las superficies que no están en contacto con alimentos, como pisos, paredes, techos y exteriores del equipo, no tocan los alimentos pero aún acumulan polvo, grasa y residuos que atraen plagas. Deben limpiarse regularmente según el programa maestro de limpieza.","ru":"Поверхности, не контактирующие с пищей, — полы, стены, потолки и внешние части оборудования — не касаются пищи, но всё же накапливают пыль, жир и мусор, привлекающие вредителей. Их нужно регулярно чистить по основному графику уборки.","tr":"Zeminler, duvarlar, tavanlar ve ekipman dış yüzeyleri gibi gıdayla temas etmeyen yüzeyler gıdaya değmez ama yine de haşereleri çeken toz, yağ ve kalıntı biriktirir. Ana temizlik programına göre düzenli temizlenmelidir.","hi":"फर्श, दीवारें, छत और उपकरण के बाहरी हिस्से जैसी गैर-खाद्य-संपर्क सतहें भोजन को नहीं छूतीं लेकिन फिर भी धूल, ग्रीस और मलबा जमा करती हैं जो कीटों को आकर्षित करता है। इन्हें मास्टर सफाई कार्यक्रम के अनुसार नियमित रूप से साफ किया जाना चाहिए।","ar":"الأسطح غير الملامسة للطعام مثل الأرضيات والجدران والأسقف والأسطح الخارجية للمعدات لا تلامس الطعام لكنها لا تزال تجمع الغبار والشحوم والبقايا التي تجذب الآفات. يجب تنظيفها بانتظام وفق جدول التنظيف الرئيسي."}},{"cat":"facilities","a":3,"q":{"en":"Handwashing sinks in a food establishment should be used for:","es":"Los lavamanos en un establecimiento de alimentos deben usarse para:","ru":"Раковины для мытья рук на предприятии питания должны использоваться для:","tr":"Bir yiyecek işletmesindeki el yıkama lavaboları ne için kullanılmalıdır:","hi":"खाद्य प्रतिष्ठान में हाथ धोने के सिंक का उपयोग किसके लिए किया जाना चाहिए:","ar":"يجب استخدام أحواض غسل اليدين في المنشأة الغذائية من أجل:"},"o":[{"en":"Washing produce quickly when other sinks are busy","es":"Lavar productos rápidamente cuando otros fregaderos están ocupados","ru":"Быстрого мытья продуктов, когда другие мойки заняты","tr":"Diğer evyeler meşgulken ürünleri hızlıca yıkamak","hi":"जब अन्य सिंक व्यस्त हों तो जल्दी से उपज धोने के लिए","ar":"غسل المنتجات بسرعة عندما تكون الأحواض الأخرى مشغولة"},{"en":"Filling and dumping mop buckets","es":"Llenar y vaciar cubos de trapear","ru":"Наполнения и опорожнения вёдер для мытья полов","tr":"Paspas kovalarını doldurmak ve boşaltmak","hi":"पोछा बाल्टी भरने और खाली करने के लिए","ar":"ملء دلاء الممسحة وتفريغها"},{"en":"Thawing frozen chicken under running water","es":"Descongelar pollo congelado bajo agua corriente","ru":"Размораживания замороженной курицы под проточной водой","tr":"Donmuş tavuğu akan su altında çözmek","hi":"बहते पानी के नीचे जमे हुए चिकन को पिघलाने के लिए","ar":"إذابة الدجاج المجمد تحت الماء الجاري"},{"en":"Handwashing only, and nothing else","es":"Solo lavarse las manos y nada más","ru":"Только мытья рук и ничего больше","tr":"Yalnızca el yıkama, başka hiçbir şey değil","hi":"केवल हाथ धोने के लिए, और कुछ नहीं","ar":"غسل اليدين فقط، ولا شيء آخر"}],"e":{"en":"A handwashing sink must be used only for handwashing. Using it to rinse food, fill or dump mop buckets, or thaw food risks contamination and can leave staff without a dedicated place to wash their hands.","es":"Un lavamanos debe usarse solo para lavarse las manos. Usarlo para enjuagar alimentos, llenar o vaciar cubos de trapear o descongelar alimentos arriesga la contaminación y puede dejar al personal sin un lugar dedicado para lavarse las manos.","ru":"Раковина для мытья рук должна использоваться только для мытья рук. Использование её для ополаскивания продуктов, наполнения или опорожнения вёдер для мытья полов или размораживания пищи создаёт риск загрязнения и может лишить персонал специального места для мытья рук.","tr":"El yıkama lavabosu yalnızca el yıkama için kullanılmalıdır. Onu yiyecek durulamak, paspas kovası doldurup boşaltmak veya yiyecek çözmek için kullanmak kirlenme riski oluşturur ve personeli ellerini yıkayacak özel bir yerden yoksun bırakabilir.","hi":"हाथ धोने के सिंक का उपयोग केवल हाथ धोने के लिए किया जाना चाहिए। इसे भोजन धोने, पोछा बाल्टी भरने या खाली करने, या भोजन पिघलाने के लिए उपयोग करना दूषण का जोखिम पैदा करता है और कर्मचारियों को हाथ धोने के लिए एक समर्पित स्थान से वंचित कर सकता है।","ar":"يجب استخدام حوض غسل اليدين لغسل اليدين فقط. واستخدامه لشطف الطعام أو ملء دلاء الممسحة أو تفريغها أو إذابة الطعام يعرّض للتلوث وقد يترك الموظفين دون مكان مخصص لغسل أيديهم."}},{"cat":"facilities","a":0,"q":{"en":"A grease trap (grease interceptor) is installed primarily to:","es":"Una trampa de grasa (interceptor de grasa) se instala principalmente para:","ru":"Жироуловитель (жироотделитель) устанавливается главным образом для того, чтобы:","tr":"Bir yağ tutucu (yağ ayırıcı) esas olarak ne için kurulur:","hi":"ग्रीस ट्रैप (ग्रीस इंटरसेप्टर) मुख्य रूप से किसके लिए स्थापित किया जाता है:","ar":"تُركّب مصيدة الشحوم (فاصل الشحوم) بشكل أساسي من أجل:"},"o":[{"en":"Keep grease from clogging and contaminating the plumbing and sewage system","es":"Evitar que la grasa obstruya y contamine el sistema de plomería y alcantarillado","ru":"Не допустить засорения и загрязнения жиром системы канализации и водоотведения","tr":"Yağın tesisatı ve kanalizasyon sistemini tıkamasını ve kirletmesini önlemek","hi":"ग्रीस को प्लंबिंग और सीवेज सिस्टम को अवरुद्ध और दूषित करने से रोकने के लिए","ar":"منع الشحوم من انسداد وتلويث نظام السباكة والصرف الصحي"},{"en":"Heat water for the dish machine","es":"Calentar agua para la máquina lavavajillas","ru":"Нагревать воду для посудомоечной машины","tr":"Bulaşık makinesi için suyu ısıtmak","hi":"डिश मशीन के लिए पानी गर्म करने के लिए","ar":"تسخين الماء لآلة غسل الأطباق"},{"en":"Filter drinking water at the tap","es":"Filtrar el agua potable en el grifo","ru":"Фильтровать питьевую воду в кране","tr":"Musluktaki içme suyunu filtrelemek","hi":"नल पर पीने के पानी को फ़िल्टर करने के लिए","ar":"تصفية مياه الشرب عند الصنبور"},{"en":"Prevent backflow into the potable supply","es":"Prevenir el reflujo hacia el suministro potable","ru":"Предотвращать обратный поток в систему питьевой воды","tr":"İçilebilir su beslemesine geri akışı önlemek","hi":"पीने योग्य आपूर्ति में बैकफ्लो को रोकने के लिए","ar":"منع التدفق العكسي إلى إمداد المياه الصالحة للشرب"}],"e":{"en":"A grease trap captures fats, oils, and grease before they enter the drain lines, preventing clogs, backups, and contamination of the sewage system. It must be cleaned and maintained regularly to work.","es":"Una trampa de grasa captura grasas, aceites y grasa antes de que entren en las líneas de desagüe, evitando obstrucciones, retrocesos y contaminación del sistema de alcantarillado. Debe limpiarse y mantenerse regularmente para funcionar.","ru":"Жироуловитель улавливает жиры, масла и жир до их попадания в дренажные линии, предотвращая засоры, обратный подпор и загрязнение канализации. Для работы его нужно регулярно чистить и обслуживать.","tr":"Yağ tutucu, yağları ve gresleri tahliye hatlarına girmeden önce yakalayarak tıkanmaları, geri tepmeleri ve kanalizasyon sisteminin kirlenmesini önler. Çalışması için düzenli temizlenmeli ve bakımı yapılmalıdır.","hi":"ग्रीस ट्रैप वसा, तेल और ग्रीस को नाली लाइनों में प्रवेश करने से पहले पकड़ लेता है, जिससे रुकावटें, बैकअप और सीवेज सिस्टम का दूषण रुकता है। काम करने के लिए इसे नियमित रूप से साफ और बनाए रखा जाना चाहिए।","ar":"تلتقط مصيدة الشحوم الدهون والزيوت والشحوم قبل دخولها خطوط الصرف، مما يمنع الانسدادات والارتجاع وتلوث نظام الصرف الصحي. ويجب تنظيفها وصيانتها بانتظام لتعمل."}},{"cat":"facilities","a":2,"q":{"en":"A cutting board's surface has become deeply scored and pitted from heavy use. What should the manager do?","es":"La superficie de una tabla de cortar se ha rayado y picado profundamente por el uso intenso. ¿Qué debe hacer el gerente?","ru":"Поверхность разделочной доски покрылась глубокими порезами и выбоинами от интенсивного использования. Что должен сделать менеджер?","tr":"Bir kesme tahtasının yüzeyi yoğun kullanımdan derin çizik ve çukurlarla dolmuş. Müdür ne yapmalı?","hi":"भारी उपयोग से कटिंग बोर्ड की सतह गहराई से खरोंची और गड्ढेदार हो गई है। प्रबंधक को क्या करना चाहिए?","ar":"أصبح سطح لوح التقطيع محزّزًا ومنقّرًا بعمق بسبب الاستخدام الكثيف. ماذا يجب أن يفعل المدير؟"},"o":[{"en":"Keep using it as long as it is washed daily","es":"Seguir usándola mientras se lave a diario","ru":"Продолжать пользоваться ею, пока её моют ежедневно","tr":"Günlük yıkandığı sürece kullanmaya devam etmek","hi":"जब तक इसे रोज धोया जाता है, इसका उपयोग जारी रखना","ar":"الاستمرار في استخدامه طالما يُغسل يوميًا"},{"en":"Cover the grooves with plastic wrap before use","es":"Cubrir las ranuras con envoltura plástica antes de usarla","ru":"Закрывать бороздки плёнкой перед использованием","tr":"Kullanmadan önce yivleri plastik streçle kapatmak","hi":"उपयोग से पहले खांचों को प्लास्टिक रैप से ढकना","ar":"تغطية الأخاديد بغلاف بلاستيكي قبل الاستخدام"},{"en":"Resurface or replace it, because scratches and pits harbor bacteria and cannot be fully cleaned","es":"Reacondicionarla o reemplazarla, porque los rayones y picaduras albergan bacterias y no pueden limpiarse por completo","ru":"Отшлифовать или заменить её, потому что царапины и выбоины укрывают бактерии и не могут быть полностью очищены","tr":"Yeniden yüzeylemek veya değiştirmek, çünkü çizikler ve çukurlar bakteri barındırır ve tam temizlenemez","hi":"इसे फिर से सतह करना या बदलना, क्योंकि खरोंच और गड्ढे बैक्टीरिया को आश्रय देते हैं और पूरी तरह से साफ नहीं किए जा सकते","ar":"إعادة تسوية سطحه أو استبداله، لأن الخدوش والتنقرات تؤوي البكتيريا ولا يمكن تنظيفها بالكامل"},{"en":"Use it only for cooked foods from now on","es":"Usarla solo para alimentos cocidos de ahora en adelante","ru":"Использовать её отныне только для приготовленной пищи","tr":"Bundan sonra yalnızca pişmiş yiyecekler için kullanmak","hi":"अब से इसका उपयोग केवल पके हुए भोजन के लिए करना","ar":"استخدامه من الآن فصاعدًا للأطعمة المطبوخة فقط"}],"e":{"en":"Food-contact surfaces must stay smooth and easy to clean. Deep scratches and pits in a cutting board trap food and bacteria that cannot be removed by cleaning, so the board should be resurfaced or replaced.","es":"Las superficies en contacto con alimentos deben permanecer lisas y fáciles de limpiar. Los rayones y picaduras profundos en una tabla de cortar atrapan comida y bacterias que no se pueden eliminar limpiando, por lo que la tabla debe reacondicionarse o reemplazarse.","ru":"Поверхности, контактирующие с пищей, должны оставаться гладкими и легко очищаемыми. Глубокие царапины и выбоины на разделочной доске задерживают пищу и бактерии, которые нельзя удалить очисткой, поэтому доску следует отшлифовать или заменить.","tr":"Gıdayla temas eden yüzeyler pürüzsüz ve temizlenmesi kolay kalmalıdır. Kesme tahtasındaki derin çizikler ve çukurlar, temizlemeyle giderilemeyen yiyecek ve bakteri barındırır, bu nedenle tahta yeniden yüzeylenmeli veya değiştirilmelidir.","hi":"खाद्य-संपर्क सतहें चिकनी और साफ करने में आसान रहनी चाहिए। कटिंग बोर्ड में गहरी खरोंच और गड्ढे भोजन और बैक्टीरिया को फंसाते हैं जिन्हें सफाई से नहीं हटाया जा सकता, इसलिए बोर्ड को फिर से सतह किया जाना चाहिए या बदला जाना चाहिए।","ar":"يجب أن تبقى الأسطح الملامسة للطعام ملساء وسهلة التنظيف. الخدوش والتنقرات العميقة في لوح التقطيع تحبس الطعام والبكتيريا التي لا يمكن إزالتها بالتنظيف، لذا يجب إعادة تسوية اللوح أو استبداله."}}]};
